-- Poems batch 186
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f2393a8b-b1df-4a56-ae3f-e494f44d18d4','薦福塔聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','踴甓皇都壯，盤基紫宙雄。',193,'全唐诗/poet.song.18000.json','["踴甓皇都壯，盤基紫宙雄。", "山河供遠目，簷戶發高風。", "梯險三休上，輪開一氣中。", "門當谷子午，影落陌西東。", "韻鐸翻天籟，危觚駐夕紅。", "仙聆悲下俗，仰面識長空。", "絕若神擠至，深疑壑暗通。", "人寰如蟻垤，身世甚秋蓬。", "歎息興亡地，沈吟製作工。", "清思抱明月，狂欲把飛鴻。", "去矣登臨興，巍乎是造化功。", "凉襟當爽塏，幽意入鴻濛。", "頭角峯如揖，丹青樹不同。", "城郭回迤邐，閣殿失穹隆。", "可使孤懷放，胡爲萬恨然。", "何當得壯士，提取出塵籠。"]'),
('97b893af-2575-4546-8d33-5c50a4c532ff','悲二子聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','有客自遠方，來以二字說。',288,'全唐诗/poet.song.18000.json','["有客自遠方，來以二字說。", "穆子病疾初，家事巨細缺。", "鄰人苦其求，醫師久以决。", "案杯小大空，布被旁午裂。", "餘喘尚能鼓，老憤知已結。", "目凄望羊泓，髭斷反蝟茁。", "憂酸繫餘生，嗥嘑留永訣。", "語妻後日計，書策未可徹。", "教子勤誦讀，時命不復說。", "吾屬何流離，眾人方草竊。", "凌子久道路，十口著羈紲。", "拾稆重江間，正值大饑節。", "既無裹飯交，疾走繼粗糲。", "又無執飲人，及時沃枯竭。", "惜哉損天命，痛焉在親絰。", "帝胡生爾身，世復稱其傑。", "胸伏氣萬丈，腸貯怨百折。", "艱難汨風波，顦顇墮霜雪。", "久僕勤龍鍾，弱女癡蹩躠。", "文隨寒餓空，道與煙燄滅。", "魂兮竟何歸，去矣不得別。", "中府豈無財，莫濟醫藥切。", "太倉豈無粟，莫解腹腸熱。", "天子聖在上，海內清欲澈。"]'),
('b04439c7-72d0-4234-a58f-c2037717f2cf','地動聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','大荒孟冬月，末旬高舂時。',288,'全唐诗/poet.song.18000.json','["大荒孟冬月，末旬高舂時。", "日腹昏盲倀，風口鳴嗚咿。", "萬靈困陰戚，百植嗟陽衰。", "濃寒有勝氣，天凍無敗期。", "六指忽摇拽，羣蹠初奔馳。", "丸銅落蟾吻，始異張渾儀。", "列宿犯天紀，預念漢志辭。", "民甍函鼓舞，禁堞强崩離。", "坐駭市聲死，立怖人足踦。", "坦途重車僨，急傳壯馬敧。", "陵阜動撫手，礫塊當揚箕。", "停污有亂浪，僵木無靜枝。", "眾喙不敢息，沓嶂驚欲飛。", "踊塔撼鐸碎，安流蕩舟疲。", "倒壺喪午漏，顛巢駭眠鴟。", "居人眩眸子，行客勞髑兒。", "南北頓儵忽，西東播戎夷。", "四鎮一毛重，百川寸涔微。", "斗藪不如大，軒幹主者誰。", "共工豈復怒，富嫗安得爲。", "寧無折軸患，頓易崩山悲。", "眾蟄不安土，羣毛難麗皮。", "驚者去靡所，仆或如見擠。", "轟雷下檐瓦，決玉傾倉粢。"]'),
('0f6817e6-5741-4d8a-873c-e767071c6f01','瓦亭聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','陰霜策策風呼虓，羌賊膽開兇燄豪。',384,'全唐诗/poet.song.18000.json','["陰霜策策風呼虓，羌賊膽開兇燄豪。", "赤膠脆折乳馬健，漢野秋穟黄雲高。", "驅先老尩伏壯黠，裹以山壑鬼莫招。", "烽臺屹屹百丈起，但報平安摇桔槹。", "喜聞羸師入吾地，主將踴躍士惰驕。", "神鋒前揮擁勝勢，橫陣立敵俱奔逃。", "不知餌牽落檻穽，一麾發伏如驚飆。", "重圍八面鳥難度，相顧無路惟青霄。", "地形窄束甲刺骨，眥裂不復能相鏖。", "棄兵衮衮今不殺，部曲易主無纖囂。", "慟哭皇天未厭禍，空同無色勁氣消。", "狂童得志賤物命，隴上盤馬爲嬉遨。", "蒼皇林間健兒婦，翦紙瀝酒呼嗸嗸。", "將軍疾趨占葬地，年年載柩爭咸崤。", "朝廷不惜好官爵，絳蠟刻印埋蓬蒿。", "三公悲吟困數敗，車上輕重如鴻毛。", "白衣壯士氣塞腹，憤勇不忍羞本朝。", "重瞳三顧可易得，亮輩本亦生吾曹。", "窮居哀勞厭咄咄，歲月奔激朱顔凋。", "當年請行大明下，今日頹墮思南巢。", "陽羨溪光逗蒼玉，尺半健鯽煙中跳。", "便欲買田學秧稻，不復與世爭錙毫。", "奈何三世奉恩澤，肯以軀命辭枯焦。", "以知出處繫大義，一飯四顧情如燒。"]'),
('91d83011-bcea-4714-9047-22ba61a6f027','淮上喜雨聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','江淮經歲旱，春暮忽然雨。',240,'全唐诗/poet.song.18000.json','["江淮經歲旱，春暮忽然雨。", "亂點踰廣津，散灑入原土。", "萬物氣稍蘇，厲妖莫能聚。", "羣山洗故塵，紫翠坐可數。", "昏如籠纖紗，媚若隱紺縷。", "碧瓦南崦中，重疊出迥覩。", "扁舟凌空飛，白鳥入煙舞。", "遥林動新滋，顔色若可取。", "碧草弄微芳，低昂欲來語。", "緐聲過沙頭，上下謳啞櫓。", "濃澹新畫成，快愜久病愈。", "念此時多虞，豈得歲少阻。", "焦心閔疲農，虛口待香稌。", "縣吏事兇貪，氣若解縛虎。", "惟於縱誅斂，乃能奮怒武。", "青天雖云明，疑不照艱苦。", "此時忽霶霈，知有神物主。", "不然諸蒼生，性命委草莽。", "本蹷邦豈寧，皮去毛安附。", "歌此告巨公，行當視前古。"]'),
('5f75c94e-3b68-4429-8043-ac30b0933389','和石曼卿明河詠','蘇舜欽','宋','宋诗','song-poetry','','[]','八月銀河好，天高夜自明。',48,'全唐诗/poet.song.18000.json','["八月銀河好，天高夜自明。", "樓臺通迥意，風露得餘清。", "幾爲浮雲亂，都宜小雨晴。", "離人强回首，耿耿邈無情。"]'),
('54229deb-efc4-4176-b355-70740ded9c78','師黯以彭甘五子爲寄因懷四明園中此果甚多偶成長句以爲謝','蘇舜欽','宋','宋诗','song-poetry','','[]','憶向江東太守園，猗猗甘樹蔽前軒。',64,'全唐诗/poet.song.18000.json','["憶向江東太守園，猗猗甘樹蔽前軒。", "風摇玉蕊霏微落，霜發金衣委墜緐。", "枕畔冷香通醉夢，齒邊餘味滌吟魂。", "天彭路遠無因得，猶賴君心記舊恩。"]'),
('396bef12-6111-4ad8-89fa-f3338105256c','遊洛中內','蘇舜欽','宋','宋诗','song-poetry','','[]','洛陽宮殿鬰嵯峨，千古榮華逐逝波。',64,'全唐诗/poet.song.18000.json','["洛陽宮殿鬰嵯峨，千古榮華逐逝波。", "別殿秋高風淅瀝，後園春老樹婆娑。", "露凝碧瓦寒光滿，日轉觚稜暖豔多。", "早晚金輿此遊幸，鳳樓前後看山河。"]'),
('4835bd7d-23ec-4f37-8974-6091ba26fd44','送杜密學赴并州','蘇舜欽','宋','宋诗','song-poetry','','[]','維帝私明哲，遥遥世可論。',192,'全唐诗/poet.song.18000.json','["維帝私明哲，遥遥世可論。", "風流擅南國，文采續高門。", "才美趨賢路，名雄出帝閽。", "雍容初入幕，烜赫已開藩。", "黠吏腹心潰，疲民襦袴溫。", "讞刑曾攬轡，按俗亦飛軒。", "倚注宸襟切，淹回物論喧。", "朔區官益峻，憲府望彌尊。", "除弊朝之急，于時孰肯言。", "議高心不撓，補外眾爲冤。", "西雍新恩重，中臺故事存。", "政行殊有體，化洽密無痕。", "尺詔來丹扆，雙符換太原。", "具裝明晚野，大旆卷朝暾。", "惠愛留關輔，風威入塞垣。", "安車行急召，想望慰元元。"]'),
('92d54d32-887c-4057-94fa-4221ab976cd3','送家靜及第後赴官清水','蘇舜欽','宋','宋诗','song-poetry','','[]','幾年塵土客京華，一日春乘犯斗槎。',64,'全唐诗/poet.song.18000.json','["幾年塵土客京華，一日春乘犯斗槎。", "夢好夜歸全蜀道，眼明朝宴上林花。", "白頭佐邑非爲晚，藍綬還鄉亦可誇。", "況有雄圖看悟主，莫傷孤宦向天涯。"]'),
('2a8fa4ed-cb7b-4926-86b2-6234c54e2725','串夷','蘇舜欽','宋','宋诗','song-poetry','','[]','區區黠虜敢狂呼，遣使峨冠謁上都。',64,'全唐诗/poet.song.18000.json','["區區黠虜敢狂呼，遣使峨冠謁上都。", "輒出封章辭國命，妄傳聲勢困軍須。", "閉之塞漠爲良策，啖以民膏是失圖。", "淳俗易摇無自撓，每聞流議一長吁。"]'),
('04570565-f2dc-4ab7-a9ec-1745212a7493','靜勝堂夏日呈王尉','蘇舜欽','宋','宋诗','song-poetry','','[]','虛堂吏事稀，吟卧欲忘機。',48,'全唐诗/poet.song.18000.json','["虛堂吏事稀，吟卧欲忘機。", "窗靜蜂迷出，簾輕燕誤飛。", "煩心傾晚簟，倦體快風衣。", "更想霜雲外，同君看翠微。"]'),
('e62c89a3-8b35-4527-b40d-f0ac18928de4','黎生下第還鄉','蘇舜欽','宋','宋诗','song-poetry','','[]','人云之子賢，文采出巴川。',48,'全唐诗/poet.song.18000.json','["人云之子賢，文采出巴川。", "失意聲名在，還愛歲月遷。", "離懷春色裏，歸路夕陽邊。", "無廢青箱學，窮愁古亦然。"]'),
('c7a15e7b-3955-43dd-ab55-358c424e26ce','春日晚晴','蘇舜欽','宋','宋诗','song-poetry','','[]','人言春雨好，更好晚來晴。',48,'全唐诗/poet.song.18000.json','["人言春雨好，更好晚來晴。", "樹色通簾翠，烟姿著物明。", "得泥初燕喜，避弋去鴻輕。", "誰見危欄外，斜陽盡眼平。"]'),
('f2db393f-3c6e-40bc-968d-9fa11bd954ff','代人上申公祝壽','蘇舜欽','宋','宋诗','song-poetry','','[]','維神祚炎曆，發藴復含靈。',264,'全唐诗/poet.song.18000.json','["維神祚炎曆，發藴復含靈。", "嶷爾爲人瑞，居然出相庭。", "舜門登夙望，韋氏繼先經。", "積學方開隩，當官已發硎。", "純誠貫白日，闊步上青冥。", "才力回元氣，胸懷納四溟。", "八荒歸富壽，萬象染丹青。", "懇牘辭魁柄，開藩密帝扃。", "碧旌油重潤，蒼佩玉明熒。", "輿望知難轉，王心幾不寧。", "西羌動妖孽，秦塞困羶腥。", "羽奏飛關路，兜烽照濁涇。", "裴公辭激烈，袁相涕飄零。", "天爲移文象，人思奉典型。", "歡謠塞歸路，召節下宸廷。", "勝算劇破竹，威聲如走霆。", "折衝千里定，指畫眾心醒。", "大議虛懷納，訏謨前席聽。", "玉關收舊地，廟鼎續新銘。", "復聳巖巖石，增輝兩兩星。", "川源流盛美，岳鎮敵長齡。", "有客慙才薄，區區詠德馨。"]'),
('72002f28-adfc-4386-aaf6-9b5f7a435eae','有客','蘇舜欽','宋','宋诗','song-poetry','','[]','有客論時事，相看各慘然。',48,'全唐诗/poet.song.18000.json','["有客論時事，相看各慘然。", "蠻夷殺郡將，蝗蝻食民田。", "蕭瑟心空遠，徘徊志自憐。", "何人同國恥，餘憤落樽前。"]'),
('5c3720c9-f2cf-48fc-9b99-fad4ac59bcf0','遊南內九龍宮','蘇舜欽','宋','宋诗','song-poetry','','[]','昔帝龍驤後，因池大此宮。',168,'全唐诗/poet.song.18000.json','["昔帝龍驤後，因池大此宮。", "蕭笳疊終日，旌仗展無窮。", "繪塑神靈集，飛潛爪角雄。", "陰軒常隱霧，暗堵亦含風。", "巨盜來移國，天王遽避戎。", "蒼黄狩巴蜀，倏忽陷河潼。", "閣殿回看遠，塵氛久見蒙。", "歸來故基在，不與往時同。", "疊瓦煙間碧，新蕖露下紅。", "波春蕩初月，沙晚發悲鴻。", "世變今無復，人愁杳莫終。", "樹穿瑶甃裂，碑碎玉樓空。", "九曲皆遺石，諸王祗斷蓬。", "興亡何足問，一一夕陽中。"]'),
('89febe35-0239-4b7c-9599-be8682fd31e6','送陳進士遊江南','蘇舜欽','宋','宋诗','song-poetry','','[]','昔也衣裾已化塵，驅車今去涉驚津。',64,'全唐诗/poet.song.18000.json','["昔也衣裾已化塵，驅車今去涉驚津。", "淮天蒼茫背殘臘，江路逶迤逢舊春。", "時有飄梅應得句，苦無蒸酒可霑巾。", "歸來莫戀溪山勝，楓鬼揶揄解笑人。"]'),
('7867b198-79fb-4f0f-8de8-69837b762829','和馬承之古廟','蘇舜欽','宋','宋诗','song-poetry','','[]','廟貌空山裏，垣頹入逕斜。',48,'全唐诗/poet.song.18000.json','["廟貌空山裏，垣頹入逕斜。", "尚應名竹素，不復祭牲豭。", "木暗鴞呼鬼，庭荒雀啅虵。", "有靈從寂寞，慎勿學兇邪。"]'),
('10f95124-1e38-4427-820e-649597d90276','和解生中秋月','蘇舜欽','宋','宋诗','song-poetry','','[]','不爲人間意，居然節物清。',48,'全唐诗/poet.song.18000.json','["不爲人間意，居然節物清。", "銀堂通夜白，金餅隔林明。", "醉客尊前倒，棲烏露下驚。", "悲歡今古事，寂寂墮荒城。"]'),
('1c52e007-5dbe-4ea5-8797-e9cd221af550','宿太平宮','蘇舜欽','宋','宋诗','song-poetry','','[]','驅車長道久塵勞，一宿清宮醒骨毛。',64,'全唐诗/poet.song.18000.json','["驅車長道久塵勞，一宿清宮醒骨毛。", "古檜有風天自籟，石壇多露鶴爭嗥。", "星河耿耿秋還迥，棲觀澄澄夜更高。", "吟對疎鐘俗機盡，已疑身世屬仙曹。"]'),
('84dd1c29-de30-4197-beed-4abe1c630d1c','獨遊輞川','蘇舜欽','宋','宋诗','song-poetry','','[]','行穿翠靄中，絕澗落疎鐘。',48,'全唐诗/poet.song.18000.json','["行穿翠靄中，絕澗落疎鐘。", "數里踏亂石，一川環碧峯。", "暗林麋養角，當路虎留蹤。", "隱逸何曾見，孤吟對古松。"]'),
('e56a0706-49ea-4f18-9614-4a97f840647a','過下馬陵','蘇舜欽','宋','宋诗','song-poetry','','[]','下馬陵頭草色春，我一懷古一霑巾。',32,'全唐诗/poet.song.18000.json','["下馬陵頭草色春，我一懷古一霑巾。", "陵邊又有纍纍冢，應是當年取酒人。"]'),
('5ef32316-bc6e-40ef-9069-858f9887e120','覽含元殿基因想昔時朝會之盛且感其興廢之故','蘇舜欽','宋','宋诗','song-poetry','','[]','在昔朝元日，千門動地來。',168,'全唐诗/poet.song.18000.json','["在昔朝元日，千門動地來。", "方隅正無事，輔相復多才。", "仗下簪纓肅，天中繖扇開。", "皇威瞻斗極，曙色辨崔嵬。", "赤案波光卷，鳴梢殿尾回。", "熊羆驅禁衛，雨露覆蘭臺。", "橫賜傾中帑，窮奢役九垓。", "只知營國用，不畏屈民財。", "翠輦還移幸，旻天未悔災。", "羣心爭困獸，回首變寒灰。", "曾以安無慮，翻令世所哀。", "行人看碧瓦，獨鳥下蒼苔。", "雖念陵爲谷，遥知禍有胎。", "青編遺迹在，此地亦悠哉。"]'),
('eb411181-5b77-47c8-a873-1118e2a3a766','望秦陵','蘇舜欽','宋','宋诗','song-poetry','','[]','雄心雖蓋世，竟亦棄羣臣。',48,'全唐诗/poet.song.18000.json','["雄心雖蓋世，竟亦棄羣臣。", "役重傾天下，時危啟聖人。", "石麟空舉首，銀海罷流春。", "隴闕今無復，應深行路塵。"]'),
('2cac80fd-42dc-4386-afdb-f9cc14fd48d3','留題樊川李長官莊','蘇舜欽','宋','宋诗','song-poetry','','[]','社曲東邊風物幽，我來繫馬獨淹留。',64,'全唐诗/poet.song.18000.json','["社曲東邊風物幽，我來繫馬獨淹留。", "門前翠影山無數，竹下寒聲水亂流。", "酒壓新塵常得醉，花開番次不知秋。", "主公堆案縈官事，早晚歸來今白頭。"]'),
('a29bea74-205f-4661-bc11-c47e8ab563ab','宿終南山下百塔院','蘇舜欽','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','驅馬山前訪古蹤，僧居蕭灑隔塵籠。',64,'全唐诗/poet.song.18000.json','["驅馬山前訪古蹤，僧居蕭灑隔塵籠。", "遶庭石鼈谷間水，入戶鳴鴟堆上風。", "無限老松秋色裏，數聲疎鐸月明中。", "村雞坐聽三號徹，去去前朝氣味同。"]'),
('b78d4144-73c1-4e9a-862a-fe593b8450ab','宿華嚴寺與友生會話','蘇舜欽','宋','宋诗','song-poetry','','[]','危構岧嶤出太虛，坐看斜日墮平蕪。',64,'全唐诗/poet.song.18000.json','["危構岧嶤出太虛，坐看斜日墮平蕪。", "白煙覆地澄江闊，皎月當天尺璧孤。", "疎磬悲吟來竹閣，青燈寂寞照吟軀。", "老僧怪我何爲者，說盡興亡涕淚俱。"]'),
('8d38f9c3-62a5-404f-8dbb-6e35c1128174','送王楊庭著作宰巫山','蘇舜欽','宋','宋诗','song-poetry','','[]','蘭臺舊漫郎，爲邑上瞿唐。',48,'全唐诗/poet.song.18000.json','["蘭臺舊漫郎，爲邑上瞿唐。", "地僻風煙古，公餘日景長。", "江聲通白帝，山勢入青羌。", "落筆多佳句，時應滿錦囊。"]'),
('f0db2980-2b51-4994-b685-00ef0f5fade8','晚意','蘇舜欽','宋','宋诗','song-poetry','','[]','晚色微茫至，前山次第昏。',48,'全唐诗/poet.song.18000.json','["晚色微茫至，前山次第昏。", "羸牛歸徑遠，宿鳥傍檐翻。", "盤喜黄粱熟，杯餘白酒渾。", "田家雖澹薄，猶得離塵喧。"]'),
('354f40c2-4373-424a-92f3-e42593458a33','春暮初晴自御宿川之華嚴寺','蘇舜欽','宋','宋诗','song-poetry','','[]','春暮曾無屬物心，野行聊得據鞍吟。',64,'全唐诗/poet.song.18000.json','["春暮曾無屬物心，野行聊得據鞍吟。", "路經廢苑情通古，水遶蒼山意共深。", "殘日花間浮暖豔，斷雲樓外卷輕陰。", "騷人自昔傷鶗鴂，休苦風前送好音。"]'),
('4ff0e1d4-fbf9-4ca1-a1f7-f0a207ccec5d','次韻和師黯寄王耿端公','蘇舜欽','宋','宋诗','song-poetry','','[]','嫉惡曾收柱後冠，淹淪今未復榮班。',64,'全唐诗/poet.song.18000.json','["嫉惡曾收柱後冠，淹淪今未復榮班。", "青雲失路初心遠，白雪盈簪壯志閑。", "廄馬尚嘶驄奮迅，篋衣猶曝繡斕斑。", "風流縣尹多才思，時寄篇章與解顔。"]'),
('6e2e4880-c7bc-4135-a415-3ede82f90c5c','聞京尹范希文謫鄱陽尹十二師魯以黨人貶郢中歐陽九永叔移書責諫官不論救而謫夷陵令因成此詩以寄且慰其遠邁也','蘇舜欽','宋','宋诗','song-poetry','','[]','朝野蔚多士，衮然良可羞。',144,'全唐诗/poet.song.18000.json','["朝野蔚多士，衮然良可羞。", "伊人秉直節，許國有深謀。", "大議摇巖石，危言犯采旒。", "蒼黄出京府，憔悴謫南州。", "引黨俄嗟尹，移書遽竄歐。", "安慙言得罪，要避曲如鉤。", "郢路幾束馬，荆川還泝舟。", "傷心眾山集，舉目大江流。", "遠動家公念，深貽壽母憂。", "橫身罹禍難，當路積仇讎。", "衛上寧無術，亢宗非所優。", "吾君思正士，莫賦畔牢愁。"]'),
('63874ff7-f391-4251-86c9-edc18a75fb03','暑景','蘇舜欽','宋','宋诗','song-poetry','','[]','溽暑倦幽齋，縱橫書亂堆。',48,'全唐诗/poet.song.18000.json','["溽暑倦幽齋，縱橫書亂堆。", "風多應秀麥，雨密不黄梅。", "乳燕並頭語，紅葵向背開。", "吟餘晴月上，凉思入尊罍。"]'),
('68ccadcd-cfd6-4613-9d1e-a85d518579bb','夏中','蘇舜欽','宋','宋诗','song-poetry','','[]','院僻簾深晝景虛，輕風時見動竿烏。',64,'全唐诗/poet.song.18000.json','["院僻簾深晝景虛，輕風時見動竿烏。", "池中綠滿魚留子，庭下陰多燕引雛。", "雨後看兒爭墜果，天晴同客曝殘書。", "幽棲未免牽塵事，身世相忘在酒壺。"]'),
('de8109fb-1ee0-486b-bfd4-9f96902db752','夏意','蘇舜欽','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u590f\u5929"]','別院深深夏簟清，石榴開遍透簾明。',32,'全唐诗/poet.song.18000.json','["別院深深夏簟清，石榴開遍透簾明。", "樹陰滿地日當午，夢覺流鶯時一聲。"]'),
('d1dfb75b-b124-4c9b-9ade-e3e58aec5d57','和淮上遇便風','蘇舜欽','宋','宋诗','song-poetry','','[]','浩蕩清淮天共流，長風萬里送歸舟。',32,'全唐诗/poet.song.18000.json','["浩蕩清淮天共流，長風萬里送歸舟。", "應愁晚泊喧卑地，吹入滄溟始自由。"]'),
('32562975-a1ec-476f-af61-8ef70da19ae8','先公之愛馬以病寄他廄今死矣','蘇舜欽','宋','宋诗','song-poetry','','[]','先君所乘馬，其色白於銀。',96,'全唐诗/poet.song.18000.json','["先君所乘馬，其色白於銀。", "磊落龍之種，權奇世共珍。", "獨嘶如想望，久步見精神。", "方目照代夜，拳毛刷渭津。", "鬣寒如擁浪，蹄駃不驚塵。", "潦倒已伏櫪，蒼黄仍借人。", "俄傳弊帷信，無復錦蒙親。", "倚棹思神駿，蕭然淚灑巾。"]'),
('31091a85-9089-41b9-bae9-454e3e15e405','重過句章郡','蘇舜欽','宋','宋诗','song-poetry','','[]','曾隨使旆此東歸，日日登臨到落暉。',64,'全唐诗/poet.song.18000.json','["曾隨使旆此東歸，日日登臨到落暉。", "疇昔侍行猶總角，如今重過合霑衣。", "窺魚翠碧忘形坐，趁伴蜻蜓照影飛。", "風物依然皆自得，歲華飄忽賞心違。"]'),
('c454420a-85ee-46f0-9d54-851a6e0c54a9','晚出潤州東門','蘇舜欽','宋','宋诗','song-poetry','','[]','京口古雄處，昔年嘗此過。',48,'全唐诗/poet.song.18000.json','["京口古雄處，昔年嘗此過。", "風流看石獸，人事共江波。", "河轉路疑盡，日斜山更多。", "城樓鬰天半，回首恣吟哦。"]'),
('579ccf09-f58e-4533-95fb-77da5321a831','無錫惠山寺','蘇舜欽','宋','宋诗','song-poetry','','[]','寺古名傳唐相詩，三伏奔迸予何之。',64,'全唐诗/poet.song.18000.json','["寺古名傳唐相詩，三伏奔迸予何之。", "雲山相照翠會合，殿閣對走凉參差。", "清泉絕無一塵染，長松自是拔俗姿。", "二邊羌胡日鬭格，釋子宴坐殊不知。"]'),
('c2e97e72-3bdf-470f-b7bb-28b593ce264f','過蘇州','蘇舜欽','宋','宋诗','song-poetry','','[]','東出盤門刮眼明，蕭蕭疎雨更陰晴。',64,'全唐诗/poet.song.18000.json','["東出盤門刮眼明，蕭蕭疎雨更陰晴。", "綠楊白鷺俱自得，近水遠山皆有情。", "萬物盛衰天意在，一身羈苦俗人輕。", "無窮好景無緣住，旅櫂區區暮亦行。"]'),
('5ec3994d-6165-4200-a4e6-bbd2531a73a7','吳江亭','蘇舜欽','宋','宋诗','song-poetry','','[]','氣象清雄天與鄰，世間不合有埃塵。',32,'全唐诗/poet.song.18000.json','["氣象清雄天與鄰，世間不合有埃塵。", "擬將累句酬佳景，只恐江山解笑人。"]'),
('be26c84d-d693-4f46-9b8c-aa48cb5ac487','秀州通越門外八九里臨水多佳木茂樹以便風不得停舟一賞愴然爲詩','蘇舜欽','宋','宋诗','song-poetry','','[]','密樹重蘿覆水光，珍禽無數語琅琅。',32,'全唐诗/poet.song.18000.json','["密樹重蘿覆水光，珍禽無數語琅琅。", "驚帆瞥過如飛鳥，回首風煙空斷腸。"]'),
('57e84e00-dc0b-4d38-b774-7be1f0481888','秀州城外九里有竹樹小橋予十八年前與友人解晦叔飲別於此今過之景物依然而解生已亡悲嘆不足復成小詩','蘇舜欽','宋','宋诗','song-poetry','','[]','當年共醉此橋邊，道舊狂歌至暮天。',64,'全唐诗/poet.song.18000.json','["當年共醉此橋邊，道舊狂歌至暮天。", "得句旋題新竹上，移舟還傍亂花前。", "君埋塵土骨應化，我逐風波心欲燃。", "落日長號感人事，沙頭寂寞上漁船。"]'),
('2134753f-f407-43b6-805e-12684bffe1ea','天章道中','蘇舜欽','宋','宋诗','song-poetry','','[]','畫鷁低飛湖水平，高低樓閣滿稽城。',64,'全唐诗/poet.song.18000.json','["畫鷁低飛湖水平，高低樓閣滿稽城。", "人遊鏡裏山相照，魚戲空中日共明。", "盡是荷風香不斷，忽逢溪雨氣尤清。", "籃輿却上蘭亭步，猿鳥雲蘿伴此行。"]'),
('432405b1-f53e-4a94-87d7-067cdda18967','望太湖','蘇舜欽','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','杳杳波濤閱古今，四無邊際莫知深。',64,'全唐诗/poet.song.18000.json','["杳杳波濤閱古今，四無邊際莫知深。", "潤通曉月爲清露，氣入霜天作暝陰。", "笠澤鱸肥人膾玉，洞庭柑熟客分金。", "風烟觸目相招引，聊爲停橈一楚吟。"]'),
('405346b2-f304-4bdd-88d1-47f54b5e01eb','大禹寺','蘇舜欽','宋','宋诗','song-poetry','','[]','鑑湖盡處眾峯前，寺古蕭疎水石間。',64,'全唐诗/poet.song.18000.json','["鑑湖盡處眾峯前，寺古蕭疎水石間。", "殿閣北垂連禹廟，松筠東去入稽山。", "坐中巖鳥自上下，吟久溪雲時往還。", "我厭區區走名宦，未能來此一生閑。"]'),
('c9d71ae9-b035-434d-b7df-8bb901a802bd','杭州巽亭','蘇舜欽','宋','宋诗','song-poetry','','[]','公自登臨闢草萊，赫然危構壓崔嵬。',64,'全唐诗/poet.song.18000.json','["公自登臨闢草萊，赫然危構壓崔嵬。", "凉翻簾幌潮聲過，清入琴尊雨氣來。", "疇昔江山何處好，生平懷抱此中開。", "東南地本多幽勝，此向東南特壯哉。"]'),
('f4def8c5-31f3-4424-81af-535f22698604','宿錢塘安濟亭觀潮','蘇舜欽','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','支肘聽潮聲，喧豗久未停。',72,'全唐诗/poet.song.18000.json','["支肘聽潮聲，喧豗久未停。", "隨風過漁浦，伴月出滄溟。", "鰌穴浚時滿，胥神果有靈。", "連天卷雲霧，徹曉下雷霆。", "捨檝游心倦，憑闌醉魄醒。", "誰窮造物意，擬訪酈元經。"]'),
('13c375e4-01a4-44f7-b7d4-0e67c59f76c6','使風','蘇舜欽','宋','宋诗','song-poetry','','[]','長風天外來，十幅健帆開。',48,'全唐诗/poet.song.18000.json','["長風天外來，十幅健帆開。", "仰首飛雲合，牽心翠竹回。", "閑觀水知性，靜與睡爲媒。", "始覺揚舲快，疲駑亦可哀。"]'),
('0d4e4203-a43f-440d-8078-a1a548d546da','松江長橋未明觀漁','蘇舜欽','宋','宋诗','song-poetry','','[]','曙光東向欲朧明，漁艇縱橫映遠汀。',64,'全唐诗/poet.song.18000.json','["曙光東向欲朧明，漁艇縱橫映遠汀。", "濤面白煙昏落月，嶺頭殘燒混疎星。", "鳴根莫觸蛟龍睡，舉網時聞魚鼈腥。", "我實宦遊無況者，擬來隨爾带笭箵。"]'),
('2949ccde-9272-4c9a-b3da-e95593563853','新開湖晚霽','蘇舜欽','宋','宋诗','song-poetry','','[]','霽霞飛盡失西東，水入天光浩氣中。',32,'全唐诗/poet.song.18000.json','["霽霞飛盡失西東，水入天光浩氣中。", "籍籍輕帆一遊鳥，似乘風力上虛空。"]'),
('084596d6-b65a-4ec9-a58f-c0250180b558','九日汴中','蘇舜欽','宋','宋诗','song-poetry','','[]','旅櫂出江湖，漂然迹更孤。',48,'全唐诗/poet.song.18000.json','["旅櫂出江湖，漂然迹更孤。", "風波數破膽，時事一長吁。", "聞說西羌使，猶稽北闕誅。", "俗言無上策，且復醉茱萸。"]'),
('29d51cc3-bd2b-48c4-b3bd-eca133f2974a','淮中晚泊犢頭','蘇舜欽','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5199\u666f", "\u95f2\u9002"]','春陰垂野草青青，時有幽花一樹明。',32,'全唐诗/poet.song.18000.json','["春陰垂野草青青，時有幽花一樹明。", "晚泊孤舟古祠下，滿川風雨看潮生。"]'),
('5a6fa1a0-b635-4c88-a1df-5d1a97c8dbaa','韓忠憲公挽詞二首  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','才發經綸地，心開忠義源。',48,'全唐诗/poet.song.18000.json','["才發經綸地，心開忠義源。", "朝端遺盛業，泉下閟英魂。", "儲禁追封美，儀曹集謚尊。", "他年還駟馬，餘德在高門。"]'),
('aac4cb81-73be-494f-818a-2e1885dd406f','韓忠憲公挽詞二首  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','中臺典故明，二府弼諧成。',48,'全唐诗/poet.song.18000.json','["中臺典故明，二府弼諧成。", "車挂身方佚，舟移世共驚。", "霜風吹縞帳，野月照丹旌。", "寂寞都門路，傷哉如昔行。"]'),
('b6a89e6b-158d-40e3-a20d-50936bdd4c06','詔獄中懷藍田高先生','蘇舜欽','宋','宋诗','song-poetry','','[]','自嗟疏野性，不曉世塗艱。',48,'全唐诗/poet.song.18000.json','["自嗟疏野性，不曉世塗艱。", "仰首羨飛鳥，冥心思故山。", "剛來投密網，誰復爲顰顔。", "寄語高安素，今思日往還。"]'),
('350a7098-b8c9-471c-821d-53e34c5a9eac','湘公院冬夕有懷','蘇舜欽','宋','宋诗','song-poetry','','[]','去年急雪灑窗夜，獨對殘燈觀陣圖。',48,'全唐诗/poet.song.18000.json','["去年急雪灑窗夜，獨對殘燈觀陣圖。", "今夕悲風撼軒竹，又來開卷擁寒爐。", "禪房瀟灑皆依舊，世路崎嶇有萬殊。"]'),
('c1dd2d64-bd12-452a-874f-8b5b3f49ce9f','離京後作','蘇舜欽','宋','宋诗','song-poetry','','[]','春風奈別何，一櫂逐驚波。',48,'全唐诗/poet.song.18000.json','["春風奈別何，一櫂逐驚波。", "去國丹心折，流年白髮多。", "脫身離網罟，含笑入煙蘿。", "窮達皆常事，難忘對酒歌。"]'),
('515f75d7-ab82-4883-8e9d-e0b6cbf3f8ff','答和叔春日舟行','蘇舜欽','宋','宋诗','song-poetry','','[]','幽人漂泊興無窮，弄水尋花處處同。',64,'全唐诗/poet.song.18000.json','["幽人漂泊興無窮，弄水尋花處處同。", "春入水光成嫩碧，日勻花色變鮮紅。", "靜中物象知誰見，閑極情懷覺道充。", "寄語悠悠莫疑我，五湖今作狎鷗翁。"]'),
('b072f855-0a0e-4af3-99d5-0b702ce2105a','答子履','蘇舜欽','宋','宋诗','song-poetry','','[]','塌翼下層雲，飄然江漢濆。',48,'全唐诗/poet.song.18000.json','["塌翼下層雲，飄然江漢濆。", "蒼蠅休聚謗，白鳥已爲羣。", "銀鯽晨烹美，松醪夜酌醺。", "生平同得失，此日又逢君。"]'),
('551eb5a9-2b8f-42cf-aef6-52013aba2e09','舟行有感','蘇舜欽','宋','宋诗','song-poetry','','[]','忽忽賞節物，區區何所歸。',48,'全唐诗/poet.song.18000.json','["忽忽賞節物，區區何所歸。", "天陰鳥自語，水落岸生衣。", "客況知誰念，人生與願違。", "東風百花發，獨採北山薇。"]'),
('61785c42-bdc9-4f98-bbac-1cfaa34d4ace','淮亭小飲','蘇舜欽','宋','宋诗','song-poetry','','[]','山氣復清淮，亭臨亂石開。',48,'全唐诗/poet.song.18000.json','["山氣復清淮，亭臨亂石開。", "旅愁無處避，春色爲誰來。", "酒賴啼鶯送，歌隨去雁哀。", "相携聊一醉，休使壯心摧。"]'),
('f3d1f18d-08ab-4fd5-8691-acab02955faf','淮中風浪','蘇舜欽','宋','宋诗','song-poetry','','[]','春風如怒虎，掀浪沃斜暉。',48,'全唐诗/poet.song.18000.json','["春風如怒虎，掀浪沃斜暉。", "天闊雲相亂，汀遥鷺共飛。", "冥冥走陰氣，凜凜挫陽威。", "難息人間險，臨流涕一揮。"]'),
('fbbdf64e-3b0a-4651-9610-b87de501eb85','壽陽閒望有感','蘇舜欽','宋','宋诗','song-poetry','','[]','維舟亭下偶登臨，下蔡風流古至今。',64,'全唐诗/poet.song.18000.json','["維舟亭下偶登臨，下蔡風流古至今。", "遠嶺抱淮隨曲折，亂雲行野乍晴陰。", "幽人憔悴搔白首，啼鳥哀鳴思故林。", "觸處塗窮何足慟，直回天地入悲吟。"]'),
('3dc7caa2-473e-40e8-9a38-2511a127bba0','阻風野步有感呈子履','蘇舜欽','宋','宋诗','song-poetry','','[]','輕舟留滯已春殘，携手栖栖田野間。',64,'全唐诗/poet.song.18000.json','["輕舟留滯已春殘，携手栖栖田野間。", "盡日東風吹百草，有時雙鷺下前灣。", "古爲少見如君困，世上應無似我閑。", "抖擻塵襟莫回首，謗書終不到溪山。"]'),
('c9bb4e0f-3ee9-47e2-a094-1ab69697d552','過泗水','蘇舜欽','宋','宋诗','song-poetry','','[]','五年六經此，仰首歎勞生。',48,'全唐诗/poet.song.18000.json','["五年六經此，仰首歎勞生。", "山是往時色，人皆今日情。", "機心去國少，塵眼向淮明。", "物理吾俱曉，漂流安足驚。"]'),
('f6c1896c-791a-49bd-b923-43d639812515','和丹陽公素學士晚望見懷','蘇舜欽','宋','宋诗','song-poetry','','[]','古郡登臨足勝遊，使君才調更風流。',64,'全唐诗/poet.song.18000.json','["古郡登臨足勝遊，使君才調更風流。", "過雲送雨海山暗，斜日催蟬江樹秋。", "屢辱嘉招嗟放棄，又傳新詠慰淹留。", "霜天乘興當西謁，共醉城尖四望樓。"]'),
('97307f44-0824-4c06-b179-567c05b0d719','送子履','蘇舜欽','宋','宋诗','song-poetry','','[]','一舸風前五兩飛，南遷今去別慈闈。',64,'全唐诗/poet.song.18000.json','["一舸風前五兩飛，南遷今去別慈闈。", "人生多難古如此，吾道能全世所稀。", "幸有江山聊助思，莫隨魚鳥便忘歸。", "君親恩大須營報，學取三春寸草微。"]'),
('ae6a4a6b-c5d8-4f7e-b333-d7538593bf90','題花山寺壁','蘇舜欽','宋','宋诗','song-poetry','','["\u54f2\u7406"]','寺裏山因花得名，緐英不見草縱橫。',32,'全唐诗/poet.song.18000.json','["寺裏山因花得名，緐英不見草縱橫。", "栽培翦伐須勤力，花易調零草易生。"]'),
('b30017c0-a964-4e83-881d-312ed6e37f15','春睡','蘇舜欽','宋','宋诗','song-poetry','','[]','別院簾昏掩竹扉，朝酲未解接春暉。',64,'全唐诗/poet.song.18000.json','["別院簾昏掩竹扉，朝酲未解接春暉。", "身如蟬蛻一榻上，夢似楊花千里飛。", "嗒爾暫能離世網，陶然直欲見天機。", "此中有德堪爲頌，絕勝人間較是非。"]'),
('24ae7e96-208c-4570-b7dc-e22f888b6e1f','覽照','蘇舜欽','宋','宋诗','song-poetry','','[]','鐵面蒼髯目有稜，世間兒女見須驚。',64,'全唐诗/poet.song.18000.json','["鐵面蒼髯目有稜，世間兒女見須驚。", "心曾許國終平虜，命未逢時合退耕。", "不稱好文親翰墨，自嗟多病足風情。", "一生肝膽如星斗，嗟爾頑銅豈見明。"]'),
('b78a1e76-73f0-49ee-ab11-a6e9db41747c','病起','蘇舜欽','宋','宋诗','song-poetry','','[]','吳天摇落奈愁何，病起風前白髮多。',32,'全唐诗/poet.song.18000.json','["吳天摇落奈愁何，病起風前白髮多。", "爭得松江變醇酒，拍浮終日恣酣歌。"]'),
('7ea33708-06fa-41fa-abc3-ca93cc7ae355','秋懷','蘇舜欽','宋','宋诗','song-poetry','','[]','年華冉冉催人老，風物蕭蕭又變秋。',32,'全唐诗/poet.song.18000.json','["年華冉冉催人老，風物蕭蕭又變秋。", "家在鳳皇城闕下，江山何事苦相留。"]'),
('a2b4b8e5-0090-4e19-adf6-b457b5501f29','秋曉聞鶴唳一聲','蘇舜欽','宋','宋诗','song-poetry','','[]','落月銜栖露乍零，竹間孤唳入青冥。',32,'全唐诗/poet.song.18000.json','["落月銜栖露乍零，竹間孤唳入青冥。", "未知蟋蟀緣何事，牀下微吟不暫停。"]'),
('d19b2d36-d86d-4a96-96d1-0292f749767e','中秋松江新橋對月和柳令之作','蘇舜欽','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','月晃長江上下同，畫橋橫絕冷光中。',64,'全唐诗/poet.song.18000.json','["月晃長江上下同，畫橋橫絕冷光中。", "雲頭豔豔開金餅，水面沈沈卧綵虹。", "佛氏解爲銀色界，仙家多住玉華宮。", "地雄景勝言不盡，但欲追隨乘曉風。"]'),
('a374d7f1-eeb1-4317-b00d-cb68a3fbdf72','病中得杜丞相見寄詩感而有作','蘇舜欽','宋','宋诗','song-poetry','','[]','易毀唯遷客，難諧是俗情。',48,'全唐诗/poet.song.18000.json','["易毀唯遷客，難諧是俗情。", "愁多怯秋夜，病久厭人生。", "委順聞之舊，衰羸見者驚。", "新詩如接侍，吟罷涕淋纓。"]'),
('18e4b65c-a0f8-406a-8dd1-b16aba3f7c86','滄浪懷貫之','蘇舜欽','宋','宋诗','song-poetry','','[]','滄浪獨步亦無悰，聊上危臺四望中。',64,'全唐诗/poet.song.18000.json','["滄浪獨步亦無悰，聊上危臺四望中。", "秋色入林紅黯澹，日光穿竹翠玲瓏。", "酒徒漂落風前燕，詩社調零霜後桐。", "君又暫來還徑去，醉吟誰復伴衰翁。"]'),
('bac68932-367a-4e5c-8627-a08b7e92ff0e','和彥猷晚宴明月樓二首  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','溪聲來從一氣外，樓閣插在蒼霞中。',64,'全唐诗/poet.song.18000.json','["溪聲來從一氣外，樓閣插在蒼霞中。", "豔歌橫飛送落日，哀箏自響吹霜風。", "低昂黛色四山黯，凌亂纈紋疎樹紅。", "憑闌揮手問世俗，何人得到蟾蜍宮。"]'),
('ded4de71-1005-479a-a795-bc129752b020','和彥猷晚宴明月樓二首  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','落晚天邊燕席開，溪山相照絕纖埃。',64,'全唐诗/poet.song.18000.json','["落晚天邊燕席開，溪山相照絕纖埃。", "綠楊有意簷前舞，凉月多情海上來。", "香穗縈斜凝畫棟，酒鱗環合起金罍。", "自疑身是乘槎客，泛徹銀河却欲回。"]'),
('4be067e9-55c2-4bf1-a4ee-b6144c7af658','依韻和王景章見寄','蘇舜欽','宋','宋诗','song-poetry','','[]','歲律崢嶸臘候深，一天風雪卷愁陰。',160,'全唐诗/poet.song.18000.json','["歲律崢嶸臘候深，一天風雪卷愁陰。", "故人默默懷交意，逐客栖栖上國心。", "千里相望空盼盻，當年下吏阻追尋。", "咄嗟謗口聞高誼，披豁羈懷見雅吟。", "學道元將禦窮困，浮生何必計升沈。", "世間機穽知難避，往者圖書可自箴。", "猶得雲山開醉眼，可無俗物撓沖襟。", "鵩來閒暇何須怪，鬼見揶揄豈易禁。", "楚客留情著香草，啟期傳意入鳴琴。", "夫君自上丹霄去，莫忘雲泉寄好音。"]'),
('66c29fcc-75c9-40fd-85a5-e751a7861249','答仲儀見寄','蘇舜欽','宋','宋诗','song-poetry','','[]','前歲京都吏議諠，勁弓摧翮兩連翩。',64,'全唐诗/poet.song.18000.json','["前歲京都吏議諠，勁弓摧翮兩連翩。", "男兒窮困終歸道，世路傾危自有天。", "雲壑已通塵外意，茅齋仍得日高眠。", "寄聲吾舅無相念，今作江湖九館仙。"]'),
('9b266a8d-d829-4a94-8b95-715acc7ea5d9','雨中聞鶯','蘇舜欽','宋','宋诗','song-poetry','','[]','嬌騃人家小女兒，半啼半語隔花枝。',32,'全唐诗/poet.song.18000.json','["嬌騃人家小女兒，半啼半語隔花枝。", "黄昏雨密東風急，向此漂零欲泥誰。"]'),
('ae88c617-fd29-4ef8-b750-f26d8257072b','滄浪亭','蘇舜欽','宋','宋诗','song-poetry','','[]','一逕抱幽山，居然城市間。',48,'全唐诗/poet.song.18000.json','["一逕抱幽山，居然城市間。", "高軒面曲水，脩竹慰愁顔。", "迹與豺狼遠，心隨魚鳥閑。", "吾甘老此境，無暇事機關。"]'),
('bcdcc915-a61a-46e7-9337-cd8c949b2f05','秋雨','蘇舜欽','宋','宋诗','song-poetry','','[]','陰風攪林壑，驟雨到江湖。',48,'全唐诗/poet.song.18000.json','["陰風攪林壑，驟雨到江湖。", "白日不覺沒，緐雲何處無。", "樓吟凉筆硯，溪夢亂菰蒲。", "聞說京華盛，污泥入敝廬。"]'),
('4a1cc0c4-0e5d-4354-977f-2f8a6e7e8680','中秋三夕對月','蘇舜欽','宋','宋诗','song-poetry','','[]','三夕月俱好，清光惟望多。',48,'全唐诗/poet.song.18000.json','["三夕月俱好，清光惟望多。", "風應落桂子，露恐減金波。", "念昔歡娛極，如今羈旅何。", "窮猿不相棄，夜夜伴吟哦。"]'),
('7f869553-0b53-489f-a03b-5f611b0d4979','懷月來求聽琴詩因作六韻','蘇舜欽','宋','宋诗','song-poetry','','[]','正聲今遁矣，古道此焉存。',72,'全唐诗/poet.song.18000.json','["正聲今遁矣，古道此焉存。", "商緩知臣僭，風薰見帝尊。", "雄豪尚餘勇，淡泊忽忘言。", "緐極殊無閒，來長若有源。", "已能通變化，直可探胚渾。", "此理師應得，西風獨掩門。"]'),
('681965f8-20e8-491e-bf8e-766af56dc33b','送黄通','蘇舜欽','宋','宋诗','song-poetry','','[]','浪遊天下訪知音，健節亭亭恥陸沈。',64,'全唐诗/poet.song.18000.json','["浪遊天下訪知音，健節亭亭恥陸沈。", "當日拜官隨鶴版，此時孤宦入蛇林。", "羈愁雖得著書樂，風物能傷遷客心。", "顧我冥頑如瓦石，爲君分袂亦悲吟。"]'),
('297b68fb-0e1b-4454-b829-bc225954c5d6','秋宿虎丘寺數夕執以詩見貺因次元韻','蘇舜欽','宋','宋诗','song-poetry','','[]','生事飄然付一舟，吳山蕭寺且淹留。',64,'全唐诗/poet.song.18000.json','["生事飄然付一舟，吳山蕭寺且淹留。", "白雲已有終身約，醁酒聊驅萬古愁。", "峽束蒼淵深貯月，巖排紅樹巧裝秋。", "徘徊欲出向城市，引領烟蘿還自羞。"]'),
('c42db81c-4810-48fc-9a5c-e080132025d4','滕子京哀辭  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','雲霓收壯氣，星象卷英魂。',48,'全唐诗/poet.song.18000.json','["雲霓收壯氣，星象卷英魂。", "賢去人何賴，才亡世不尊。", "論兵虛玉帳，問俗失朱轓。", "自爲知音絕，低回慟寢門。"]'),
('b1bc2f22-1db5-416c-90aa-2d85551333d6','滕子京哀辭  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','忠義平生事，聲名夷翟聞。',48,'全唐诗/poet.song.18000.json','["忠義平生事，聲名夷翟聞。", "言皆出諸老，勇復冠全軍。", "冥莫知誰主，賢愚豈更分。", "江頭送丹旐，哭向九華雲。"]'),
('1baeb68f-e5e7-4f5e-a8ad-bc0523706e37','寒食招和叔遊園','蘇舜欽','宋','宋诗','song-poetry','','[]','異鄉風俗傷嘉節，久客情懷喜友人。',32,'全唐诗/poet.song.18000.json','["異鄉風俗傷嘉節，久客情懷喜友人。", "共挈一尊諸處賞，誰家得似故園春。"]'),
('7f8767fe-b18a-4817-8978-58386d7ad5f3','春日懷舊遊','蘇舜欽','宋','宋诗','song-poetry','','[]','羈旅怯春風，風光上國同。',48,'全唐诗/poet.song.18000.json','["羈旅怯春風，風光上國同。", "情如花有約，愁與酒相攻。", "雨外傷飄燕，樓頭羨去鴻。", "西郊遊冶地，誰復醉芳叢。"]'),
('205731e7-10b8-46d9-8683-62a8829c594a','春日感懷','蘇舜欽','宋','宋诗','song-poetry','','[]','微物亦生輝，輕風弄客衣。',48,'全唐诗/poet.song.18000.json','["微物亦生輝，輕風弄客衣。", "花閑情脈脈，蝶煖喜霏霏。", "望國勳名晚，傷時歲月飛。", "淹留伴猿鳥，何日片帆歸。"]'),
('2a26e6be-318e-4065-b797-96a71e892678','夢歸','蘇舜欽','宋','宋诗','song-poetry','','[]','雨隔疎鐘曉不知，春風吹夢過江西。',32,'全唐诗/poet.song.18000.json','["雨隔疎鐘曉不知，春風吹夢過江西。", "雨聲破夢北窗響，卧意江西路亦迷。"]'),
('f21e65dd-003e-46ee-ba49-fc5d466e5ecc','獨步遊滄浪亭','蘇舜欽','宋','宋诗','song-poetry','','[]','花枝低敧草色齊，不可騎入步是宜。',32,'全唐诗/poet.song.18000.json','["花枝低敧草色齊，不可騎入步是宜。", "時時携酒祗獨往，醉倒唯有春風知。"]'),
('a3c0acf4-157e-47c8-a2f2-662734be6097','初晴遊滄浪亭','蘇舜欽','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u6292\u6000", "\u5199\u666f", "\u5b8b\u8bd7"]','夜雨連明春水生，嬌雲濃暖弄陰晴。',32,'全唐诗/poet.song.18000.json','["夜雨連明春水生，嬌雲濃暖弄陰晴。", "簾虛日薄花竹靜，時有乳鳩相對鳴。"]'),
('d3714c4d-7eed-4ccc-8b22-817b41738df3','滄浪觀魚','蘇舜欽','宋','宋诗','song-poetry','','[]','瑟瑟清波見戲鱗，浮沈追逐巧相親。',32,'全唐诗/poet.song.18000.json','["瑟瑟清波見戲鱗，浮沈追逐巧相親。", "我嗟不及羣魚樂，虛作人間半世人。"]'),
('4bb03bdc-6cd1-4ea1-a8ac-4372feeeea4a','遊招隱道中','蘇舜欽','宋','宋诗','song-poetry','','[]','揚鞭望招隱，塵思漠然收。',48,'全唐诗/poet.song.18000.json','["揚鞭望招隱，塵思漠然收。", "雲接青林合，泉兼碧草流。", "疎鐘傳別壑，晚日動前樓。", "嘉遁平生志，吁嗟得暫遊。"]'),
('27e7b00b-a92b-4cff-b3c8-0514bfcc0725','揚州城南延賓亭','蘇舜欽','宋','宋诗','song-poetry','','[]','亂蟬咽咽柳霏霏，獨上危亭俯落暉。',64,'全唐诗/poet.song.18000.json','["亂蟬咽咽柳霏霏，獨上危亭俯落暉。", "江外山從林下見，城中人向渡頭歸。", "風烟遠近思高遁，豺虎縱橫難息機。", "出處兩乖空自撓，傷哉吾道欲何依。"]'),
('74175f0d-3808-4938-a39e-40083c416792','吳江岸','蘇舜欽','宋','宋诗','song-poetry','','[]','曉色兼秋色，蟬聲雜鳥聲。',24,'全唐诗/poet.song.18000.json','["曉色兼秋色，蟬聲雜鳥聲。", "壯懷消鑠盡，回首尚心驚。"]'),
('e7317007-8816-475d-8023-d548820e1911','晚泊龜山','蘇舜欽','宋','宋诗','song-poetry','','[]','南灣晚泊一徘徊，小徑山間佛寺開。',64,'全唐诗/poet.song.18000.json','["南灣晚泊一徘徊，小徑山間佛寺開。", "石勢向人森劍戟，灘光和月瀉瓊瑰。", "每傷道路銷時序，但屈心情入酒盃。", "夜籟不喧羣動息，長吟聊以寄餘哀。"]'),
('f6127240-634b-4054-87e3-90b5849915b7','滄浪靜吟','蘇舜欽','宋','宋诗','song-poetry','','[]','獨遶虛亭步石矼，靜中情味世無雙。',64,'全唐诗/poet.song.18000.json','["獨遶虛亭步石矼，靜中情味世無雙。", "山蟬带響穿疎戶，野蔓盤青入破窗。", "二子逢時猶死餓，三閭遭逐便沈江。", "我今飽食高眠外，惟恨醇醪不滿缸。"]'),
('dca0e912-928e-419c-b43a-36b62ddf53d5','丹陽子高得逸少瘞鶴銘于焦山之下及梁唐諸賢四石刻共作一亭以寶墨名之集賢伯鎮爲之作記遠來求詩因作長句以寄','蘇舜欽','宋','宋诗','song-poetry','','[]','山陰不見換鵝經，京口今存瘞鶴銘。',64,'全唐诗/poet.song.18000.json','["山陰不見換鵝經，京口今存瘞鶴銘。", "蕭灑集仙來作記，風流太守爲開亭。", "兩篇玉蕊塵初滌，四體銀鉤蘚尚青。", "我久臨池無所得，願觀遺法快沈冥。"]'),
('02fd6b27-c1b7-488d-8485-30d09ae49609','遊霅上何山','蘇舜欽','宋','宋诗','song-poetry','','[]','今古何山是勝遊，亂峯縈轉繞滄洲。',64,'全唐诗/poet.song.18000.json','["今古何山是勝遊，亂峯縈轉繞滄洲。", "雲含老樹明還滅，石礙飛泉咽復流。", "遍嶺烟霞迷俗客，一溪風雨送歸舟。", "自嗟塵土先衰老，底事孤僧亦白頭。"]'),
('e56be417-1d46-42f3-846b-a8bacc17f6cf','霅上','蘇舜欽','宋','宋诗','song-poetry','','[]','玉人携手弄秋英，尋徧池臺見月生。',32,'全唐诗/poet.song.18000.json','["玉人携手弄秋英，尋徧池臺見月生。", "小杜有靈應羨我，今爲閑客此閑行。"]'),
('58b9d650-1ffc-4ed9-b22e-0c5de22a66a9','冬夕偶書','蘇舜欽','宋','宋诗','song-poetry','','[]','謾走聲名三十年，亦曾文采動君前。',32,'全唐诗/poet.song.18000.json','["謾走聲名三十年，亦曾文采動君前。", "玉顔皓齒他人樂，獨守殘燈理斷編。"]'),
('8915165f-aa18-4188-bc7e-88c9b70abf16','寒夜十六韻答子履見寄','蘇舜欽','宋','宋诗','song-poetry','','[]','風雨夜寒新，空齋感慨頻。',192,'全唐诗/poet.song.18000.json','["風雨夜寒新，空齋感慨頻。", "詩書窮不放，燈火靜相親。", "眺聽時懷土，低摧動畏人。", "漫書成咄咄，遠吠厭狺狺。", "念昔罹憂患，唯君共苦辛。", "漂流數千里，會合十餘旬。", "各閔傷弓翼，聊同煦沫鱗。", "誰知公冶罪，眾笑伯龍貧。", "隔絕今一水，暌離將再春。", "喜篇數爲貺，尺牘亦相珍。", "倚伏時難定，屯亨理亦循。", "劍埋猶有氣，蠖屈尚能伸。", "邦國方登俊，江湖且放神。", "不憂知在命，任重莫如身。", "白首襟期遠，青雲志業均。", "陶然任元化，慎勿損天真。"]'),
('0b0a195a-f3bb-4235-bad0-8182360157b5','獨遊曹氏園館因寄伯玉','蘇舜欽','宋','宋诗','song-poetry','','[]','去年把酒共徘徊，今日尋幽獨此來。',64,'全唐诗/poet.song.18000.json','["去年把酒共徘徊，今日尋幽獨此來。", "竹密似嫌閑客入，梅含應待主人開。", "贊謀盛府方投刃，捍患長隄正展才。", "早晚得歸如舊約，伴君池上倒尊罍。"]'),
('e00a63de-b033-4b76-9ffd-ae7980825c00','小酌','蘇舜欽','宋','宋诗','song-poetry','','[]','寒雀喧喧滿竹枝，驚風淅瀝玉花飛。',32,'全唐诗/poet.song.18000.json','["寒雀喧喧滿竹枝，驚風淅瀝玉花飛。", "霜柑糖蟹新醅美，醉覺人生萬事非。"]'),
('e7e7850d-e683-464d-be62-1fabfdb6798c','送人還吳江道中作','蘇舜欽','宋','宋诗','song-poetry','','[]','江雲春重雨垂垂，索寞情懷送客歸。',32,'全唐诗/poet.song.18000.json','["江雲春重雨垂垂，索寞情懷送客歸。", "不憤東風促行棹，羨他雙燕逆風飛。"]'),
('29902080-065a-4983-894a-9c55d9df84df','題廣喜法師堂','蘇舜欽','宋','宋诗','song-poetry','','[]','我爲名驅苦俗塵，師知法喜自怡神。',32,'全唐诗/poet.song.18000.json','["我爲名驅苦俗塵，師知法喜自怡神。", "未知歡戚兩忘者，始是人間出世人。"]'),
('d610abb2-1b85-40e3-a3d3-e6ee223b3e9f','詩僧則','蘇舜欽','宋','宋诗','song-poetry','','[]','全吳氣象豪，詩思合翹翹。',48,'全唐诗/poet.song.18000.json','["全吳氣象豪，詩思合翹翹。", "風雅久零落，江山應寂寥。", "會將趨古淡，先可去浮囂。", "好約長吟處，霜天看怒潮。"]'),
('4636bb0e-d912-403a-a3c7-bbb4389007ca','關都官孤山四照閣','蘇舜欽','宋','宋诗','song-poetry','','[]','勢壓蒼崖險可驚，攀雲半日到軒楹。',64,'全唐诗/poet.song.18000.json','["勢壓蒼崖險可驚，攀雲半日到軒楹。", "旁觀竹樹回環翠，下視湖山表裏清。", "慚覺愁隨烟靄散，只疑身有羽翰生。", "他年君挂朱轓後，蠟屐邛枝伴此行。"]'),
('b2eb545a-b95f-4756-a3ed-4dd08bb66816','清軒','蘇舜欽','宋','宋诗','song-poetry','','[]','誰鑿幽軒刮眼清，湖中嘉處更禪扃。',64,'全唐诗/poet.song.18000.json','["誰鑿幽軒刮眼清，湖中嘉處更禪扃。", "龍聽夜講寒生席，鷗伴晨齋暖戲庭。", "水月澄明應作觀，雲山濃淡自開屏。", "我公亦爲留奇句，此地人間合有靈。"]'),
('a639bf7a-1e3c-4f15-8d79-8e74451d0fdc','某爲世所棄困居於蘇平生交遊過門不顧長安侍讀葉丈不以秦吳之遠高下之隔閔此窮悴特貺以詩然韻險句奇不可攀續仰酬高誼强抉蕪音','蘇舜欽','宋','宋诗','song-poetry','','[]','公鎮西都擁劇權，遠嗟窮苦寄新篇。',64,'全唐诗/poet.song.18000.json','["公鎮西都擁劇權，遠嗟窮苦寄新篇。", "氣雄迥出關河外，句險空驚魚鳥前。", "玉帳夜嚴兵似水，茅齋春靜草如烟。", "才愚榮悴皆殊絕，自笑相酬更斐然。"]'),
('3f7ab7ef-809f-4b6e-9a16-60c5c1ba45d9','暑中閑詠','蘇舜欽','宋','宋诗','song-poetry','','[]','嘉果浮沈酒半醺，床頭書冊亂紛紛。',32,'全唐诗/poet.song.18000.json','["嘉果浮沈酒半醺，床頭書冊亂紛紛。", "北軒涼吹開疎竹，卧看青天行白雲。"]'),
('08f5167c-da6b-4ca5-b0ca-11439c4e7e35','寄題趙叔平嘉樹亭','蘇舜欽','宋','宋诗','song-poetry','','[]','嘉樹名亭古意同，拂簷圍砌共青葱。',64,'全唐诗/poet.song.18000.json','["嘉樹名亭古意同，拂簷圍砌共青葱。", "午陰閑淡茶烟外，曉韻蕭疎睡雨中。", "開戶常時對君子，遶軒終日是清風。", "盤根得地年年盛，豈學春林一晌紅。"]'),
('167a1d8c-fcee-461f-a993-953ab7dacc32','西軒垂釣偶作','蘇舜欽','宋','宋诗','song-poetry','','[]','曾以文章上石渠，忽因讒口出儲胥。',32,'全唐诗/poet.song.18000.json','["曾以文章上石渠，忽因讒口出儲胥。", "致君事業堆胸臆，却伴溪童學釣魚。"]'),
('ef2b9ee3-7048-450d-8101-3f93e3e08dad','夜聞笮酒有聲因而成詠','蘇舜欽','宋','宋诗','song-poetry','','[]','糟牀新壓響泠泠，敧枕初聞睡自輕。',64,'全唐诗/poet.song.18000.json','["糟牀新壓響泠泠，敧枕初聞睡自輕。", "幾段愁悰俱滴破，一番歡意已篘成。", "空階夜雨徒傳句，三峽流泉無此聲。", "只待松軒看飛雪，呼賓同飲甕頭清。"]'),
('353eb33d-29af-41a2-801f-b3ef03f4e283','秋夕懷南中故人','蘇舜欽','宋','宋诗','song-poetry','','[]','向夕依闌念昔遊，蕭條節物更他州。',64,'全唐诗/poet.song.18000.json','["向夕依闌念昔遊，蕭條節物更他州。", "池平不動天深碧，月色無情人獨愁。", "千里江山幽信絕，一場風露敗荷秋。", "征鴻急急知何事，斷續哀鳴過不休。"]'),
('4880c8b8-7084-488f-823e-ee87e0333102','送梁子熙聯句','蘇舜欽','宋','宋诗','song-poetry','','[]','大榮大辱，能生死人。',130,'全唐诗/poet.song.18000.json','["大榮大辱，能生死人。", "二物不並，以撓厥真。", "之子病悶，腸如車輪。", "勞憂到母，餓寒著身。", "世俗鹵莽，輒置莫親。", "文彩光豔，伏不得伸。", "悽吟哀號，酸入四鄰。", "夜計破午，若燕若秦。", "腹憤軋軋，胸奇陳陳。", "淮國晚嶺，吳渠春津。", "去謝夙藴，歸逢故辛。", "雌火在丑，刮鑿遯屯。", "駕風鞭霆，以脫凡鱗。"]'),
('bb2c26b3-1524-4bb5-9afb-738a4f89111c','寄守堅覺初二僧','蘇舜欽','宋','宋诗','song-poetry','','[]','曾携舊書卷，來宿古禪林。',192,'全唐诗/poet.song.18000.json','["曾携舊書卷，來宿古禪林。", "方外求知性，詩中得賞音。", "爐開山夜靜，門掩雪天陰。", "杌上一寒硯，燈前三苦吟。", "韵强顔汗落，句切鬢絲侵。", "玉就還重琢，河窮更遠尋。", "穴爭探乳虎，沙獨揀良金。", "字穩天星轉，篇終海月沈。", "唱酬同記錄，得失暗規箴。", "木鐸不徇路，薰風難和琴。", "半生誰引手，中道比分襟。", "分野三吳闊，年華二紀深。", "師方傳祖印，我欲謝朝簪。", "嶺外烟嵐地，湖邊雲水心。", "情悰張翰鱠，夢想陸機禽。", "松下莓苔石，何年重訪臨。"]'),
('8eeef95c-f22c-460b-9811-6b3d90a9f156','邂逅劉公尤於平望之西聯舟夜語走筆敘意','蘇舜欽','宋','宋诗','song-poetry','','[]','昔別蘋初生，離謳發清商。',108,'全唐诗/poet.song.18000.json','["昔別蘋初生，離謳發清商。", "契闊幾何時，遺囀猶在梁。", "我亦宦遊者，吳會非我鄉。", "三考一瞬息，扁舟引徜徉。", "邂逅通夕語，弭棹水中央。", "淡景月照戶，遥音鴈南翔。", "攄意良未盡，詎及羅酒漿。", "子去尚千里，道路阻且長。", "嶔崎慎所歷，無令馬玄黄。"]'),
('1c3a66fc-7132-4b59-9c0a-5b96878335d9','竹軒','蘇舜欽','宋','宋诗','song-poetry','','[]','君與我同好，數過我不窮。',72,'全唐诗/poet.song.18000.json','["君與我同好，數過我不窮。", "對之酌綠酒，又爲鳴絲桐。", "作詩寫此意，韵和霜間鐘。", "清篇與翠榦，歲久日益穠。", "惜哉嵇阮放，當世已不容。", "吾儕有雅尚，千載挹高蹤。"]'),
('8d74294d-5e62-408d-aa10-6816a6632ab5','寄題水月  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','參差峯岫晝雲昏，入望交蘿濁浪奔。',64,'全唐诗/poet.song.18000.json','["參差峯岫晝雲昏，入望交蘿濁浪奔。", "震澤湧山來此岸，華陽連洞到東門。", "日生樹掛紅霞脚，風起波摇白石根。", "聞有上方僧住處，橘花林下採蘭蓀。"]'),
('2c03d260-8314-4321-b2e1-cc5aac40dc3c','寄題水月  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','積翠湖心迤邐長，洞臺蕭寺雨交光。',64,'全唐诗/poet.song.18000.json','["積翠湖心迤邐長，洞臺蕭寺雨交光。", "鳥行黑點波濤白，楓葉紅連橘柚黄。", "人我絕時隈樹石，是非來處接帆檣。", "如何遂得追遊性，擺却營營不急忙。"]'),
('8c4a9edc-2e10-4899-90fa-62f85dcb26d7','獨酌','蘇舜欽','宋','宋诗','song-poetry','','[]','一酌澆腸俗慮奔，鷃微鵾大豈堪論。',32,'全唐诗/poet.song.18000.json','["一酌澆腸俗慮奔，鷃微鵾大豈堪論。", "楚靈當日能知此，肯入滄江作旅魂。"]'),
('b560d452-0ff5-4c44-967f-41d5574e3cf5','寄陸同年','蘇舜欽','宋','宋诗','song-poetry','','[]','忽憶前年科第後，此時雞鶴蹔同羣。',32,'全唐诗/poet.song.18000.json','["忽憶前年科第後，此時雞鶴蹔同羣。", "秋風惆悵忽吹散，雞在中庭鶴在雲。"]'),
('949239ea-5cc0-44ac-83bf-445257502647','楚天','蘇舜欽','宋','宋诗','song-poetry','','[]','楚天遥望每長嚬，宋玉襄王盡作塵。',32,'全唐诗/poet.song.18000.json','["楚天遥望每長嚬，宋玉襄王盡作塵。", "不作瑶姬歌入夢，更爲雲雨待何人。"]'),
('3bc43cc2-9178-41ce-80cb-b79bdf66d436','觀煬帝寶帳','蘇舜欽','宋','宋诗','song-poetry','','[]','漢文窮相作前王，慳惜明珠不斗量。',32,'全唐诗/poet.song.18000.json','["漢文窮相作前王，慳惜明珠不斗量。", "翡翠鮫綃何所直，千裨萬補上書囊。"]'),
('a3c9769b-ebfa-4dcd-92f3-d0ae799d8cdb','春晚','蘇舜欽','宋','宋诗','song-poetry','','[]','紛紛從此見花殘，已覺長繩繫日難。',32,'全唐诗/poet.song.18000.json','["紛紛從此見花殘，已覺長繩繫日難。", "樓上有愁春不淺，小桃風雨凭闌干。"]'),
('65c4d8cc-e37e-49ab-a735-bcf90e85730a','送陳生還烏龍山舊居','蘇舜欽','宋','宋诗','song-poetry','','[]','百丈清溪見戲鱗，嚴公祠宇與天鄰。',32,'全唐诗/poet.song.18000.json','["百丈清溪見戲鱗，嚴公祠宇與天鄰。", "此中舊隱君歸去，笑指人寰一片塵。"]'),
('58bb95a8-3021-4282-ad9b-de38b4977f3f','戒珠寺上方','蘇舜欽','宋','宋诗','song-poetry','','[]','躋攀出上楹，疊勢與雲平。',48,'全唐诗/poet.song.18000.json','["躋攀出上楹，疊勢與雲平。", "日暮蒼煙合，秋來遠水明。", "幽軒開極望，疎磬落餘清。", "便有飛騰意，俄嗟俗慮縈。"]'),
('902cf7e2-1011-4af4-b552-0c7b2f71e364','送張行之越','蘇舜欽','宋','宋诗','song-poetry','','[]','五雲寺下石橋邊，六月谿風灑面寒。',32,'全唐诗/poet.song.18000.json','["五雲寺下石橋邊，六月谿風灑面寒。", "今正炎天君獨往，松閒尋我舊題看。"]'),
('6ac1831e-39f6-46c5-a519-5ab619aa4b71','越谿懷儼老','蘇舜欽','宋','宋诗','song-poetry','','[]','擊槳轉山曲，雲間谿更深。',48,'全唐诗/poet.song.18000.json','["擊槳轉山曲，雲間谿更深。", "鳧鷗带波起，藻荇共魚沈。", "上國久離意，故人相念心。", "天涯逢絕景，不得對清吟。"]'),
('4e38e0d9-04d2-47b9-ab6c-0e901f468872','重過齊山清溪','蘇舜欽','宋','宋诗','song-poetry','','[]','翠微曾與客同遊，陟險搜奇興未休。',64,'全唐诗/poet.song.18000.json','["翠微曾與客同遊，陟險搜奇興未休。", "八載重來驚老大，千年高詠想風流。", "雲迷複嶺深藏洞，水落寒江遠見洲。", "安得符離張太守，畫圖再與瀉清愁。"]'),
('755acfe5-34da-4980-a340-d04dd6fcfacc','過池陽遊齊山洞','蘇舜欽','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','城南飛橋跨青溪，度橋並轡千丈隄。',304,'全唐诗/poet.song.18000.json','["城南飛橋跨青溪，度橋並轡千丈隄。", "隄窮水盡翠微出，繫馬道旁尋杖藜。", "巉巉石骨不見土，一色新削青玻瓈。", "怪巖奇壑分左右，絕頂俯睨長江低。", "當時登高插菊處，至今勝日爭提携。", "荒亭已頹斷碣仆，霜草滿地寒螿啼。", "杜郎風流杳何處，祇有茲山仍號齊。", "其間一洞景更絕，喜子曾遊知舊蹊。", "踰岡陟巘數里險，路斷忽復忘東西。", "石芒鉤衣藤罣帽，荒榛叢篠交冥迷。", "遥呼野人問不識，下趨却踏湖邊畦。", "前邊佳處似髣髴，興倦不惜重攀躋。", "徑穿蒙密得竅六，俛首匍匐藤拄臍。", "日光忽漏天宇小，所見正爾如醯雞。", "流蘇承蓋結高屋，旁入詰曲房與閨。", "卦蓍二碑史氏植，欲讀柰此苔蘚泥。", "斯人好事世亦少，挽置俛視茫無梯。", "崖間名字半磨滅，後來遊者猶堪稽。", "摸碑幸寄却細讀，我思仍欲煩鎸題。"]'),
('b71a7d9f-6693-474e-b2a2-8b82c3ee1381','詩一首','蘇舜欽','宋','宋诗','song-poetry','','[]','滁陽太守好山水，公餘日醉羣山間。',32,'全唐诗/poet.song.18000.json','["滁陽太守好山水，公餘日醉羣山間。", "滁峯環回秀相倚，作亭正對溪山前。"]'),
('817716d3-13ef-4fbd-98fa-fbeecbc4f7c6','詩一首','蘇舜欽','宋','宋诗','song-poetry','','[]','崑崙氣候西時春，紫府光陰夜如曉。',32,'全唐诗/poet.song.18000.json','["崑崙氣候西時春，紫府光陰夜如曉。", "來時不用五雲車，跨著清風下蓬島。"]'),
('517b86fc-3099-45a4-89ef-2250344e4ba9','句','蘇舜欽','宋','宋诗','song-poetry','','[]','沿橋待金鯽，竟日獨遲留。',12,'全唐诗/poet.song.18000.json','["沿橋待金鯽，竟日獨遲留。"]'),
('c1612417-cdf0-4cca-bc8d-1535e70cb855','存目  其一','蘇舜欽','宋','宋诗','song-poetry','','[]','詩題：田家詞首句：南風霏霏麥花落。',17,'全唐诗/poet.song.18000.json','["詩題：田家詞首句：南風霏霏麥花落。"]'),
('a08bd3a4-d6ca-4629-b5f0-85fb05985537','存目  其二','蘇舜欽','宋','宋诗','song-poetry','','[]','詩題：南園首句：西施臺下見名園。',16,'全唐诗/poet.song.18000.json','["詩題：南園首句：西施臺下見名園。"]'),
('9366f5aa-2d33-4b7b-9ef6-77fff54c671b','存目  其三','蘇舜欽','宋','宋诗','song-poetry','','[]','詩題：游靈巖寺首句：古來興廢一愁人。',18,'全唐诗/poet.song.18000.json','["詩題：游靈巖寺首句：古來興廢一愁人。"]'),
('7d811411-75ee-406f-a6fa-1b0cba68cbd6','薦福塔聯句','王緯','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.18000.json','["無正文。"]'),
('49dbcee7-77b2-4bd4-bcfb-69ab34215bfd','瓊花','韓琦','宋','宋诗','song-poetry','','[]','維揚一株花，四海無同類。',168,'全唐诗/poet.song.18000.json','["維揚一株花，四海無同類。", "年年后土祠，獨比瓊瑶貴。", "中含散水芳，外團蝴蝶戲。", "酴醾不見香，芍藥慚多媚。", "扶踈翠蓋圓，散亂真珠綴。", "不從眾格繁，自守幽姿粹。", "嘗聞好事家，欲移京轂地。", "既違孤潔情，終誤栽培意。", "洛陽紅牡丹，適時名轉異。", "新榮託舊枝，萬狀呈妖麗。", "天工借顔色，深淡隨人智。", "三春愛賞時，車馬喧如市。", "草木稟賦殊，得失豈輕議。", "我來首見花，對花聊自醉。"]'),
('c431aa01-d4b2-43a5-b9da-70402c8a95ae','夜合','韓琦','宋','宋诗','song-poetry','','[]','俗人之愛花，重色不重香。',168,'全唐诗/poet.song.18000.json','["俗人之愛花，重色不重香。", "吾今得真賞，似矯時之常。", "所愛夜合花，清芬踰眾芳。", "葉葉自相對，開斂隨陰陽。", "不慚歷草滋，獨擅堯階祥。", "得此合歡名，憂忿誠可忘。", "茸茸紅白姿，百和從風颺。", "沉水燎庭檻，薰陸紛纓裳。", "彌月固未歇，況茲夏景長。", "凡目不我貴，馥烈徒自將。", "仲尼失滅明，史遷疑子房。", "以貌不以行，舉世同悲傷。", "予欲先馨德，羣豔孰可方。", "埋饒妖牡丹，須讓花中王。"]'),
('856107fa-dac6-4c0f-9084-6893c0de11ab','蜂蠆','韓琦','宋','宋诗','song-poetry','','[]','事小不可忽，議或戒蜂蠆。',204,'全唐诗/poet.song.18000.json','["事小不可忽，議或戒蜂蠆。", "蜂蠆之中人，始意脫己害。", "人兮怒一蠚，爲報速睚眥。", "白晝擿危巢，夜燭窮纖介。", "必獲而後已，立死以爲快。", "彼誠畜微毒，謂己有所賴。", "失於小不忍，而自取糜壞。", "吁嗟陰巧徒，毒萬蜂蠆大。", "包潛中善良，斷腕未足駭。", "小或一身危，甚則家族逮。", "淵微如鬼神，無隙可漏敗。", "君子被戕賊，守道不爲怪。", "有時醜迹露，事或無可奈。", "一旦吾道行，乃置之度外。", "使其自愧縮，似不容覆載。", "非力不足較，顧有盛德在。", "陰巧既常幸，蜂蠆胡不貸。"]'),
('2c1f8f72-eda1-4c18-b40b-f60375718ff2','啄木','韓琦','宋','宋诗','song-poetry','','[]','剝剝復卜卜，意若念良木。',168,'全唐诗/poet.song.18000.json','["剝剝復卜卜，意若念良木。", "營營求蠹心，未獲空我腹。", "或露一襠紅，或展雙翅綠。", "捷緣都盧橦，響弄羯鼓曲。", "搜索不知疲，利嘴信摧禿。", "忽爾破姦宄，種類無遺族。", "內孽固難辨，一發知潛伏。", "彼實害珍材，盡殄此非酷。", "直疑天意深，不使嗜粱肉。", "專爲眾蠹仇，侍飫弗與足。", "如令知庶味，恣擇蟲與粟。", "杞梓任陰賊，長喙罷攻觸。", "飽食作羣飛，時下泉沼浴。", "歸鳴凉樹陰，暮趁高枝宿。"]'),
('0569e101-cfea-475e-9dc8-7c4266170edb','來鳦','韓琦','宋','宋诗','song-poetry','','[]','來鳦趨社期，翩若天外至。',216,'全唐诗/poet.song.18000.json','["來鳦趨社期，翩若天外至。", "徘徊大厦間，汲汲營巢意。", "中心有所託，自謂得其地。", "銜泥兩吻瘡，旦暮不少憩。", "主人愛高堂，病爾如疣贅。", "爾巢屢膚寸，長梃輒摧墜。", "胡爲不識嫌，又續前功棄。", "何處無蓬茅，自足爲生計。", "不爾卵而覆，其禍愈非細。", "予既傷爾愚，竊復探爾志。", "孜孜不忍去，欲動主人義。", "萬一憐其勤，庶獲息我類。", "臣棟既不撓，出處安且貴。", "其能無報乎，唯守信無貳。", "年年應候來，馴狎如兒稚。", "雙雙軒戶前，爲君作嘉致。", "不學君家客，去就惟勢利。", "微羽一知歸，至死不他詣。"]'),
('f9fe5a4c-e0a6-4c57-81a1-a7d2d6e25f33','感花','韓琦','宋','宋诗','song-poetry','','[]','彫堂瞰寶欄，有花病不妍。',60,'全唐诗/poet.song.18000.json','["彫堂瞰寶欄，有花病不妍。", "誰知窮山顛，牡丹一尺圓。", "寶欄鋤溉足，窮山風日煎。", "彼此不得地，天道胡爲然。", "兩適豈易得，茲恨無窮年。"]'),
('27d13b0c-148c-45f7-9b66-30ac8d904408','落葉','韓琦','宋','宋诗','song-poetry','','[]','人觀落葉悲，我視落葉喜。',96,'全唐诗/poet.song.18000.json','["人觀落葉悲，我視落葉喜。", "請看四序速，次第若屈指。", "風霜一瞬過，望春時有幾。", "榮固悴之端，衰亦盛之始。", "須知眾木踈，便是羣芳啟。", "舉此較人事，蓋不異物理。", "否泰與消長，反復殊未已。", "釀酒整笙歌，坐待新萌起。"]'),
('891ee029-d14a-45d0-82e2-10e979284442','讀劉易春秋新解','韓琦','宋','宋诗','song-poetry','','[]','夫子春秋之所記，二百四十有二年。',352,'全唐诗/poet.song.18000.json','["夫子春秋之所記，二百四十有二年。", "謹嚴之法不可犯，欲示萬世天子權。", "禮樂征伐必上出，諸侯雖大莫得專。", "周平東遷魯君隱，王綱壞裂勿復聯。", "天王所存位與號，列國自用公承傳。", "齊桓晉文無實義，挾周狥己掩大愆。", "不歸聖筆立中制，誰其當罪誰其賢。", "絲紛五傳角同異，各專門記執所偏。", "遂令學者蹈迷徑，不探元本遭羈牽。", "至於歆向父子間，亦反天性相鑱鎸。", "何休杜預范甯輩，離經附傳以臆箋。", "膏肓廢疾互譏病，雖欲針起難自痊。", "前人文字安可數，議難啾唧秋嘒蟬。", "有唐名儒陸淳者，始開奧壤窺源泉。", "我朝又得孫明復，大明聖意疏重淵。", "劉生新解最後出，了無塞礙成通川。", "所趨旨義極簡正，撐拄異論牢且堅。", "事不歸王皆不與，達經之志所以然。", "詩三百可一言蔽，曰思無邪而已焉。", "方今四海大一統，萬里號令猶君前。", "安不思危易其治，毋容僭亂生階緣。", "往持此說助邦政，坐令當扆尊如天。"]'),
('333d526f-f2e1-4f28-9605-9f7b433bedf0','答孫植太博後園宴射','韓琦','宋','宋诗','song-poetry','','[]','花梢點紅芽綠茁，宴亭爽塏堋雲列。',384,'全唐诗/poet.song.18000.json','["花梢點紅芽綠茁，宴亭爽塏堋雲列。", "呼賓習射次序升，體裁人人矜㔢挃。", "六鈞力副百中藝，由基注目老羿拽。", "支左屈右何大工，象弭急收如列缺。", "須臾一鏑入鵠心，畫鼓連轟盡聲喝。", "後者審固意愈精，有時大呼劈箭筈。", "惜哉最是毫釐差，彩侯似動笴微撇。", "分明角勝各記暈，將終或爲一箭奪。", "當筵主籌令難犯，大白時舉出正罰。", "此禮自古尤所重，矍圃去留宜有別。", "五善大抵主和容，不止穿楊與穿札。", "因憶當年黠羌叛，非才誤授將軍鉞。", "帳下貔貅十萬師，力過生犀心似鐵。", "大人未許覆兇巢，飭謹封垂禦侵越。", "悍夫猛士志待騁，貯填憤氣何由洩。", "正值高秋天氣寒，塞場霜重嚴風刮。", "約束偏裨整隊兵，旌旗爍電戈矛雪。", "驅出長郊閱奇陣，離合應麾皆有節。", "次引精銳較絕技，控弦命中無虛發。", "氣豪馬健走危坡，直下千尋未嘗蹷。", "收軍校獵圍平原，犬順人呼鷹解紲。", "山麋衝軼犯勁矢，崗兔奔跳迷狡穴。", "大鵰盤空不輕搏，老狐仰視肝膽裂。", "駐鞍賞獲犒部曲，浪瀉酒車論染血。"]'),
('f2bde536-ac2c-4c66-ba7d-fe30e321cfc4','廣陵大雪','韓琦','宋','宋诗','song-poetry','','[]','淮南常歲冬猶燠，今年陰沴何嚴酷。',256,'全唐诗/poet.song.18000.json','["淮南常歲冬猶燠，今年陰沴何嚴酷。", "黑雲漫天一月昏，大雪飛揚平壓屋。", "風力軒號助其勢，擺撼琳瑯摧凍木。", "通宵徹晝不暫停，堆積樓臺滿溪谷。", "有時造出可憐態，柳絮梨花亂紛撲。", "乘溫變化雨聲來，度日階庭恣淋漉。", "幾縈寒霰不成絲，驟集踈簷還掛瀑。", "蟄蛙得意欲跳擲，幽鷺無情成挫辱。", "罾魚江叟冰透蓑，賣炭野翁泥沒輻。", "閭閻細民誠可哀，三市不喧游手束。", "牛衣破解突無烟，餓犬聲微饑子哭。", "我聞上天主時澤，亦有常數滋農穀。", "膏潤均於一歲中，是謂年豐調玉燭。", "此來盛冬過爾多，却慮麥秋欠霑足。", "太守憂民仰天祝，願曙氛霾看晴旭。", "望晴不晴無奈何，擁被醉眠頭更縮。"]'),
('1823ebe3-7c9c-4a25-b777-23b0f807b5dc','答袁陟節推遊禪智寺','韓琦','宋','宋诗','song-poetry','','[]','春去惜餘景，偶來郊外觀。',240,'全唐诗/poet.song.18000.json','["春去惜餘景，偶來郊外觀。", "蕪城千古恨，一顧殊悲酸。", "荒祠枕大道，尚記吳城邗。", "遠近綠陰合，水襯紅莢殘。", "隴麥齊若剪，隨風卷波瀾。", "罷農喜有望，守臣心粗寬。", "蕭踈禪智寺，壞址不甚完。", "叢花亂芍藥，籬竹摧琅玕。", "空有亭亭柏，成行如筆端。", "供帳具朝膳，僚寀成清歡。", "小杜詩板暗，樂石曾未刊。", "乘興詣茶圃，百步登平巒。", "摘焙試烹啜，甘挹零露漙。", "午過倦微暑，堤路騰歸鞍。", "天子憂歲旱，引咎古所難。", "列郡承新詔，朝夕弗敢安。", "況此行春意，固不在遊盤。", "朝廷責吏治，莫若久其官。", "政和氣亦應，災沴無由干。", "願循三載舊，庶幾酬素餐。"]'),
('b8b2454e-5d74-4e46-98c0-00cda32faf6e','和袁陟節推龍興寺芍藥','韓琦','宋','宋诗','song-poetry','','[]','廣陵芍藥真奇差，名與洛花相上天。',384,'全唐诗/poet.song.18000.json','["廣陵芍藥真奇差，名與洛花相上天。", "洛花年來品格卑，所在隨人趁高價。", "接頭著處騁新妍，輕去本根無顧藉。", "不論姚花與魏花，只供俗目陪妖姹。", "廣陵之花性絕高，得地不移歸造化。", "大豪人力或强遷，費盡雍培無豔冶。", "東君固是花之主，千苞萬萼從榮謝。", "似矯東君泛愛心，枉殺春風不肯嫁。", "遂令天下走香名，髣髴丹青競誇詫。", "以此揚花較洛花，自合揚花推定覇。", "其間絕色可粗陳，天工著意誠堪訝。", "仙家冠子鏤紅雲，金線粧治無匹亞。", "旋心體弱不勝枝，寶髻欹斜猶墮馬。", "冰雪肌膚一纈斑，新試守宮明似赭。", "雙頭兩兩最多情，象物更呈鞍面窊。", "樓子亭亭欠姿媚，特有怪狀堪圖寫。", "見者方知畫不真，未見直疑傳者詐。", "前賢大欲巧賦詠，片言未出心先怕。", "天上人間少其比，不似餘芳資假借。", "我來淮海涉三春，三訪龍興舊僧舍。", "問得龍興好事僧，每歲看承不敢暇。", "後園栽植雖甚蕃，及見花成由取捨。", "出羣標致必驚人，方徙矮壇臨大厦。", "客來只見軒檻前，國艷天姿相照射。"]'),
('aba89813-e9b6-48fe-8cba-a7be12d97d12','歲旱晚雨','韓琦','宋','宋诗','song-poetry','','[]','慶曆丙戌夏，早氣蒸如焚。',264,'全唐诗/poet.song.18000.json','["慶曆丙戌夏，早氣蒸如焚。", "行路盡嬰暍，居人猶中瘟。", "墮鳥不收喙，游魚幾爛鱗。", "絺綌亦難御，更值成雷蚊。", "驕陽斷雨脈，焦熬逾五旬。", "農塍坐耗裂，縱橫龜灼文。", "眾目血坼眥，日睇西郊雲。", "守臣卹民病，心亂千絲棼。", "祈龍割舒雁，縱陰開北門。", "古法久弗驗，羣祠益致勤。", "徧走于境內，神兮若不聞。", "或時得泛灑，濛濛才濕塵。", "豐年望既絕，節候俄秋分。", "忽爾降大澍，霄冥連日昏。", "垂空狀戰戟，入霤疑傾盆。", "田禾十九死，强漬枯槁根。", "蕭稂賤易活，勢茂如逢春。", "蛙黽渴易滿，泥躍嬉成羣。", "濟物乃容易，應時何艱辛。", "轍鮒骨已壞，徐激西江津。", "谷黍霜已厚，始調鄒律溫。", "天意執可問，對之空氣吞。"]'),
('b9adf62b-a1b3-4eda-a3ce-e2db1e138179','喜雪答趙宗道學士','韓琦','宋','宋诗','song-poetry','','[]','去年大雪如山積，今年大旱千里赤。',192,'全唐诗/poet.song.18000.json','["去年大雪如山積，今年大旱千里赤。", "凍民虛死麥實少，稻子空乾無一獲。", "陰陽之沴已過差，物理固知當反極。", "入冬和氣漸融怡，霈澤時時蘇土脈。", "廣莫朝來一陣寒，變作雪花紛亂坼。", "瓊樹瑶臺豁眼明，直疑誤到神仙宅。", "城中喜色與歡聲，併在高樓歌舞席。", "老農視之笑復啼，大言累歲遭兇厄。", "纔下種時雨雪多，禾稼欲成無一滴。", "此回雖有豐登兆，未信天公真愛惜。", "太守聞之亦慘顔，造化誠哉非易測。", "但願天意悔前禍，豈使吾民常慼慼。"]'),
('f5d5b302-088d-42a7-bba5-0a0ff168b14c','閱古堂','韓琦','宋','宋诗','song-poetry','','[]','仲尼大聖人，文武亦云學。',192,'全唐诗/poet.song.18000.json','["仲尼大聖人，文武亦云學。", "況其下者乎，而不事礱琢。", "伊予之逢辰，進本任愚樸。", "今辱寄中山，地重扼幽朔。", "日懼不克堪，誤上所簡擢。", "古之良守帥，功業甚奇卓。", "思以救空踈，志慕極堅確。", "後圃新吾堂，左右謹圖模。", "公餘時縱觀，大可儆齪齪。", "奔雷發聾聵，皎日破昏濁。", "苟能奉規矩，曷愧大匠斲。", "或此賢賓僚，指顧便揚攉。", "四座企清風，耳目外優樂。", "子好虛名哉，事實出誠愨。", "庶幾得涓塵，聊以助海嶽。", "唯有大忠心，不在先覺覺。"]'),
('707cc911-9307-4cc5-96bc-113c6a4ed986','眾春園','韓琦','宋','宋诗','song-poetry','','[]','中山雄北邊，地得要害扼。',288,'全唐诗/poet.song.18000.json','["中山雄北邊，地得要害扼。", "烽警昔未徹，民日困兵革。", "一從無事來，歷祀且半百。", "戈矛既錢鎛，比屋遂仁宅。", "人生亦自勞，營業鮮暇隙。", "誠哉百日勤，固願一日適。", "爲政本人情，三代所不易。", "漢吏稱循良，在宣布恩澤。", "茲吾治廢園，大揭眾春額。", "庶乎時節遊，使見太平迹。", "園中何所有，風物難具籍。", "方塘百畝餘，遥派逗寒碧。", "虛亭跨彩橋，孤嶼聳幽石。", "環堤柳萬株，無時張翠帟。", "移得江南天，不覺萬里隔。", "芳林灼灼花，次第錦繡坼。", "三春爛熳時，爲民開宴席。", "觀者如堵牆，士女雜城陌。", "野態得天真，靚粧非俗格。", "惟意任所如，去來何絡繹。", "多歡知有今，勝致駭非昔。", "如登老氏臺，懷抱罔不釋。", "既以休吾民，又足奉嘉客。", "清暑暨凉秋，池景尤可惜。"]'),
('28b89642-3981-43e7-b6c1-80a19a56b22f','覽資政富公新詩','韓琦','宋','宋诗','song-poetry','','[]','賢輔于朝廷，中外唯所用。',240,'全唐诗/poet.song.18000.json','["賢輔于朝廷，中外唯所用。", "中則翊萬樞，天業日以重。", "外則泰一方，君治亦云共。", "公今得淮康，大厦輟隆棟。", "惠政聊一施，萬室絕愁痛。", "獄訟不復煩，甘脆誠足奉。", "優游爲文章，六義本規諷。", "長篇燦臣軸，郵驛邈見送。", "發函捧瓊瑰，再拜喜吟誦。", "高調既古雅，奇格復豪縱。", "鈞天張廣樂，累夕駭谷夢。", "宛馬歷夷途，萬里不可控。", "李杜若復生，屈伏事非恐。", "況夫淺淺流，固莫測源洞。", "何時衮衣歸，瞻望慰民眾。", "事業追夔龍，風烈陋姚宋。", "曰賡元首歌，間助薰琴弄。", "太平告成功，郊廟形嘉頌。", "九奏人神和，舞獸而儀鳳。", "休聞狼跋詩，萬世發長慟。"]'),
('173714fb-d2d0-467c-a195-1f61cb4869ce','謝資政富公再以近詩見寄','韓琦','宋','宋诗','song-poetry','','[]','惟公之所存，致后協二典。',240,'全唐诗/poet.song.18000.json','["惟公之所存，致后協二典。", "當入相天子，賢業遂大展。", "萬類隨坯陶，四時無盭舛。", "如保守一藩，疢甚斥和扁。", "遂令康濟功，鬰抑未恢顯。", "寄懷吟詠間，唯以道自遣。", "公才如河源，渾渾日東演。", "洪濤奔巨海，萬里縱傾卷。", "小哉西北流，孰可議深淺。", "公思如天匠，春物歸裁剸。", "珍叢與奇葩，萬態極婉孌。", "一一得天真，倣象困雕剪。", "河源無時窮，天匠非世辨。", "湖爲每成編，遂以貺罷輭。", "裸壤本無知，安足道文冕。", "俚耳固不通，烏用奏姑洗。", "我實知公心，愛我久益腆。", "誘我進學勤，要在納諸善。", "我素荷公德，公教不敢踐。", "諷誦復宗師，夙夜以自勉。"]'),
('ef105e39-9b24-4082-8548-39917ecda577','苦熱','韓琦','宋','宋诗','song-poetry','','[]','皇祐辛卯夏，六月朔伏暑。',168,'全唐诗/poet.song.18000.json','["皇祐辛卯夏，六月朔伏暑。", "始伏之七日，大熱極炎苦。", "赫日燒扶桑，焰焰指亭午。", "陽烏自焦鑠，垂翅不西舉。", "炙翻四海波，天地入烹煮。", "蛟龍竄潭穴，汗喘不敢雨。", "雷神抱桴逃，不顧車裂鼓。", "豈無堂室深，氣鬰如炊釜。", "豈無臺榭高，風毒如遭蠱。", "直疑萬類繁，盡欲變脩脯。", "嘗聞崑閬間，別有神仙宇。", "雷散滌煩襟，玉漿清濁腑。", "吾欲飛而往，於義不獨處。", "安得世上人，同日生毛羽。"]'),
('f792a797-0ed1-4676-b627-9a121c0396b4','後園寒步','韓琦','宋','宋诗','song-poetry','','[]','如何天地舉寒令，獨將殺氣凌邊遐。',192,'全唐诗/poet.song.18000.json','["如何天地舉寒令，獨將殺氣凌邊遐。", "公園跬步亦難往，試來舉目成吁嗟。", "長空黯淡作愁色，日光似透雲還遮。", "朔風刮面不吹雪，徒擾萬竅掀黄沙。", "園中索寞不可狀，唯視眾木攢枯槎。", "有如漢將肅行陣，遠涉大漠平番家。", "貔貅凍列樹營壁，巨矛長戟何交加。", "老松一二柯葉在，外皮皴裂埋僵蛇。", "幽禽聲好久絕聽，孤城遠近號饑鴉。", "齋中酒熱忍自酌，幾何貧戶無纖麻。", "冥官持權因意惡，直欲萬類殲陰邪。", "窮嚴極烈勢未已，不知泉底生陽芽。"]'),
('398ec477-968c-4783-834c-3a34469f445d','臘日出獵近交','韓琦','宋','宋诗','song-poetry','','[]','悲風吼林霜草白，殺氣稜稜慘空碧。',320,'全唐诗/poet.song.18000.json','["悲風吼林霜草白，殺氣稜稜慘空碧。", "因畋講事比其時，況值嘉平農已隙。", "暫整和門出近郊，獵獵旌旗原燒赤。", "狩場一望天四垂，貔虎意豪猶恨窄。", "鼓動圍開翼復箕，人知部分如刀劃。", "飛刊竄伏不得暇，狡兔幸生徒奮擲。", "饑鷹眼捷翅頭健，下鞲風發無虛搦。", "鶻拳交擊或未仆，繼嗾韓盧追以咋。", "忽穿叢薄失所捕，耻焉便縱摩霄翮。", "不似寒鴟得腐鼠，傲然直視鴛雛嚇。", "烏鶉鵲雉曷足數，亦有晨風競搜索。", "其間駭獸欲陵突，焊卒爭趨矜手格。", "前驅返旆弗及舍，邱山大委虞中獲。", "翻車瀉酒犒士眾，萬刀刲肉恣燔炙。", "塞防寓令豈徒然，不在詩人刺荒癖。", "王者設官猶取眾，大姦宿猾許擒扼。", "乘時廢職莫自效，勿謂鷙鳥無全策。", "別有老狐智計巧，只就高城營窟宅。", "疑冰識扱行步穩，此日胡由見蹤跡。", "鵰兮鵰兮未得志，將軍憤懣如何釋。"]'),
('567c4d35-aef1-4af0-b310-ea36574e609f','病鶴貽劉易','韓琦','宋','宋诗','song-poetry','','[]','塵寰病思苦，仙府歸魂勞。',48,'全唐诗/poet.song.18000.json','["塵寰病思苦，仙府歸魂勞。", "禿翼敗風霰，卑棲掩蓬蒿。", "池圃擯時玩，雞鳧豈吾曹。", "誰知牢落心，萬里孤雲高。"]'),
('0531bff5-ad21-434e-8299-98fe5571b93d','示直彥','韓琦','宋','宋诗','song-poetry','','[]','人惟萬物靈，各肖天地貌。',192,'全唐诗/poet.song.18000.json','["人惟萬物靈，各肖天地貌。", "中人無賢愚，在稟父師教。", "稟則道業成，奮躍出泥淖。", "不稟墜素風，隱身于不孝。", "汝父最汝憐，五歲入學校。", "文采冀日彰，謂如隱霧豹。", "不見汝成人，齎恨掩泉窖。", "汝兮胡不思，先矩勉而傚。", "奈何一夕眠，乃至巳午覺。", "開口受飲食，摩腹混笑鬧。", "四體遂吾懶，萬事絕掛撓。", "習焉而忘返，紈綺事不較。", "高秋八月凉，蚊蟆罷蒙罩。", "燃膏繼晝景，著撰勤節抄。", "詔舉有前期，富貴孰不樂。", "忍捐卿相科，甘坐閱醯酵。"]'),
('af776988-c656-4e93-a830-ca7c9c8c62bf','謝宮師杜公寄惠草書','韓琦','宋','宋诗','song-poetry','','[]','公之德業天下重，四海萬物思壞罏。',384,'全唐诗/poet.song.18000.json','["公之德業天下重，四海萬物思壞罏。", "太平之策未全發，先朝請老叩帝居。", "天子只欲勵薄俗，不惜一夔從二疏。", "公持儉節出天性，下建萬世清風孤。", "歸卜睢陽旋營第，棟宇僅足容妻孥。", "自此閒燕何所樂，非絲非竹非歌壺。", "經史日與聖賢遇，參以吟詠爲自娛。", "興來弄翰尤得意，真楷之外精草書。", "因書乞得字數幅，伯英筋肉羲之膚。", "字體真渾遠到古，神馬初見八卦圖。", "精神熠熠欲飛動，鸞鳳鼓舞龍蛇攄。", "天姿瘦硬斥俗軟，狂藤束纏巖松枯。", "中含婉媚更可愛，十葩萬萼爭春敷。", "開合向背一皆好，造化欲衒天工夫。", "張旭雖顛懷素逸，較以年力非公徒。", "公今眉壽俯八十，老筆勁健自古無。", "固知大賢不世出，百福來萃相所扶。", "公之佳壻蘇子美，得公一二名已沽。", "矜奇恃儁頗自放，質之公法慙豪麤。", "乘歡捧以示僚屬，一坐聳駭歎且呼。", "便欲刻石傳不朽，荒邊匠拙無人模。", "歸來一一戒兒姪，秘重世與家諜俱。", "重巾密橐置吾室，寶護直比驪頷珠。", "神物孰敢容易探，電雹霹靂來須臾。"]'),
('523d526b-bde0-4961-b8f5-8a56bb2096dd','遊開化寺','韓琦','宋','宋诗','song-poetry','','[]','開化得勝地，崇侈何代作。',288,'全唐诗/poet.song.18000.json','["開化得勝地，崇侈何代作。", "全山鑱佛身，萬木亙高閣。", "突然數百尺，較力陋禹鑿。", "峰巒翠環合，與寺爲郛郭。", "煙霞無四時，爲我張幄幙。", "飛泉乘空來，直在庭砌落。", "松柏森成行，鬭狀蛟龍惡。", "如整萬人陣，偏伍不敢錯。", "春芳難悉名，紅紫競灼灼。", "點綴巖壁間，圖畫曾未若。", "距城纔一舍，曠絕類霄堮。", "噫吾何自勞，日窘吏事縛。", "到官踰二朞，未克造林壑。", "引疾得鄉邦，晝錦行遂著。", "猛拋公几煩，不負真境約。", "精廬始一登，百慮已澄擴。", "徘徊延賓僚，開席盛燕酌。", "歌留嶺上雲，吹亂風前鐸。", "勿譏清賞累，粗繼東山樂。", "數刻方暫歡，俄景忽西薄。", "歸鞅下危岑，眷戀心欲却。", "何處無林泉，隔閡牽寵爵。", "終期報國家，功業效涓勺。", "連露乞骸章，不待七十削。"]'),
('d7a4e0d6-e0b7-4221-acca-7eae143b883c','再賦','韓琦','宋','宋诗','song-poetry','','[]','蒙山崦裏藏禪宮，朝蒼暮翠嵐光濃。',64,'全唐诗/poet.song.18000.json','["蒙山崦裏藏禪宮，朝蒼暮翠嵐光濃。", "枯松老柏競醜怪，危巒峻嶺相彌縫。", "劔峽路岐唯少棧，榆關氣象全無烽。", "恩深報淺來未得，暫留金節開塵容。"]'),
('ac20e48c-6c39-4b94-a89c-da66701ca63a','晉祠魚池','韓琦','宋','宋诗','song-poetry','','[]','女郎祠下池，清瑩薄山脚。',120,'全唐诗/poet.song.18000.json','["女郎祠下池，清瑩薄山脚。", "游鱗明鑑中，素恃神可託。", "羣嬉不畏人，似得天真樂。", "祠者常見憐，投食任爭綽。", "且疑神佑之，縱嚵安敢摸。", "達者時公攘，羹鱠陷烹斫。", "神乎所保扶，未免挫陰惡。", "何如致君人，其道本宏博。", "天下日唐虞，聲教盡薰灼。", "推此及微類，魚鱉得咸若。"]'),
('ab25dd79-ca4e-43eb-9c57-817f0dbfde8c','難老泉','韓琦','宋','宋诗','song-poetry','','[]','晉源發濫觴，勃勃漲春綠。',120,'全唐诗/poet.song.18000.json','["晉源發濫觴，勃勃漲春綠。", "泓然一鑑閒，俯視神意肅。", "游鯈何太繁，戢戢鬧如粥。", "烏能污吾清，更足示容蓄。", "中或起蛟龍，威怒鼓天福。", "膏澤被九區，靈德潛山麓。", "平時任疏達，所存終海瀆。", "常豐沃稻粱，餘潤霑花木。", "伊予臨此泉，自得仁人勗。", "奚專智者心，犇走無停躅。"]'),
('2c3b3006-a1b2-44f1-b08c-bfd9e0dc669d','甲午中秋夜不見月','韓琦','宋','宋诗','song-poetry','','[]','中秋待月高樓上，浮雲妬明逞頑黑。',128,'全唐诗/poet.song.18000.json','["中秋待月高樓上，浮雲妬明逞頑黑。", "姮娥積貯一歲光，欲放天下不可得。", "今夕實繫天下望，未必舉世罹遮塞。", "歡明慼暗一時偏，人不咎天雲所職。", "吾問雲兮爾無心，胡爲動與人相賊。", "歲旱不能含雨來，翻於此夜濃如墨。", "吾欲獨仗倚天劔，上决重陰走姦慝。", "空中奪出黄金盤，萬宇澄然同一色。"]'),
('90a0c845-2b7e-4e5d-b623-e1362e579d73','病中望雪','韓琦','宋','宋诗','song-poetry','','[]','日日顛風喧病枕，曾無片雲飛虛空。',64,'全唐诗/poet.song.18000.json','["日日顛風喧病枕，曾無片雲飛虛空。", "方嗟大疾被囚縛，敢請上帝前民豐。", "人囑衰翁略外事，心存眾瘼能寬中。", "紛紛盈尺諒旦夕，和霽迎得春融融。"]'),
('7ecf39f2-bdd3-463d-93ab-8edbd3313547','離并州至晉祠次韻答宣徽富公','韓琦','宋','宋诗','song-poetry','','[]','公名傑出天下賢，終身師慕常顓顓。',64,'全唐诗/poet.song.18000.json','["公名傑出天下賢，終身師慕常顓顓。", "十年一面數日別，行行不忍移歸軿。", "剛腸出淚收還注，感公知己難違去。", "黄昏病作宿荒城，離緒不堪紛似雨。"]'),
('b2de1fe1-7a8b-4b5d-8968-816006a187f6','塗次答宣徽富公書意','韓琦','宋','宋诗','song-poetry','','[]','臨并踰二朞，病慼居其半。',216,'全唐诗/poet.song.18000.json','["臨并踰二朞，病慼居其半。", "雖以志自勉，精識奈耗亂。", "故於一道事，十六七不幹。", "貪權莫即亂，罪大孰可逭。", "納節求本邦，所幸脫誅竄。", "君仁惻至誠，亟俾賢者換。", "與公同心人，金固其利斷。", "安然解印歸，萬喜無一惋。", "爲別信宿來，書日慰愚懦。", "張瑟久不調，易調猶未斷。", "非才辱公知，處道誠一貫。", "至於措置間，在理有殊判。", "不當牽以私，經畫誤遠算。", "願公新政條，布若星日燦。", "害邊者剗除，垢俗者滌浣。", "使茲全晉民，比屋競聳觀。", "僕遠聞公爲，省過安敢憚。", "雖有好事徒，議論烏得間。"]'),
('76ab5083-a06e-4c17-88a8-2edb35d6a25e','晝錦堂','韓琦','宋','宋诗','song-poetry','','[]','古人之富貴，貴歸本郡縣。',288,'全唐诗/poet.song.18000.json','["古人之富貴，貴歸本郡縣。", "譬若衣錦游，白晝自光絢。", "不則如夜行，雖麗胡由見。", "事累載方冊，今復著俚諺。", "或紆太守章，或擁使者傳。", "歌樵忘故窮，滌器掩前賤。", "所得快恩仇，愛惡任驕狷。", "其志止于此，士固不足羨。", "茲予來舊邦，意弗在矜衒。", "以疾而量力，懼莫稱方面。", "抗表納金節，假守冀鄉便。", "帝曰其汝俞，建纛往臨殿。", "行路不云非，觀歎溢郊甸。", "病軀諧少休，先隴遂完繕。", "歲時存父老，伏臘潔親薦。", "恩榮孰與偕，衰劣愧獨擅。", "公餘新此堂，夫豈事飲燕。", "亦非張美名，輕薄詫紳弁。", "重祿許安閑，顧己常競戰。", "庶一視題榜，則念報主眷。", "汝報能何爲，進道確無倦。", "忠義聳大節，匪石烏可轉。", "雖前有鼎鑊，死耳誓不變。", "丹誠難悉陳，感泣對筆硯。"]'),
('ee5f295c-2f09-4a9b-840b-f66f231a025c','康樂園','韓琦','宋','宋诗','song-poetry','','[]','惟人生多艱，康世豈易偶。',288,'全唐诗/poet.song.18000.json','["惟人生多艱，康世豈易偶。", "服業罔不勤，樂事豈常有。", "朝家恩澤寬，宣布在封守。", "體民當有時，使得遂仁壽。", "時而無所適，是不守之咎。", "相署雖有園，狹陋日已久。", "州人歲節遊，若度一筒口。", "至則無足觀，疊跡但虛走。", "遂令歡賞心，歸去成煩嘔。", "有圃隔牙城，廣袤半百畝。", "我來闢而通，高戶敞軒牖。", "其中完廢臺，雄壯卑培塿。", "城野四望間，萬景如在手。", "疏池育蓮芰，表道植楊柳。", "糞壤悉反除，桃李換葱韮。", "成時寒食春，觀者惟恐後。", "人一變壅閼，曠若在郊藪。", "或相携以歌，或相醉以酒。", "知爲太平民，歎語競聚首。", "曰非時之康，還得此樂不。", "予因揭是名，命意安敢苟。", "凡茲屏翰賢，一境實父母。", "必與眾同樂，斯地肯藜莠。", "作詩告來者，庶可傳不朽。"]'),
('471c6656-b3e2-445b-9f23-23d34f6a25fc','休逸臺','韓琦','宋','宋诗','song-poetry','','[]','牙城之北好大圃，中有廢臺名抱螺。',384,'全唐诗/poet.song.18000.json','["牙城之北好大圃，中有廢臺名抱螺。", "基圓有道盤屈上，故以螺目義匪佗。", "當時興者擇地審，氣象爽塏形勢多。", "今如孤冢但荆棘，不知隳壞年幾何。", "背城人迹既罕到，往往滿歲無一過。", "我來侵圃治兵庫，得披榛莽登巍峩。", "襟懷豁若出塵外，四視天末窮纖羅。", "滿城風物聚掌上，紅芳綠樹明交柯。", "太行之下不可數，萬峯起落如翻波。", "北來州域盡平地，孰若舊鄴襟山河。", "此爲遊覽最佳處，遂施畚筑完陂陀。", "臺頭結宇尚簡樸，臺面甃甓嚴鎸磨。", "魏宮冰井久湮沒，鐵梁有四淪耕禾。", "精剛之質不少動，俚俗傳詫鄰妖訛。", "云有神物常默護，守令千百無敢拖。", "我憐古物輦而至，爲臺之柱植四阿。", "州人聞至極驚異，就臺觀者肩相摩。", "榜以休逸豈獨尚，與眾共樂乘春和。", "主人間復命賓酌，樽前隨分絃且歌。", "病來飲興直衰淺，獻酬勉强顔須酡。", "退嘗內省爾何德，爾求自逸人譏訶。", "反思吾本任忠義，日不作僞心無頗。", "君恩至厚假鄉守，正宜休此祛餘疴。", "尫孱報國未能奮，慨然倚檻空長哦。"]'),
('0c1b4eff-4a71-4518-9602-46fcb30aee06','答章望之祕校惠詩求古瓦硯','韓琦','宋','宋诗','song-poetry','','[]','魏宮之廢知幾春，其間萬事成埃塵。',244,'全唐诗/poet.song.18000.json','["魏宮之廢知幾春，其間萬事成埃塵。", "唯有昭陽殿瓦不可壞，埋沒曠野迷荒榛。", "陶甄之法世莫得，但貴美璞踰方珉。", "數百年來取爲硯，墨光爛發波成輪。", "求之日盛得日少，片材無異圭璧珍。", "巧工近歲知眾寶，雜以假僞規錢緡。", "頭方面凸槩難別，千百未有三二真。", "我來本邦責鄴令，朝搜暮索勞精神。", "遺基壞地徧坑窟，始獲一瓦全元淳。", "蘚斑著骨尚乾翠，夜雨點漬痕如新。", "當時此復近簷溜，即以篆字花其脣。", "磨礱累日喜成就，要完舊質知無倫。", "吾才寡陋不足稱，思與好古能文人。", "好古能文今者誰，武寧祕書章表民。", "無詩尚欲兩手付，何況大雅之奏聞鏗純。"]'),
('ce05dd33-820d-41f6-8e63-8aebe70a5c76','答陳舜俞推官惠詩求全瓦古硯','韓琦','宋','宋诗','song-poetry','','[]','鄴宮廢瓦埋荒草，取之爲硯成堅好。',163,'全唐诗/poet.song.18000.json','["鄴宮廢瓦埋荒草，取之爲硯成堅好。", "求者如麻幾百年，宜乎今日難搜討。", "吾邦匠巧世其業，能辨環奇幼而老。", "隨材就器固不遺，大則梁棟細棼橑。", "必須完者始稱珍，何殊巨海尋三島。", "荆人之璧尚有瑕，夏后之璜豈無考。", "況乎此物出壞陶，千耕萬斸常翻攪。", "吾今所得不專全，祕若英瑶藉文繅。", "君詩苦擇未如意，持贈只虞咍絕倒。", "君不見鎮圭尺二瑁四寸，大小雖異皆君寶。"]'),
('a3c49c51-0476-4b11-8c6d-c94e47101105','觀胡九齡員外畫牛','韓琦','宋','宋诗','song-poetry','','[]','丹青之筆奪造化，能者幾何登品錄。',358,'全唐诗/poet.song.18000.json','["丹青之筆奪造化，能者幾何登品錄。", "蛟龍獰惡鬼神怒，更工不接時人目。", "有形之物至者稀，是否難欺眾所矚。", "絳臺胡掾文章外，偏向畫牛其好酷。", "海內馳名三十年，得者珍藏過金玉。", "老來纔始著青衫，養親不及朝家祿。", "前日野服忽相過，云訪恩知走京轂。", "微風入指未能畫，示我蠟本數十幅。", "採摭諸家百餘狀，毫端古意多含蓄。", "鬭者取力全在角，卧者稱身全在腹。", "立身髣髴精神慢，背者分數頭項促。", "行者動作皆得羣，乳者顧視真憐犢。", "當流泅戲益自在，欲渡或疑猶蓄縮。", "從容飲囓得天真，荷鞭時有童兒牧。", "或橫一笛坐牛角，便是無聲太平曲。", "江天雨雲易溟濛，風勢掀號摧古木。", "欹斜簑笠趁牛歸，蕭踈暮景煙村宿。", "奇哉胡掾老筆不可到，戴叟重生須死伏。", "吾觀諸牛之態雖盡妙，尚有所遺思未熟。", "牛於生民功最大，不畫牛功牛亦辱。", "胡君胡君聽我言，別選輕綃成巨軸。", "寫出區區耒耜勤，貴知天下由吾方食足。"]'),
('f8995d1f-499b-4ee5-8930-328ffa35a08d','中秋對月送姚闢教授南歸','韓琦','宋','宋诗','song-poetry','','[]','去歲中秋安帥并，今歲中秋病守相。',256,'全唐诗/poet.song.18000.json','["去歲中秋安帥并，今歲中秋病守相。", "并筵極口詈浮雲，終久蟾光被遮障。", "相臺此夜天如水，露壓凉風秋氣王。", "有客軒然襟義高，直自睢陽來一訪。", "相與僚賢共茲賞，坐看玉輪從海上。", "皓色疑專白帝權，晴舒萬宇俱澄曠。", "斜漢昭回列緯繁，收縮精神烏敢放。", "有如大臣得時用，上化恢宣賢業暢。", "千官戢伏任施設，默默壞陶從巧匠。", "金波漸轉落金樽，酒色映空寒動蕩。", "一宵清景換塵寰，自得詩人難擬狀。", "時揮大白目嬋娟，意入杳冥搜絕唱。", "勿嗤幽圃陋吾邦，吾樂不知崑與閬。", "人生聚散固難必，明年此會知何向。", "相逢對月復開懷，詩筆鬭豪杯鬭量。", "不然千里起相思，百尺樓高同一望。"]'),
('4bfb45a9-46a1-46e9-bbfd-4913b0bb1b1a','喜雪','韓琦','宋','宋诗','song-poetry','','[]','至和乙未夏，二麥死大旱。',264,'全唐诗/poet.song.18000.json','["至和乙未夏，二麥死大旱。", "秋田不下種，熬然六月半。", "天意忽垂惻，滂澤遂瀰漫。", "九穀飽甘滋，時若被溉灌。", "一變大有年，農籍脫逋竄。", "既豐復不雨，累月病乾暵。", "驕陽發仲冬，溫氣襲閭閈。", "斂輸誠無艱，瘥癘恐莫逭。", "何期日至前，風怒陰不散。", "吹開六出花，空際自凌亂。", "徐徐失埃氛，稍稍重枝幹。", "移時平瓦隴，逮夕沒田畔。", "雖下不及尺，近歲亦稀看。", "瑞諜宜首書，他物烏足冠。", "始寤天之神，俾下不可算。", "小民徒怨咨，一顧回屯難。", "君子當信天，夷險存大觀。", "惠姦豈固然，福善終冥判。", "吾喜開吾樽，對客共歡歎。", "一病久誡飲，當席由吾斷。", "引滿且酣歌，輕凜談間扞。", "未必不因此，反得攄吾患。"]'),
('927c48e7-3e73-465d-8815-b56c652f2000','別鎮陽監倉陳薦祕丞','韓琦','宋','宋诗','song-poetry','','[]','一紀帥三垂，待士敢不至。',168,'全唐诗/poet.song.18000.json','["一紀帥三垂，待士敢不至。", "推誠以求應，百不得一二。", "彥升其應者，所應由道義。", "幕中六七年，始卒無少異。", "嚴霜摧萬木，老柏彌蒼翠。", "烈火熾三日，良玉自溫粹。", "奉親不可留，含笑就委吏。", "須代處洺邑，潔羞勤以遂。", "我病來相臺，去客無所覬。", "彥升兩見過，顧舊不顧利。", "言別之遠官，駑櫪飼騏驥。", "蹄齧慎勿較，所困非吾類。", "自古賢者爲，爭免不肖忌。", "坐待天衢亭，萬里觀騰轡。"]'),
('667baf3d-75ad-4b5d-a069-2280571ff77e','寒食親拜二墳因誡子姪','韓琦','宋','宋诗','song-poetry','','[]','春色清且明，節盛一百五。',288,'全唐诗/poet.song.18000.json','["春色清且明，節盛一百五。", "寒食遵遺俗，潑火霽微雨。", "非才忝國恩，因病得吾土。", "何以知殊榮，此日奉宗祖。", "新安唯皇考，豐安則王父。", "松楸各萬株，崗勢擁城府。", "二塋相去間，近止一舍許。", "前曉揭旌牙，蠲潔具罍俎。", "芬馨達孝誠，僾若侍容語。", "禮成無一違，觀者競牆堵。", "退惟愚小子，未老膺旄斧。", "顧己胡能然，世德大門戶。", "思爲後嗣誡，永永著家矩。", "子姪聽吾言，汝各志心膂。", "汝曹生綺紈，得仕匪難苦。", "學業勤則成，富貴汝自取。", "仁睦周吾親，忠義報吾主。", "間須求便官，墳隴善完補。", "死則託二塋，慎勿葬他所。", "得從祖考游，魂魄自寧處。", "無惑葬師言，背親圖福祜。", "有一廢吾言，汝行則夷虜。", "宗族正其罪，聲伐可鳴鼓。", "宗族不繩之，鬼得而誅汝。"]'),
('85d73e9f-fa41-402a-9a62-ac053d041d67','初赴早朝','韓琦','宋','宋诗','song-poetry','','[]','踈星掛闕角，落月含輕雲。',48,'全唐诗/poet.song.18000.json','["踈星掛闕角，落月含輕雲。", "兀兀馬上身，叱叱馬前人。", "瘦骨酸秋霜，病瞳昏陌塵。", "自顧爾空空，胡以裨吾君。"]'),
('ac2828a6-a872-4c88-928c-e6d446d5b402','次韻答子淵學士','韓琦','宋','宋诗','song-poetry','','[]','憶昔明道初，窮冬極短晝。',120,'全唐诗/poet.song.18000.json','["憶昔明道初，窮冬極短晝。", "給札金鑾坡，孤拙並髦秀。", "諸公名世才，奮筆若神佑。", "蕪辭亦見收，聖造等天覆。", "子淵親契深，實出同試右。", "自茲接珍羣，軒翼羾紫宙。", "忠義必相勉，權利孰肯就。", "洞照無隱情，胸臆爛辰宿。", "宦路有亨塞，叨竊愧鄙陋。", "何時聚德星，一慰荀陳舊。"]'),
('075c1ab1-78d0-44e8-aed8-bb50b9a2e7c8','寄題西京致政張郎中靜居院','韓琦','宋','宋诗','song-poetry','','[]','休官得宴閑，理固居處靜。',240,'全唐诗/poet.song.18000.json','["休官得宴閑，理固居處靜。", "中或不自達，觸物撓天性。", "遂令優游心，反致寂寞病。", "二川有耆英，識豈斯人並。", "周才當要職，美譽著羣聽。", "氣體殊未衰，援禮請還政。", "安車得西歸，蕪沒治三徑。", "蕭然絕世紛，日以道自勝。", "以靜名厥居，內外了相稱。", "君懷本清虛，復此林泉瑩。", "君道本和樂，況有琴樽命。", "新堂闢四隅，立意尤高迥。", "夷襟造真境，友益具子令。", "藥品稽神仙，門法尚忠正。", "肌膚松菊香，庭砌芝蘭盛。", "天宜錫難老，以示君子慶。", "予亦希君者，誤寵竊機柄。", "無裨紫極尊，動有赤松興。", "報國苟錙銖，竄身違陷穽。", "雅志呈未諧，高山徒景行。"]'),
('f0e19253-9a87-4bbd-b638-c22c1f763bc9','戊申臘寒','韓琦','宋','宋诗','song-poetry','','[]','朔風吹苦寒，近歲省未有。',120,'全唐诗/poet.song.18000.json','["朔風吹苦寒，近歲省未有。", "重裘不可禦，凍袖敢出手。", "初嚴刮面膚，漸虐摇臂肘。", "終難凌壯肌，殊易挫衰朽。", "持觴欲爲敵，病胃怯戰酒。", "茵幬通作冰，强卧安得久。", "擁鼻反收吟，其孰噤汝口。", "何心窺園池，銳意墐戶牖。", "流庸方滿塗，天不念黔首。", "吁嗟卒無奈，默坐算五九。"]'),
('48f590e7-0a6e-4967-9d2b-a76916f10c82','榮歸堂','韓琦','宋','宋诗','song-poetry','','[]','非才忝四鄰，待罪涉一紀。',288,'全唐诗/poet.song.18000.json','["非才忝四鄰，待罪涉一紀。", "妨賢得云久，不退不自耻。", "永厚復土初，疊奏犯斧扆。", "乞身臨本邦，多疾便攝理。", "帝曰吁汝琦，輔翼甚勞止。", "今俾爾榮歸，揭節治故里。", "均逸向盛辰，寵異固絕擬。", "整裝將北轅，羌釁兆西鄙。", "俄易帥感秦，旰食論所倚。", "艱難惡敢辭，奔走奉寄委。", "天聲方震揚，狡穴懼夷毀。", "欵塞械兇酋，唯幸赦狂詭。", "疆事計日寧，拙疹乘衰起。", "披誠叩上仁，再遂守桑梓。", "尫疲解劇煩，宴息良自喜。", "園池昔恢拓，顧覽盡遺軌。", "獨於北堂北，地勝失經始。", "前人欲興作，就此創基址。", "中輟如有待，命我成斯美。", "鳩材亟僝功，因陋謹增侈。", "芳林環密陰，鯨口下洹水。", "吾堂據其陽，萬象來明煒。", "匪直怡病襟，間足具賓簋。", "僚屬請吾名，在景或在己。"]'),
('a501a41f-44eb-4c66-92c7-d865e21e61d4','謝并帥王仲儀端明惠葡萄酒','韓琦','宋','宋诗','song-poetry','','[]','并門昔歲叨擁旄，公厨酒熟醺葡萄。',288,'全唐诗/poet.song.18000.json','["并門昔歲叨擁旄，公厨酒熟醺葡萄。", "公時帥謂輒馳獻，助臨軍享投芳醪。", "辱公詩答極愛重，氣骨雄健凌風騷。", "公今大鹵盛開府，我得鄉守均疲勞。", "却煩新釀遠相遺，故人義比丘山高。", "衰翁拜賜喜自酌，持杯有感生鬰陶。", "憶昨朔邊被朝寄，亭燧滅警兵鋒韜。", "時平會數景物好，齒髮未老胸襟豪。", "當筵引滿角勝負，金船灧溢翻紅濤。", "間折圓荷代舉酌，坐客駭去如奔逃。", "我乘餘勇興尚逸，直欲拍浮騰巨艘。", "此來病質極枯瘠，兩目眵淚顛無毛。", "較前飲量復何有，十分耗謝餘釐毫。", "復嬰風眩戒食味，饞口絕望霑珍螯。", "雖然公醞敢輕用，留吞藥劑傾甘膏。", "縱逢嘉客衒公貺，三爵已命緘封牢。", "錦堂風和弄弱柳，螺榭日暖烘夭桃。", "茲辰慶我重加惠，勉與父老同春遨。"]'),
('7a2fcddb-453b-4dfd-97a0-e94626086447','安正堂','韓琦','宋','宋诗','song-poetry','','[]','公居胡葺爲，非事土木盛。',288,'全唐诗/poet.song.18000.json','["公居胡葺爲，非事土木盛。", "湫陋必氣鬰，爽塏則神瑩。", "全魏今別都，地總北道勝。", "軺傳既旁午，牒訴亦紛競。", "惟日過目前，豈暇圖休靜。", "因仍府舍間，敝壞殊不稱。", "茲余忝帥守，上責賦荒政。", "無術濟饑流，感速賴仁聖。", "連書大有年，愁慼變謳詠。", "漸舒綏集勞，猶治淹痼病。", "頤生擇所宜，宴息務清迥。", "乘閑新此堂，庶用安吾正。", "汝正果何如，自得本天性。", "進特仗孤忠，退免全剛勁。", "內確信吾守，外一歸諸命。", "安然而處思，吾宇甚泰定。", "詩酒延嘉賓，二戰或酣醟。", "笙歌樂良辰，高郢下淫鄭。", "射圃夾羣芳，角妙資豪興。", "所適敢專享，意實在遐夐。", "繼來皆鉅公，同調決相應。", "從容坐鎮餘，浩氣端而挺。", "將寧道德淵，諒悉欣流泳。", "知不廢吾堂，是可以前慶。"]'),
('1d22fdeb-da40-4049-b622-11d7fb7b5219','善養堂','韓琦','宋','宋诗','song-poetry','','[]','金銅飾巨扉，其上覆高屋。',240,'全唐诗/poet.song.18000.json','["金銅飾巨扉，其上覆高屋。", "青石鑿雙轍，其下走彫轂。", "東西翼危墉，陰以捍攻觸。", "自昔藩鎮强，尚此存遺躅。", "後守營厥居，鄆擬苦迫促。", "余來亦患之，重改敢輕速。", "會茲歲月深，朽敗鮮完木。", "一旦忽傾摧，僣迹詎可復。", "余得矯前爲，命徒墮舊筑。", "堂皇遂延袤，興寢適凉燠。", "廊廡悉舒明，瞻望快耳目。", "移樓成廣厦，面勢壓平陸。", "既忘登陟勞，又遠顛躓辱。", "外將延賓僚，內足燕親族。", "乘閑娛詩書，遇節振絲竹。", "頤真與放懷，動靜獲所欲。", "於氣貴能養，在禮思無凟。", "侯邦謹法度，是克綏遐福。", "踰制苟幸免，更久猶追戮。", "吾居已絕嫌，道義斯同育。"]'),
('c989b069-3f95-41db-8221-3922f52a2540','孫賁書記以齊安舊文爲示感而成詠','韓琦','宋','宋诗','song-poetry','','[]','余兄天聖中，尚抑齊安守。',216,'全唐诗/poet.song.18000.json','["余兄天聖中，尚抑齊安守。", "余遭所生憂，得歸侍左右。", "孤煢獲苟存，朝夕賴誨誘。", "兄材無不宜，吏治孰可偶。", "公庭常寂然，所樂在文酒。", "臨江三四樓，次第壓城首。", "山光拂軒檻，波影撼窗牖。", "原鴒款集間，萬景皆吾有。", "兄詩豪且奇，氣燄摩星斗。", "優游預賡和，惟自愧荒醜。", "于今四十年，日月甚奔走。", "當時相聚者，十已喪八九。", "嘗爲春亭記，烏敢示不朽。", "孫君里中來，云亭廢已久。", "徒有舊文在，況足失其手。", "兄後見曾孫，弟老成衰叟。", "一身雖寵榮，百慮鎖紛糾。", "何如昔日歡，抆泣念愛友。"]'),
('ac2b0e64-afbd-4978-aa90-4d7df043bd17','開泉','韓琦','宋','宋诗','song-poetry','','[]','先塋東北隅，有泉渤而出。',144,'全唐诗/poet.song.18000.json','["先塋東北隅，有泉渤而出。", "奔跳若爨鼎，萬眼沸不一。", "始雖稍泓登，漸乃肆沕潏。", "吾嘗展祀餘，愛玩必終日。", "爰從大旱來，數歲竭如窒。", "傷哉利澤源，頓爾藏於密。", "吾今具畚鍤，試欲疏潛屈。", "開無數尺間，舊脈俄騰溢。", "涓涓力尚微，勢已舒沈鬰。", "我願天道常，不使五行失。", "均調四氣和，寒燠皆從律。", "宣其潤下功，復得霑羣物。"]'),
('16fb6972-04c9-436d-b610-64950c53a0a8','虛心堂會陳龍圖','韓琦','宋','宋诗','song-poetry','','[]','余嘗愛此君，中虛外有節。',192,'全唐诗/poet.song.18000.json','["余嘗愛此君，中虛外有節。", "手植數年間，萬戟競森列。", "爲堂於其中，一境遂清絕。", "雖歸臨本邦，事豈免羈紲。", "不得時相親，固負好風月。", "方將乞殘骸，就第養衰拙。", "孤懷造崑閬，直氣卷金鐵。", "終日對嬋娟，卒歲伴高潔。", "春來忘芳非，夏至失炎熱。", "秋深凌嚴霜，冬暮映積雪。", "居無一不宜，嘯傲遠塵媟。", "茲樂期誰同，實係長者轍。", "相從挹天真，共話到禪悅。", "簪籜豸冠聳，拉筍犀株折。", "乘醉卧踈影，敲玉應仙闕。", "此志吁未遂，對酒勿輕別。"]'),
('37a3893f-40b9-4678-81b0-1e9f144b40c0','醉白堂','韓琦','宋','宋诗','song-poetry','','[]','戇老新成池上堂，因憶樂天池上篇。',352,'全唐诗/poet.song.18000.json','["戇老新成池上堂，因憶樂天池上篇。", "樂天先識勇退早，凜凜萬世清風傳。", "古人中求尚難擬，自顧愚者孰可肩。", "但舉當時池上物，媿今之有殊未全。", "池東無廩貯餘粟，池西無亭揮五絃。", "中無高橋跨三島，下壓鼇背浮清漣。", "其間合奏散序者，童妓百指皆嬋娟。", "平無三石展湘簟，靜無雙鶴翹丁仙。", "雅無吳郡青版舫，游泛安便牢且堅。", "吾今謀退亦易足，池南大屋藏羣編。", "一車豈若萬籍富，子孫得以精覃研。", "夾堂脩竹抱幽翠，森森擁檻竿逾千。", "池中所出粗可愛，芡盤菱角紅白蓮。", "芍藥多名來江都，牡丹絕艷移洛川。", "及時花發池左右，香苞爛染朝霞鮮。", "戇老于此興不淺，間會賓屬陳芳筵。", "妖妍姬侍目嘉卉，吚啞絲竹聽流泉。", "宜城釀法亦云美，詩酒僅可追前賢。", "狂吟氣健薄霄漢，豪飲體放忘貂蟬。", "酒酣陶陶睡席上，醉鄉何有但浩然。", "人生所適貴自適，斯適豈異白樂天。", "未能得謝已知此，得謝吾樂知誰先。"]'),
('ab4d862f-bb88-45d7-b30c-fdfa1854cb64','龍','韓琦','宋','宋诗','song-poetry','','[]','育德知何宅，逢辰或見靈。',48,'全唐诗/poet.song.18000.json','["育德知何宅，逢辰或見靈。", "配乾雖有象，作解本無形。", "浹物周寰宇，遺功在杳冥。", "丹青如可狀，試下葉公庭。"]'),
('bc808987-8aaa-4e5b-975f-1fa014d31140','鳳','韓琦','宋','宋诗','song-poetry','','[]','破卵應難至，聞韶定有儀。',48,'全唐诗/poet.song.18000.json','["破卵應難至，聞韶定有儀。", "去同君子道，來協聖人期。", "苑竹多成實，宮梧幾換枝。", "何時天閣上，巢可俯而窺。"]'),
('2b0c0f47-bcaa-4919-9799-3caa6f4f6399','次韻和春聊學士早春','韓琦','宋','宋诗','song-poetry','','[]','雪霽春來極目心，遠眉新黛破遥岑。',64,'全唐诗/poet.song.18000.json','["雪霽春來極目心，遠眉新黛破遥岑。", "風傳花信值寒晚，煙染柳姿隨日春。", "酒美好陪遊騎鬭，桃香誰待此門尋。", "歡期未集芳辰在，冤對慵繙簡字金。"]'),
('88289983-47df-4c6b-a7d4-e9507146e51d','明鎬學士領漕益州','韓琦','宋','宋诗','song-poetry','','[]','忠臣重此過邛崍，經計才優帝命諧。',64,'全唐诗/poet.song.18000.json','["忠臣重此過邛崍，經計才優帝命諧。", "縣弩清塵資遠撫，史彤修職峻榮階。", "蜀天星入人先候，劍路銘昏蘚半埋。", "錦里萬家迎使旆，壺漿應釋去思懷。"]'),
('9676cf99-124c-4e99-ae66-54fa9afd5de2','次韻和子淵學士春雨','韓琦','宋','宋诗','song-poetry','','[]','天幕沉沉淑氣溫，雨絲輕軟墜雲根。',64,'全唐诗/poet.song.18000.json','["天幕沉沉淑氣溫，雨絲輕軟墜雲根。", "洗開春色無多潤，染盡花光不見痕。", "寂寞畫樓和夢鎖，依微芳樹過人昏。", "堂虛座密珠簾下，試問淳于醉幾樽。"]'),
('d0046018-1a9c-4c22-8a85-fc1c4e4dc303','周沆著作宰秀州嘉禾','韓琦','宋','宋诗','song-poetry','','[]','庇身名邑得嘉禾，銅墨猶嗟滯俊科。',64,'全唐诗/poet.song.18000.json','["庇身名邑得嘉禾，銅墨猶嗟滯俊科。", "前席未期宣室召，聞絃還繼武城歌。", "酒旗穿柳春堤迥，魚艇藏花夕唱和。", "對此不勞披縣譜，且求新句解詩魔。"]'),
('80dfbb22-406c-4a7c-97e1-cc16f61e36a2','叔平學士知青州','韓琦','宋','宋诗','song-poetry','','[]','厭直圖書府，思爲海岱州。',120,'全唐诗/poet.song.18000.json','["厭直圖書府，思爲海岱州。", "郡符分竹使，親膳潔蘭羞。", "文石輸忠密，仙山進職優。", "過家門納駟，卜地隴眠牛。", "暮霰凌羈玉，朝暾豔戟油。", "恩寬敷漢札，政善洽齊謳。", "水際春芳盛，尊中客醞浮。", "物饒三服麗，居樂五民游。", "松鬣低容宴，峯螺翠入樓。", "行聞西掖召，真賞莫淹留。"]'),
('e902632e-040c-42de-8624-6375ee8c8420','館直二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','玉山岑寂雪花乾，仙掌風高露未漙。',32,'全唐诗/poet.song.18000.json','["玉山岑寂雪花乾，仙掌風高露未漙。", "自笑曼都凡格在，一宵無奈月邊寒。"]'),
('d1edae14-d39b-49db-8a92-c5f2fb7e203a','館直二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','章溝傳漏過三更，霜壓寒威特地生。',32,'全唐诗/poet.song.18000.json','["章溝傳漏過三更，霜壓寒威特地生。", "苦恨回環窗外鐸，幾番幽夢不教成。"]'),
('69f502f5-222a-4f81-ac21-ecd07854cc81','張唐卿狀元通判陜府','韓琦','宋','宋诗','song-poetry','','[]','發策無雙動紫宸，班條新貳兩朱輪。',64,'全唐诗/poet.song.18000.json','["發策無雙動紫宸，班條新貳兩朱輪。", "窅窊仙桂天香重，蔽芾甘棠俗化醇。", "駟馬同榮歸蜀道，二龍齊躍出雲津。", "前期丹禁徊翔地，鳳沼波平藥樹春。"]'),
('91d5b830-1115-476e-9931-ce34c3e5ac2a','和春卿學士柳枝詞五闋  其一','韓琦','宋','宋诗','song-poetry','','[]','樓前輕雪未全銷，偷得春光入嫩條。',32,'全唐诗/poet.song.18000.json','["樓前輕雪未全銷，偷得春光入嫩條。", "似向東風猶旅拒，可能渾忘舞時腰。"]'),
('ee7f3814-0f5e-47a5-a304-c7e8832a93dc','和春卿學士柳枝詞五闋  其二','韓琦','宋','宋诗','song-poetry','','[]','陌閑宮古綠煙迷，惹盡春愁困拂堤。',32,'全唐诗/poet.song.18000.json','["陌閑宮古綠煙迷，惹盡春愁困拂堤。", "却爲多情足離恨，故教溝水亦東西。"]'),
('a1bc8d89-23bf-4066-baec-701f3d3480f4','和春卿學士柳枝詞五闋  其三','韓琦','宋','宋诗','song-poetry','','[]','章街風曉起新眠，寒食輕陰未雨天。',32,'全唐诗/poet.song.18000.json','["章街風曉起新眠，寒食輕陰未雨天。", "無限青絲拂遊騎，一生芳意負金鞭。"]'),
('b431a40a-8f91-406f-be8d-0dc42f5c1d05','和春卿學士柳枝詞五闋  其四','韓琦','宋','宋诗','song-poetry','','[]','淡煙輕日簇誰家，微出青旗一带斜。',32,'全唐诗/poet.song.18000.json','["淡煙輕日簇誰家，微出青旗一带斜。", "對景似嫌春意老，更摇踈影掃殘花。"]'),
('062b61e3-700d-4218-ab54-675785e8c7a2','和春卿學士柳枝詞五闋  其五','韓琦','宋','宋诗','song-poetry','','[]','畫橋南北水連天，纔聽鶯聲又晚蟬。',32,'全唐诗/poet.song.18000.json','["畫橋南北水連天，纔聽鶯聲又晚蟬。", "長使離魂容易斷，春風秋月自依然。"]'),
('29afb5cb-8ac4-4423-90ee-f705a698c9e0','和春卿學士上元罷燈','韓琦','宋','宋诗','song-poetry','','[]','絲竹沉聲月泛波，警宵方喜罷誰何。',64,'全唐诗/poet.song.18000.json','["絲竹沉聲月泛波，警宵方喜罷誰何。", "樓深酒密客留易，路遠香殘人去多。", "寒燭倚蓮猶結淚，澹雲歸隴不停歌。", "那知夢穩瀛洲上，正是鈞天九奏和。"]'),
('98c059b9-d5b3-4e0e-8ef8-6eeee6a1f1f2','次韻酬子淵學士燈夕不出聞諸公繼有遊賞','韓琦','宋','宋诗','song-poetry','','[]','繁聲沉夕籟，香燭競春葩。',48,'全唐诗/poet.song.18000.json','["繁聲沉夕籟，香燭競春葩。", "玉射樓前雪，雪驚陌上車。", "月閑花院掩，風軟酒帘斜。", "莫駐城南騎，遊人自有家。"]'),
('767a8a23-a075-4e92-be2c-f42021fd626c','和邃卿學士霽登祕閣','韓琦','宋','宋诗','song-poetry','','[]','曉來延閣步層梯，春色周圍一望低。',64,'全唐诗/poet.song.18000.json','["曉來延閣步層梯，春色周圍一望低。", "殘雪半留珠殿北，非煙長護綺窗西。", "幽情自逐歸鴻斷，芳意還因遠樹迷。", "金匱有書猶未見，祕封香篆鎖芝泥。"]'),
('44cc7127-47e2-418d-872f-f9bea31835d4','上巳前與同舍出郊過金明池','韓琦','宋','宋诗','song-poetry','','[]','天波新綠染成春，波面輕風起細鱗。',64,'全唐诗/poet.song.18000.json','["天波新綠染成春，波面輕風起細鱗。", "隔岸鳥聲低弄曲，出牆花艷遠含嚬。", "柳經傷別還多緒，鷗爲忘機不避人。", "三月偷遊仙署友，肯思迢遞走征輪。"]'),
('7cff59b0-2f37-4193-a93b-16adf6e14b7a','和春卿學士登廣文閣觀京闕之盛','韓琦','宋','宋诗','song-poetry','','[]','層閣鬰嵯峩，登臨逸意和。',48,'全唐诗/poet.song.18000.json','["層閣鬰嵯峩，登臨逸意和。", "雨餘春物動，天闊夕陽多。", "棊布金杯第，環通璧沼波。", "泥中足車騎，應笑翟公羅。"]'),
('c8708531-2294-476f-99f0-f8a6ee5d2168','和曼卿學士明河','韓琦','宋','宋诗','song-poetry','','[]','太極疏靈派，長河注遠津。',48,'全唐诗/poet.song.18000.json','["太極疏靈派，長河注遠津。", "波明動星斗，氣直貫秋旻。", "月滿還知晦，雲收不亂真。", "何妨借餘潤，膏雨及生民。"]'),
('cfb3740b-ebe7-43e9-924a-d806f899d8a4','葉參兵部知湖州','韓琦','宋','宋诗','song-poetry','','[]','鄉郡分符兔刻銀，彯纓清曉別楓宸。',64,'全唐诗/poet.song.18000.json','["鄉郡分符兔刻銀，彯纓清曉別楓宸。", "駟車歸邸夸新綬，鶴表還家謝故人。", "度日客樽盈若酒，經春詩筆賦汀蘋。", "編民應久歌來暮，棠樹成陰即舊鄰。"]'),
('394abe23-78cf-41ab-a77d-1426c262b7bf','邵亢茂材南歸','韓琦','宋','宋诗','song-poetry','','[]','褐衣親策對中宸，三道精求素業陳。',64,'全唐诗/poet.song.18000.json','["褐衣親策對中宸，三道精求素業陳。", "履跡見穿期仕漢，璧瑕因指不留秦。", "雲迷江樹歸艎促，翼退天閽客夢新。", "好俟鄉人再推上，決科優等繼平津。"]'),
('a3ef0d7a-41a8-4055-94a7-cc0da3d1847f','陳洎太博知虢州','韓琦','宋','宋诗','song-poetry','','[]','官綬飛花使轂丹，臘天行色犯輕寒。',64,'全唐诗/poet.song.18000.json','["官綬飛花使轂丹，臘天行色犯輕寒。", "持平久奉虞刑恤，宣澤新承漢詔寬。", "擁傳想逢關吏歎，愛棠還接陜民歡。", "三堂風物應如舊，公退先尋記字看。"]'),
('36301379-47b7-43f9-b353-fae55bbb8663','王礪寺丞河南知錄','韓琦','宋','宋诗','song-poetry','','[]','西都爲掾促征輪，南浦分携碧草春。',64,'全唐诗/poet.song.18000.json','["西都爲掾促征輪，南浦分携碧草春。", "卿寺試才方命秩，天衢飛步已逢辰。", "洛濱修禊浮觴散，水際看花第品新。", "櫻酪有期誰其薦，曲江應記並遊人。"]'),
('81ece79e-d953-4fd2-b44f-c7f659fc02b3','次韻和方謹言郎中再觀省中手值竹','韓琦','宋','宋诗','song-poetry','','[]','翠影參差漸拂階，清郎曾此占奇哉。',64,'全唐诗/poet.song.18000.json','["翠影參差漸拂階，清郎曾此占奇哉。", "辭君昔爲蓴羹去，戀爾今同菊徑來。", "玉聳勁枝欺暮雪，繡殘文籜委寒苔。", "虛心高節依然在，幾見繁英落又開。"]'),
('2524e571-eb8e-413e-8cf3-86cfa31928ab','寄葉參兵部','韓琦','宋','宋诗','song-poetry','','[]','向宦心難止，遺榮世所稀。',96,'全唐诗/poet.song.18000.json','["向宦心難止，遺榮世所稀。", "誰知懷綬去，便作掛冠歸。", "行錦方爲寵，裝金已盡揮。", "官閑同吏隱，身逸晦塵幾。", "山鶴來無怨，江鷗浄不飛。", "雨晴峯障活，秋老鱠絲肥。", "庭玉名方遠，陔蘭志暫違。", "倚門休結戀，史筆借光輝。"]'),
('c1d2add9-18f0-4b68-a6ad-4f82c9aabda2','馬尋比部兩浙提點刑獄','韓琦','宋','宋诗','song-poetry','','[]','東南詳讞得材臣，親對天墀奉至仁。',64,'全唐诗/poet.song.18000.json','["東南詳讞得材臣，親對天墀奉至仁。", "舜服暫平惟恤典，漢庭曾譽不寃民。", "圜扉鞠草提封靜，高蓋容門令德新。", "最好齋航初按部，柳汀花瀨正逢春。"]'),
('683bb61d-49af-4d4c-b541-761123d738c6','陳商學士知常州','韓琦','宋','宋诗','song-poetry','','[]','疊鼓聲喧下鷁舟，書山蕭索別英游。',64,'全唐诗/poet.song.18000.json','["疊鼓聲喧下鷁舟，書山蕭索別英游。", "青蔾照字觀奇廢，朱雀分符錫命優。", "霞夾烏檣晴旆卷，星摇漁浦夜燈幽。", "蓴風正孰帆無恙，一色江天望處秋。"]'),
('a0648ff4-7021-4d79-af37-55641539d808','得太清小檜植館中','韓琦','宋','宋诗','song-poetry','','[]','仙檜移來近紫壇，亭亭將見起亭端。',64,'全唐诗/poet.song.18000.json','["仙檜移來近紫壇，亭亭將見起亭端。", "纖枝未覺來風韻，勁節先知度歲寒。", "得地最宜儒館種，結根須作棟材看。", "願將軒竹陪蒼翠，带雪聞樽助雅歡。"]'),
('8996ed84-0244-4d1f-9d84-c2984c9671a4','宋任著作宰江寧溧水','韓琦','宋','宋诗','song-poetry','','[]','訊察無冤善最聞，剸繁南邑遇盤根。',64,'全唐诗/poet.song.18000.json','["訊察無冤善最聞，剸繁南邑遇盤根。", "還將決獄平反意，去作臨民撫字恩。", "淮上月高生麗思，浦前春老醉離魂。", "知君陰德終陽報，容駟何妨大里門。"]'),
('6c9f034c-99b6-4e95-bd76-78617d743ecb','道卿學士領二浙漕賦得酒','韓琦','宋','宋诗','song-poetry','','[]','傾釀留佳客，秋亭弭使旄。',72,'全唐诗/poet.song.18000.json','["傾釀留佳客，秋亭弭使旄。", "奉觴歸養切，行算別魂勞。", "上若名鄉近，長安美價高。", "清懷思酌水，惠政憶投醪。", "論德堪成頌，評詩更助豪。", "行聞趨節覲，同我怨持螯。"]'),
('003a6cf4-4c54-4f63-9d38-65291d11dbea','再賦柳枝詞二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','曲江風暖曉陰斜，翠色相宜拂鈿車。',32,'全唐诗/poet.song.18000.json','["曲江風暖曉陰斜，翠色相宜拂鈿車。", "自有春眠慵未起，日高人困又飛花。"]'),
('f32111d9-c1bd-4cc0-a2c8-8823c49fff7b','再賦柳枝詞二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','葉葉新長約黛蛾，絲絲輕軟任風梭。',32,'全唐诗/poet.song.18000.json','["葉葉新長約黛蛾，絲絲輕軟任風梭。", "啼鶯便學歌喉囀，知是春來舞意多。"]'),
('b6213dff-edb0-45a0-8199-29ed8c8848b2','離都','韓琦','宋','宋诗','song-poetry','','[]','握節背都門，春天景半溫。',48,'全唐诗/poet.song.18000.json','["握節背都門，春天景半溫。", "柔鞭難駐馬，芳草易銷魂。", "遠目和煙重，離懷助酒昏。", "好花無奈野，時復映遥村。"]'),
('6e347c53-d6bb-46dd-a292-ab5a0f8d45f1','上巳','韓琦','宋','宋诗','song-poetry','','[]','遠道今逢祓禊辰，雨餘風物一番新。',64,'全唐诗/poet.song.18000.json','["遠道今逢祓禊辰，雨餘風物一番新。", "等閑臨水還思舊，取次看花使當春。", "絮雪暖迷西苑路，車雷晴起曲江塵。", "臺英正約尋芳會，誰是山陰作序人。"]'),
('9d8ba389-a4e1-4d3e-b2a1-3b2db3d63026','寓目','韓琦','宋','宋诗','song-poetry','','[]','擁傳脩途倦，逢春旅思長。',48,'全唐诗/poet.song.18000.json','["擁傳脩途倦，逢春旅思長。", "遠煙含樹色，細雨起塵香。", "隴麥成行綠，林鶯並對黄。", "揚鞭聊自慰，舉目見韶光。"]'),
('010a6929-a3be-44ba-8390-8997b469c085','早行','韓琦','宋','宋诗','song-poetry','','[]','脂轄行傷早，揚旌興莫窮。',48,'全唐诗/poet.song.18000.json','["脂轄行傷早，揚旌興莫窮。", "水遥天色共，雲細月波通。", "巧舌爭啼曉，香牙盡入風。", "縱吟殊未已，初旭放晴紅。"]'),
('5df5659c-07ce-4258-96e7-abee4d9897e7','寒食','韓琦','宋','宋诗','song-poetry','','[]','漢宮新蠟未開煙，寒食東郊躍駿天。',64,'全唐诗/poet.song.18000.json','["漢宮新蠟未開煙，寒食東郊躍駿天。", "人面映花誰感事，客心燃火獨成篇。", "塞鴻歸渚遥書字，營柳因風强破眠。", "賴有目前隨分景，數村如樹起鞦韆。"]'),
('6f40808b-326e-4fa5-ad0d-6debf1a00f91','登永濟驛樓','韓琦','宋','宋诗','song-poetry','','[]','遠煙芳草媚斜陽，蕭索郵亭一望長。',32,'全唐诗/poet.song.18000.json','["遠煙芳草媚斜陽，蕭索郵亭一望長。", "盡日倚欄還獨下，綠楊風軟杏花香。"]'),
('03231d91-e318-4150-8bc1-858f7a17688c','途中暑熱憶諸同舍','韓琦','宋','宋诗','song-poetry','','[]','振野驚風拂面塵，赫曦流爍犯征輪。',64,'全唐诗/poet.song.18000.json','["振野驚風拂面塵，赫曦流爍犯征輪。", "酒非逃暑虛成會，花未忘憂謾映人。", "綠水已傷春別舊，碧雲長起暮愁新。", "朝來記得瀛洲夢，目斷英游極愴神。"]'),
('1b7e938f-1fb9-421f-9604-cbf922104dab','聞角','韓琦','宋','宋诗','song-poetry','','[]','古堞連雲暝靄收，嗚嗚清調起邊樓。',63,'全唐诗/poet.song.18000.json','["古堞連雲暝靄收，嗚嗚清調起邊樓。", "雍琴垂淚虛情恨，羌笛殘梅未勝愁。", "數曲伴風吹戍壘，幾侵夢入賓郵。", "聽來便覺春心破，素髮生多不待秋。"]'),
('3441bab3-d5b8-4fce-a545-be8db6ae33ba','雄州遇雪','韓琦','宋','宋诗','song-poetry','','[]','雲壓孤城勢漸低，昏昏臺榭雪霏霏。',64,'全唐诗/poet.song.18000.json','["雲壓孤城勢漸低，昏昏臺榭雪霏霏。", "人遊兔苑何妨醉，使適龍沙未得歸。", "夜館月明交素影，曉塗霜重借嚴威。", "風前似慰征軺意，先學楊花二月飛。"]'),
('493422f5-f373-4347-94c5-3becc9243c39','紫濛遇風','韓琦','宋','宋诗','song-poetry','','[]','草白崗長暮驛賒，朔風終日起平沙。',64,'全唐诗/poet.song.18000.json','["草白崗長暮驛賒，朔風終日起平沙。", "寒鞭易促鄣泥躍，冷袖難勝便面遮。", "迥嶺卷回雲族破，遠天吹入雁行斜。", "土囊微乞緘餘怒，留送歸程任擺花。"]'),
('6e3d7890-64c8-4c0d-8c23-8ebded04ea39','使回戲成','韓琦','宋','宋诗','song-poetry','','[]','專對慙非出使才，拭圭申好歛旌回。',64,'全唐诗/poet.song.18000.json','["專對慙非出使才，拭圭申好歛旌回。", "禮煩偏苦元正拜，戶大猶輕永壽杯。", "欹枕頓無歸夢擾，據鞍潛覺旅懷開。", "明朝便是侵星去，不怕東風拂面來。"]'),
('83dd9aa6-cee2-4415-97fe-7e222562af69','過虎北口','韓琦','宋','宋诗','song-poetry','','[]','東西層巘鬰嵯峩，關口纔容數騎過。',32,'全唐诗/poet.song.18000.json','["東西層巘鬰嵯峩，關口纔容數騎過。", "天意本將南北限，即今天意又如何。"]'),
('77655bc8-d5cd-4561-a5b5-ad0fe8c0fe63','戲題仙掌','韓琦','宋','宋诗','song-poetry','','[]','三峰晴曉碧相挨，仙掌分明出霧開。',32,'全唐诗/poet.song.18000.json','["三峰晴曉碧相挨，仙掌分明出霧開。", "莫向巍峩衒高手，也曾先得桂枝來。"]'),
('4d2ddd22-33c4-42dd-95e4-6a19c49f3078','題利州昭化驛','韓琦','宋','宋诗','song-poetry','','[]','嘉陵源出本朝宗，地險無因直赴東。',32,'全唐诗/poet.song.18000.json','["嘉陵源出本朝宗，地險無因直赴東。", "從此逆流歸順去，恬波遥與峽江通。"]'),
('67033754-91e4-4fdf-b15c-a37f96b8af28','過三泉龍門二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','洞戶呀然透碧溪，竹軒茅榭映高低。',32,'全唐诗/poet.song.18000.json','["洞戶呀然透碧溪，竹軒茅榭映高低。", "行人不待桃花發，一到仙扃已自迷。"]'),
('f978fcea-1ece-458d-aea5-a702534a93ae','過三泉龍門二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','欣過龍門柅使車，頓驚凡目識仙都。',32,'全唐诗/poet.song.18000.json','["欣過龍門柅使車，頓驚凡目識仙都。", "海中知有三山在，未信能加此景無。"]'),
('c26cf9ef-dcad-4380-957d-9a1fa246da59','漫天嶺','韓琦','宋','宋诗','song-poetry','','[]','欲使行人直過難，倚江凌漢任盤盤。',32,'全唐诗/poet.song.18000.json','["欲使行人直過難，倚江凌漢任盤盤。", "紆回到頂終須下，如此天高甚處漫。"]'),
('d5b12194-ebaf-431c-b61a-519c04007b60','題嘉州嘉望亭','韓琦','宋','宋诗','song-poetry','','[]','欲知藩境得嘉名，試策筇枝上此亭。',64,'全唐诗/poet.song.18000.json','["欲知藩境得嘉名，試策筇枝上此亭。", "江色照城平似練，嵐光堆檻活如屏。", "好遨民阜充衢樂，出品花奇襲坐馨。", "使馹暫來閑寓目，幾多高意在鴻冥。"]'),
('44fd12ee-5cba-43c2-a2fb-1a4e37cc04e2','再賦一闋','韓琦','宋','宋诗','song-poetry','','[]','檻外風光觸處奇，嶺頭金像對巍巍。',32,'全唐诗/poet.song.18000.json','["檻外風光觸處奇，嶺頭金像對巍巍。", "主人偏戀南犍樂，只恐瓜時示肯歸。"]'),
('2dd2fdff-20c6-47da-8a57-cbfdda37c91d','韓瀆學士領益漕','韓琦','宋','宋诗','song-poetry','','[]','去年巴蜀失秋成，西顧饑流惻睿情。',64,'全唐诗/poet.song.18000.json','["去年巴蜀失秋成，西顧饑流惻睿情。", "嘗忝乘軺宣渥命，更煩持節拯遐氓。", "夜亭微雨多侵夢，春峽繁花少記名。", "到日莫辭行部數，屬城凋瘵望君生。"]'),
('ce70c1d8-7f4e-4e34-a13b-3c2b6262c9ec','皇子誕慶五言十二韻','韓琦','宋','宋诗','song-poetry','','[]','聖統垂千祀，天仁覆萬方。',144,'全唐诗/poet.song.18000.json','["聖統垂千祀，天仁覆萬方。", "思賢詠場藿，興儉緝帷囊。", "寬法均疏網，憂民甚納隍。", "畫衣期不犯，行葦見無傷。", "列廟靈潛佑，高穹意默彰。", "故教生嗣晚，欲示卜年長。", "帝夢前推吉，郊禖此報祥。", "協辰初告望，紀節正迎商。", "和氣城銅律，休符集畫堂。", "清飚來美應，瑞旭薦榮光。", "九縣歡聲沸，三都惠澤滂。", "非才塵近掖，援筆頌無疆。"]'),
('40246273-9e2d-470e-bcde-5c2578c71679','慶曆甲申郊禮告成五言十韻','韓琦','宋','宋诗','song-poetry','','[]','聖饗申精意，靈心察至虔。',120,'全唐诗/poet.song.18000.json','["聖饗申精意，靈心察至虔。", "因知齋次雪，爲顯祭時天。", "清廟陳豐潔，中壇致吉蠲。", "樂和來瑞物，景霽見非煙。", "卜日灰飛管，通祠火舉權。", "短茵新禮重，虛幄睟容專。", "盛美推穹昊，釐祥被幅員。", "慶成朝萬玉，霈澤謹三錢。", "有幸瞻熙事，無才列奏篇。", "爲民祈福應，親記德音宣。"]'),
('28f8b7f2-ac90-46eb-bd83-382554dc09ec','雲','韓琦','宋','宋诗','song-poetry','','[]','郁郁疑非霧，融融散薄陰。',48,'全唐诗/poet.song.18000.json','["郁郁疑非霧，融融散薄陰。", "油然天下澤，淡若嶺頭心。", "適意自舒卷，有容誰淺深。", "朝來殊未起，幽谷閟龍吟。"]'),
('8cf85120-b273-47b4-a7ad-a9c2109671d3','霜','韓琦','宋','宋诗','song-poetry','','[]','霜威昨夜肅天區，平曉蒿蘭一槩枯。',64,'全唐诗/poet.song.18000.json','["霜威昨夜肅天區，平曉蒿蘭一槩枯。", "一寤春仁入根本，只憑秋慘及皮膚。", "寒鋒刺甲過矛戟，皓色禁人著鬢鬚。", "料得西風如未緊，且來枝上作明珠。"]'),
('f3390a90-05ed-424a-9347-46e7364f3a71','初雨','韓琦','宋','宋诗','song-poetry','','[]','乍覺塵香動，風前細若繅。',48,'全唐诗/poet.song.18000.json','["乍覺塵香動，風前細若繅。", "無聲猶似雪，得潤已如膏。", "美利存南畝，餘滋付小桃。", "誰知青皡德，意不爲嬉遨。"]'),
('cdf1facb-bbbc-444a-a32e-8f26de557761','新柳二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','弄黄含綠葉開眉，最有春來次第知。',32,'全唐诗/poet.song.18000.json','["弄黄含綠葉開眉，最有春來次第知。", "生計任隨栽者意，却嗤松柏不禁移。"]'),
('2ed6d646-1092-4f85-8375-bd7d744ad717','新柳二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','驛路行人東復西，等閑攀折損芳枝。',32,'全唐诗/poet.song.18000.json','["驛路行人東復西，等閑攀折損芳枝。", "有生自是無根物，忍向樂風贈別離。"]'),
('6024abb5-8790-4d33-9b86-962b815568a3','惜花','韓琦','宋','宋诗','song-poetry','','[]','看花關有分，分薄亦蹉跎。',48,'全唐诗/poet.song.18000.json','["看花關有分，分薄亦蹉跎。", "蜂蝶爭無限，笙歌得幾何。", "利名長自役，風雨不須多。", "趁取紅香在，高吟卷醉螺。"]'),
('612dc71f-54c0-4036-9126-b38df1878ad6','柳絮二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','慣惱東風不定家，高樓長陌奈無涯。',32,'全唐诗/poet.song.18000.json','["慣惱東風不定家，高樓長陌奈無涯。", "一春情緒空撩亂，不是天生穩重花。"]'),
('6add1fff-2943-4c49-a33f-e98c3d210387','柳絮二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','絮雪紛紛不自持，亂愁縈困滿春暉。',32,'全唐诗/poet.song.18000.json','["絮雪紛紛不自持，亂愁縈困滿春暉。", "有時穿入花枝過，無限蜂兒作隊飛。"]'),
('58ce814b-a17d-46aa-b4fb-5ad2120c510f','錦被堆二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','碎剪紅綃間綠叢，風流疑在列仙宮。',32,'全唐诗/poet.song.18000.json','["碎剪紅綃間綠叢，風流疑在列仙宮。", "朝真更欲薰香去，爭擲霓衣上寶籠。"]'),
('4bac742e-b18e-4722-b93a-7a333b4c43e7','錦被堆二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','不管鶯聲向曉催，錦衾春晚尚成堆。',32,'全唐诗/poet.song.18000.json','["不管鶯聲向曉催，錦衾春晚尚成堆。", "香紅若解知人意，睡取東君不放回。"]'),
('fa1d931a-1926-444a-b598-ee294d6b70aa','牡丹初芽爲鴉啄之感而成詠','韓琦','宋','宋诗','song-poetry','','[]','牡丹經雨發香芽，滿地新紅因餓鴉。',32,'全唐诗/poet.song.18000.json','["牡丹經雨發香芽，滿地新紅因餓鴉。", "利嘴可能傷國豔，只教春色入凡花。"]'),
('b51c73fb-3196-40c8-a0c3-7a4721c4743e','遊蜂','韓琦','宋','宋诗','song-poetry','','[]','遊蜂紛撲競花繁，未到香鬚只自喧。',32,'全唐诗/poet.song.18000.json','["遊蜂紛撲競花繁，未到香鬚只自喧。", "盡日却輸蝴蝶計，鬧紅心裏默無言。"]'),
('66ad0fbf-a4b4-4ebd-8d70-c751e9765744','新燕','韓琦','宋','宋诗','song-poetry','','[]','出入高堂性似馴，泥巢深穩足容身。',32,'全唐诗/poet.song.18000.json','["出入高堂性似馴，泥巢深穩足容身。", "雕梁並宿嫌頻看，巧語多應是罵人。"]'),
('31b02b2b-e7e4-4e67-a572-0b5357e02aae','過隋城','韓琦','宋','宋诗','song-poetry','','[]','信馬隋城下，行春訪舊傳。',48,'全唐诗/poet.song.18000.json','["信馬隋城下，行春訪舊傳。", "樓臺在何處，瓦礫半耕田。", "遠籟悲笳咽，餘花墜靨圓。", "只留荒侈迹，千古監青編。"]'),
('7722ed3c-d380-4be7-95c6-13ff94b8f85a','苦雨方霽蛙聲不已','韓琦','宋','宋诗','song-poetry','','[]','暑雨朝來已厭多，蛙鳴猶更幸滂沱。',32,'全唐诗/poet.song.18000.json','["暑雨朝來已厭多，蛙鳴猶更幸滂沱。", "雖然快爾狂跳志，爭奈良田有害何。"]'),
('8a48a6d5-461d-4273-a967-6735319e5011','題翠鐘亭','韓琦','宋','宋诗','song-poetry','','[]','鐘峯隱隱隔江湍，翠色偏宜雨後看。',32,'全唐诗/poet.song.18000.json','["鐘峯隱隱隔江湍，翠色偏宜雨後看。", "大抵興王須恃德，饒君終古作龍盤。"]'),
('199ed629-a82e-4490-8ce0-0a76ecce0cd9','蜀葵','韓琦','宋','宋诗','song-poetry','','[]','炎天花盡歇，錦繡獨成林。',48,'全唐诗/poet.song.18000.json','["炎天花盡歇，錦繡獨成林。", "不入當時眼，其如向日心。", "寶釵知自棄，幽蝶或來尋。", "誰許清風下，芳醪對一斟。"]'),
('523c6a21-a5de-4e78-a38b-446a533013af','中秋月二首  其一','韓琦','宋','宋诗','song-poetry','','[]','自古中秋月，風騷昨意難。',48,'全唐诗/poet.song.18000.json','["自古中秋月，風騷昨意難。", "幾人亭醉筆，終夕凭危欄。", "海際掀鯨目，雲端擢露盤。", "一年相別恨，併與此時看。"]'),
('f6f0cb86-6a5b-4c96-adb9-2477abfc4745','中秋月二首  其二','韓琦','宋','宋诗','song-poetry','','[]','月滿中秋夜，人人惜最明。',48,'全唐诗/poet.song.18000.json','["月滿中秋夜，人人惜最明。", "悲歡徒自感，圓缺本無情。", "天外有相憶，世間多江平。", "嫦娥難借問，寂寞趁西傾。"]'),
('baddf7ed-c2ec-4d15-906a-64514c508681','張逸人歸杭','韓琦','宋','宋诗','song-poetry','','[]','不因疔適出中林，塵外高蹤豈易尋。',64,'全唐诗/poet.song.18000.json','["不因疔適出中林，塵外高蹤豈易尋。", "鴻在碧霄誰可慕，雲歸蒼島本無心。", "堤奩一鑑平湖滿，寺枕千屏疊嶂深。", "知己重留多下榻，故棲猿鶴莫驚吟。"]'),
('135d7f81-3f23-470f-9c23-39edb7217cf9','答丹陽李公素學士','韓琦','宋','宋诗','song-poetry','','[]','與君爲郡不相遥，只隔瓜洲一信潮。',64,'全唐诗/poet.song.18000.json','["與君爲郡不相遥，只隔瓜洲一信潮。", "誨字屢傳來客素，治聲常逐過江橈。", "詞垣暫爾淹鴻筆，宴席何妨引巨蕉。", "詩句滿筒煩借譽，爰居空自愧虞韶。"]'),
('ad1f24cb-3b99-4498-b9b5-85f2ec42e834','謝丹陽李公素學士惠鶴','韓琦','宋','宋诗','song-poetry','','[]','高籠携得意何勤，玉樹慙無可待君。',64,'全唐诗/poet.song.18000.json','["高籠携得意何勤，玉樹慙無可待君。", "只愛羽毛欺白雪，不知魂夢託青雲。", "孤標直好和松畫，清唳偏宜带月聞。", "自有三山歸去路，莫辭時暫處雞羣。"]'),
('48aea1fe-175b-4422-a2a8-13a1ac2b47e4','和潤倅王太博林畔松','韓琦','宋','宋诗','song-poetry','','[]','鬰鬰山頭翠色攢，就中高格出林端。',64,'全唐诗/poet.song.18000.json','["鬰鬰山頭翠色攢，就中高格出林端。", "霜凌勁節難摧抑，石纏危根任屈盤。", "古鬣自隨仙日老，孤風不入俗人看。", "時來匠者須回顧，且稟幽姿待歲寒。"]'),
('b46823d7-26b7-494b-9027-b8e466ded328','菊','韓琦','宋','宋诗','song-poetry','','[]','萬卉趁枯死，香金鬭晚葩。',48,'全唐诗/poet.song.18000.json','["萬卉趁枯死，香金鬭晚葩。", "甘名應得露，野色豈如家。", "俗態惜遲暮，芳情誰怨嗟。", "重陽樽酒伴，不見牡丹花。"]'),
('e9382e8f-b9ca-4ae0-be1d-9c9cb183fca6','重九會光化二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','寺枕隋家廢苑前，登高還此會僚賢。',32,'全唐诗/poet.song.18000.json','["寺枕隋家廢苑前，登高還此會僚賢。", "凭軒莫賦悲秋事，剩撚黄花送酒船。"]'),
('8e0ca005-b222-46c1-8e71-861f44bc3c52','重九會光化二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','誰言秋色不如春，及到重陽景自新。',32,'全唐诗/poet.song.18000.json','["誰言秋色不如春，及到重陽景自新。", "隨分笙歌行樂處，菊花萸子更宜人。"]'),
('626736dd-6111-4e6b-9f2e-0a22e7450a94','黄通尉鄖鄉','韓琦','宋','宋诗','song-poetry','','[]','古邑萬山裏，區區一尉行。',48,'全唐诗/poet.song.18000.json','["古邑萬山裏，區區一尉行。", "高堂方待養，寸祿豈宜輕。", "身屈何傷道，才多少晦名。", "贈言如可取，榮路坦然平。"]'),
('8da01608-307f-4502-bd53-877ab3488c93','答湖恢推官','韓琦','宋','宋诗','song-poetry','','[]','當年都寺接賢初，屈指光陰一紀餘。',64,'全唐诗/poet.song.18000.json','["當年都寺接賢初，屈指光陰一紀餘。", "自說三茆深處穩，不逢又鯉寄來書。", "隔江聞授諸生業，命駕因煩長者車。", "得見新詩與高論，積年勞吝已全祛。"]'),
('8c73a523-beda-437f-a14c-a8136c3e0be1','春晴','韓琦','宋','宋诗','song-poetry','','[]','霽色破春昏，高樓日未曛。',48,'全唐诗/poet.song.18000.json','["霽色破春昏，高樓日未曛。", "林稍零舊雨，山頂入殘雲。", "醉粉勻花頰，風羅縐水紋。", "踏青入誤約，芳思幾紛紛。"]'),
('55de7cf8-ec1a-40bd-9951-ebcaf57980c9','春霖','韓琦','宋','宋诗','song-poetry','','[]','咫尺東郊路，春霖絕未通。',48,'全唐诗/poet.song.18000.json','["咫尺東郊路，春霖絕未通。", "銷閑生弈思，醒睡費茶功。", "樓迥昏昏霧，窗寒霎霎風。", "待晴桑陌上，五馬恣𤧚瓏。"]'),
('a80f2a89-fbba-4dba-ad2c-fa105b3ac05e','馬上成春雪二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','二月風光盡屬春，六霙何苦妬芳辰。',32,'全唐诗/poet.song.18000.json','["二月風光盡屬春，六霙何苦妬芳辰。", "東君等是回生意，須與鶯花作主人。"]'),
('12528cec-7f8f-45d7-ba82-ba55f66cb9b6','馬上成春雪二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','曉來飛雪抑香芽，料峭輕寒特地加。',32,'全唐诗/poet.song.18000.json','["曉來飛雪抑香芽，料峭輕寒特地加。", "青帝似矜春意早，更粧新萼與梅花。"]'),
('7723d80e-7212-46e9-9e85-d9c8d5af0ea7','過梁山泊','韓琦','宋','宋诗','song-poetry','','[]','巨澤渺無際，齋船度日撐。',48,'全唐诗/poet.song.18000.json','["巨澤渺無際，齋船度日撐。", "漁人駭鐃吹，水鳥背旗旌。", "蒲密遮如港，山遥勢似彭。", "不知蓮芰裏，白晝苦蚊蝱。"]'),
('f86ce2a3-db2f-44ea-b089-91a3498fc0ce','移帥真定次韻答致政杜公','韓琦','宋','宋诗','song-poetry','','[]','常山畫野直天街，寄重如何付不才。',64,'全唐诗/poet.song.18000.json','["常山畫野直天街，寄重如何付不才。", "躍馬敢辭奔命去，扞羌曾是奮身來。", "軍中紀律勞人葺，林下罇罍得意開。", "引領恩軒無路到，幾臨風月獨徘徊。"]'),
('478fc241-d013-4c84-bba5-f787d3343cd3','常山出郊馬上口占','韓琦','宋','宋诗','song-poetry','','[]','旌旗乘曉出郊原，五馬臨風一慨然。',64,'全唐诗/poet.song.18000.json','["旌旗乘曉出郊原，五馬臨風一慨然。", "山勢似屏西限晉，地形如掌北擒燕。", "麥含豐澤催齊秀，蠶飽柔桑起大眠。", "守帥勉希廉與藺，九重高枕不憂邊。"]'),
('0120b4a7-d8df-4223-b410-b2d98ffde5f4','登西大悲閣','韓琦','宋','宋诗','song-poetry','','[]','藹藹西藍閣，煩襟一望開。',48,'全唐诗/poet.song.18000.json','["藹藹西藍閣，煩襟一望開。", "山川歸盛德，姦傑委塵埃。", "城迥雲連堞，烽閑草蔽臺。", "誰知太守意，不爲納凉來。"]'),
('24249ced-f816-4a2d-9f8a-b125ea442675','別潭','韓琦','宋','宋诗','song-poetry','','[]','一潭嘉景四時新，不得經年作主人。',64,'全唐诗/poet.song.18000.json','["一潭嘉景四時新，不得經年作主人。", "蓮芰風前忘九夏，綺羅香裏醉三春。", "勤勞疆場誠無避，粧點蓬瀛惜未真。", "多少勝遊休結戀，報君須自立涓塵。"]'),
('fd66c1a3-4cf9-4d70-88c6-a0b62c11e00c','新館','韓琦','宋','宋诗','song-poetry','','[]','宴宇新成苦未嘉，忽膺朝委易軍牙。',64,'全唐诗/poet.song.18000.json','["宴宇新成苦未嘉，忽膺朝委易軍牙。", "張侯暫喜留歡客，開檻憑誰種好花。", "北沼不難平釣岸，西峰猶欠入窗紗。", "後賢政敏多餘暇，高會何妨月影斜。"]'),
('e7ed3383-2e94-4750-9291-73fb648bf10b','次韻和兗州王待制過汶上見寄','韓琦','宋','宋诗','song-poetry','','[]','淺局雖難繼大才，谿堂佳致亦添來。',64,'全唐诗/poet.song.18000.json','["淺局雖難繼大才，谿堂佳致亦添來。", "奇花並蔕宜新種，芳樹連柯得舊栽。", "良執假途形詠歎，鄰封爲治惜淹徊。", "想君醉問歌人處，不向風前酹一杯。"]'),
('686e1b44-d767-42f2-b974-98300305c275','中秋不見月','韓琦','宋','宋诗','song-poetry','','[]','中秋宜月不教晴，人倚危樓意未平。',32,'全唐诗/poet.song.18000.json','["中秋宜月不教晴，人倚危樓意未平。", "任是他時圓更好，爭如今夜畧分明。"]'),
('d4646ea2-2e7b-4f6c-8db1-55d60cc75d8c','北嶽','韓琦','宋','宋诗','song-poetry','','[]','四海尊方嶽，常推朔鎮雄。',192,'全唐诗/poet.song.18000.json','["四海尊方嶽，常推朔鎮雄。", "陽爲中夏勝，陰與北胡窮。", "孕秀賢豪出，宣靈造化通。", "斗乘天位正，乾發帝基隆。", "盛畜嚴凝氣，橫障廣莫風。", "舉頭瞻峻極，危坐壓崆峒。", "殖物資坤德，栖真固坎宮。", "星躔函畢昴，祀典軼王公。", "俗仰良材富，年隨喜澤豐。", "左肱揮渤澥，右股跨獯戎。", "地險祠庭革，時平戍壘空。", "嵐光朝撲黛，寶色夜舒虹。", "有藥皆奇種，無花不異叢。", "層巔健雕鶚，怪穴老羆熊。", "肆覲儀雖闊，斯民望未充。", "何時清大漠，封牒紀宸功。"]'),
('0149a4ef-ff4d-428c-a94f-aa2b2dddb3cc','喜雪','韓琦','宋','宋诗','song-poetry','','[]','朔雪飛殘臘，融和變凜嚴。',168,'全唐诗/poet.song.18000.json','["朔雪飛殘臘，融和變凜嚴。", "徐來花出在，驟急霰聲兼。", "數住天應惜，爭繁酒易添。", "積深函久潤，濟大畧微嫌。", "雅意明書幌，多情入宴簾。", "舞腰難學轉，峯頂尚饒尖。", "露蕊仙盤挹，風毛鬣囿燖。", "宮牆胡粉畫，梅梗蜀酥黏。", "影澹三春絮，光寒八月蟾。", "垣塗誰復辨，巨壑有何厭。", "狂助詩毫逸，清驅厲氣潛。", "歡謠騰紫塞，喜色上彤幨。", "凝霤收冰乳，堆庭鏤虎鹽。", "吾民無足慮，豐歲可前占。"]'),
('5c95dd35-abd0-4859-b251-ffbdc234482d','上元罷燈','韓琦','宋','宋诗','song-poetry','','[]','燈夕何蕭索，朝家恤殣災。',48,'全唐诗/poet.song.18000.json','["燈夕何蕭索，朝家恤殣災。", "民心無奈鬰，春意有誰開。", "明月舒雲懶，遊人怯漏回。", "堪嗤愚太守，獨欲上熙臺。"]'),
('8ae041d1-dec6-48f8-9c34-5269a8f6989a','郡西齋有夜合萱草對開因成二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','合歡香影拂西齋，萱草前臨小檻開。',32,'全唐诗/poet.song.18000.json','["合歡香影拂西齋，萱草前臨小檻開。", "待爾忘憂與蠲忿，爭如無事起靈臺。"]'),
('6c6a72d1-81d8-46ce-ad9a-58e0cdbfe7d1','郡西齋有夜合萱草對開因成二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','合歡萱草兩含芳，一見令人樂興長。',32,'全唐诗/poet.song.18000.json','["合歡萱草兩含芳，一見令人樂興長。", "唯是憂邊與憂國，對花終日不能忘。"]'),
('e2c84003-3359-4fbb-9523-892bc54e1a03','謝真定李密學惠牡丹','韓琦','宋','宋诗','song-poetry','','[]','窮邊無處覩春榮，咫尺常山似洛城。',64,'全唐诗/poet.song.18000.json','["窮邊無處覩春榮，咫尺常山似洛城。", "會得主人將雅意，欲教鄰境伏香名。", "全開正弄朝霞色，半謝猶含暮雨情。", "只上賓筵共一醉，也勝渾不見芳英。"]'),
('a5c3f973-e6b9-49d0-9dd0-17400956ba7c','答陜府春卿資政','韓琦','宋','宋诗','song-poetry','','[]','蓬山曾許挹浮邱，踰紀光陰一瞬休。',64,'全唐诗/poet.song.18000.json','["蓬山曾許挹浮邱，踰紀光陰一瞬休。", "朔塞風霜人易老，申湖歌舞景長留。", "我臨賓席頻先醉，君對仙棊幾自謳。", "千里詩來還感舊，不堪斜日凭邊樓。"]'),
('2e3e3f54-7fa5-447d-8984-172b065e99f7','再答','韓琦','宋','宋诗','song-poetry','','[]','一從西北困邊塵，瀛館仙游更莫親。',64,'全唐诗/poet.song.18000.json','["一從西北困邊塵，瀛館仙游更莫親。", "只慣彎弧揮太白，幾曾橫槊賦青春。", "晴郊按獵長侵暮，夜橐飛郵不待晨。", "多羨某棠閴無訟，時將佳句惱粗人。"]'),
('278276e9-27ef-4080-8dc1-3f5b9131f61a','題覽勝亭','韓琦','宋','宋诗','song-poetry','','[]','極目知何勝，東西矗萬岑。',48,'全唐诗/poet.song.18000.json','["極目知何勝，東西矗萬岑。", "天雖限夷夏，人自失喉襟。", "遠木已秋色，亂雲猶夕陰。", "清風誰會我，太息撫霜鐔。"]'),
('52494259-aa93-48f3-9edd-7dc4c90fcd0f','題養真亭','韓琦','宋','宋诗','song-poetry','','[]','新葺公居北，虛亭號養真。',48,'全唐诗/poet.song.18000.json','["新葺公居北，虛亭號養真。", "所期清策慮，不是愛精神。", "滿目林壑趣，一心忠義身。", "吏民還解否，吾豈苟安人。"]'),
('c16ff7ee-89c7-433b-acba-f1c94e7817c4','北塘避暑','韓琦','宋','宋诗','song-poetry','','[]','盡室林塘滌暑煩，曠然如不在塵寰。',64,'全唐诗/poet.song.18000.json','["盡室林塘滌暑煩，曠然如不在塵寰。", "誰人敢議清風價，無樂能過白日閒。", "水鳥得魚長自足，嶺雲含雨只空還。", "酒闌何物醒魂夢，萬柄蓮香一枕山。"]'),
('fa77d16d-5960-41ef-ae13-20847b44baaa','次韻和致政王子融侍郎歸休述懷二首  其一','韓琦','宋','宋诗','song-poetry','','[]','周旋通顯竭忠勤，勇退翩然得謝身。',64,'全唐诗/poet.song.18000.json','["周旋通顯竭忠勤，勇退翩然得謝身。", "鳴玉乍辭天上貴，揮金長示里中仁。", "滿牀黄卷閒爲伴，一枕清眠任過晨。", "六十九歸今昔少，萬年青史紀高人。"]'),
('679f826b-5885-4865-bd0b-75475e48444c','次韻和致政王子融侍郎歸休述懷二首  其二','韓琦','宋','宋诗','song-poetry','','[]','禮稱七十還君事，豈必如期許退身。',64,'全唐诗/poet.song.18000.json','["禮稱七十還君事，豈必如期許退身。", "臣子引年雖審分，朝廷圖舊合推仁。", "曉登文石方延刻，暮掛危冠不待晨。", "竊惜聖神求治意，未宜輕去老成人。"]'),
('8bc49330-0b57-411a-a6bd-a8d9e2066814','次韻和真定李侍郎新創流杯','韓琦','宋','宋诗','song-poetry','','[]','不有浮觴樂，誰知愛客深。',72,'全唐诗/poet.song.18000.json','["不有浮觴樂，誰知愛客深。", "投醪當席意，修禊昔賢心。", "自至疑仙術，虛來協道襟。", "去留雖任物，斟酌孰窺陰。", "阻挹齋中酒，空勞塞上吟。", "清潭時一望，搔首莫能簪。"]'),
('e62c480f-c50e-4b19-8031-919cb6a9394f','依韻和機宜陳薦請游城北池館二首  其一','韓琦','宋','宋诗','song-poetry','','[]','只恨無才濟阻饑，北塘因爾失春期。',64,'全唐诗/poet.song.18000.json','["只恨無才濟阻饑，北塘因爾失春期。", "民心方喜稻禾熟，秋色不關臺榭隳。", "一派芰連輸水鳥，幾船烟雨卧風旗。", "佳辰賴有詩人覺，較得紅芳又變衰。"]'),
('926d3a52-632e-44da-b545-331fa8e275cf','依韻和機宜陳薦請游城北池館二首  其二','韓琦','宋','宋诗','song-poetry','','[]','去歲饑流待撫循，日憂疲瘵苦傷神。',64,'全唐诗/poet.song.18000.json','["去歲饑流待撫循，日憂疲瘵苦傷神。", "細民溝壑方援手，別館鸎花任送春。", "舉目山河生壯氣，經時臺榭極芳塵。", "秋來幸有豐年兆，還作偷安樂事人。"]'),
('918b0c77-24ba-403c-9752-3797d284bbe1','秋夕二首  其一','韓琦','宋','宋诗','song-poetry','','[]','大暑喪餘酷，凉秋袪眾瘥。',48,'全唐诗/poet.song.18000.json','["大暑喪餘酷，凉秋袪眾瘥。", "歊氛隨雨斷，素景入宵多。", "雁影穿池月，蛩聲出砌莎。", "披襟予自快，楚澤任悲歌。"]'),
('ad1d0add-d33f-4a77-8598-dc98bad5b460','秋夕二首  其二','韓琦','宋','宋诗','song-poetry','','[]','此夕何清曠，新秋乍奪炎。',48,'全唐诗/poet.song.18000.json','["此夕何清曠，新秋乍奪炎。", "凉飚來似舊，熏暑逝如潛。", "露重翻香芰，踈雲點素蟾。", "放懷殊不寤，箕斗轉前簷。"]'),
('4f1ff865-bb7a-41ec-bdfe-dbf107974e39','秋日出郊','韓琦','宋','宋诗','song-poetry','','[]','疆野壓雄邊，乘秋行此田。',48,'全唐诗/poet.song.18000.json','["疆野壓雄邊，乘秋行此田。", "萬峯朝巨嶽，多稼入平天。", "農飽忘饑後，童嬉逼社前。", "僚賢須共樂，舉白盡歌筵。"]'),
('a4f8643c-d5b8-4f14-a95b-1ce7b34283cf','中秋月','韓琦','宋','宋诗','song-poetry','','[]','清商纔過半，皓魄最宜圓。',48,'全唐诗/poet.song.18000.json','["清商纔過半，皓魄最宜圓。", "自是秋光好，非緣人意偏。", "一宵歌吹地，萬里雪霜天。", "忍見西樓下，佳期又隔年。"]'),
('e49ba941-9762-4bfd-a888-a7575cf187e3','蒙恩加職寄餘杭希文資政','韓琦','宋','宋诗','song-poetry','','[]','燕石寧參楚璧珍，六膺君槳共言綸。',32,'全唐诗/poet.song.18000.json','["燕石寧參楚璧珍，六膺君槳共言綸。", "老聃道大誰同傳，千古韓非是罪人。"]'),
('537ea750-422e-4f35-a23d-851444736841','重九次韻答真定李密學','韓琦','宋','宋诗','song-poetry','','[]','琴瑟煩更化，椒蘭喜望鄰。',48,'全唐诗/poet.song.18000.json','["琴瑟煩更化，椒蘭喜望鄰。", "致儀慚蟻酧，申好忝莩親。", "惜此登高節，難偕逐勝賓。", "遥知潭上酌，多少插花人。"]'),
('6fe22aee-0372-45da-8389-be82d860d637','次韻答致政宮保杜公','韓琦','宋','宋诗','song-poetry','','[]','無勞遷職此何名，只有慚羞敢自榮。',64,'全唐诗/poet.song.18000.json','["無勞遷職此何名，只有慚羞敢自榮。", "撫俗未能宣上意，治邊徒欲振天聲。", "邱山莫副推恩重，銖兩唯憂效死輕。", "高句不須期任舊，已求三載奏官成。"]'),
('83b4bc6c-d66f-4d52-83dd-57258074c8c9','依前韻再答','韓琦','宋','宋诗','song-poetry','','[]','不與皇家致太平，康寧時節便遺榮。',64,'全唐诗/poet.song.18000.json','["不與皇家致太平，康寧時節便遺榮。", "寰中自樂喬彭壽，海內空流邴魏聲。", "一品坐來恩固重，萬鍾拋去祿何輕。", "朝廷欲繼姬周盛，會向磻谿問老成。"]'),
('805927b6-a6e2-42ac-8af6-98e81f435cd7','送省副崔刑部','韓琦','宋','宋诗','song-poetry','','[]','此去參邦計，時才固異倫。',48,'全唐诗/poet.song.18000.json','["此去參邦計，時才固異倫。", "富民知有道，言利不違仁。", "餘帳無情日，歸途適意春。", "前期對清問，犧閣近槐宸。"]'),
('9d24900d-a6df-41e6-bf5e-16b23da19f7d','雪','韓琦','宋','宋诗','song-poetry','','[]','六花來應臘，望歲一開顔。',48,'全唐诗/poet.song.18000.json','["六花來應臘，望歲一開顔。", "歌舞喧侯第，風沙雜戍關。", "餘芳留草樹，清興入江山。", "後夜高樓月，蕭然崑閬間。"]'),
('5788d38e-09dc-4fa8-a16a-61d83b4c4ad0','髮白有感','韓琦','宋','宋诗','song-poetry','','[]','區區邊朔有何成，三失流年只自驚。',32,'全唐诗/poet.song.18000.json','["區區邊朔有何成，三失流年只自驚。", "無一事來頭尚白，白人頭處豈堪行。"]'),
('23cd3de1-3466-4156-8498-a05eaa8fc66c','晚步後園覺有春色','韓琦','宋','宋诗','song-poetry','','[]','桃李知春意，陽和到嫩萌。',48,'全唐诗/poet.song.18000.json','["桃李知春意，陽和到嫩萌。", "風霜誰自困，鸎蝶始多情。", "終入芳菲賞，休論早晚榮。", "窮邊何所負，轟鼓醉金觥。"]'),
('d2c60b4c-36d9-46ea-b0bf-57db9ecd18c3','北樓望春','韓琦','宋','宋诗','song-poetry','','[]','良疇芳圃汩飛埃，生意顒顒望震雷。',32,'全唐诗/poet.song.18000.json','["良疇芳圃汩飛埃，生意顒顒望震雷。", "北嶺有雲空自繞，幾時爲雨出山來。"]'),
('18613114-2e10-4a62-a33a-f4615adb88d4','寒食','韓琦','宋','宋诗','song-poetry','','[]','塞上逢寒食，郊園此重臨。',48,'全唐诗/poet.song.18000.json','["塞上逢寒食，郊園此重臨。", "一時行樂意，萬室欲春心。", "節物隨人好，風光得處深。", "只思民盡適，守鬢忘霜侵。"]'),
('57b654c6-5d1b-4cdb-a013-2702780b8016','感事','韓琦','宋','宋诗','song-poetry','','[]','一來邊障地，走馬過三秋。',48,'全唐诗/poet.song.18000.json','["一來邊障地，走馬過三秋。", "萬緒事常擾，九分春又休。", "鸎花誰在目，霜雪只侵頭。", "從得風光住，風光可奈憂。"]'),
('b7179960-5dd2-48ca-a60a-d0c2b41a2d09','上巳北塘席上','韓琦','宋','宋诗','song-poetry','','[]','修禊春塘上，誰知物趣深。',48,'全唐诗/poet.song.18000.json','["修禊春塘上，誰知物趣深。", "萬花開喜色，眾樂出和心。", "雨意隨人住，杯情逐勝斟。", "從茲窮塞地，佳節似山陰。"]'),
('17c8fd2b-3e6c-4240-86f0-45ee89e13dbb','喜雨','韓琦','宋','宋诗','song-poetry','','[]','晚雷驅雨協春雩，誰識天工用意殊。',64,'全唐诗/poet.song.18000.json','["晚雷驅雨協春雩，誰識天工用意殊。", "不許繁花私潤澤，獨教嘉穀足膏腴。", "羣心有答方思報，寸草無求亦自蘇。", "始信雲龍施美利，豈勞功力費毫銖。"]'),
('13e42c22-0775-43df-8d23-0112b4d678f3','北塘春雨','韓琦','宋','宋诗','song-poetry','','[]','葉葉輕雲帳薄羅，坐看膏澤灑庭柯。',64,'全唐诗/poet.song.18000.json','["葉葉輕雲帳薄羅，坐看膏澤灑庭柯。", "風前芳杏紅香減，煙外垂楊綠意多。", "聲落簷牙飛短瀑，點勻池面起圓波。", "晴來西北凭欄望，拂黛遥峯濯萬螺。"]'),
('a03aa3bb-b52d-4add-ba94-65f854b87575','再謝真定李密學惠牡丹','韓琦','宋','宋诗','song-poetry','','[]','牡丹京洛豔，惠我見新鄰。',48,'全唐诗/poet.song.18000.json','["牡丹京洛豔，惠我見新鄰。", "一與樽前賞，重生塞上春。", "衰榮存主意，深淺盡天真。", "却似登蘭室，清香暗襲人。"]'),
('0f6079f1-fe55-4408-8698-d636bc919df1','新植花開','韓琦','宋','宋诗','song-poetry','','[]','去歲栽花遍小欄，只憂芳豔不禁寒。',32,'全唐诗/poet.song.18000.json','["去歲栽花遍小欄，只憂芳豔不禁寒。", "年來醉賞春風裏，無限邊人見牡丹。"]'),
('c66a49a2-a57e-459d-80c9-957286659460','牡丹二首  其一','韓琦','宋','宋诗','song-poetry','','[]','真是羣芳主，羣芳更孰過。',48,'全唐诗/poet.song.18000.json','["真是羣芳主，羣芳更孰過。", "豔新知品少，開晚得春多。", "幾日瑶姬夢，平生金縷歌。", "寒邊今幸活，風雨莫相魔。"]'),
('e33b7598-d5c7-4a15-b554-ca5585e53b57','牡丹二首  其二','韓琦','宋','宋诗','song-poetry','','[]','青帝恩偏壓眾芳，獨將奇色寵花王。',64,'全唐诗/poet.song.18000.json','["青帝恩偏壓眾芳，獨將奇色寵花王。", "已推天下無雙豔，更占人間第一香。", "欲比世終難類取，待開心始覺春長。", "不教四季呈妖麗，造化如何是主張。"]'),
('9810fa06-82a4-400e-b1e9-a3e42d7495ee','落花二首  其一','韓琦','宋','宋诗','song-poetry','','[]','妖豔憑誰主，春光去不停。',48,'全唐诗/poet.song.18000.json','["妖豔憑誰主，春光去不停。", "離魂亂飛絮，生意逐浮萍。", "錢莢偷餘態，茵蕪襲舊馨。", "年年芳信在，慎勿歎飄零。"]'),
('d288439c-97b9-4550-a32a-027f35500aa9','落花二首  其二','韓琦','宋','宋诗','song-poetry','','[]','一夜殘芳泣露痕，曉來紅雨點蘭蓀。',32,'全唐诗/poet.song.18000.json','["一夜殘芳泣露痕，曉來紅雨點蘭蓀。", "對人終有風流在，幾片斜飛在酒樽。"]'),
('ca9c4580-a449-4e4a-b13c-35971dbca855','郡甫初夏','韓琦','宋','宋诗','song-poetry','','[]','池館何無賴，青春幾日回。',48,'全唐诗/poet.song.18000.json','["池館何無賴，青春幾日回。", "酒隨花謝減，心爲水凉開。", "幽鳥閑鳴和，清風自往來。", "峯巒新在目，天與白雲裁。"]'),
('3ff6390f-0387-4b53-9068-9b9c4907370e','夏暑北塘','韓琦','宋','宋诗','song-poetry','','[]','一夕輕雲卷怒雷，回塘經雨絕纖埃。',64,'全唐诗/poet.song.18000.json','["一夕輕雲卷怒雷，回塘經雨絕纖埃。", "蓮房倒盞揮人飲，柳幄牽絲待席開。", "未必鷗飛知客意，莫嫌蟬噪是風來。", "歊煩盡滌宜無累，奈有詩情費剪裁。"]'),
('e34485e8-c7d3-43ae-a7f4-c5e10aba3902','覽劉易詩集感其遊賞江山放懷自適','韓琦','宋','宋诗','song-poetry','','[]','區區西北十經春，强力今爲老病身。',64,'全唐诗/poet.song.18000.json','["區區西北十經春，强力今爲老病身。", "白髮丹心論底事，清風明月屬閑人。", "千鈞未免嗤鼷鼠，一簣猶思抑孟津。", "早晚粗酬忠國志，五湖煙水樂吾真。"]'),
('2690651a-2b5a-4d70-9ce4-7bd9b20a2554','席上聞蟬','韓琦','宋','宋诗','song-poetry','','[]','柳際一蟬鳴，停樽忽自驚。',48,'全唐诗/poet.song.18000.json','["柳際一蟬鳴，停樽忽自驚。", "所傷非節物，未立是功名。", "默默悲時事，區區狥世情。", "不須爭噪急，衰鬢舊霜莖。"]'),
('1d13c8a5-56c2-462b-b4fc-af2c08bdfbc4','次韻和國信趙內翰北口見寄','韓琦','宋','宋诗','song-poetry','','[]','時得不可失，時乎況得天。',48,'全唐诗/poet.song.18000.json','["時得不可失，時乎況得天。", "蔓圖非易力，鴆毒是安眠。", "廟勝兩楹決，壺漿一檄傳。", "臨關休發詠，歸議主當然。"]'),
('8d4d6946-b2d2-4d8e-b5be-c830279a6ba4','寄題廣信軍四望亭','韓琦','宋','宋诗','song-poetry','','[]','西北雲高拂女牆，危亭虛豁望中長。',64,'全唐诗/poet.song.18000.json','["西北雲高拂女牆，危亭虛豁望中長。", "田間堤陌成新險，天外江山是舊疆。", "古道入秋漫黍稷，遠坡乘晚下牛羊。", "凭欄多少無言恨，不在歸鴻送夕陽。"]'),
('751f4a3b-ed33-4259-af27-ad6dba178524','與餘杭希文資政經時兩絕音問忽得訊正與近致書同日因以詩寄','韓琦','宋','宋诗','song-poetry','','[]','閏首郵音得到無，使來還喜發雙魚。',64,'全唐诗/poet.song.18000.json','["閏首郵音得到無，使來還喜發雙魚。", "却思塞上經時問，恰是吳中當日書。", "人邈江山神自照，道存忠義信從踈。", "昔年元白慈恩事，詩意雖同志未如。"]'),
('1d5f0b33-23d1-41d9-bb1d-8de3e4e406bb','一志','韓琦','宋','宋诗','song-poetry','','[]','一志事邊徼，難甘景物催。',48,'全唐诗/poet.song.18000.json','["一志事邊徼，難甘景物催。", "流年花易落，久戍雁頻回。", "細葉未成幄，飛蚊還聚雷。", "顛毛從自變，肯使壯心摧。"]'),
('c7e7d047-7fdd-4364-9dbb-85fc1283c960','閱古堂八詠 牡丹','韓琦','宋','宋诗','song-poetry','','[]','極塞將何奉燕娛，牡丹池館一株無。',32,'全唐诗/poet.song.18000.json','["極塞將何奉燕娛，牡丹池館一株無。", "誰人會我栽培意，欲見吳宮小陣圖。"]'),
('fad9d80a-ce84-46aa-a97a-31d2d35f11fd','閱古堂八詠 芍藥','韓琦','宋','宋诗','song-poetry','','[]','從來良守重農桑，何事栽花玷此堂。',32,'全唐诗/poet.song.18000.json','["從來良守重農桑，何事栽花玷此堂。", "已愛昔賢形藻繪，更移嘉卉伴馨香。"]'),
('907568f1-69ce-47cc-a406-172396fc96a3','閱古堂八詠 垂柳','韓琦','宋','宋诗','song-poetry','','[]','東君於此最多情，先與黄金撚畫成。',32,'全唐诗/poet.song.18000.json','["東君於此最多情，先與黄金撚畫成。", "何似亞夫堅壁地，因人千古得嘉名。"]'),
('6417b05f-7b32-43c6-a098-05dba24e0835','閱古堂八詠 疊石','韓琦','宋','宋诗','song-poetry','','[]','疊疊雲根漬古苔，煙巒隨指在庭階。',32,'全唐诗/poet.song.18000.json','["疊疊雲根漬古苔，煙巒隨指在庭階。", "主人未有銘功處，日視崔嵬激壯懷。"]'),
('c57391b8-dd75-4363-aa8e-a2bcafc3b1e0','閱古堂八詠 藥圃','韓琦','宋','宋诗','song-poetry','','[]','堂下開畦植藥苗，更將靈種悉名標。',32,'全唐诗/poet.song.18000.json','["堂下開畦植藥苗，更將靈種悉名標。", "吾心盡欲醫民病，長得憂民病不銷。"]'),
('3cb0a5a3-fda5-4b7d-a009-b89200441805','閱古堂八詠 溝泉','韓琦','宋','宋诗','song-poetry','','[]','遥派分流過近階，潺潺終日瀉瓊瑰。',32,'全唐诗/poet.song.18000.json','["遥派分流過近階，潺潺終日瀉瓊瑰。", "誰知到此幽閑地，多少餘波潤物來。"]'),
('d63cf82e-885e-4c0a-bab9-5d7978dfd6cb','閱古堂八詠 小檜','韓琦','宋','宋诗','song-poetry','','[]','小檜新移近曲欄，養成隆棟亦非難。',32,'全唐诗/poet.song.18000.json','["小檜新移近曲欄，養成隆棟亦非難。", "當軒不是憐蒼翠，只要人知耐歲寒。"]'),
('b3d5b526-1b8b-447e-aa33-20befa465ccd','閱古堂八詠 芭蕉','韓琦','宋','宋诗','song-poetry','','[]','邊俗稀曾識此科，南方地暖北寒多。',32,'全唐诗/poet.song.18000.json','["邊俗稀曾識此科，南方地暖北寒多。", "孤芳莫念違天性，無奈深恩愛育何。"]'),
('c66783ed-fd63-45c8-95e0-ec9da4202171','次韻答承旨王端明','韓琦','宋','宋诗','song-poetry','','[]','禁扃清切擬仙都，多病年年絕寒居。',64,'全唐诗/poet.song.18000.json','["禁扃清切擬仙都，多病年年絕寒居。", "四海風雷歸舊筆，二垂霜霰乃吾廬。", "道同今古猶相照，事役鱗鴻不計踈。", "莫謂安恬道留滯，是非終有史臣書。"]'),
('e1f97a40-7146-4657-80b5-f79112b7bccf','七夕同末伏會眾春園','韓琦','宋','宋诗','song-poetry','','[]','七夕今同末伏辰，方塘陶暑集珍羣。',64,'全唐诗/poet.song.18000.json','["七夕今同末伏辰，方塘陶暑集珍羣。", "嬌鸎萬囀風前曲，秀嶺千層水上雲。", "幽鷺倚蒲真入畫，香荷擎酒不須熏。", "天孫莫衒機頭巧，倒載歸來豈羨君。"]'),
('0c6e20b8-d34c-4912-9c92-e8523a5da824','初秋塘上','韓琦','宋','宋诗','song-poetry','','[]','池塘凉意早，秋色動邊關。',48,'全唐诗/poet.song.18000.json','["池塘凉意早，秋色動邊關。", "酷暑不終暴，清風來自閑。", "畏螳蟬屢起，辭幕燕將還。", "盡日當軒卧，看雲歸故山。"]'),
('8c71c89e-0d02-412e-99af-bb34949da5b4','次韻答渭帥王龍圖','韓琦','宋','宋诗','song-poetry','','[]','十年西北保疆垂，只恐非才誤委毗。',64,'全唐诗/poet.song.18000.json','["十年西北保疆垂，只恐非才誤委毗。", "報國心誠雖慷慨，背時蹤跡極孤危。", "欲求褒貶明千古，直把窮通託二儀。", "多謝高篇遠相勞，召南風格本王基。"]'),
('6cfccf1f-7cd0-41bf-8fa5-e444caf596b9','覽渭帥王龍圖西行詩集','韓琦','宋','宋诗','song-poetry','','[]','久陟風騷上將壇，更持旄鉞撫邊關。',64,'全唐诗/poet.song.18000.json','["久陟風騷上將壇，更持旄鉞撫邊關。", "山川滿目吟雖苦，戈甲藏胸意自閑。", "威望昔嘗流塞外，雅歌今復奏兵間。", "禁中日夜思頗牧，四牡看隨杕杜還。"]'),
('a75ea008-8ce4-4d69-ac6d-a9070a991b84','送劉易歸洛','韓琦','宋','宋诗','song-poetry','','[]','滿懷經術欲誰傳，却憶西歸治洛田。',64,'全唐诗/poet.song.18000.json','["滿懷經術欲誰傳，却憶西歸治洛田。", "富貴苟求誠損義，聖賢難遇亦推天。", "春風始入花王國，夜月長涵宓女川。", "巖谷弓旌如未及，且憑詩酒作閑仙。"]'),
('590e584d-8f48-4044-896c-8fc1b4dba9e9','次韻答侍讀張龍圖索閱古堂詩石本','韓琦','宋','宋诗','song-poetry','','[]','千年賢迹一堂間，日企英風敢自安。',32,'全唐诗/poet.song.18000.json','["千年賢迹一堂間，日企英風敢自安。", "爭似公陳無逸義，君王圖入殿屏看。"]'),
('f7def685-4f91-4d9a-9b06-3f750237dbcf','閱古堂前植菊二本九月十八日花猶未開因以小詩嘲之','韓琦','宋','宋诗','song-poetry','','[]','只趁重陽選菊栽，當欄殊不及時開。',32,'全唐诗/poet.song.18000.json','["只趁重陽選菊栽，當欄殊不及時開。", "風霜日緊猶何待，甚得迎春見識來。"]'),
('f3b648e0-a5e5-48b4-a116-40dbdd8d20f1','北塘重九','韓琦','宋','宋诗','song-poetry','','[]','堪嗤唐彥鄙連疆，不信重陽草木霜。',32,'全唐诗/poet.song.18000.json','["堪嗤唐彥鄙連疆，不信重陽草木霜。", "樽裏有花荷萬葉，三年酣賞好風光。"]'),
('698b3061-e599-48c1-924f-13ab8ce59044','試獵','韓琦','宋','宋诗','song-poetry','','[]','試獵秋原亦治戎，飄然豪氣滿秋風。',32,'全唐诗/poet.song.18000.json','["試獵秋原亦治戎，飄然豪氣滿秋風。", "饑鷹猘犬爭爲用，不在人知指縱功。"]'),
('106b508c-f2a5-4dbb-9b79-3a2c07b54302','禱雪有感','韓琦','宋','宋诗','song-poetry','','[]','靈嶽祠宮尚未回，六花隨禱下瓊瑰。',64,'全唐诗/poet.song.18000.json','["靈嶽祠宮尚未回，六花隨禱下瓊瑰。", "只憂風力狂無定，最喜雲容重不開。", "但得餘滋周畎畝，敢求嬌意助樽罍。", "夜深猶使家人探，平地依稀幾寸來。"]'),
('7b3cf09a-4924-401b-9c1c-88b49d181e1a','次韻答留臺春卿集賢侍郎','韓琦','宋','宋诗','song-poetry','','[]','聞說西臺遂懇章，一何欽聳一何傷。',64,'全唐诗/poet.song.18000.json','["聞說西臺遂懇章，一何欽聳一何傷。", "赤松世外誠先覺，白首兵間是不祥。", "得失兩忘祛病術，利名相賊溺人鄉。", "幾時微立疆垂效，去伴公閑亦道光。"]'),
('e5c17a48-fd39-4546-817d-ea30bd88add3','再答','韓琦','宋','宋诗','song-poetry','','[]','拙者奔馳智者藏，細論朝體豈無傷。',64,'全唐诗/poet.song.18000.json','["拙者奔馳智者藏，細論朝體豈無傷。", "蒼生困敝誰更化，賢弼優游自考祥。", "四海唐虞終我事，三川風月且吾鄉。", "軍中不識陽春贈，幾按青萍駭夜光。"]'),
('c303621f-7cb8-4735-829a-0d29efffc2a8','再答','韓琦','宋','宋诗','song-poetry','','[]','久拋儒掖禦戎疆，每憶青氈只自傷。',64,'全唐诗/poet.song.18000.json','["久拋儒掖禦戎疆，每憶青氈只自傷。", "馬上文章終是俗，胸中戈甲亦非祥。", "哇聲誤入離韶耳，藻衮輕投被毳鄉。", "賴得高賢時借譽，不然幽迹轉無光。"]'),
('a32133b3-dc7b-4732-a394-ba08faa6091c','後園閑步','韓琦','宋','宋诗','song-poetry','','[]','池圃足高趣，公餘事少關。',48,'全唐诗/poet.song.18000.json','["池圃足高趣，公餘事少關。", "幽禽聲自樂，流水意長閑。", "近竹花終俗，過欄草費刪。", "心休誰似我，官府有青山。"]'),
('72d7f06e-2232-47d4-935b-4dabff3002c2','北塘探春','韓琦','宋','宋诗','song-poetry','','[]','大鈞將首化，微物亦先知。',48,'全唐诗/poet.song.18000.json','["大鈞將首化，微物亦先知。", "草木色皆得，禽魚意自怡。", "和風無不到，餘凜欲何爲。", "會與斯民樂，熙臺興未遲。"]'),
('6829ff68-fcbf-45a1-9029-d8a46822a82a','觀稼回北園席上','韓琦','宋','宋诗','song-poetry','','[]','郊原飛隼拂晴霓，秋入豐年未慘悽。',64,'全唐诗/poet.song.18000.json','["郊原飛隼拂晴霓，秋入豐年未慘悽。", "嘗酒管絃先社集，捺弮禾黍極雲齊。", "雪鋪蕎麥花漫野，黛抹蔓菁菜滿畦。", "區脫狴牢無一事，山翁贏得醉如泥。"]'),
('87cd016b-d9da-4e51-8520-61b635670982','燈夕遇雪席上','韓琦','宋','宋诗','song-poetry','','[]','此夕仙花降羯陀，萬燈光裏雪花和。',64,'全唐诗/poet.song.18000.json','["此夕仙花降羯陀，萬燈光裏雪花和。", "天心要足良農望，人世常多好事魔。", "雲際未應成霢霂，風前疑欲助婆娑。", "陰晴況是民俱樂，無奈嘉賓惜醉何。"]'),
('da47c8d3-06fc-46e3-a405-8be72704e6ed','次韻答致政杜公小詩見戲','韓琦','宋','宋诗','song-poetry','','[]','塞上區區罄拙勤，回頭芳歲已三旬。',32,'全唐诗/poet.song.18000.json','["塞上區區罄拙勤，回頭芳歲已三旬。", "何須更殢中山酒，日日憂邊似醉人。"]'),
('cb64339f-803c-4f9d-be1a-e7a8f5dc7360','次韻答致政杜公以遷職惠詩','韓琦','宋','宋诗','song-poetry','','[]','滿歲窮邊喜未還，飛塵猶擬助高山。',64,'全唐诗/poet.song.18000.json','["滿歲窮邊喜未還，飛塵猶擬助高山。", "一年願借雖慚寇，萬里思歸却笑班。", "紫塞風煙長冷淡，赤松光景正安閑。", "何時少奉揮金宴，免役勞魂夢寐間。"]'),
('3862eea1-ce19-4634-bc67-b82f08927461','種樹','韓琦','宋','宋诗','song-poetry','','[]','一守中山四載餘，栽成芳樹滿郊衢。',32,'全唐诗/poet.song.18000.json','["一守中山四載餘，栽成芳樹滿郊衢。", "州民如有某棠念，惜取清陰萬萬株。"]'),
('210a2573-998b-419c-86ea-b210210f3fda','壬辰寒食眾春園','韓琦','宋','宋诗','song-poetry','','[]','寒食郊園此會稀，吏民隨意賞芳菲。',64,'全唐诗/poet.song.18000.json','["寒食郊園此會稀，吏民隨意賞芳菲。", "樽前有樂人還去，牆外無花蝶亂飛。", "眾裏鞦韆應是騃，岸邊鷗鳥却忘機。", "黄昏易覺春醪散，細雨迎風灑西歸。"]'),
('26eef373-8d8b-429f-bc36-e2e715954432','釋奠廟中作','韓琦','宋','宋诗','song-poetry','','[]','舍奠修彝禮，齋誠致吉蠲。',48,'全唐诗/poet.song.18000.json','["舍奠修彝禮，齋誠致吉蠲。", "普天同日祀，聖道幾人傳。", "窮厄當時教，雅崇萬世賢。", "蒙然如可寤，朝夕在拳拳。"]'),
('17ceca7b-e8d9-4524-bfaf-ba05d80e7441','壬辰重九即席','韓琦','宋','宋诗','song-poetry','','[]','中山風物有前緣，經賞重陽第五年。',64,'全唐诗/poet.song.18000.json','["中山風物有前緣，經賞重陽第五年。", "莫爲素毛悲晚歲，且吹黄菊酌芳筵。", "退求僻郡疑邀寵，甘老窮邊似好權。", "笑問此身何計是，不如嘉節倒垂蓮。"]'),
('2b05396b-203c-4acd-a976-37ec47f4530c','次韻答留臺春卿集賢侍郎見寄','韓琦','宋','宋诗','song-poetry','','[]','十稔違談燕，區區混濁流。',48,'全唐诗/poet.song.18000.json','["十稔違談燕，區區混濁流。", "經時無一信，度夕是三秋。", "友會此難約，君恩尚未酬。", "何人伴高興，洛棹與嵩樓。"]'),
('9e4d32f5-f916-43f5-bd01-3960117f46b6','壬辰歲除喜雪','韓琦','宋','宋诗','song-poetry','','[]','祈雪經冬未應人，歲除方喜六花勻。',64,'全唐诗/poet.song.18000.json','["祈雪經冬未應人，歲除方喜六花勻。", "解蘇民望終爲臘，要入時宜不在春。", "欲使休祥同節賀，更教生物及年新。", "明朝元會排天仗，萬玉相輝拜紫宸。"]'),
('3813157b-a2f1-4da6-814e-0e2c279083ba','賓雁','韓琦','宋','宋诗','song-poetry','','[]','候時賓雁覺秋分，便委胡霜遡楚氛。',64,'全唐诗/poet.song.18000.json','["候時賓雁覺秋分，便委胡霜遡楚氛。", "一片畫屏橫遠岫，幾行書字帖輕雲。", "信通離闊誠虛語，聲到英雄似不聞。", "莫趁衡陽戀閑暖，南兒矰繳正紛紛。"]'),
('69b19036-eb1d-4f61-a6fa-9e9a7668e162','次韻答致政杜公以加節見寄','韓琦','宋','宋诗','song-poetry','','[]','西北連憂寄責深，十年回首失光陰。',64,'全唐诗/poet.song.18000.json','["西北連憂寄責深，十年回首失光陰。", "丹心報國期輸盡，白日當天荷照臨。", "賜鉞何勞誠靦面，扞邊雖久即甘心。", "孤根只有衰危甚，不得終身被傅霖。"]'),
('3b69c796-d827-461c-a7df-83f786df5521','次韻答留臺春卿侍郎以加節見寄二首  其一','韓琦','宋','宋诗','song-poetry','','[]','一落粗官伍噲曹，清流甘分絕英髦。',64,'全唐诗/poet.song.18000.json','["一落粗官伍噲曹，清流甘分絕英髦。", "建牙恩有丘山重，扞塞功無尺寸高。", "許國壯心輕蹈死，殄戎豪氣入橫刀。", "只期名遂扁舟去，掉臂江湖擲錦袍。"]'),
('979b6273-ab44-4c62-b79e-5d0e24658fd0','次韻答留臺春卿侍郎以加節見寄二首  其二','韓琦','宋','宋诗','song-poetry','','[]','洛下安然塞下勞，公持霜簡我持旄。',64,'全唐诗/poet.song.18000.json','["洛下安然塞下勞，公持霜簡我持旄。", "憂無虛日三垂重，閑入芳春萬事高。", "病虎厭風摧漢節，卧龍慳雨澀吳刀。", "遥知嘯傲煙霞外，肯把仙袍換戰袍。"]'),
('b3c6325d-a052-4c5e-ac5c-9b57db8aa8d0','清明獲鹿道中','韓琦','宋','宋诗','song-poetry','','[]','尺雪征塗已倦行，那堪寂寞過清明。',64,'全唐诗/poet.song.18000.json','["尺雪征塗已倦行，那堪寂寞過清明。", "農居近古鞦韆野，縣堞成虛睥睨平。", "只見靚粧矜節服，更無閑地匝春耕。", "山川寓目皆形勝，可惜虛屯百萬兵。"]'),
('716bde8a-4dc8-4fc2-852f-6a06c5f1eada','過井陘淮侯廟','韓琦','宋','宋诗','song-poetry','','[]','破趙降燕漢業成，兔亡良犬日圖烹。',64,'全唐诗/poet.song.18000.json','["破趙降燕漢業成，兔亡良犬日圖烹。", "家僮上變安知實，史筆加誣貴有名。", "功蓋一時誠不滅，恨埋千古欲誰明。", "荒祠尚枕陘間道，澗水空傳哽咽聲。"]'),
('d7e78fc6-c273-46bf-be51-db4f3a45c157','離天威驛','韓琦','宋','宋诗','song-poetry','','[]','早發天威驛，深春尚薄寒。',48,'全唐诗/poet.song.18000.json','["早發天威驛，深春尚薄寒。", "龍蛇盤道路，波浪卷峯巒。", "古人萌常晚，新流勢未端。", "忠臣方叱馭，更險不辭難。"]'),
('21e0c651-3cb1-408d-b842-231cb0b65cf8','過故關','韓琦','宋','宋诗','song-poetry','','[]','春入并州路，羣芳夾故關。',48,'全唐诗/poet.song.18000.json','["春入并州路，羣芳夾故關。", "前騶驅弩過，別境荷戈還。", "古戍餘荒堞，新耕入亂山。", "時平民自適，白首樂農閑。"]'),
('f147f0df-8943-44df-b375-bf9a7faa36b5','百井路山桃盛開','韓琦','宋','宋诗','song-poetry','','[]','漫嶺夭桃樹，無人亦自開。',48,'全唐诗/poet.song.18000.json','["漫嶺夭桃樹，無人亦自開。", "雲霞深隱洞，錦繡遠成堆。", "生意驚樵斧，芳情謝宴杯。", "莫迷行客路，不似武陵回。"]'),
('3d633fe0-3ea1-451b-8667-7994a028eaa0','黑砂嶺路','韓琦','宋','宋诗','song-poetry','','[]','詰曲榆關道，終朝險復平。',48,'全唐诗/poet.song.18000.json','["詰曲榆關道，終朝險復平。", "後旌緣磴下，前騎半天行。", "舉目自山水，勞生徒利名。", "報君殊未效，何暇及歸耕。"]'),
('ffca8999-acce-4908-9db5-1e89c770ba01','過側石驛','韓琦','宋','宋诗','song-poetry','','[]','二月春光薄，川寒驛路長。',48,'全唐诗/poet.song.18000.json','["二月春光薄，川寒驛路長。", "虎蹲難動石，龍矯已刳桑。", "嶺狹居多險，耕勤地少荒。", "山農駭車騎，兒女滿莊牆。"]'),
('64486737-4cd8-4b24-8a4e-178b7c6f2211','出山口','韓琦','宋','宋诗','song-poetry','','[]','待曉出山口，溟濛雨乍晴。',48,'全唐诗/poet.song.18000.json','["待曉出山口，溟濛雨乍晴。", "始知經盡險，終得坦然平。", "草樹開春意，川原豁眼明。", "吏民當自信，竹馬不須迎。"]'),
('f972264b-9dd3-4b46-af47-b2ee05da6320','送門人曾宏秘校登第南歸','韓琦','宋','宋诗','song-poetry','','[]','十載辭鄉志，登科一旦伸。',48,'全唐诗/poet.song.18000.json','["十載辭鄉志，登科一旦伸。", "青綸歸養客，白髮倚門人。", "家釀難禁蟹，江鱸正得蓴。", "之官如自立，吾館有賢賓。"]'),
('f86a0a33-82e9-4758-8fda-bfa5b25a5418','呂景初殿院被召歸闕','韓琦','宋','宋诗','song-poetry','','[]','邇臣清舉世推公，驛召歸馳御史驄。',64,'全唐诗/poet.song.18000.json','["邇臣清舉世推公，驛召歸馳御史驄。", "不獨危言開正道，更將高節激頹風。", "嚴霜透骨寒威重，健鶻盤空殺氣雄。", "朝選雖精知尚薄，濟時才業滿胸中。"]'),
('e7f61aa9-7093-4dad-815a-145457231c98','初伏柳溪','韓琦','宋','宋诗','song-poetry','','[]','萬柳籠溪借碧漣，滌煩高會喜僚賢。',64,'全唐诗/poet.song.18000.json','["萬柳籠溪借碧漣，滌煩高會喜僚賢。", "人間酷暑病庚伏，世外清風有洞天。", "一枕易醒西嶠雨，滿筵思醉北池蓮。", "棠陰訟閴邊烽靜，誰信榆關作地仙。"]'),
('21a6e80c-7867-4217-85c9-7d3198ea1e8f','重九以疾不能主席因成小詩勸北園諸官飲','韓琦','宋','宋诗','song-poetry','','[]','病襟深惜好重陽，莫接郊園醉晚芳。',64,'全唐诗/poet.song.18000.json','["病襟深惜好重陽，莫接郊園醉晚芳。", "豪飲直輸無比戶，清歡全落少年場。", "感時蕭索休成詠，中酒無流不是傷。", "猛戰巨觥吹嫩菊，且陶佳節趁康强。"]'),
('7c197025-1361-4d42-b974-e49d10ba02c2','并塞晚秋','韓琦','宋','宋诗','song-poetry','','[]','莫賦悲哉學楚騷，寒庭秋色一時高。',64,'全唐诗/poet.song.18000.json','["莫賦悲哉學楚騷，寒庭秋色一時高。", "霜嚴獵衛鷹權峻，風入弓膠士氣豪。", "對月清吟森玳瑁，吹花芳酌醉葡萄。", "汾波照骨銀河淡，曉夕寒光助帳刀。"]'),
('da7076f0-b917-487c-84ff-3c2b3e5cd1ab','過太原舊城','韓琦','宋','宋诗','song-poetry','','[]','車書從此九區同，雉堞隳雲百載空。',64,'全唐诗/poet.song.18000.json','["車書從此九區同，雉堞隳雲百載空。", "欲把金湯角天命，却驚禾黍滿秋風。", "雖餘墟落人煙悄，不改山河氣象雄。", "何必壞城心可壞，祖宗恩德浸無窮。"]'),
('03c9380f-aea3-4cfc-b236-295d3caa9ea4','晉祠','韓琦','宋','宋诗','song-poetry','','[]','唐叔祠推晉域雄，乘春來謁想遺風。',64,'全唐诗/poet.song.18000.json','["唐叔祠推晉域雄，乘春來謁想遺風。", "前庭樹古圭曾剪，近垅禾新穎未同。", "山峻尚存維翰德，泉深長瀉及人功。", "愚民不識邦君重，歲歲西神酒食豐。"]'),
('c3d446b7-2787-4a8d-84ce-f25de223e292','獅子柳','韓琦','宋','宋诗','song-poetry','','[]','柳出狻猊首，天然癭贅高。',48,'全唐诗/poet.song.18000.json','["柳出狻猊首，天然癭贅高。", "楓瘤嗤鬼伏，松幹讓龍豪。", "根聳伸獰爪，絲輕被毳毛。", "三眠漢宮樹，人狀可同褒。"]'),
('361ec3f6-16c2-4e66-a623-c825cca4e7cc','長生蘋','韓琦','宋','宋诗','song-poetry','','[]','奇種定仙草，長生晉水蘋。',48,'全唐诗/poet.song.18000.json','["奇種定仙草，長生晉水蘋。", "採芳曾著詠，薦潔可供神。", "萬卉衰何速，三冬色自新。", "大年如欲較，吾豈愧莊椿。"]'),
('c80c7cbd-6f07-4b9e-9b13-b1f1c2c327a7','過甘泉寺','韓琦','宋','宋诗','song-poetry','','[]','甘泉穿石磴，山腹啟禪扉。',48,'全唐诗/poet.song.18000.json','["甘泉穿石磴，山腹啟禪扉。", "自笑逃塵境，翻來觸靜機。", "花開松色淡，歌咽磬聲微。", "十里薔薇路，香風送馬歸。"]'),
('7c691aa8-2a92-47d5-84b4-3e236101b931','甲午冬閱','韓琦','宋','宋诗','song-poetry','','[]','練士當時閱，臨高共一觀。',216,'全唐诗/poet.song.18000.json','["練士當時閱，臨高共一觀。", "勢憑朝氣銳，令入曉霜寒。", "事重三軍國，形存八陣灘。", "燒烘旗幟動，雷吼鼓鼙乾。", "畫守誰能犯，循環莫見端。", "赴谿驅稚子，飄石走驚湍。", "彈壓提封靜，周旋四野寬。", "機深天地秘，知少古今難。", "寨巧花齊出，營新月未圓。", "全師充國慎，堅卧亞夫安。", "鵝鸛行雖卷，貔貅伎要殫。", "撒韁馳鐵騎，疊箭取銀盤。", "避槊身藏鐙，揚塵足掛鞍。", "弩飛三刃劍，砲擲百星丸。", "鐃管喧歸隊，肴觴足犒餐。", "父兄人自衛，鳧藻眾胥歡。", "有志銘燕石，無勞誤漢壇。", "壯心徒內激，神武正勝殘。"]'),
('82cb34bb-fcf4-40b4-a3bd-473cdeaa5e25','賀宮師杜公增秩','韓琦','宋','宋诗','song-poetry','','[]','漢唐二傅推疏白，高退當時歎莫如。',64,'全唐诗/poet.song.18000.json','["漢唐二傅推疏白，高退當時歎莫如。", "雖有清風傳舊史，不聞優寵及安車。", "直緣賢迹光君輔，更約師模在帝儲。", "何似詔公還廟席，萬靈和樂浹堪輿。"]'),
('6465fc8a-8175-4a7a-9d59-3e4a9653ae6a','賀觀文富公遷職','韓琦','宋','宋诗','song-poetry','','[]','秘殿班崇極邇聯，九重思舊及高賢。',64,'全唐诗/poet.song.18000.json','["秘殿班崇極邇聯，九重思舊及高賢。", "雖知榮寵公非樂，且喜孤忠帝尚憐。", "惠物袴襦聯一境，得時霖雨即敷天。", "萬方翹首臯夔入，待見唐虞致治年。"]'),
('28b2bbec-0fa9-43fa-af8c-424a6d7367c7','賀春卿加大資政職','韓琦','宋','宋诗','song-poetry','','[]','別殿深嚴峻寵班，再煩開府扼秦關。',64,'全唐诗/poet.song.18000.json','["別殿深嚴峻寵班，再煩開府扼秦關。", "棠郊陰滿修前治，蕙帳香銷在故山。", "天意未容賢者樂，官方唯許老時閑。", "蒼生況結爲霖望，豈要窮邊俗吏攀。"]'),
('8c8c8f66-ab24-47b8-b670-5794972b442d','走筆戲呈機宜著作與諸同席','韓琦','宋','宋诗','song-poetry','','[]','不草邊書絕塞氛，英僚高會喜同羣。',64,'全唐诗/poet.song.18000.json','["不草邊書絕塞氛，英僚高會喜同羣。", "朋間射鵠雖連中，坐上飛觥不五分。", "烈士感時何晚歲，男兒行樂是從軍。", "速揮大白申嚴令，多得紅心即戰勳。"]'),
('9f644cd3-f234-406a-902d-e9a9975ec80d','上巳柳溪席上次韻答機宜張吉甫判官勸飲','韓琦','宋','宋诗','song-poetry','','[]','天意如何未應人，蛟龍猶得戢乖鱗。',64,'全唐诗/poet.song.18000.json','["天意如何未應人，蛟龍猶得戢乖鱗。", "民間望極經時雨，寒上寒深幾日春。", "麥脚埋塵難自展，柳眉低水只乾勻。", "西溪不在浮觴樂，且慰羣心祓禊辰。"]'),
('f4891526-c1e5-4bad-827b-c3ac7c71f7e7','柳溪嘲蓮','韓琦','宋','宋诗','song-poetry','','[]','清香奇色匝芳洲，只得公餘一見休。',32,'全唐诗/poet.song.18000.json','["清香奇色匝芳洲，只得公餘一見休。", "道是好花堪謔問，幾時曾上美人頭。"]'),
('5ad4aafd-8578-4d79-a30b-9bab319dcb36','次韻答永興安撫文公','韓琦','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','建牙非稱冢司官，正是宸襟注意安。',32,'全唐诗/poet.song.18000.json','["建牙非稱冢司官，正是宸襟注意安。", "即日太平歸輔翼，侍祠重陟岱宗壇。"]'),
('b44ceb6c-9884-44e1-a1c5-30288e1cb5eb','次韻和都運崔諫議寄示立春前一日宿嵐谷山程','韓琦','宋','宋诗','song-poetry','','[]','絕塞風霜正樹威，不知韶律起從微。',64,'全唐诗/poet.song.18000.json','["絕塞風霜正樹威，不知韶律起從微。", "十千酒且迎春酌，五九寒須半臘歸。", "破屐好山連日上，費詩嬌雪著人飛。", "屬封所過皆蒙惠，民吏應如挾纊衣。"]'),
('b41a7979-293e-4d6d-ad34-bdd85a8c5d4f','代書寄大資政春卿侍郎','韓琦','宋','宋诗','song-poetry','','[]','霄躔將欲正三台，促召深思輔翼才。',64,'全唐诗/poet.song.18000.json','["霄躔將欲正三台，促召深思輔翼才。", "只聽燮調光玉鉉，若爲封駮滯銀臺。", "殿帷延納君恩厚，經席敷陳聖慮開。", "命相幾時符眾望，遞中看錄白麻來。"]'),
('59cd8f97-244d-43d6-817d-c76f4c6ab5ac','六月六日雨後過嶽廟遊從封寺觀稼席上','韓琦','宋','宋诗','song-poetry','','[]','暑雨頻經信宿休，近郊方出釋潛憂。',64,'全唐诗/poet.song.18000.json','["暑雨頻經信宿休，近郊方出釋潛憂。", "雖妨麥始二停穫，且見苗知一半收。", "神嶽怖民藏電雹，老松憑寺偃蛟虬。", "佳遊況遇從豐讖，好飾千倉待有秋。"]'),
('1bab4bbd-c78b-4745-a661-9aab64ded095','自和','韓琦','宋','宋诗','song-poetry','','[]','鄣泥何惜出郊遊，始霽才寬望歲憂。',64,'全唐诗/poet.song.18000.json','["鄣泥何惜出郊遊，始霽才寬望歲憂。", "鬰若山光疑是活，飄然詩思盡難收。", "隈林杏頰紅初抹，拂砌莎髯綠自虬。", "禾黍坐看雲四合，有年將乞載春秋。"]'),
('99e798f2-991d-430c-8f7f-416685a034cc','待制崔嶧給事移守圃田','韓琦','宋','宋诗','song-poetry','','[]','使臺凝績大河東，榮圃更臨輔鎮雄。',64,'全唐诗/poet.song.18000.json','["使臺凝績大河東，榮圃更臨輔鎮雄。", "鸞省要資雖錫命，犧圖清職未推公。", "滿天秋色增詩骨，一路歡謠入歲豐。", "會取朝家精選意，陪京今是漢扶風。"]'),
('5dac4ea8-aa98-43a1-a213-6c87eb526642','菊觴','韓琦','宋','宋诗','song-poetry','','[]','九日陪嘉客，金英泛酒船。',48,'全唐诗/poet.song.18000.json','["九日陪嘉客，金英泛酒船。", "撥醅時上下，浮蟻自周旋。", "香逐榴花發，甘嗤柏葉先。", "坐中宜醉挹，仙錄載延年。"]'),
('29a85726-e769-4a86-b633-1b04486eebee','北園秋雨','韓琦','宋','宋诗','song-poetry','','[]','輕雨來秋晚，郊園對客樽。',48,'全唐诗/poet.song.18000.json','["輕雨來秋晚，郊園對客樽。", "暫和春氣味，將冷雪胚渾。", "聲入關榆苦，陰纏塞嶺昏。", "黄花應自笑，摇落獨承恩。"]'),
('1ab72594-8541-4886-8eeb-bf3291993589','病中喜雪','韓琦','宋','宋诗','song-poetry','','[]','天地久閉塞，氣和方一開。',48,'全唐诗/poet.song.18000.json','["天地久閉塞，氣和方一開。", "花從無象出，澤藴太虛來。", "慶可萬區浹，豐宜百瑞魁。", "病襟雖麤釋，歡意阻賓罍。"]'),
('d37eb7bb-7028-4ba3-bf71-04b2c5a387dc','屬疾','韓琦','宋','宋诗','song-poetry','','[]','一紀三垂慮，中疲病早侵。',48,'全唐诗/poet.song.18000.json','["一紀三垂慮，中疲病早侵。", "人生何苦甚，世事愈思深。", "冬漏長難過，霜風峭不禁。", "幾時拋組綬，芝朮老雲林。"]'),
('8ad884fa-6555-4548-94be-7ef24e2b41cc','次韻答運使楊畋舍人','韓琦','宋','宋诗','song-poetry','','[]','軺車勤按問，并部此先行。',48,'全唐诗/poet.song.18000.json','["軺車勤按問，并部此先行。", "糴重傷農業，年豐報力耕。", "幾時蘇俗困，異日復民兵。", "公策方經遠，提封可坐清。"]'),
('2e944207-38e3-4eef-8708-02786b0acf16','至和乙未元日立春','韓琦','宋','宋诗','song-poetry','','[]','元日難逢是立春，普天誰不喜佳辰。',64,'全唐诗/poet.song.18000.json','["元日難逢是立春，普天誰不喜佳辰。", "一年氣候均諸節，萬卉芳菲實九旬。", "柏葉始傾爲壽酒，土牛隨示力耕人。", "故陰盡革無餘臘，端朔陽來慶共新。"]'),
('395aa916-4e3e-40b2-be86-6e84237c50fe','元夕','韓琦','宋','宋诗','song-poetry','','[]','萬家燈火徹重闉，通夕熙然本順民。',64,'全唐诗/poet.song.18000.json','["萬家燈火徹重闉，通夕熙然本順民。", "誰道升平無可狀，請觀豐稔及茲辰。", "月隨遊騎何曾動，蓮嫁春風不是真。", "半病使君心未伏，欲驅歌吹逐香塵。"]'),
('b122a444-3dda-4060-8046-d5eb65e50b0b','春寒','韓琦','宋','宋诗','song-poetry','','[]','春寒著人骨，病軀殊未堪。',48,'全唐诗/poet.song.18000.json','["春寒著人骨，病軀殊未堪。", "雁慵難遡北，花怯不開南。", "詩筆少新興，戰觥思舊酣。", "邊垂何事樂，寂寞月將三。"]'),
('6e6ca314-cfa6-4b13-bb03-0cd7724c96d9','後園春日','韓琦','宋','宋诗','song-poetry','','[]','并塞園林古，春來似不知。',48,'全唐诗/poet.song.18000.json','["并塞園林古，春來似不知。", "雨輕成凍易，樹老發花遲。", "劇事隨年倦，歡悰入病衰。", "芳時期强賞，宴鼓揭天搥。"]'),
('a07d1327-0594-405c-8273-c7f31aa2dd88','乙未寒食西溪','韓琦','宋','宋诗','song-poetry','','[]','三月鞦韆節，西郊菡萏洲。',48,'全唐诗/poet.song.18000.json','["三月鞦韆節，西郊菡萏洲。", "塞寒春尚淺，俗樂政同優。", "賞愜杯忘算，歌妍餌失鈎。", "黄昏垂柳岸，人意共遲留。"]'),
('36be12fa-d1ae-4731-8bbe-b794f1171170','上巳西溪同日清明','韓琦','宋','宋诗','song-poetry','','[]','拍堤春水展輕紗，元巳清明景共嘉。',64,'全唐诗/poet.song.18000.json','["拍堤春水展輕紗，元巳清明景共嘉。", "人樂一時看開禊，飲隨節日發桐花。", "紅芳雨過粧新拂，綠柳含風带盡斜。", "欲繼永和書盛事，愧無神筆走龍蛇。"]'),
('48cef363-7a58-4d9a-8a92-c01934767d25','水嬉','韓琦','宋','宋诗','song-poetry','','[]','巧匠矜能作水嬉，偶形千狀擬真爲。',64,'全唐诗/poet.song.18000.json','["巧匠矜能作水嬉，偶形千狀擬真爲。", "機關自謂無知者，手足其如有見時。", "鈞叟投竿魚自出，舞姬揮□□□□。", "□□□□□□□，□□□□□□□。"]'),
('927a5464-a529-4dbe-8185-41a9bda86e11','詩一首','韓琦','宋','宋诗','song-poetry','','[]','晉陽封守遠睢陽，空有馳魂若侍傍。',64,'全唐诗/poet.song.18000.json','["晉陽封守遠睢陽，空有馳魂若侍傍。", "處世少容雖鑿枘，與公相協自宮商。", "冥鴻愈適知難慕，疲駕將顛失預量。", "新句暗投頻駭目，少陵光焰極輝煌。"]'),
('1d951d08-e0d6-4877-bb4c-04fe26c85409','謝宮師杜公寄示詩編','韓琦','宋','宋诗','song-poetry','','[]','百諷新篇百忘勞，直將淵旨質風騷。',64,'全唐诗/poet.song.18000.json','["百諷新篇百忘勞，直將淵旨質風騷。", "閑觀景物辭終巧，意到安恬格自高。", "三代正聲傳雅樂，千年嘉味入蟠桃。", "誰知八十歸休相，字體詩情日日豪。"]'),
('19c5e0e1-a188-4795-9016-eff135f8fbb5','次韻謝宮師杜公惠詩慶富公爲代','韓琦','宋','宋诗','song-poetry','','[]','彥國賢推不世奇，兩諧交政辱公詩。',64,'全唐诗/poet.song.18000.json','["彥國賢推不世奇，兩諧交政辱公詩。", "如褎事契誠多幸，欲並才名敢固辭。", "疏傅退來光漢史，周公歸已靜淮夷。", "須知病守榮非淺，日對鄉枌擁郡麾。"]'),
('3ae57b55-5908-4806-9eba-17e6d87d80c2','寺底遇大雨寄呈二運使','韓琦','宋','宋诗','song-poetry','','[]','怒雷傾雨灑無垠，天意須臾復至仁。',64,'全唐诗/poet.song.18000.json','["怒雷傾雨灑無垠，天意須臾復至仁。", "比屋士民平歎息，一川和黍長精神。", "徹犁農喜通新種，隔轍人誰謂不均。", "大利豈當論小害，路泥深尺沒征輪。"]'),
('015d9bfc-2afa-44da-9d62-62d2535676d1','早行','韓琦','宋','宋诗','song-poetry','','[]','冒暑行宜早，修途不困人。',48,'全唐诗/poet.song.18000.json','["冒暑行宜早，修途不困人。", "遠風清逐睡，微露濕低塵。", "好月看無盡，高吟意益新。", "未雞知漸曉，天角下星辰。"]'),
('117e3204-7b5b-4349-941a-292628c3a18b','褫高道中農居','韓琦','宋','宋诗','song-poetry','','[]','山脚林成簇舍窠，門前流水養嘉禾。',64,'全唐诗/poet.song.18000.json','["山脚林成簇舍窠，門前流水養嘉禾。", "森森松柏圍先隴，濈濈牛羊滿近坡。", "官賦已供餘歲備，村歌無節得天和。", "安全盡責廉平吏，三歲齊民更孰過。"]'),
('8f1aab50-e206-4eb6-b93a-04c50ed9155e','山行','韓琦','宋','宋诗','song-poetry','','[]','山路何曾倦，官程幸不賒。',48,'全唐诗/poet.song.18000.json','["山路何曾倦，官程幸不賒。", "片雲無定雨，香草逐時花。", "暑序秋天氣，農居古室家。", "鄉關勤一望，峯翠列高牙。"]'),
('12fde474-90dc-4ed3-92c0-17fe4f6071fa','過微子領','韓琦','宋','宋诗','song-poetry','','[]','崎嶇微子道，行路始知難。',48,'全唐诗/poet.song.18000.json','["崎嶇微子道，行路始知難。", "峻嶺萬千疊，紆途百十盤。", "地磽民力薄，天旱穀苗乾。", "未寤蒼蒼意，平川雨澤寬。"]'),
('b5b02b43-01d9-4e2d-96a5-496db8332df9','過吳兒谷','韓琦','宋','宋诗','song-poetry','','[]','曉入吳兒谷，危塗信不虛。',48,'全唐诗/poet.song.18000.json','["曉入吳兒谷，危塗信不虛。", "千峯疑絕路，一逕俯容車。", "山鳥過雲語，田夫半嶺鋤。", "時平盡周道，天險欲何如。"]'),
('902e89d5-7a51-4fe5-857d-9a55335af166','過涉縣熊耳山','韓琦','宋','宋诗','song-poetry','','[]','我從團柏歷山岐，秀絕唯於熊耳知。',64,'全唐诗/poet.song.18000.json','["我從團柏歷山岐，秀絕唯於熊耳知。", "芳草經年被重席，輕雲無日展時旗。", "羊頭有黍名終俗，壺口稱關類亦卑。", "何似半天留鶴馭，此來憑軾與仙期。"]'),
('7bc7fe48-3c13-4a14-9371-bd0c3a7930c7','至昭德','韓琦','宋','宋诗','song-poetry','','[]','出却千山與萬山，坦途由引達鄉關。',64,'全唐诗/poet.song.18000.json','["出却千山與萬山，坦途由引達鄉關。", "邊垂未減宵衣念，閭里徒矜晝錦還。", "憂國敢忘經日慮，治身能得幾時閑。", "遥知上冢光榮處，只在州城一舍間。"]'),
('399f36b6-ff8c-4e2d-a5b3-72fa5fb04399','拜墳','韓琦','宋','宋诗','song-poetry','','[]','欲知爲郡寵，晝錦入家村。',48,'全唐诗/poet.song.18000.json','["欲知爲郡寵，晝錦入家村。", "自古拜松檟，幾人如子孫。", "麾幢新俗觀，牛酒飫鄉尊。", "儒者榮斯甚，將何報國恩。"]'),
('eb366e47-bf2a-497f-88e1-046c41bf82ce','喜雨','韓琦','宋','宋诗','song-poetry','','[]','垂稔良田雨信愆，三農憂死只呼天。',64,'全唐诗/poet.song.18000.json','["垂稔良田雨信愆，三農憂死只呼天。", "應時滂洽真無價，數日淹遲誤有年。", "立解焦枯非甚力，不知神化此誰權。", "何妨四序均膏澤，長使生靈得自然。"]'),
('a1d0a627-9c8d-4287-b6dc-6dec528f8517','觀稼二首  其一','韓琦','宋','宋诗','song-poetry','','[]','尺雨滂然滌旱災，行田因得過家來。',64,'全唐诗/poet.song.18000.json','["尺雨滂然滌旱災，行田因得過家來。", "催成禾黍拖泥秀，長就枌榆揭凍栽。", "三組不矜聊問俗，一廛雖陋且容杯。", "郊原躍馬都忘病，隨目山川氣象開。"]'),
('aeef3507-c155-4215-abcb-784af4780458','觀稼二首  其二','韓琦','宋','宋诗','song-poetry','','[]','一夕甘滋起瘁田，斗回災沴作豐年。',64,'全唐诗/poet.song.18000.json','["一夕甘滋起瘁田，斗回災沴作豐年。", "便晴誰恐禾生耳，將熟偏宜穀捺弮。", "雲退不留驅旱迹，氣清渾露已秋天。", "衰翁豈獨同民樂，更覺詩豪似有權。"]'),
('ba501d37-b9b7-48d9-a0dd-712f800f5a11','觀稼回','韓琦','宋','宋诗','song-poetry','','[]','雨過觀田出近垌，敝廬還喜及柴刑。',64,'全唐诗/poet.song.18000.json','["雨過觀田出近垌，敝廬還喜及柴刑。", "雲平多稼徹天盡，黛拂遠山隨馬行。", "寂寞秋風催晚角，徘徊先隴奈重城。", "鄉人莫羨前驅弩，吾意何如負郭耕。"]'),
('686f2a91-29e5-4777-8dd5-615cabf78047','早赴墳莊','韓琦','宋','宋诗','song-poetry','','[]','疊疊山依皺曉霞，羲輪騰海露天涯。',64,'全唐诗/poet.song.18000.json','["疊疊山依皺曉霞，羲輪騰海露天涯。", "一川圖畫秋方靜，萬積京坻穀盡槎。", "舊鄴餘風含古意，太行高景落詩家。", "訟庭經日如僧舍，又到村居倚將牙。"]'),
('96fefede-888e-46bb-a9ec-8068a6c99199','再出行田','韓琦','宋','宋诗','song-poetry','','[]','豐歲觀農穫，先疇路不遐。',48,'全唐诗/poet.song.18000.json','["豐歲觀農穫，先疇路不遐。", "子多宜晚穀，生柪就新麻。", "蕎麥方成齪，蔓菁未入椏。", "鄉民愚自詫，太守是吾家。"]'),
('5411a412-aaee-4175-87d8-061da69ac064','送張吉甫寺丞歸洛','韓琦','宋','宋诗','song-poetry','','[]','洛中平日是吾家，時節芳菲正可誇。',64,'全唐诗/poet.song.18000.json','["洛中平日是吾家，時節芳菲正可誇。", "權去獨思來衛幕，春歸誰約醉桃花。", "晴飛縣舄瞻仙翼，暖擷新蘭薦潔牙。", "更想緱笙聞夜月，翩然高意薄青霞。"]'),
('0bbf9bd1-dc6d-4f3d-9167-3295ac1d7846','賀春卿宣微出帥延安','韓琦','宋','宋诗','song-poetry','','[]','延塞何須輟鉅公，西師今復久櫜弓。',64,'全唐诗/poet.song.18000.json','["延塞何須輟鉅公，西師今復久櫜弓。", "三台班秩名雖重，四海生靈澤未豐。", "莫泥兵韜求策勝，更充賢業俟時通。", "歸來談笑巖廊上，致主唐虞始是功。"]'),
('05a5ab8a-76d0-4d98-b4d3-c151979ee387','重陽甲子雨霽','韓琦','宋','宋诗','song-poetry','','[]','猛收宵雨發秋光，甲子朝來甚不傷。',64,'全唐诗/poet.song.18000.json','["猛收宵雨發秋光，甲子朝來甚不傷。", "天意欲教成九穀，人心兼遂樂重陽。", "山開霽碧迎軒秀，菊染新黄助酒香。", "氣與民和自無沴，豈須從俗佩萸囊。"]'),
('a6a8b8b5-a469-4829-a96c-0ec1a3e35d68','登抱螺臺','韓琦','宋','宋诗','song-poetry','','[]','壞圃蕭踈有廢臺，登高留客此徘徊。',64,'全唐诗/poet.song.18000.json','["壞圃蕭踈有廢臺，登高留客此徘徊。", "幾年埋沒荒榛滿，今日崔巍宴席開。", "一境山川俱入眼，重陽風物盡宜杯。", "坐中不勸猶當醉，菊蕊浮香似撥醅。"]'),
('aa3bee52-c5f6-4897-88a4-ea792bd30d7e','次韻答滑守梅龍圖重陽惠酒二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','芳醇盈榼副風騷，慰我漳濱病擁旄。',32,'全唐诗/poet.song.18000.json','["芳醇盈榼副風騷，慰我漳濱病擁旄。", "把菊不同陶令喜，白衣人只送香醪。"]'),
('636b65e2-b226-4b45-b4dc-b7788a176ba0','次韻答滑守梅龍圖重陽惠酒二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','滑醪清滿菊花巵，只欠新螯左手持。',32,'全唐诗/poet.song.18000.json','["滑醪清滿菊花巵，只欠新螯左手持。", "欲報善隣將意厚，苦慚家釀带春醨。"]'),
('9c72531e-ed2d-4a7a-a339-9affd024226d','次韻答滑州梅龍圖惠鼎州甘橘','韓琦','宋','宋诗','song-poetry','','[]','芳訊欣隨客鯉開，雅篇并付木奴來。',32,'全唐诗/poet.song.18000.json','["芳訊欣隨客鯉開，雅篇并付木奴來。", "病翁逢酒唯憂過，更使湘包下滑杯。"]'),
('7a9b251d-e969-4ba0-a7bd-d0941357dffc','寒食會康樂園','韓琦','宋','宋诗','song-poetry','','[]','欲識芳園立意新，康辰聊以樂吾民。',64,'全唐诗/poet.song.18000.json','["欲識芳園立意新，康辰聊以樂吾民。", "天收寒食時來雨，人得常年數倍春。", "密密樓臺花外好，蚩蚩歌舞醉中真。", "朝來必要升平象，請繪輕綃獻紫宸。"]'),
('c31c1c31-a636-4251-a3f0-465e850f0a59','次韻答滑州梅龍圖以詩酒見寄二首  其一','韓琦','宋','宋诗','song-poetry','','[]','對敵公如論酒兵，病夫雖劣敢先登。',32,'全唐诗/poet.song.18000.json','["對敵公如論酒兵，病夫雖劣敢先登。", "如將壓境求詩戰，即豎降旗示不勝。"]'),
('7df36675-8575-4fda-b2db-40c75b6b6266','次韻答滑州梅龍圖以詩酒見寄二首  其二','韓琦','宋','宋诗','song-poetry','','[]','東郡何能抑上才，召書看即日邊來。',32,'全唐诗/poet.song.18000.json','["東郡何能抑上才，召書看即日邊來。", "名醪價重詩篇好，㮰泛西園感遇杯。"]'),
('98328b4a-eadc-4fc4-94a8-7797b8049abe','拜西墳','韓琦','宋','宋诗','song-poetry','','[]','樓角聲喧促曉更，致虔塋域出西垌。',64,'全唐诗/poet.song.18000.json','["樓角聲喧促曉更，致虔塋域出西垌。", "春山带雨和雲重，麥隴如梳破雪青。", "鄉樹溟濛天水墨，村農淳野古畦丁。", "陰迷俄景催歸馭，暫向東風俗眼醒。"]'),
('a9621781-8e1c-49f5-9328-738db46c2fb5','次韻酬滑州梅龍圖惠詩','韓琦','宋','宋诗','song-poetry','','[]','自昔能詩者，如公敏思稀。',192,'全唐诗/poet.song.18000.json','["自昔能詩者，如公敏思稀。", "清風當世聳，大雅一時歸。", "京輔方期治，天顔此暫違。", "召棠隨有愛，庖刃不勞揮。", "吟筆閑邀戰，隣邦動怯圍。", "疲神支敗北，對景失芳菲。", "無物酬明月，何心衒晝衣。", "驚弦常跕跕，突陣正騑騑。", "溪柳柔金幄，園花爛錦幃。", "嬉遊成樂國，佳氣俯端闈。", "郢曲高難和，荆棲近莫依。", "流年傷阻闊，好夢接容輝。", "不信降旗豎，猶勝走檄威。", "可慚貂莫續，安敵虎而飛。", "窘蹙圖更郡，奔逃始見機。", "吾鄉雖甚美，無計戀柴扉。"]'),
('1cc37356-a720-43ae-917f-502c02d6bfd1','次韻和滑州梅龍圖寒食溪園','韓琦','宋','宋诗','song-poetry','','[]','溪園高致此非遐，請爲公陳眾所誇。',64,'全唐诗/poet.song.18000.json','["溪園高致此非遐，請爲公陳眾所誇。", "一境熙臺躋舊俗，萬民和氣入新花。", "流芳只有人思召，行樂何須坐有車。", "不獨清明資勝會，四時風月愜詩家。"]'),
('c135ee9f-2f5b-44bf-ab83-d6315021fbe7','次韻答磁州王復都官','韓琦','宋','宋诗','song-poetry','','[]','本邦爲守獲隣封，民政雖殊道則同。',64,'全唐诗/poet.song.18000.json','["本邦爲守獲隣封，民政雖殊道則同。", "浹境歡然君有惠，一鄉榮甚我何功。", "漸濡美化規模近，珍重高篇氣格雄。", "德薄可能勝尹誦，穆如空自愧清風。"]'),
('6ff74d3e-283e-415c-9641-46cb0993c4a5','上巳會城北新磑','韓琦','宋','宋诗','song-poetry','','[]','誰言智者不兼仁，請看新渠激磑輪。',64,'全唐诗/poet.song.18000.json','["誰言智者不兼仁，請看新渠激磑輪。", "本爲酒材寬物力，更饒春月樂鄉民。", "陰晴天色將寒食，狂醉人心即蠟賓。", "父老他年傳故事，可忘修禊起茲辰。"]'),
('84ddcf4f-e285-4b26-9643-193c71709172','晝錦堂賞新牡丹','韓琦','宋','宋诗','song-poetry','','[]','欲集珍叢稱此堂，春來栽檻首花王。',64,'全唐诗/poet.song.18000.json','["欲集珍叢稱此堂，春來栽檻首花王。", "連砧不動開猶少，對酒多情格自强。", "白晝已凌鄉錦色，清陰宜接訟棠芳。", "娛賓一奉笙歌賞，從此香名歲月長。"]'),
('736a6323-1566-42e5-b1b0-5d163c2a5fd5','暮春康樂園','韓琦','宋','宋诗','song-poetry','','[]','榆莢紛紛擲亂錢，柳花相撲輥新綿。',64,'全唐诗/poet.song.18000.json','["榆莢紛紛擲亂錢，柳花相撲輥新綿。", "一年寂寞頻來地，三月芳菲已過天。", "樹密只喧閑鳥雀，臺高猶得好山川。", "病夫不飲時如此，徒有詩情益自然。"]'),
('ce9c3fdb-5dca-4026-9b58-eab2ddcab480','庚申相臺閔稼','韓琦','宋','宋诗','song-poetry','','[]','淫雨農疇害復收，彼何恩厚此何仇。',64,'全唐诗/poet.song.18000.json','["淫雨農疇害復收，彼何恩厚此何仇。", "高田穀穗拖牛尾，卑地莊窠沒獸頭。", "稔社徹宵喧鼓樂，災居無日苦饑流。", "如云禍福關爲政，安得豐兇在一州。"]'),
('c872669c-3af7-4106-a426-d07e530ce5fb','苦雨','韓琦','宋','宋诗','song-poetry','','[]','直疑天際裂銀潢，大雨連傾特異常。',64,'全唐诗/poet.song.18000.json','["直疑天際裂銀潢，大雨連傾特異常。", "數里河聲轟陣鼓，萬條簷溜卓戎槍。", "雷霆勢惡掀人腦，蛟□朋兇碎客航。", "正熟民田多沒穗，幾時仁惻動蒼蒼。"]'),
('dd8e7f7d-fe64-4184-b61b-8776f002934f','次韻酬滑州梅龍圖惠酒','韓琦','宋','宋诗','song-poetry','','[]','久雨無書致睦隣，坦途非邈盡長津。',64,'全唐诗/poet.song.18000.json','["久雨無書致睦隣，坦途非邈盡長津。", "正憂吾里民災甚，敢覬公齋酒味醇。", "得騁蛟龍方倚浪，未鋤稂莠已齊身。", "太陽幾日披雲見，多少如葵仰望人。"]'),
('26c2ef5b-5206-4c67-9827-31c8ad2790cd','冬至前一日雪','韓琦','宋','宋诗','song-poetry','','[]','地下陽將復，人間氣已和。',120,'全唐诗/poet.song.18000.json','["地下陽將復，人間氣已和。", "羣陰明數極，六出見花多。", "賀稱新年曲，歡侔故郢歌。", "同雲留紀吉，柔荔借萌科。", "起認灰飛管，堆凝素出波。", "朝盈振鷺集，隙隘白駒過。", "樹密輕黏萼，天圓細撼羅。", "潔非容物污，碎不在風搓。", "農畝經年瑞，詩家萬古魔。", "平明開慶會，綠蟻薦紅螺。"]'),
('09c1472c-43f8-49c9-a13e-16681fa51516','臘日出獵二首  其一','韓琦','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','笳鼓擁貔貅，韓陵山下頭。',48,'全唐诗/poet.song.18000.json','["笳鼓擁貔貅，韓陵山下頭。", "人心忘岱嶽，鷹眼快離婁。", "兔逸茲窮虜，孤殲即貴酋。", "鄉民誰會我，衣錦樂畋遊。"]'),
('f6aeb140-79f5-4bbc-be42-1bda468c826b','臘日出獵二首  其二','韓琦','宋','宋诗','song-poetry','','[]','習平禮樂存形器，要閱兵須有殺生。',64,'全唐诗/poet.song.18000.json','["習平禮樂存形器，要閱兵須有殺生。", "故備姦戎侔斬伐，唯於畋獵可申明。", "妖狐膽裂逃終戮，老鶻拳高下必精。", "大獲未能矜小得，幾何人不哂吾行。"]'),
('d846b92b-e700-49f9-9cf8-dcb6fad2a968','元日雪','韓琦','宋','宋诗','song-poetry','','[]','人正開統發新陽，盈尺稀逢雪載滂。',64,'全唐诗/poet.song.18000.json','["人正開統發新陽，盈尺稀逢雪載滂。", "不必宮聲符善歲，却應和氣得嘉祥。", "同雲幾刻藏春色，利澤經時洽眾芳。", "遥想九天排曉仗，六花吹入萬年觴。"]'),
('88657634-9114-44a0-ac83-dc13ba36636e','新歲拜墳二首  其一','韓琦','宋','宋诗','song-poetry','','[]','先隴比如何，新年重一過。',48,'全唐诗/poet.song.18000.json','["先隴比如何，新年重一過。", "風迎人意好，春入鳥聲和。", "畎畝因時勸，松楸趁暖科。", "公餘私遂及，吾幸比爲多。"]'),
('75d727bf-a406-430d-b3a0-654e685f666a','新歲拜墳二首  其二','韓琦','宋','宋诗','song-poetry','','[]','新歲齋前寂訟鈴，不妨諏日展先塋。',64,'全唐诗/poet.song.18000.json','["新歲齋前寂訟鈴，不妨諏日展先塋。", "遥知隴樹春方到，一見家山眼又明。", "孝弟少期爲俗勸，里閭烏足語吾榮。", "此行猶苦圭符累，名遂歸來更盡誠。"]'),
('3528599c-b423-445b-a586-964cf818ba0d','寄并帥龐公古瓦硯','韓琦','宋','宋诗','song-poetry','','[]','鄴瓦搜來頗異常，寄誠安足奉文房。',32,'全唐诗/poet.song.18000.json','["鄴瓦搜來頗異常，寄誠安足奉文房。", "早陪神化丹青筆，莫滯邊書赤白囊。"]'),
('5d274bc3-791c-495c-a0e7-d64fb5ac654f','次韻答并帥龐公謝寄古硯','韓琦','宋','宋诗','song-poetry','','[]','誰傳石末首青州，鄴硯今推第一流。',32,'全唐诗/poet.song.18000.json','["誰傳石末首青州，鄴硯今推第一流。", "更好豈堪濡化筆，報瓊終念木瓜投。"]'),
('d0f40cfe-7f1d-4709-adc2-03d7969f5d9e','寄題滑州梅龍圖西溪園','韓琦','宋','宋诗','song-poetry','','[]','陪京高選得名卿，勤葺公園匪自寧。',64,'全唐诗/poet.song.18000.json','["陪京高選得名卿，勤葺公園匪自寧。", "政舉輔藩無一事，意尊王室有三亭。", "看花篇什煩官課，對酒笙歌易訟鈴。", "他日吏民銘惠愛，定隨碑刻載圖經。"]'),
('b688d405-82d3-4784-8b7f-80000d25baf4','寄題滑州梅龍圖西溪','韓琦','宋','宋诗','song-poetry','','[]','四時風物隱天真，咫尺城隅惜示人。',64,'全唐诗/poet.song.18000.json','["四時風物隱天真，咫尺城隅惜示人。", "幾歲壞堤埋老木，一朝春色與吾民。", "壺中有景知誠少，堂下無喧到始頻。", "我亦治園同眾樂，夾河相望稱爲隣。"]'),
('b3159c43-60ad-4478-b0db-d24a74eec8d7','御製後苑賞花釣魚奉聖旨次韻','韓琦','宋','宋诗','song-poetry','','[]','花簇香亭萬朵開，琱輿高自九關來。',64,'全唐诗/poet.song.18000.json','["花簇香亭萬朵開，琱輿高自九關來。", "輕陰閣雨迎天步，寒色留春送壽杯。", "仙吹徹雲終縹緲，恩魚逢餌幾徘徊。", "曾參二十年前會，今備台司得再陪。"]'),
('6209b93e-0421-48e3-8e9b-26c9d02c9812','御製天章閣觀三聖御書奉聖旨次韻','韓琦','宋','宋诗','song-poetry','','[]','寶閣三休地，琅函列聖文。',48,'全唐诗/poet.song.18000.json','["寶閣三休地，琅函列聖文。", "天章橫紫極，洛字覆青雲。", "花拆驚雷起，龍騰駭浪分。", "宸毫知善斷，更嗣禹邦勤。"]'),
('2f20827d-ca71-459c-a163-0bea7798cf7a','恭謝天地慶成五言六韻','韓琦','宋','宋诗','song-poetry','','[]','世積皇基厚，天扶帝極安。',72,'全唐诗/poet.song.18000.json','["世積皇基厚，天扶帝極安。", "宸心思報重，靈答匪誠難。", "蠲潔齋居敞，凝嚴路寢寬。", "二儀通聖饗，三后接神歡。", "惠澤開秋慘，和聲破曉寒。", "南山薦君壽，嶢闕聳羣觀。"]'),
('5f5b1f48-d79d-45b0-a63c-64d29459122b','祫享慶成五言二十韻','韓琦','宋','宋诗','song-poetry','','[]','大饗無先祫，精祠貴必躬。',240,'全唐诗/poet.song.18000.json','["大饗無先祫，精祠貴必躬。", "歷朝疑未講，曠典屬今崇。", "良月稽冬孟，容臺訪禮中。", "祀期當象閏，位向卒虛東。", "太卜諏元日，齋誠儼法宮。", "琱輿下丹地，琳館薦清衷。", "雪密人初駭，天高德自通。", "陰雲成瑞靄，凜色變和風。", "世室休嚴衛，宵衣集庶工。", "敘親昭穆正，合食簋鉶豐。", "既祼神斯格，居歆慶已蒙。", "歡欣流禹律，謦欬入堯聰。", "月射千圭白，星輝萬燎紅。", "茨歌將振作，晴旭漸曈曨。", "回蹕升端闕，羣瞻聳上穹。", "蕃釐均廟餕，惠澤泰民窮。", "孝著鉤鈐動，恩疏貫索空。", "致祥書可信，讓美意爾沖。", "此協亨嘉會，慚非輔翼功。", "唯知獻君壽，巍與二儀同。"]'),
('b7182dc4-3c3f-4d33-9f8c-568745f842f2','明堂慶成五言二十韻','韓琦','宋','宋诗','song-poetry','','[]','至矣君嚴父，其惟祀配天。',240,'全唐诗/poet.song.18000.json','["至矣君嚴父，其惟祀配天。", "明堂茲有法，路寢復申虔。", "禮簡刊前誤，圖新煥昔傳。", "乾坤隆正位，辰火協高躔。", "宗德停參侑，推尊獨大圓。", "兼崇太極坐，並享總章筵。", "節物豐秋後，齋精吉玄前。", "既祗真館駕，遂潔閟宮牷。", "泛灑輕塵失，涵濡惠澤先。", "直由誠意感，卒使祭無愆。", "翌日回清蹕，中宵儼邃延。", "一純通肸蠁，五室敞蟺蜎。", "和必流金石，馨非主豆籩。", "靈光燭窗戶，飚駕觸旄旃。", "齊酌終三薦，神釐答萬年。", "歡聲摇海嶽，瑞色變雲煙。", "餕已均庖賤，恩思被幅員。", "星雞隨敕豎，赦鶴下樓宣。", "教不煩家至，民惟視德遷。", "普天知子道，斯匪化工然。"]'),
('cb4d1272-7d4b-4bc7-b94e-ef3066a9cf82','天章閣觀御飛白書五言十韻','韓琦','宋','宋诗','song-poetry','','[]','內閣門清曉，中天對邇臣。',120,'全唐诗/poet.song.18000.json','["內閣門清曉，中天對邇臣。", "唐虞遺典在，河洛奧書陳。", "二聖勤勞舊，千齡矩法新。", "帝暉方咫尺，宸翰復躬親。", "鸞拂宮綃舞，花隨御筆春。", "奎光連璧府，劍影動龍津。", "今古神功絕，頒宣上意均。", "玉峯羅俎豆，黼坐拱星辰。", "魚藻符亨會，蓬瀛寄此身。", "流霞仙飲罷，又賜一杯醇。"]'),
('1a138a1d-5385-4741-97a8-5dc74b6f4262','樞廷對竹','韓琦','宋','宋诗','song-poetry','','[]','一紀前曾對此君，依然軒檻喜重親。',64,'全唐诗/poet.song.18000.json','["一紀前曾對此君，依然軒檻喜重親。", "丹心自覺同高節，青眼相看似故人。", "不雜囂塵終冷淡，飽經霜雪尚精神。", "樞廷豈是琴樽伴，會約幽居稱幅巾。"]'),
('70c9bc3c-a8ee-4b8a-8702-3d4069c30046','韓縝太傅之任洋州','韓琦','宋','宋诗','song-poetry','','[]','昔年疆場寵雙旌，官寄洋州實治并。',64,'全唐诗/poet.song.18000.json','["昔年疆場寵雙旌，官寄洋州實治并。", "今喜遠民留上意，故求賢守紹家聲。", "升雲仙迹唐祠古，踏石春遊灙水清。", "時閱吏文應笑我，從前銜署只虛名。"]'),
('4c6bb8b0-5050-4576-b664-7538407c6023','答定帥仲儀龍圖寄示堂詩刻','韓琦','宋','宋诗','song-poetry','','[]','好勝時多尚己爲，前人勤力必隨隳。',64,'全唐诗/poet.song.18000.json','["好勝時多尚己爲，前人勤力必隨隳。", "所圖營葺猶如是，欲樹功名即可知。", "昔慕先賢形藻繪，本同來哲作箴規。", "得公詩刻增光燄，定警媮風變俗漓。"]'),
('a2bf9c2f-711e-4cc4-aa35-2dc0ee7fc9f0','夏景即事','韓琦','宋','宋诗','song-poetry','','[]','槐耳籠前檻，雲峯透曲櫺。',48,'全唐诗/poet.song.18000.json','["槐耳籠前檻，雲峯透曲櫺。", "凉風即崑閬，煩思入滄溟。", "荷弱翻青蓋，榴新倒綠缾。", "晚來收驟雨，一枕夢魂醒。"]'),
('18ea6db7-55ec-40e4-ae38-23ccba066f78','夏暑早時朝二首  其一','韓琦','宋','宋诗','song-poetry','','[]','凉風吹暑豁煩歊，上馬迎風趁早朝。',32,'全唐诗/poet.song.18000.json','["凉風吹暑豁煩歊，上馬迎風趁早朝。", "宿霧欲開星月澹，隱然雙闕在層霄。"]'),
('a53a9c26-d220-48e1-9f89-0dc0d246d388','夏暑早時朝二首  其二','韓琦','宋','宋诗','song-poetry','','[]','奪熱清風幾快襟，禁街岑寂漏聲沉。',64,'全唐诗/poet.song.18000.json','["奪熱清風幾快襟，禁街岑寂漏聲沉。", "東方似動陰氛失，北斗高垂帝闕深。", "憂國遠圖深入夢，費詩閑景懶成吟。", "平明天外鳴鞘下，萬玉顒然拱極心。"]'),
('018c01fa-4a33-4a42-b79e-dfea310d97e5','重九席上賦金鈴菊','韓琦','宋','宋诗','song-poetry','','[]','黄金綴菊鈴，兗地獨馳名。',48,'全唐诗/poet.song.18000.json','["黄金綴菊鈴，兗地獨馳名。", "細蕊浮杯雅，香筒貯露清。", "風休沉夜警，雨碎入寒聲。", "自此傳仙種，秋芳冠玉京。"]'),
('13c3bb7a-741f-4d83-b35b-79015a9e04c9','召赴天章閣觀新柑','韓琦','宋','宋诗','song-poetry','','[]','雲閣崇先重，霜柑薦瑞新。',72,'全唐诗/poet.song.18000.json','["雲閣崇先重，霜柑薦瑞新。", "臨觀紆法從，趨召獨隣臣。", "虹實開天意，重榮浹上人。", "不隨淮枳變，自比禹包珍。", "廟獻宸心格，親頒聖寵均。", "從茲魁眾果，仙府占長春。"]'),
('cd0d41a4-ff84-422c-824a-e41b0b8fd49f','祈雪宿齋醴泉觀','韓琦','宋','宋诗','song-poetry','','[]','愆陽經臘惻皇情，徧走靈祠達意誠。',64,'全唐诗/poet.song.18000.json','["愆陽經臘惻皇情，徧走靈祠達意誠。", "馬殆始知仙府迥，露寒如到月宮清。", "甘泉既久蠲民瘼，惠澤非難滌厲萌。", "日待神龍興熱窟，一吁嘉雪滿寰瀛。"]'),
('e9d85789-46b2-4fc0-911c-47c36d01cb29','戊戌元日喜雪','韓琦','宋','宋诗','song-poetry','','[]','新元迎曉朔風凉，零落同雲勢漸霶。',64,'全唐诗/poet.song.18000.json','["新元迎曉朔風凉，零落同雲勢漸霶。", "氣候未春終是臘，禱祈方得合稱祥。", "拜章粉絮迷朝珮，獻壽瓊花入御觴。", "自是三農豐歲兆，人聲何必問宮商。"]'),
('7246b317-a452-4ad7-81b1-f4976dc8f981','張吉甫殿丞宰資陽','韓琦','宋','宋诗','song-poetry','','[]','去物輕遐邑，宸心與近均。',48,'全唐诗/poet.song.18000.json','["去物輕遐邑，宸心與近均。", "宜將寬詔意，善恤遠方民。", "寒驛鳧先下，春郊雉自馴。", "白雲休引望，馨膳有天倫。"]'),
('80683911-1712-4593-825a-b9cbfb56c5e9','次韻和崔象之寺丞西亭雨下','韓琦','宋','宋诗','song-poetry','','[]','初暑軒窗覆翠陰，更宜飛雨濯塵襟。',64,'全唐诗/poet.song.18000.json','["初暑軒窗覆翠陰，更宜飛雨濯塵襟。", "喜花添色自人意，爲歲期豐獨帝心。", "餘潤日隨和氣浹，好聲時逐遠風沉。", "郊原徧採農家議，一寸真如一寸金。"]'),
('c4fce52c-4c8d-401d-badc-535028f1f3b9','庚子重九菊未盛開席上偶成','韓琦','宋','宋诗','song-poetry','','[]','重九開樽節未寒，黄花初發葉皆單。',32,'全唐诗/poet.song.18000.json','["重九開樽節未寒，黄花初發葉皆單。", "待看旬日金鈴綻，剩得東籬一醉歡。"]'),
('fb4afe1f-62bd-4405-9722-9f34c26de856','九日賞菊未開席上次韻答崔象之寺丞','韓琦','宋','宋诗','song-poetry','','[]','誰知九日接賓觴，未放寒花折露房。',64,'全唐诗/poet.song.18000.json','["誰知九日接賓觴，未放寒花折露房。", "早是生來悲晚節，那堪開不在重陽。", "滿頭且應良辰插，一夜寧衰淺意香。", "守待金鈴披絕艷，共君搴蕊醉餘芳。"]'),
('f415182f-673d-45e9-9e61-cfe2bdf04036','覽崔象之寺丞詩編','韓琦','宋','宋诗','song-poetry','','[]','驚人侍句本天成，艷格清奇不易評。',64,'全唐诗/poet.song.18000.json','["驚人侍句本天成，艷格清奇不易評。", "秋月照空澄萬景，洛花無品盡多名。", "珠藏赤水搜求苦，礦出黄金鍛鍊精。", "郊廟有歌猶未採，只輸高興寫幽情。"]'),
('82ac9681-dfbc-415c-9cba-32f32a0439f5','和崔象之紫菊','韓琦','宋','宋诗','song-poetry','','[]','紫菊披風碎曉霞，年年霜挽賞奇葩。',64,'全唐诗/poet.song.18000.json','["紫菊披風碎曉霞，年年霜挽賞奇葩。", "嘉名自合開仙府，麗色何妨奪錦砂。", "雨徑蕭踈凌蘚暈，露叢芬馥敵蘭芽。", "孤標只取當筵重，不似尋常泛酒花。"]'),
('887db8a0-ea53-4a02-8ecd-448217b68ff9','祫享加恩押班宣制','韓琦','宋','宋诗','song-poetry','','[]','大祫休成慶澤新，廣庭宣制寵臣隣。',64,'全唐诗/poet.song.18000.json','["大祫休成慶澤新，廣庭宣制寵臣隣。", "非煙薦瑞籠宮殿，出綍敷言聳搢紳。", "風結冰簷駢玉箸，日融霜瓦半魚鱗。", "移時始放金吾仗，鵷鷺齊飛出禁闉。"]'),
('a641f45a-fd0e-49f8-bbe3-e86825ee2758','辛丑中秋不見月','韓琦','宋','宋诗','song-poetry','','[]','懊惱閑雲取次生，中秋觀月悞人情。',64,'全唐诗/poet.song.18000.json','["懊惱閑雲取次生，中秋觀月悞人情。", "一時雖不充羣望，萬古終難掩至明。", "疑有陰魔憎好事，更虞淫雨害豐盛。", "須知席上徘徊意，直似葵心向日傾。"]'),
('17084384-02e0-436c-b60f-d663a973c4e0','崔象之中舍宰陽翟','韓琦','宋','宋诗','song-poetry','','[]','君於榮利已恬然，此治韓城屬薦賢。',64,'全唐诗/poet.song.18000.json','["君於榮利已恬然，此治韓城屬薦賢。", "惠政即隨春共煦，道心常與月同圓。", "門踈俗客禪詮遠，亭掩修篁定力堅。", "思退幾人曾上籍，可容名記託新篇。"]'),
('64bcddfb-5fd6-403f-8345-f371cd31aa65','辛丑季秋大饗明堂中書宿齋','韓琦','宋','宋诗','song-poetry','','[]','紫極宸居重，黄扉禁戶深。',96,'全唐诗/poet.song.18000.json','["紫極宸居重，黄扉禁戶深。", "齋精嚴帝配，祗翼達天心。", "百刻延壺箭，千廬肅羽林。", "秋聲來易感，仙夢斷難尋。", "小雨隨雲散，踈星伴月沉。", "樹雞先曉唱，菊酒带香斟。", "寂爾潛神化，翛然適道襟。", "惟馨思在德，肸蠁佇靈歆。"]'),
('6db7ef04-6bdb-4832-9317-ca0c7465fbdc','中書東廳十詠 迎春','韓琦','宋','宋诗','song-poetry','','[]','覆欄纖弱綠條長，带雪衝寒拆嫩黄。',32,'全唐诗/poet.song.18000.json','["覆欄纖弱綠條長，带雪衝寒拆嫩黄。", "迎得春來非自足，百花千卉任芬芳。"]'),
('2c2a8d71-2898-41c8-8462-5b4de9ffde0c','中書東廳十詠 牡丹','韓琦','宋','宋诗','song-poetry','','[]','當欄新植盡珍叢，異格同妍出化工。',32,'全唐诗/poet.song.18000.json','["當欄新植盡珍叢，異格同妍出化工。", "何物眾人驚絕艷，一枝花坼瑞雲紅。"]'),
('1c0c68ed-3a2d-4a3e-a5ff-7052d46882d5','中書東廳十詠 夜合','韓琦','宋','宋诗','song-poetry','','[]','合昏枝老拂簷牙，紅白開成蘸暈花。',32,'全唐诗/poet.song.18000.json','["合昏枝老拂簷牙，紅白開成蘸暈花。", "最是清香合蠲忿，累旬風送入窗紗。"]'),
('e6e88541-8d7c-4ea7-856d-72d3281bfc59','中書東廳十詠 四季','韓琦','宋','宋诗','song-poetry','','[]','牡丹殊絕委春風，露菊蕭踈怨晚叢。',32,'全唐诗/poet.song.18000.json','["牡丹殊絕委春風，露菊蕭踈怨晚叢。", "何似此花榮艷足，四時長放淺深紅。"]'),
('9d8cf53f-d6d7-4613-8fba-1e036311dc47','中書東廳十詠 綠篠','韓琦','宋','宋诗','song-poetry','','[]','莫輕叢篠綠陰微，迸笋方抽嫩玉枝。',32,'全唐诗/poet.song.18000.json','["莫輕叢篠綠陰微，迸笋方抽嫩玉枝。", "結實他年臻瑞物，最宜栽向鳳凰池。"]'),
('0998bd12-ad5c-4c78-ad73-6792b805de9f','中書東廳十詠 芎藭','韓琦','宋','宋诗','song-poetry','','[]','蘼蕪嘉種列羣芳，禦濕前推藥品良。',32,'全唐诗/poet.song.18000.json','["蘼蕪嘉種列羣芳，禦濕前推藥品良。", "時摘嫩草烹賜茗，更從雲脚發清香。"]'),
('d7f7e20a-9476-4fc5-90d9-1e28344dac2e','中書東廳十詠 山芋','韓琦','宋','宋诗','song-poetry','','[]','隨竹縈回翠蔓延，土藷名異出前編。',32,'全唐诗/poet.song.18000.json','["隨竹縈回翠蔓延，土藷名異出前編。", "會須霜晚餐珠實，可挹浮后作地仙。"]'),
('d1c81b71-3c0e-4ad3-9c48-3f8ca667ebf7','中書東廳十詠 盆池','韓琦','宋','宋诗','song-poetry','','[]','圓沼泓登璧彩浮，萍新殊未覆游鯈。',32,'全唐诗/poet.song.18000.json','["圓沼泓登璧彩浮，萍新殊未覆游鯈。", "纖鱗不用時驚沒，香餌雖投是直鈎。"]'),
('c63ea295-0756-4169-87e2-1bbb9e54f389','中書東廳十詠 假山','韓琦','宋','宋诗','song-poetry','','[]','危峰疊疊起丸泥，莫愛幽奇是假爲。',32,'全唐诗/poet.song.18000.json','["危峰疊疊起丸泥，莫愛幽奇是假爲。", "黄閣何功宜自劾，去尋真隱老衰疲。"]'),
('4eed04b6-9b19-4db4-aecf-08b3b209e27b','中書東廳十詠 馴鵲','韓琦','宋','宋诗','song-poetry','','[]','靈鵲雙雙日自馴，徘徊軒檻若相親。',32,'全唐诗/poet.song.18000.json','["靈鵲雙雙日自馴，徘徊軒檻若相親。", "主人素解忘榮辱，何用喃喃送喜頻。"]'),
('0d84d1ee-7ea1-40af-a76d-7b06597e968a','崔象之宰韓城','韓琦','宋','宋诗','song-poetry','','[]','去年同舉菊花觴，自揭清音入醉鄉。',64,'全唐诗/poet.song.18000.json','["去年同舉菊花觴，自揭清音入醉鄉。", "此日高秋來一別，幾旬佳節負重陽。", "風生古操安新治，雨徹踈茅鎖舊堂。", "民里更繁應自化，宰君心地本空王。"]'),
('72bc639e-80d7-4637-ad1d-83acd69d2839','駕幸西太一宮祈雨','韓琦','宋','宋诗','song-poetry','','[]','曉蹕聲乾下九重，西郊岑寂款琳宮。',64,'全唐诗/poet.song.18000.json','["曉蹕聲乾下九重，西郊岑寂款琳宮。", "驕陽尚作三春旱，多稼期霑一雨豐。", "恤物致虔歸上德，應誠爲答即神聰。", "從來聖感無旋日，不在商巖傅說功。"]'),
('e0c7ccd5-ec7f-418d-8b5e-20ddd8f58962','駕幸西太一宮道傍耕桑者皆以茶絹賜之','韓琦','宋','宋诗','song-poetry','','[]','杪春時澤未全滂，西禱真祠徯福祥。',64,'全唐诗/poet.song.18000.json','["杪春時澤未全滂，西禱真祠徯福祥。", "蠶女捨籠驚法從，耕夫投耒目天光。", "勞勤率有優恩及，拜賜皆知佚道長。", "海內承風誰不勸，何須躬籍與躬桑。"]'),
('152e483e-3740-4b3d-bbb5-cda00bbf1806','駕幸西太一宮陌上耕者叱牛聲厲左右皆笑之','韓琦','宋','宋诗','song-poetry','','[]','皇心憫雨出西坰，親禱靈宮致潔誠。',32,'全唐诗/poet.song.18000.json','["皇心憫雨出西坰，親禱靈宮致潔誠。", "扈蹕不知農事苦，輦前爭笑叱牛聲。"]'),
('587264a0-8373-4ae2-85e4-237845c22107','駕幸西太一宮謝雨','韓琦','宋','宋诗','song-poetry','','[]','太一尊神宅近坰，特紆天仗乞殊靈。',64,'全唐诗/poet.song.18000.json','["太一尊神宅近坰，特紆天仗乞殊靈。", "清衷祠禱才三日，大澍滂沱足四溟。", "上釋憂勞嚴報謝，民祛愁鬰得康寧。", "至誠有答真如響，更異言閒退守星。"]'),
('9bd9b635-41b7-4868-b99a-d70f12582936','從駕過金明池','韓琦','宋','宋诗','song-poetry','','[]','帳殿深沉壓水開，幾時宸輦一遊來。',64,'全唐诗/poet.song.18000.json','["帳殿深沉壓水開，幾時宸輦一遊來。", "春留苑樹陰成幄，雨漲池波色染苔。", "空外長橋橫螮蝀，城邊真境闢蓬萊。", "匪朝侍宴臨彫檻，共看龍艘奪錦回。"]'),
('a0628ddd-ccda-40e9-a089-70b9f36a7895','駕幸金明池','韓琦','宋','宋诗','song-poetry','','[]','西池風景出塵寰，春豫方乘禁坐閑。',64,'全唐诗/poet.song.18000.json','["西池風景出塵寰，春豫方乘禁坐閑。", "庶俗一令趨壽域，從官齊許宴蓬山。", "樓臺金碧芳菲心，舟楫笙歌浩渺間。", "與眾盡歡宮漏促，萬花香裏屬車還。"]'),
('8103219b-be7a-4ab5-bec0-b274926f8f6e','寄崔象之國博','韓琦','宋','宋诗','song-poetry','','[]','知君爲邑解銅章，却復先廬坐葆光。',64,'全唐诗/poet.song.18000.json','["知君爲邑解銅章，却復先廬坐葆光。", "對境風幡俱不問，安禪心法兩皆忘。", "滿庭脩竹爭高節，近砌幽蘭稱獨芳。", "若論厭喧遭拄杖，何如趣駕返周行。"]'),
('29464bf6-fde7-4274-aa0a-278470ec7c0a','甲辰景靈宿齋謝雨','韓琦','宋','宋诗','song-poetry','','[]','邃寂敞仙扃，心齋物外清。',48,'全唐诗/poet.song.18000.json','["邃寂敞仙扃，心齋物外清。", "滂沲今應禱，肸蠁此通誠。", "月殿栖真境，風梧醒睡聲。", "如何謝靈貺，至道本難名。"]'),
('54209aab-64fa-4f0d-8ca4-ffd0d47138c5','癸卯喜雪','韓琦','宋','宋诗','song-poetry','','[]','一夜陰雲匝四溟，朝來嘉雪灑寰瀛。',64,'全唐诗/poet.song.18000.json','["一夜陰雲匝四溟，朝來嘉雪灑寰瀛。", "因風絮起先春媚，剪水花飛到地輕。", "天際定迷瓊蕊屑，世間今有玉樓成。", "應時何止銷民疹，直壓胡沙萬里清。"]'),
('c2b4be09-3c21-43bc-a1b0-7f2b04658ed7','聞崔公孺國博將入都近重九未至','韓琦','宋','宋诗','song-poetry','','[]','幾日知君命駕來，芳辰看失獨徘徊。',32,'全唐诗/poet.song.18000.json','["幾日知君命駕來，芳辰看失獨徘徊。", "黄封御酒新霑賜，更偶金鈴菊未開。"]'),
('2f0c45a6-e0f6-43c1-8cf2-00f2c27bfcc7','晚秋有感','韓琦','宋','宋诗','song-poetry','','[]','倦鵲穿林趁獨棲，此情唯有老鰥知。',32,'全唐诗/poet.song.18000.json','["倦鵲穿林趁獨棲，此情唯有老鰥知。", "西風日緊重陽近，忍對黄花把酒巵。"]'),
('578f2368-358a-4bf5-9095-c731b4236632','次韻答崔公孺國博','韓琦','宋','宋诗','song-poetry','','[]','向陪亡室鶺鴒原，正是輕霜九日天。',64,'全唐诗/poet.song.18000.json','["向陪亡室鶺鴒原，正是輕霜九日天。", "醉語忘形幾爾汝，詩毫揮紙速雲烟。", "思窮碧落今無術，淚灑黄花兩換年。", "一覽嘉章生百恨，孤懷還昧覺心圓。"]'),
('db04d7ae-07f3-4b34-a442-f361a103989c','先君寫真得永叔爲之贊而君謨書其側崔公孺國博以詩稱美次韻答之','韓琦','宋','宋诗','song-poetry','','[]','遷筆褒揚逸少書，孤風拂拂起襟裾。',64,'全唐诗/poet.song.18000.json','["遷筆褒揚逸少書，孤風拂拂起襟裾。", "孝心知覩英靈在，世系元承福慶餘。", "永向浄居同相好，任從深谷改丘墟。", "君詩意主稱人善，義節軒然到古初。"]'),
('0ce4b3a1-53a9-4504-ab1d-1313a8da2a1f','次韻和崔公孺國博觀君謨所書孝親崇福院牌','韓琦','宋','宋诗','song-poetry','','[]','欲護親塋薦福殊，僧藍營葺幾年餘。',64,'全唐诗/poet.song.18000.json','["欲護親塋薦福殊，僧藍營葺幾年餘。", "名因先帝鴻恩錫，牌得君謨大字書。", "佛宇增輝良自爾，鄉廬傳美孰加予。", "須知體法多奇處，深造鍾王奧妙墟。"]'),
('74c24a71-1061-4507-82e9-d8280f2c4143','次韻和崔公孺國博觀新模鄴王書','韓琦','宋','宋诗','song-poetry','','[]','唐季諸侯孰擅雄，鄴邦高襲世勳洪。',64,'全唐诗/poet.song.18000.json','["唐季諸侯孰擅雄，鄴邦高襲世勳洪。", "圖功自可超煙閣，接士殊優在雪宮。", "刀筆風流爭戰外，生靈安帖笑談中。", "詩豪墨妙家藏久，二美刊傳定不窮。"]'),
('f7cc2627-7c3c-4f70-9227-ed5836a4762d','次韻和崔公孺國博觀新模正獻杜公草書','韓琦','宋','宋诗','song-poetry','','[]','珍藏正獻草書詩，傳誡雲來示永貽。',64,'全唐诗/poet.song.18000.json','["珍藏正獻草書詩，傳誡雲來示永貽。", "幾夜風濤偃松柏，半天雷雨起蛟螭。", "臨池學苦應同妙，舞劍功如未是奇。", "刊石豈徒爲世玩，更思清節可師之。"]'),
('400e3679-b151-43c6-8ef2-02aa7953a0cd','次韻和崔公孺國博模刻文正范公閱古堂詩','韓琦','宋','宋诗','song-poetry','','[]','閱古堂成在北邊，希文詩筆美前賢。',64,'全唐诗/poet.song.18000.json','["閱古堂成在北邊，希文詩筆美前賢。", "高吟尚紀終軍策，小字如觀樂毅篇。", "欲起貴名增世慕，更刊餘禮廣人傳。", "其他事業知難泯，盡入仁宗實錄編。"]'),
('68d83053-7450-43f6-bfc1-5c36c77ba815','次韻答崔公孺國博西亭感懷','韓琦','宋','宋诗','song-poetry','','[]','常喜交親燕此中，忽移歡緒作悲翁。',64,'全唐诗/poet.song.18000.json','["常喜交親燕此中，忽移歡緒作悲翁。", "桃陰已盛何曾語，檜影長閑不厭風。", "數漏趁朝心拱北，忍饑開閣客盈東。", "人生易別須偷暇，爲我樽前話苦空。"]'),
('ed1edfe9-40bc-45fe-b85a-a47b1e6ea67e','甲辰冬雨','韓琦','宋','宋诗','song-poetry','','[]','凜氣回輕燠，凉飚絕怒號。',96,'全唐诗/poet.song.18000.json','["凜氣回輕燠，凉飚絕怒號。", "飛霙難自拆，細雨反如繅。", "惠澤非常降，祥編想共襃。", "民閻清歲癘，農畝得春膏。", "天意雖滂洽，人心尚鬰陶。", "未逢銀甕出，不見玉樓高。", "酒興來差淺，詩情病少豪。", "曾看紛似絮，舉白待風騷。"]'),
('59631d9d-95bf-4a0b-99e7-3ef0463eecfb','留崔公孺國博','韓琦','宋','宋诗','song-poetry','','["\u897f\u6e56"]','虛亭還喜叩禪詮，頓覺襟懷鄙吝捐。',64,'全唐诗/poet.song.18000.json','["虛亭還喜叩禪詮，頓覺襟懷鄙吝捐。", "陶暑屢開河朔飲，聚星看別潁川賢。", "我縻東府成衰叟，君向西湖即洞天。", "且緩歸期時一笑，及瓜趨闕動三年。"]'),
('63fdbec6-25a1-473d-bb3d-f6fe60e47f32','乙巳重九','韓琦','宋','宋诗','song-poetry','','[]','苦厭繁機少適懷，欣逢重九啟賓罍。',64,'全唐诗/poet.song.18000.json','["苦厭繁機少適懷，欣逢重九啟賓罍。", "招賢敢並翹材館，樂事難追戲馬臺。", "蘚布亂錢乘雨出，雁排新陣拂雲來。", "何年得遇樽前菊，此日花隨月令開。"]'),
('293d4b0c-6473-4997-829b-62cee88deec5','乙巳郊禮慶成五言二十韻','韓琦','宋','宋诗','song-poetry','','[]','堯曆方歸聖，虞琴始就聲。',240,'全唐诗/poet.song.18000.json','["堯曆方歸聖，虞琴始就聲。", "不先惟帝饗，孰見事天明。", "穀旦諏陽復，鴻儀備吉行。", "宸襟正祗謹，陰孽忽孳萌。", "淫雨頻興陣，寒花幾墜瓊。", "多言摇改卜，上意益專精。", "宗社敷冥祐，穹蒼答至誠。", "斗收連日晦，併與祀時晴。", "待曉披閶闔，凝旒下紫清。", "真廷陳潔饌，親廟展嘉牲。", "愛旭輝黄道，非煙護綵城。", "旌旗停藻衛，鐃吹起嚴更。", "冕服祛繁飾，壇壝即自成。", "晶熒奠琮璧，和雅薦英莖。", "繼志還虛次，尊神戒側迎。", "千齡俄受胙，萬乘已旋衡。", "嶢闕層霄迥，通衢眾目傾。", "疏刑空犴獄，霈澤浹寰瀛。", "統業恢長治，生靈入太平。", "因知却徽號，傳蹟固難名。"]'),
('9cfff53c-9190-47ea-b976-52b0e24b5177','次韻和崔公孺國博西亭感懷','韓琦','宋','宋诗','song-poetry','','[]','常虛西館待高賢，一見襟懷兩釋然。',64,'全唐诗/poet.song.18000.json','["常虛西館待高賢，一見襟懷兩釋然。", "且叩真詮期進道，不論衰鬢逐凋年。", "頑金在礦須當變，逸驥無鞭亦自前。", "相叩屢辭雖未得，已齊朝市與林泉。"]'),
('a31733b2-d3ea-4c23-a149-1fefd8118e04','感春貽崔公孺國博','韓琦','宋','宋诗','song-poetry','','[]','春來天氣作輕寒，故使春芳欲見難。',64,'全唐诗/poet.song.18000.json','["春來天氣作輕寒，故使春芳欲見難。", "賴得好風攄俗憤，頓開韶景與人看。", "詩情遇敵豪雖減，杯興逢辰老未闌。", "幸遇親朋時枉駕，且偷壺刻奉清歡。"]'),
('ef8f5cf5-30e4-497a-8df4-08e7839868a1','次韻和崔公孺國博黄杏花','韓琦','宋','宋诗','song-poetry','','[]','顆顆裝成藥竈牙，日邊開處近彤霞。',64,'全唐诗/poet.song.18000.json','["顆顆裝成藥竈牙，日邊開處近彤霞。", "真宜相閣栽培物，更是仙人種植花。", "高行出羣猶仰慕，香名超格合洪誇。", "諸賢繼有尋芳會，欲奉歡游決自差。"]'),
('1983adfe-8169-4bae-9e50-2f53484b389e','貽崔公孺國博','韓琦','宋','宋诗','song-poetry','','[]','三十年來契分隆，更從親炙達真空。',64,'全唐诗/poet.song.18000.json','["三十年來契分隆，更從親炙達真空。", "明非獨善諸昏破，理到無心萬事通。", "莫話離悰傷祖席，且留歡刻醉春風。", "海棠亭下花看發，壞子臙脂點點紅。"]'),
('241ed6f7-8741-4fbd-ad65-e8b751994d3a','次韻和崔公孺國博遊興國寺廣嚴院','韓琦','宋','宋诗','song-poetry','','[]','紺園南北壓通寰，氣象超然出世間。',64,'全唐诗/poet.song.18000.json','["紺園南北壓通寰，氣象超然出世間。", "只見莊嚴尊十地，不須微瑣說三山。", "浮雲自縛春春失，真境無塵事事閑。", "我有歸依殊勝願，吏文常擾幾時還。"]'),
('b235ded0-1e86-4597-bcb2-f4047ba73437','次韻答崔公孺國博西亭燕飲','韓琦','宋','宋诗','song-poetry','','[]','一稔繁機困備員，芳時何暇目春妍。',64,'全唐诗/poet.song.18000.json','["一稔繁機困備員，芳時何暇目春妍。", "自慚東閣延才地，得會西豪聚里賢。", "益友至言皆有味，禪宗高論邈無邊。", "須知樽酒相留意，老去離懷異少年。"]'),
('7f23deb6-0a9a-4c1b-8b16-92277e82189f','丙午上巳瓊林苑賜筵','韓琦','宋','宋诗','song-poetry','','[]','春光濃簇寶津樓，樓下新波漲鴨頭。',64,'全唐诗/poet.song.18000.json','["春光濃簇寶津樓，樓下新波漲鴨頭。", "嘉節難逢真上巳，賜筵榮入小瀛洲。", "仙園雨過花遺靨，御陌風長絮走球。", "禊飲不須辭巨白，清明來日尚歸休。"]'),
('12ff1562-7158-43ce-93c4-b1c01ec4a561','首夏西亭','韓琦','宋','宋诗','song-poetry','','[]','一霎輕塵小雨過，園林風物尚清和。',64,'全唐诗/poet.song.18000.json','["一霎輕塵小雨過，園林風物尚清和。", "巢棲舊燕將成子，盆植新蓮未出荷。", "欲就好峰添異石，惡侵芳卉劚狂莎。", "病襟蕭索賓如市，孤負良辰樂事多。"]'),
('8dc06a1d-de37-49e4-83c8-6a5784ece1f8','召赴天章閣觀新刻仁宗御詩','韓琦','宋','宋诗','song-poetry','','[]','天閣當年拂霧宣，紫皇端扆侍羣仙。',64,'全唐诗/poet.song.18000.json','["天閣當年拂霧宣，紫皇端扆侍羣仙。", "親揮龍鳳軒騰字，命繼咸韶雅正篇。", "勸酌屢行均聖寵，賜花中出奪春妍。", "玉峯光景都如舊，但睇宸章極泫然。"]'),
('be806f78-a771-43a2-b0fe-32d63f439ca8','次韻和崔國博西亭喜雨','韓琦','宋','宋诗','song-poetry','','[]','暑雨滂然僅作霖，連宵殊未擴陰森。',64,'全唐诗/poet.song.18000.json','["暑雨滂然僅作霖，連宵殊未擴陰森。", "全祛下土將焚患，盡識高穹不忍心。", "斗厭埃氛開眾目，了無煩熱自吾襟。", "當軒倍勝松風過，何必清音一弄琴。"]'),
('14237eae-2a9f-4123-8af7-b5f7737d05df','永興寒食後池','韓琦','宋','宋诗','song-poetry','','[]','春意陰陰百五天，小池蕭索會僚賢。',64,'全唐诗/poet.song.18000.json','["春意陰陰百五天，小池蕭索會僚賢。", "孤芳映水花終淡，勁竹凌軒節自全。", "一陣森嚴林勢合，萬魚跳落雨痕圓。", "當筵暫弭憂邊慮，且伏詩魔駕酒船。"]'),
('f81837c0-cc7a-43d6-b937-dbc23462859d','席上自和','韓琦','宋','宋诗','song-poetry','','[]','喜陶嘉節曲池邊，薄酒何須辨聖賢。',64,'全唐诗/poet.song.18000.json','["喜陶嘉節曲池邊，薄酒何須辨聖賢。", "談席且誇珠履盛，種羌誰問蟻封全。", "白楊花落眠蠶老，紅杏枝殘笑靨圓。", "不似丁年爲帥日，醉鄉方擬拍浮船。"]'),
('8e2462b8-78aa-4467-aa2a-43ae9019bbd2','清明興慶池上','韓琦','宋','宋诗','song-poetry','','[]','連日陰岑此日晴，池頭風物稱清明。',64,'全唐诗/poet.song.18000.json','["連日陰岑此日晴，池頭風物稱清明。", "萬鱗潛養雲頭坼，一鑑新開水面平。", "兩兩鳧鷖波上沒，憧憧車馬柳間行。", "嘉賓須惜難并會，莫厭芳樽冷淡傾。"]'),
('3a21b04f-7979-40c1-95db-c96bb1afbd7d','垂蘿洞','韓琦','宋','宋诗','song-poetry','','[]','池北如趨紫府家，亭臺高下景無涯。',64,'全唐诗/poet.song.18000.json','["池北如趨紫府家，亭臺高下景無涯。", "垂楊下絆遊春騎，曲水時飄出洞花。", "萬本竹深叢劍戟，一軒藤老纏龍蛇。", "使君欲共斯民樂，莫顧西山下日車。"]'),
('52448acc-3241-48ef-a5e2-fe18d5519578','上巳會興慶池二首  其一','韓琦','宋','宋诗','song-poetry','','[]','元巳開樽處，垂蘿碧洞前。',48,'全唐诗/poet.song.18000.json','["元巳開樽處，垂蘿碧洞前。", "綺羅明浩渺，臺榭插漪漣。", "曲水來如篆，輕橈去若仙。", "春寒芳意晚，未見柳飛綿。"]'),
('ca401191-4ddf-44fc-91de-a6be0384f043','上巳會興慶池二首  其二','韓琦','宋','宋诗','song-poetry','','[]','興慶池頭三月三，柳如拖綬草如衫。',64,'全唐诗/poet.song.18000.json','["興慶池頭三月三，柳如拖綬草如衫。", "禊觴臨水筵相屬，文鷁凌波尾競銜。", "花雨亂飛紅撲蔌，峯螺遥聳碧嶄巖。", "芳辰況任游人樂，不必低將席帽攙。"]'),
('f259e5db-8b29-4896-8712-82c05e89ac00','上巳晚遊九曲池','韓琦','宋','宋诗','song-poetry','','[]','九曲池邊第一開，艤舟同賞盡高才。',64,'全唐诗/poet.song.18000.json','["九曲池邊第一開，艤舟同賞盡高才。", "彎流自得黄河勢，怪石應從紫閣來。", "塵外恍迷仙境界，竹間深有古亭臺。", "徘徊復至豐碑下，花萼吁嗟作盜灰。"]'),
('60865739-8d68-438f-aebd-bfe69ffba548','春陰馬上','韓琦','宋','宋诗','song-poetry','','[]','正是風和日暖天，重陰凌擾苦纏綿。',64,'全唐诗/poet.song.18000.json','["正是風和日暖天，重陰凌擾苦纏綿。", "蕉心自結憑誰展，柳眼慷開只待眠。", "草濕謾鋪留醉席，榆寒難擲買春錢。", "幾時霞外氛霾散，放出紅輪一丈圓。"]'),
('f50d6027-5b67-4472-b171-56962831619d','聞轉運范純仁司封會興慶池','韓琦','宋','宋诗','song-poetry','','[]','池榭春深合眾芳，使臺來賞好風光。',64,'全唐诗/poet.song.18000.json','["池榭春深合眾芳，使臺來賞好風光。", "波頭灧日琉璃軟，酒面摇花琥珀香。", "訪古舊文昏琬琰，記游新刻上篔簹。", "臨歸定借西園步，愈覺禪詮氣味長。"]'),
('fdbf5d14-7b33-4671-a17d-784b33dfccc2','登廣教院閣','韓琦','宋','宋诗','song-poetry','','[]','岑寂禪扉啟晝關，公餘爲會一開顔。',64,'全唐诗/poet.song.18000.json','["岑寂禪扉啟晝關，公餘爲會一開顔。", "高臺面壘包平野，老柏參天礙遠山。", "花去春叢蝴蝶亂，雨勻朝圃桔槹閑。", "徘徊軒檻何時下，直待前枝倦鵲還。"]'),
('70bc1976-9c76-445c-87e7-f35512f0f85b','賞北禪牡丹','韓琦','宋','宋诗','song-poetry','','[]','一春顔色與花王，況在莊嚴北道場。',64,'全唐诗/poet.song.18000.json','["一春顔色與花王，況在莊嚴北道場。", "美艷且推三輔冠，嘉名誰較兩京强。", "已攢仙府霞爲葉，更奪熏爐麝作香。", "會得輕寒天意緒，故延芳景助飛觴。"]'),
('ef80276f-83ca-4a42-b83c-154108eb3805','次韻和都運孫永待制廣教院三頭牡丹','韓琦','宋','宋诗','song-poetry','','[]','駢枝三出牡丹紅，奇有雙頭結未工。',32,'全唐诗/poet.song.18000.json','["駢枝三出牡丹紅，奇有雙頭結未工。", "宛似靈芝相並秀，瑞雲攢處起香風。"]'),
('6d12b8b8-a6d7-400e-a847-177e63250a89','賞西禪牡丹','韓琦','宋','宋诗','song-poetry','','[]','幾酌西禪對牡丹，穠芳還似北禪看。',64,'全唐诗/poet.song.18000.json','["幾酌西禪對牡丹，穠芳還似北禪看。", "千球紫繡擎熏炷，萬葉紅雲砌寶冠。", "直把醉容欺玉斝，滿將春色上金盤。", "魏花一本須稱后，十朵齊開面曲欄。"]'),
('fcabf2d0-af82-419d-b1fe-b22a6166f924','四月望日會興慶池','韓琦','宋','宋诗','song-poetry','','[]','莫厭煩蒸共此行，臨流臺榭極高明。',64,'全唐诗/poet.song.18000.json','["莫厭煩蒸共此行，臨流臺榭極高明。", "風前自得披襟興，林杪時聞脫袴聲。", "洞竹交陰冠蓋爽，砌泉爭響夢魂清。", "憑軒最切雲霓望，日待民田雨足耕。"]'),
('aa1d23f3-cac2-4703-af2f-c5ec63472273','送湫馬上始見終南','韓琦','宋','宋诗','song-poetry','','[]','終南頻月晦峯巒，一雨民心萬事寬。',64,'全唐诗/poet.song.18000.json','["終南頻月晦峯巒，一雨民心萬事寬。", "救徹旱苗充歲望，洗開山色與人看。", "半天橫示全秦壯，積雪高連太白寒。", "欲識眾多欣幸意，送湫歌舞滿長安。"]'),
('b152959c-a910-43f2-869a-bc80d9f51725','會故集賢崔侍郎園池','韓琦','宋','宋诗','song-poetry','','[]','崔園高絕五門西，塵外風光是處宜。',64,'全唐诗/poet.song.18000.json','["崔園高絕五門西，塵外風光是處宜。", "唐室舊池因地得，漢宮遺址上樓知。", "青螺萬嶺前爲障，碧玉千竿近作籬。", "我住鄴臺殊草創，一來尤覺愬歸遲。"]'),
('43a10e71-a3cf-479b-a249-ef7c523427a5','再賦','韓琦','宋','宋诗','song-poetry','','[]','門徑縈紆洞府間，了無塵外累幽閑。',64,'全唐诗/poet.song.18000.json','["門徑縈紆洞府間，了無塵外累幽閑。", "長楊十丈亂風雨，流水數枝鳴珮環。", "入戶好峰誰可畫，礙人新竹不容刪。", "池亭面面圓荷滿，薄暮飛香送客還。"]'),
('c8a6d5e4-08ea-47f6-8d5b-e30f2774650a','登崔園城上亭','韓琦','宋','宋诗','song-poetry','','[]','危榭厭頹基，登臨事可悽。',48,'全唐诗/poet.song.18000.json','["危榭厭頹基，登臨事可悽。", "邱墟唐殿左，禾黍漢宮西。", "臺古疑藏劍，峯遥不見圭。", "山川難盡識，賴有舊圖携。"]'),
('c8c604f1-e762-4865-b726-50d95cc18148','覽諸人贈狄國賓察推詩','韓琦','宋','宋诗','song-poetry','','[]','凜凜梁公萬世尊，復唐功業並乾坤。',64,'全唐诗/poet.song.18000.json','["凜凜梁公萬世尊，復唐功業並乾坤。", "爲臣所守能忠義，異代猶思錄子孫。", "老嗣寂寥雖未振，大名瞻仰只如存。", "後人真有希顔志，豈特孤風擅一門。"]'),
('cb40704e-7f98-4858-971c-459d1f4bbe97','送范純仁司封移漕京西','韓琦','宋','宋诗','song-poetry','','[]','衰拙何堪定繹騷，使臺猶喜會英髦。',64,'全唐诗/poet.song.18000.json','["衰拙何堪定繹騷，使臺猶喜會英髦。", "治財絕擾常先恕，移用皆宜似不勞。", "此去任賢終漕輓，幾時當路壓風濤。", "家聲莫擬君能紹，日看青雲步步高。"]'),
('1b58fb0d-d284-406d-a3dd-395cc1a1a528','凉榭池上二闋  其一','韓琦','宋','宋诗','song-poetry','','[]','游鱗驚觸綠荷香，水馬成羣股脚長。',32,'全唐诗/poet.song.18000.json','["游鱗驚觸綠荷香，水馬成羣股脚長。", "逐浪相追留篆跡，偃波垂露滿芳塘。"]'),
('e18ce825-d061-440a-9cc7-7903a9326d37','凉榭池上二闋  其二','韓琦','宋','宋诗','song-poetry','','[]','病襟思適繞東塘，水荇初花吐嫩黄。',32,'全唐诗/poet.song.18000.json','["病襟思適繞東塘，水荇初花吐嫩黄。", "行困老樗陰下坐，兒童爭喜拾紅娘。"]'),
('6ed8d36a-e439-4779-a1cb-3ecb0d0e0b0e','長安府舍十詠 流泉','韓琦','宋','宋诗','song-poetry','','[]','龍首高源析，螭吭亂玉鏘。',48,'全唐诗/poet.song.18000.json','["龍首高源析，螭吭亂玉鏘。", "带花春共遠，和雨夜何長。", "冷撼青蛇影，平拖白練光。", "煩襟來自滌，可待濯滄浪。"]'),
('08444275-eb88-4460-b568-dba95077f87d','長安府舍十詠 凉榭','韓琦','宋','宋诗','song-poetry','','[]','忠閔規摹壯，耽然大厦開。',48,'全唐诗/poet.song.18000.json','["忠閔規摹壯，耽然大厦開。", "無時佳燕在，正暑好風來。", "池面飛泉落，林端畏景回。", "誰知仙府路，瓊室與瑶臺。"]'),
('e0af5ace-90a0-407f-b430-26f46b314207','長安府舍十詠 北塘','韓琦','宋','宋诗','song-poetry','','[]','臺榭生凉處，奫淪瞰北塘。',48,'全唐诗/poet.song.18000.json','["臺榭生凉處，奫淪瞰北塘。", "松筠成夏陰，蓮芰入秋香。", "踈雨交寒暈，輕雲襯曉光。", "無心投釣餌，游鯉莫驚藏。"]'),
('970c0f52-63fa-4aff-84e2-9a2a7fb9baa8','長安府舍十詠 雙石','韓琦','宋','宋诗','song-poetry','','[]','雙石唐餘物，來茲孰記年。',48,'全唐诗/poet.song.18000.json','["雙石唐餘物，來茲孰記年。", "嵌空危砌下，怪醜好花前。", "名氏坳猶刻，藤蘿穴任穿。", "最宜秋後看，班駁蘚痕圓。"]'),
('9edbddb4-bb8f-4da2-8968-bc10bcd6b889','長安府舍十詠 月臺','韓琦','宋','宋诗','song-poetry','','[]','待月西臺早，移時凭曲欄。',48,'全唐诗/poet.song.18000.json','["待月西臺早，移時凭曲欄。", "雲端開玉葉，海面起金盤。", "燕席通宵雅，凉波入坐寒。", "香風來不斷，清露裛紅蘭。"]'),
('ba16ed87-351e-4c89-adf1-a7f651ffc5a2','長安府舍十詠 池亭','韓琦','宋','宋诗','song-poetry','','[]','亭出水中央，輕風四面凉。',48,'全唐诗/poet.song.18000.json','["亭出水中央，輕風四面凉。", "岸平飛略彴，波暖戲鴛鴦。", "靜夜蟾蜍落，清秋菡萏芳。", "公餘時獨坐，萬慮默皆忘。"]'),
('ee4676bf-4c69-4d25-9e4c-855f15ce5754','長安府舍十詠 山樓','韓琦','宋','宋诗','song-poetry','','[]','西北高樓上，南山日面欄。',48,'全唐诗/poet.song.18000.json','["西北高樓上，南山日面欄。", "勢籠秦地勝，陰落渭波寒。", "带雨新屏活，穿雲古道難。", "仙扃如可造，便擬挂朝冠。"]'),
('0571bfde-72a1-4aef-b761-fe36b17920a9','長安府舍十詠 流杯','韓琦','宋','宋诗','song-poetry','','[]','迢遞穿花出，彎環作篆來。',48,'全唐诗/poet.song.18000.json','["迢遞穿花出，彎環作篆來。", "若非天上醴，不泛洞中杯。", "水鳥浮還沒，仙航去復回。", "蓬瀛真境事，銷得玉山頹。"]'),
('9f0712ab-2cee-42d7-84aa-8ed1b7b2a328','長安府舍十詠 石林','韓琦','宋','宋诗','song-poetry','','[]','叢石競嶄巖，當軒翠撲嵐。',48,'全唐诗/poet.song.18000.json','["叢石競嶄巖，當軒翠撲嵐。", "疑峯何啻九，仙島迥侔三。", "潤極雲猶抱，溫多玉尚含。", "樓高慵引望，坐看小終南。"]'),
('b9d03df4-297f-4540-8e45-52c6b1ad590d','長安府舍十詠 竹徑','韓琦','宋','宋诗','song-poetry','','[]','北榭層基下，森森竹徑幽。',48,'全唐诗/poet.song.18000.json','["北榭層基下，森森竹徑幽。", "枝繁低拂蓋，根密僅通流。", "勁節輕環粉，狂鞭怒走虬。", "風霜胡可動，松柏乃吾儔。"]'),
('4e1a4651-7873-4fc4-a1a4-faa0a6f5753b','題致政趙剛大卿卧雲堂','韓琦','宋','宋诗','song-poetry','','[]','一掛朝冠謝世紛，終南高隱邈難羣。',64,'全唐诗/poet.song.18000.json','["一掛朝冠謝世紛，終南高隱邈難羣。", "不容聖治詢黄髮，徑宅幽巖卧白雲。", "書簏遶牀唯我伴，磴泉喧枕乃予聞。", "此時誰可攀真馭，應有浮邱解挹君。"]'),
('f5edbca3-72c4-4a67-abad-fafe64143786','題致政趙剛大卿宴息堂','韓琦','宋','宋诗','song-poetry','','[]','家園休息敞虛堂，直造希夷境外鄉。',64,'全唐诗/poet.song.18000.json','["家園休息敞虛堂，直造希夷境外鄉。", "無物不推山下勝，有花皆似洛中芳。", "荷裁萬扇悲長信，笋擲千簪醉孟嘗。", "子藹令名居自足，主公襟韻日康强。"]'),
('35e984a0-29f5-4be2-972b-e4a6ba801e55','戊申末伏與立秋同日','韓琦','宋','宋诗','song-poetry','','[]','末伏居嘗極藴隆，今辰俄與立秋同。',64,'全唐诗/poet.song.18000.json','["末伏居嘗極藴隆，今辰俄與立秋同。", "雖餘暴虐難禁暑，奈有蕭騷已至風。", "冰出魏臺猶示貴，扇思班篋欲收功。", "從茲漸入清凉境，林嘒寒蟬露曖空。"]'),
('40d19328-469b-4d6a-bab3-db07ee4ace88','初發長安遇雨','韓琦','宋','宋诗','song-poetry','','[]','九龍朝發起程初，甘澤滂然灑路衢。',64,'全唐诗/poet.song.18000.json','["九龍朝發起程初，甘澤滂然灑路衢。", "敢倦征途泥沒踝，且觀嘉穀秀垂珠。", "高原直瀉波頭惡，弊繖平穿陣勢粗。", "繡嶺任遥須趁宿，蓮花湯下洗塵軀。"]'),
('a448fae2-0033-419a-bee7-6cfa2617855c','題靈泉觀','韓琦','宋','宋诗','song-poetry','','[]','老木陰森蓋滿山，蕭條宮展倚巑岏。',64,'全唐诗/poet.song.18000.json','["老木陰森蓋滿山，蕭條宮展倚巑岏。", "留爲治世無窮戒，自足明皇數紀歡。", "舊浴已殘湯室暖，餘悲尚慘渭川寒。", "欲知百二關河勝，更待朝元閣上看。"]'),
('67a611e6-f85c-49de-9bba-19b6a7d05f7c','題溫湯','韓琦','宋','宋诗','song-poetry','','[]','康定西征始壯餘，往還休此任馳驅。',32,'全唐诗/poet.song.18000.json','["康定西征始壯餘，往還休此任馳驅。", "白頭又罷咸秦帥，却向溫湯浴病膚。"]'),
('7f53e993-eb37-457e-a7ce-afd01293d57e','題朝元閣','韓琦','宋','宋诗','song-poetry','','[]','試往驪山頂上行，朝元孤絕聳崢嶸。',64,'全唐诗/poet.song.18000.json','["試往驪山頂上行，朝元孤絕聳崢嶸。", "了無樓殿嗟餘侈，自見耕桑復太平。", "兩後綠苔多滑徑，葉間紅子不知名。", "南巔更就丹霞挹，頓覺尫然病骨清。"]'),
('4f6ce40b-85af-43b2-8a40-95195a118257','遊石甕寺路險而返','韓琦','宋','宋诗','song-poetry','','[]','古寺跨山椒，虛明瞰泬寥。',48,'全唐诗/poet.song.18000.json','["古寺跨山椒，虛明瞰泬寥。", "路危難進馬，林密不容樵。", "飛瀑連雲濕，凝嵐带雨饒。", "崖窮徒一望，歸步默無聊。"]'),
('4d4548a1-91f1-4c3f-902f-d070d0e8f0aa','靈泉覽古','韓琦','宋','宋诗','song-poetry','','[]','靈館驪山下，開元迹尚遺。',96,'全唐诗/poet.song.18000.json','["靈館驪山下，開元迹尚遺。", "蓮穿噴玉溜，字缺照人碑。", "古殿天姿晦，真工石像奇。", "羽衣沉舊曲，錦雁失前池。", "不見長生鹿，猶看連理枝。", "辭雄小杜句，意盡老陳詩。", "治亂由斯監，賢愚共一悲。", "時君自奢儉，繡嶺此何知。"]'),
('0e74e5ea-1ed0-4b1b-9553-ceda18a8e7b2','題鎮潼西溪','韓琦','宋','宋诗','song-poetry','','[]','芳林環掩密相攙，仙府天成似隱潛。',64,'全唐诗/poet.song.18000.json','["芳林環掩密相攙，仙府天成似隱潛。", "峯面槎牙屏簇畫，溪心平澈鑑開奩。", "穠粧照檻秋蓮合，碎玉敲篷夜雨添。", "暫柅客軒醒病目，日斜無意馭彤襜。"]'),
('bf721eda-7891-4d11-92be-e9f55e892615','題雲臺觀','韓琦','宋','宋诗','song-poetry','','[]','仙掌峰前羽客家，玉虛宮殿倚雲霞。',32,'全唐诗/poet.song.18000.json','["仙掌峰前羽客家，玉虛宮殿倚雲霞。", "最高頂上誰曾到，得見蓮開十丈花。"]'),
('53fa230b-86c4-4e92-80e9-732728efeb10','題希夷先生真堂','韓琦','宋','宋诗','song-poetry','','[]','伊昔天真被謫書，亦教人境得仙居。',64,'全唐诗/poet.song.18000.json','["伊昔天真被謫書，亦教人境得仙居。", "開門翠靄三峰近，合眼紅塵萬事踈。", "髣髴舊容蟬已蛻，徘徊高隱室猶虛。", "何時歸伴赤松子，穩駕尋君物外車。"]'),
('763450cc-a26b-4287-81a0-ed196839e7fb','仲秋之八日覩雲臺觀沖觀大師北軒羣花盛開','韓琦','宋','宋诗','song-poetry','','[]','春早凡花百種榮，秋芳能得幾多名。',32,'全唐诗/poet.song.18000.json','["春早凡花百種榮，秋芳能得幾多名。", "仙家八月靈葩發，不與尋常俗艷爭。"]'),
('b14cb3aa-e5d3-4160-b6ac-30b9bebb5e80','題玉泉院','韓琦','宋','宋诗','song-poetry','','[]','兩行修柏夾雲根，引入蓮峯直下村。',64,'全唐诗/poet.song.18000.json','["兩行修柏夾雲根，引入蓮峯直下村。", "病骨醒魂安氣母，幽亭收景厭山孫。", "金堆望遠千灘出，玉溜聲喧萬馬奔。", "坐歎塵勞無計住，却尋歸路日黄昏。"]'),
('ec5f9a30-e9cb-495b-bc06-a7c0b0561f2c','硤石道中','韓琦','宋','宋诗','song-poetry','','[]','氣爽風清八月天，雨餘秋色自蕭然。',64,'全唐诗/poet.song.18000.json','["氣爽風清八月天，雨餘秋色自蕭然。", "正當崤澠難行路，得見田疇大有年。", "叢薄遠青供極望，霽雲低白半危巔。", "河橋咫尺鄉程便，病質雖疲喜强前。"]'),
('d64c0b91-4518-4f14-a17e-acbfd4627154','澠池道中','韓琦','宋','宋诗','song-poetry','','[]','渡澗登坡直幾重，嶺頭初日上曈曨。',32,'全唐诗/poet.song.18000.json','["渡澗登坡直幾重，嶺頭初日上曈曨。", "野花紅紫連官道，露裛清香散曉風。"]'),
('80b00f24-43de-4b56-8e3a-a98ffbdef151','戊申西洛中秋對月','韓琦','宋','宋诗','song-poetry','','[]','海東推出水晶毬，碧抹晴空暝靄收。',64,'全唐诗/poet.song.18000.json','["海東推出水晶毬，碧抹晴空暝靄收。", "素景獨宜惟上節，清光無敵是中秋。", "家爲梵室黄金界，人在天宮白玉樓。", "當此客途衰病者，敢於詩酒擅風流。"]'),
('edead239-f082-4228-8a16-8c47ead474d4','次韻答崔公孺比部至陳橋驛來別相會','韓琦','宋','宋诗','song-poetry','','[]','永日勞君倍驛馳，相期無失見相思。',64,'全唐诗/poet.song.18000.json','["永日勞君倍驛馳，相期無失見相思。", "義均呂駕來千里，情過陽關書一巵。", "喜接禪醫開道眼，愧逢詩將立降旗。", "此行且縱漳濱卧，免弄幽并俠少兒。"]'),
('891936b3-7b42-4a6b-b82d-22c64c4c3213','又次韻答夜宴陳橋驛','韓琦','宋','宋诗','song-poetry','','[]','客郵聊得接交親，夜席開談彼此真。',64,'全唐诗/poet.song.18000.json','["客郵聊得接交親，夜席開談彼此真。", "薄酒不辭知易別，征車從解喜難申。", "請看隨分樽罍事，可是留心富貴人。", "早晚共成林下約，釣潭風月有竿綸。"]'),
('e29efbd5-0a1b-43e8-aee2-8ff68e5773bd','又次韻答陳橋話別','韓琦','宋','宋诗','song-poetry','','[]','欲知連日柅征車，傾蓋唯憂後會賒。',64,'全唐诗/poet.song.18000.json','["欲知連日柅征車，傾蓋唯憂後會賒。", "被顧高情非白眼，論空真理黜黄牙。", "還家粗喜松成徑，懷印誰驚綬引花。", "卧治必難逃吏責，羨君奇志托青霞。"]'),
('651219c3-6c0c-4b25-9c3d-3541464f083b','重九與諸親會別橋驛','韓琦','宋','宋诗','song-poetry','','[]','郵館侵晨舉別觴，一時佳節遇重陽。',64,'全唐诗/poet.song.18000.json','["郵館侵晨舉別觴，一時佳節遇重陽。", "莫悲白首分行袂，且伴黄花入醉鄉。", "旅雁带霜橫寒陣，香萸和露貯宮囊。", "諸君送我無多念，病質將休晝錦堂。"]'),
('fc599116-f7a7-42a9-9f16-d79ddf72d177','早發韋城','韓琦','宋','宋诗','song-poetry','','[]','北去川原極目平，修途塵斂雨初晴。',64,'全唐诗/poet.song.18000.json','["北去川原極目平，修途塵斂雨初晴。", "歲豐禾黍高低積，天曉雲霞散亂明。", "宵露尚漙香草木，朔風時緊撼旗旌。", "病襟斗覺精神健，屈指鄉邦近數程。"]'),
('5745079c-42de-43fc-9462-ad251ae99813','初拜先墳','韓琦','宋','宋诗','song-poetry','','[]','未交符竹展先墳，肅肅秋天雨半昏。',64,'全唐诗/poet.song.18000.json','["未交符竹展先墳，肅肅秋天雨半昏。", "榮入松楸雖動色，感深閨闑復傷魂。", "山川望遠平如日，父老歡迎識舊恩。", "白晝錦衣人已駭，更留旄節宿郊村。"]'),
('ef70da40-432f-4d73-b9df-8c878ba29fb5','再題晝錦堂','韓琦','宋','宋诗','song-poetry','','[]','爲郡偏榮晝錦歸，再容鄉任古來稀。',64,'全唐诗/poet.song.18000.json','["爲郡偏榮晝錦歸，再容鄉任古來稀。", "邸人只駭新章貴，仙表誰瞻舊鶴飛。", "浹境士民增慰悅，一軒風物起光輝。", "鑱詩又志君恩厚，鼎鑊捐身報亦微。"]'),
('a34904d6-3120-4866-944d-63145e38b202','再題休逸堂','韓琦','宋','宋诗','song-poetry','','[]','冰井梁摧幾百秋，昔移爲柱立臺頭。',64,'全唐诗/poet.song.18000.json','["冰井梁摧幾百秋，昔移爲柱立臺頭。", "層基面壘盤蝸殼，倒影侵池側蜃樓。", "拂檻落霞凌綺席，入簷初月誤瓊鈎。", "芳林已合陰成茂，不見西山涌萬邱。"]'),
('e96324ed-49b0-4fce-ada4-0bb4139441c1','再題康樂園','韓琦','宋','宋诗','song-poetry','','[]','名園初闢至和中，思與康時眾樂同。',64,'全唐诗/poet.song.18000.json','["名園初闢至和中，思與康時眾樂同。", "一紀豐光雖易老，萬家春色且無窮。", "歸來敢衒吾鄉勝，到此須知舊鄴雄。", "病守縱疲猶强葺，欲隨民適醉東風。"]'),
('fef1570c-59e2-4adb-8b42-636a6b4104eb','狎鷗亭','韓琦','宋','宋诗','song-poetry','','[]','亭壓東池復壞基，園林須喜主人歸。',64,'全唐诗/poet.song.18000.json','["亭壓東池復壞基，園林須喜主人歸。", "憩棠猶茂應存愛，植柳堪驚僅過圍。", "魚泳藻間諳物性，月沈波底發禪機。", "羣鷗只在輕舟畔，知我無心自不飛。"]'),
('902f85f9-dc35-4ed7-b02a-282df5570f01','觀魚軒','韓琦','宋','宋诗','song-poetry','','[]','雨後方池碧漲秋，觀魚亭檻俯臨流。',64,'全唐诗/poet.song.18000.json','["雨後方池碧漲秋，觀魚亭檻俯臨流。", "時看隱荇駢頭戲，忽見開萍作隊游。", "喜擲舟前翻亂錦，靜潛波下起圓漚。", "吾心大欲同斯樂，肯插筠竿餌釣鈎。"]'),
('88a61476-5395-401f-8190-664c8d3dc28d','洗竹','韓琦','宋','宋诗','song-poetry','','[]','當日曾移碧玉竿，繚坦交植競檀欒。',64,'全唐诗/poet.song.18000.json','["當日曾移碧玉竿，繚坦交植競檀欒。", "栽培盡力宜長盛，翦拂無人已半殘。", "洗出煙姿還雅澹，削開龍影起幽蟠。", "此君高節殊堪慕，賢者來須著意看。"]'),
('beeeb8bc-485b-45d7-9dc6-d9b97896be13','素齋于君實賦別兼簡方巖侍郎','釋居簡','宋','宋诗','song-poetry','','[]','諸公皆青雲，一士獨苦心。',156,'全唐诗/poet.song.180000.json','["諸公皆青雲，一士獨苦心。", "懷哉英雄泪，亦復長滿襟。", "鄉來梁楚聲，不貴雙南金。", "九仞橫界牆，餘子不敢侵。", "兩鬢吹黄塵，倦翮投晚林。", "渺觀酒勍敵，袖手妒病瘖。", "元龍異姓兄，老鳳儀韶音。", "秋窗坐欲曙，曉燈挑不禁。", "鴒原思寥寥，雁影雲沉沉。", "東觀可縱觀，北斗當滿斟。", "雖無廣文氊，亦有丞相衾。", "好隣買道南，逸興追山陰。", "喚起方岩翁，共作商岩霖。"]'),
('dab97854-236a-49e5-af66-5021ec482764','送方岩下黄岩曲江阻風幾溺  其一','釋居簡','宋','宋诗','song-poetry','','[]','天雲卷礮車，橫波起濤頭。',48,'全唐诗/poet.song.180000.json','["天雲卷礮車，橫波起濤頭。", "拔木如剪葉，况復一葉舟。", "鄉來不鳴條，醖藉仍風流。", "今也賈餘勇，浩蕩隳前修。"]'),
('fccd09f5-f4b4-463d-81c4-99d05ead818d','送方岩下黄岩曲江阻風幾溺  其二','釋居簡','宋','宋诗','song-poetry','','[]','萬籟忽自作，蕭蕭夜何其。',48,'全唐诗/poet.song.180000.json','["萬籟忽自作，蕭蕭夜何其。", "悠然一寸闌，雪衮濤山飛。", "飛廉爾何事，狡獪取巧施。", "古井湛弗摇，鼓盪終奚爲。"]'),
('224f42a8-e2f3-45ea-8a8f-c0b8825563db','元日領客登北高','釋居簡','宋','宋诗','song-poetry','','[]','雲繞簷楹掃不開，闌干直下是飛來。',32,'全唐诗/poet.song.180000.json','["雲繞簷楹掃不開，闌干直下是飛來。", "笑看白玉芬陁利，領略風煙又一回。"]'),
('637dc1e9-1601-42eb-af21-fa69b27ea002','別李子源','釋居簡','宋','宋诗','song-poetry','','[]','分携二十年，解后復翩然。',48,'全唐诗/poet.song.180000.json','["分携二十年，解后復翩然。", "易辦長亭別，難忘短李賢。", "春非無勝日，雨是未晴天。", "最是關心處，帆開順水船。"]'),
('ebdbaef8-a341-4db0-9d54-4ddb90e20dba','景獻諸兄侍兩國入山','釋居簡','宋','宋诗','song-poetry','','[]','飛鞚入山深，幽從野逸尋。',48,'全唐诗/poet.song.180000.json','["飛鞚入山深，幽從野逸尋。", "閘開觀噴激，雲歛闖𡼭嶔。", "茵錦蒼苔綠，油幢碧樹陰。", "客兒亭最古，訪古盍重臨。"]'),
('8f6dd732-c9cb-443d-b120-da1508c1fa44','清明日聞杜鵑','釋居簡','宋','宋诗','song-poetry','','[]','吳越清明四十年，可曾歸夢攪清眠。',32,'全唐诗/poet.song.180000.json','["吳越清明四十年，可曾歸夢攪清眠。", "樓頭欲與仲宣語，驀地一聲啼杜鵑。"]'),
('e583f0cd-9a01-4b2d-90c8-adb2e2474995','方岩侍郎得靈壁一峰名碧雲','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','坡陁巨璞韜玄質，壤斷虜塵天半壁。',192,'全唐诗/poet.song.180000.json','["坡陁巨璞韜玄質，壤斷虜塵天半壁。", "鄉來誰試小龍文，切得一峯歸笠澤。", "太湖繞山三萬頃，奇産雖多不足惜。", "雲邊七十二峯青，强顔亦復無顔色。", "滑膚弗受莓苔裹，素藴豈容塵土蝕。", "雲升霞舉幻瑰奇，玉響金渾隨拊擊。", "一從越相去悠悠，幾見吳宮春寂寂。", "方岩委羽在何許，帖天弱水蓬萊隔。", "泠然一瞬三萬里，風煙浩蕩尋無迹。", "既伴壺中清晝長，想見袖中東海窄。", "那知篆鼎銘彜外，尚餘三丈浯溪石。", "擘窠不到小玲瓏，却須細細蠅頭刻。"]'),
('cc5cde2d-9a54-4d58-93bd-28e747e590f6','醒菴王大卿松柏屏障歌','釋居簡','宋','宋诗','song-poetry','','[]','青青歲寒之淡交，柏也揖遜蒼髯梢。',192,'全唐诗/poet.song.180000.json','["青青歲寒之淡交，柏也揖遜蒼髯梢。", "凜姿古調瘠而實，昔未成才先莫逆。", "執此能事柄者誰，彈壓玉霄王紫微。", "千古萬古不可追，落子亦復四十圍。", "公乎多才亦多藝，小試縯綸光帝制。", "復將餘墨散餘春，煙雲樹石皆精神。", "擎重雪枝寒不倚，霜幹相周不相比。", "山林豪逸並孤標，冠劍大臣橫勁氣。", "想當欲畫未畫時，積思凝慮全天倪。", "忽然直上盤雲霓，不見筆墨之畛畦。", "因依方寸亦磅礴，豈止一丘仍一壑。", "良木非摧石不崩，於戲九原不可作。"]'),
('169019c8-aacf-4555-aec8-59eb8ee08ab0','柳絮  其一','釋居簡','宋','宋诗','song-poetry','','[]','輕輕漠漠又斜斜，去作青萍漾水涯。',32,'全唐诗/poet.song.180000.json','["輕輕漠漠又斜斜，去作青萍漾水涯。", "院落晚春閑意緒，合分一半與梨花。"]'),
('ea009a78-cd0a-4525-99e6-e9f667c44bd8','柳絮  其二','釋居簡','宋','宋诗','song-poetry','','[]','勇作輕狂又懶飛，又如欲去却沉思。',32,'全唐诗/poet.song.180000.json','["勇作輕狂又懶飛，又如欲去却沉思。", "霅雲不度清苕曲，獨受融風款曲吹。"]'),
('610c50a8-29e6-466c-abf3-d4ae478f7fcd','送常德徐使君兼簡李伯達  其一','釋居簡','宋','宋诗','song-poetry','','[]','孺子老蹁躚，尊前小謫仙。',48,'全唐诗/poet.song.180000.json','["孺子老蹁躚，尊前小謫仙。", "水程春泛鷁，山驛夜啼鵑。", "屏小梅垂實，樓高柳度綿。", "楚天回雁字，幾日到吳天。"]'),
('5c896594-e333-490e-bb58-f4cbfa1596c6','送常德徐使君兼簡李伯達  其二','釋居簡','宋','宋诗','song-poetry','','[]','榻爲何人下，書令稚子溫。',48,'全唐诗/poet.song.180000.json','["榻爲何人下，書令稚子溫。", "定馳天際夢，來訪水邊村。", "秦地千年舊，桃花幾樹存。", "爲宣邦伯惠，詩禮教兒孫。"]'),
('af89db8e-1875-4aca-95a7-2dfbae0a3503','椀柏','釋居簡','宋','宋诗','song-poetry','','[]','土入花甆淺，林疏雪操鮮。',48,'全唐诗/poet.song.180000.json','["土入花甆淺，林疏雪操鮮。", "後凋非地力，獨秀是天年。", "老我不諧俗，惜才如養賢。", "明明千古意，渠自指庭前。"]'),
('e678a6a9-f785-4117-aed7-11814a9606af','謝隨菴趙牧之墨竹','釋居簡','宋','宋诗','song-poetry','','[]','胸中千畝不願餘，穎也戲劇資軒渠。',192,'全唐诗/poet.song.180000.json','["胸中千畝不願餘，穎也戲劇資軒渠。", "湖州九原不可作，百年合浦今還珠。", "玄卿濃淡知權變，淋浪迅疾如馳電。", "爲君擊節賞此音，孝娥廟刻題黄絹。", "君胡不歌石鼎聯，兩手笑拍彌明肩。", "又不釣垂五十犗，六鰲一掣空重淵。", "幻成群玉參差立，露梢點滴鮫人泣。", "鶻落還從兔起時，一機纔失嗟無及。", "我住雙岩峯下寺，夢斷池塘無一語。", "家山新綠報平安，萬金墮眼寬西顧。", "葛陂頭角猶完全，鏡中觀影俱茫然。", "坐令野人破屋壁，萬里風煙生咫尺。"]'),
('9704ad7b-3cb3-4916-87e5-a3165b019eb3','書誠齋答晦菴帖傷劉子澄死於貶所','釋居簡','宋','宋诗','song-poetry','','[]','宋司馬後魯臧倉，賢聖雖窮道不傷。',32,'全唐诗/poet.song.180000.json','["宋司馬後魯臧倉，賢聖雖窮道不傷。", "老子看棋高一著，噬臍空自憶劉郎。"]'),
('1a867255-e8cd-420a-a6c2-72fc3f5fb37f','石人','釋居簡','宋','宋诗','song-poetry','','[]','面冷如水瘦，心剛笑竹虛。',48,'全唐诗/poet.song.180000.json','["面冷如水瘦，心剛笑竹虛。", "痕雲衣不浣，暈蘚髻難梳。", "七鑿混沌死，十成山澤癯。", "穀城山下路，誰復理殘書。"]'),
('63471a81-6328-4377-8ea3-cc514663f87e','墨荔枝','釋居簡','宋','宋诗','song-poetry','','[]','塵蛻冰膚玉透肌，皺絺洴墨剪裳衣。',32,'全唐诗/poet.song.180000.json','["塵蛻冰膚玉透肌，皺絺洴墨剪裳衣。", "芳鮮甘與緇雲老，不與輕紅轉眼稀。"]'),
('1ee786fc-4422-4903-916d-db0b662c303c','鳳兒花  其一','釋居簡','宋','宋诗','song-poetry','','[]','小似釵頭縷粟金，不將紅淺笑紅深。',32,'全唐诗/poet.song.180000.json','["小似釵頭縷粟金，不將紅淺笑紅深。", "虛名冗到閑花草，寂寞朝陽采羽瘖。"]'),
('100bea30-97e2-4ac0-8ca0-42f2fef7c8df','鳳兒花  其二','釋居簡','宋','宋诗','song-poetry','','[]','弄玉何年墮翠鈿，託根便作九包妍。',32,'全唐诗/poet.song.180000.json','["弄玉何年墮翠鈿，託根便作九包妍。", "飛花只合秦樓去，莫與金釵壓鬢蟬。"]'),
('beca56fe-df1f-46e7-bd14-b57d73a72542','謝司令惠賜茶','釋居簡','宋','宋诗','song-poetry','','[]','昨尋密齋覓茶喫，倒屣踉蹌笑相逆。',128,'全唐诗/poet.song.180000.json','["昨尋密齋覓茶喫，倒屣踉蹌笑相逆。", "一杯青白勝黄白，好風兩袖來無跡。", "晴窗午景浣風味，露飽秋蟬謾塵蛻。", "周詩雖記苦如荼，浮俗但知濃若醴。", "歸來急足敲晨扉，香鬰密雲光陸離。", "圭零璧碎不復惜，自候泣蚓聲悲嘶。", "不妨爲佛先拈出，油然雪乳翻秋色。", "更需佳士細商評，我恐眼中無此生。"]'),
('55bb3c3f-7be0-4704-ae96-e7c565eddf54','次陳中書惠生綃韵','釋居簡','宋','宋诗','song-poetry','','[]','曾評五字玉堂詩，豪壓城南示阿宜。',32,'全唐诗/poet.song.180000.json','["曾評五字玉堂詩，豪壓城南示阿宜。", "池上鳳毛今幾箇，阿宜何似阿戎奇。"]'),
('de9a0030-819b-42c9-b204-c70218fb5838','錢竹岩之官清遠','釋居簡','宋','宋诗','song-poetry','','[]','帆挂之清遠，潮來駕濁流。',120,'全唐诗/poet.song.180000.json','["帆挂之清遠，潮來駕濁流。", "火雲方振虐，仙舄自生秋。", "拔宅雖浮汎，逢山得款留。", "一夔携驥子，幾度訪羊裘。", "景盡孤臺勝，題分庾嶺幽。", "風餐愁欵乃，水宿貫鈎輈。", "文采休藏豹，詩盟莫冷鷗。", "神明毋自鄙，蠻瘴不勝瘳。", "單父鳴弦外，巴東野水頭。", "鼎鍾餘事業，一德配靈脩。"]'),
('35fd6c7f-9d79-46af-8ce5-ad5159ee2c60','書陳平佐刺圖','釋居簡','宋','宋诗','song-poetry','','[]','千慮難窮智士心，周防密計保千金。',32,'全唐诗/poet.song.180000.json','["千慮難窮智士心，周防密計保千金。", "寧能有備爲無用，一寸淵淵幾許深。"]'),
('5124d4e9-ef57-42fb-b61e-518794d75194','早過湖','釋居簡','宋','宋诗','song-poetry','','[]','喚得航船傍采菱，柳橋竹榭曙煙深。',32,'全唐诗/poet.song.180000.json','["喚得航船傍采菱，柳橋竹榭曙煙深。", "船頭驚起蜻蜓睡，欲立還飛到湧金。"]'),
('af0141ac-71bc-4b2d-a5ae-4b59a5932ac7','日者鶴軒','釋居簡','宋','宋诗','song-poetry','','[]','令威不在鶴軒先，華表歸來是幾年。',32,'全唐诗/poet.song.180000.json','["令威不在鶴軒先，華表歸來是幾年。", "試向青田問休咎，不知何日去乘軒。"]'),
('ccb41ca5-03e8-4448-9e47-2bb00437fddb','題三教圖','釋居簡','宋','宋诗','song-poetry','','[]','巖高風壓樹頭低，三子相逢把手歸。',32,'全唐诗/poet.song.180000.json','["巖高風壓樹頭低，三子相逢把手歸。", "掩室在陳無足笑，笑它同傳有韓非。"]'),
('6f913d8e-bf00-4b1a-8de8-19fd3cd0a778','苦旱','釋居簡','宋','宋诗','song-poetry','','[]','荼蘼殿春春云徂，芳庭過雨紅欲無。',208,'全唐诗/poet.song.180000.json','["荼蘼殿春春云徂，芳庭過雨紅欲無。", "一晴不雨苦陽久，四五十日瞻天衢。", "黄塵陸漲草樹暗，積水戽乾河港枯。", "秧猶未插莠如棘，田已不勝龜拆塗。", "沈牛投虎竟茫昧，死鷸脯蚌才斯須。", "蜿蜒展轉不肯寤，山川尸素方寧居。", "困魚止陸相喣濡，斗升未必副所需。", "元首股肱本同德，熙怡和樂綿九區。", "萬幾總覽天所見，十目所視吾誰諛。", "商羊弗見來庭除，旱魃妄冀逃天誅。", "曩聞尺箠笞單于，豈不足將雷電驅。", "不須决海戒覆車，不須挽河洗潢洿。", "只願閉門十日雨，四海涼生斃九烏。"]'),
('90158fc4-9de9-4a4f-8ecc-24dd6991025c','苦旱書蕉葉','釋居簡','宋','宋诗','song-poetry','','[]','自是秋懷易寂寥，强將離緒怨芭蕉。',32,'全唐诗/poet.song.180000.json','["自是秋懷易寂寥，强將離緒怨芭蕉。", "教它不報𩃎𩃱信，只麽蕭蕭過夜遥。"]'),
('d2c04c03-1574-423a-9f26-7e0d5aa377bb','酬謝寺丞','釋居簡','宋','宋诗','song-poetry','','[]','厥月維良慶佛生，誕彌隨佛際昌明。',64,'全唐诗/poet.song.180000.json','["厥月維良慶佛生，誕彌隨佛際昌明。", "循良既負劍南最，枉直暫丞天下平。", "池草自隨新句好，砌蘭長傍故家榮。", "當年駢儷歸彈壓，今日絲綸要老成。"]'),
('d7cce530-fc29-49f1-9a03-a16e55cef0b9','太湖初日','釋居簡','宋','宋诗','song-poetry','','["\u592a\u6e56"]','飛光飛上碧瀾底，碧跨三州連底明。',32,'全唐诗/poet.song.180000.json','["飛光飛上碧瀾底，碧跨三州連底明。", "多少潛珍畏人見，只知犀炬太無情。"]'),
('bf836c17-5573-400e-b7f0-288ff04db020','朱菴睡起','釋居簡','宋','宋诗','song-poetry','','[]','簷外飛花不翳天，階前淺水恰通船。',32,'全唐诗/poet.song.180000.json','["簷外飛花不翳天，階前淺水恰通船。", "借床睡起自作供，餐盡楚英霜後妍。"]'),
('b5c8d8bc-a743-4a93-a91d-c5643d2b2964','會稽胡丞相過','釋居簡','宋','宋诗','song-poetry','','[]','眚目醌銜冰，逃空喜弗勝。',48,'全唐诗/poet.song.180000.json','["眚目醌銜冰，逃空喜弗勝。", "別懷雖易久，雅况獨難承。", "官業清於水，家生少似僧。", "不知廳壁記，幾箇似君能。"]'),
('0525a984-bf30-44ce-8581-ad8261059d91','桃源行','釋居簡','宋','宋诗','song-poetry','','[]','種桃種得春一原，逃死逃得秦外天。',160,'全唐诗/poet.song.180000.json','["種桃種得春一原，逃死逃得秦外天。", "殺雞爲黍替草具，不識晉語猶秦言。", "昨日相逢今日別，流水落花行路絕。", "雞黍更從仙隠設，疑是齊東野人說。", "典午亂多仍治少，此事明明不分曉。", "一秦才滅一秦生，避世避人還避秦。", "憶昔怒驅丞相去，猶思上蔡東門兔。", "縱有封君祿萬鍾，爭如食邑桃千樹。", "空山惜日見日長，秦民怨日偕日亡。", "恨身不爲治時草，不恨祖龍長不老。"]'),
('c5c68085-8d7b-484e-97b6-a4966cca5d66','拜總持尼祖塔','釋居簡','宋','宋诗','song-poetry','','[]','平生自愛黄金膝，肯屈榛蕪草棘深。',32,'全唐诗/poet.song.180000.json','["平生自愛黄金膝，肯屈榛蕪草棘深。", "弗似灌溪閑上座，尼壇再展不同心。"]'),
('ff4e45eb-6465-4ee9-a27d-26545c1bf2db','自壽','釋居簡','宋','宋诗','song-poetry','','[]','燕雀生成日幾何，技慙斷斷更無它。',64,'全唐诗/poet.song.180000.json','["燕雀生成日幾何，技慙斷斷更無它。", "近來同歲人尤少，老去思親泪更多。", "無事關身慙素食，有心作佛笑凡科。", "思量大欠工夫在，更把餘生細濯磨。"]'),
('8ed3b03f-d764-4ee7-9be7-b85c345c533e','戇菴約子與素齋赴二石丈江閣之集得頰字','釋居簡','宋','宋诗','song-poetry','','[]','半山蛇腹彎城頰，層雲鴟尾翔山脇。',160,'全唐诗/poet.song.180000.json','["半山蛇腹彎城頰，層雲鴟尾翔山脇。", "紫萸獨自對黄花，采筆不須題落葉。", "山容入秋太瘦生，倚筇欲賦登山行。", "諸公譚玄若破敵，萬籟爲我俱銷聲。", "俯瞰市人酣戰蟻，喧寂兩忘同一眡。", "悠然五字隠長城，萬馬循牆看披靡。", "數峰薄暮方展眉，笑人買山後小支。", "誰能料理身後計，更復願爲天下奇。", "滄江潮晚鯨吞吐，白鷗群分復群聚。", "出門一笑問浮圖，風動琅璫半天語。"]'),
('8f29d965-2f9e-47a1-9b04-03a543f64043','粟隠','釋居簡','宋','宋诗','song-poetry','','[]','坤壤大如許，或謂藏於斯。',120,'全唐诗/poet.song.180000.json','["坤壤大如許，或謂藏於斯。", "此理頗未安，如之何勿思。", "鄉來雲夢吞八九，眇而眡之竟何有。", "是中餘地渺無邊，盡吸西江斟北斗。", "區區載笑觸與蠻，流血如海骸如山。", "蟭螟之國蚊睫間，開邊拓土久不還。", "隠淪蕭洒塵囂外，六合塵囂在其內。", "俗子先標出大門，我欲乘風跨鵬背。"]'),
('ee93ebac-9709-4d03-a3e9-f77c350a2562','持鉢  其一','釋居簡','宋','宋诗','song-poetry','','[]','未必腰纏把鶴騎，可堪青女奮全威。',64,'全唐诗/poet.song.180000.json','["未必腰纏把鶴騎，可堪青女奮全威。", "推蓬教密寒尤重，挾纊雖重煖尚微。", "沓足敢忘偎葉記，屈身不與曲肱違。", "船頭亦有蘢葱日，水激風回作雪飛。"]'),
('00fff8d8-1261-4d53-9d89-dfd541749cba','持鉢  其二','釋居簡','宋','宋诗','song-poetry','','[]','樂歲持盂尚許艱，有求那解破人慳。',64,'全唐诗/poet.song.180000.json','["樂歲持盂尚許艱，有求那解破人慳。", "立殘穰草堆頭日，撐盡苹蕪斷處灣。", "鍾鼓敢嫌貧指衆，斗筲庸恤老腰頑。", "歸舟只載華亭月，不作華亭誤夾山。"]'),
('d9043ea7-8f6a-47a1-8b59-bf26e8186e2e','持鉢  其三','釋居簡','宋','宋诗','song-poetry','','[]','顛風挾玄霜，跋扈清溪陰。',144,'全唐诗/poet.song.180000.json','["顛風挾玄霜，跋扈清溪陰。", "長年把船尾，鐵面抵弗禁。", "面皴不暇問，腕裂龜文深。", "手中老篙竹，出水冰淋淋。", "一步一千里，進寸或退尋。", "抵死爲食謀，俛首潜呻吟。", "勞人凍入骨，寸心攢萬針。", "樂哉田舍郎，坐擁廩若林。", "强使損緒餘，瞪目如病瘖。", "所得不盈把，粒米敵數金。", "沈思耕者志，豈異舟子心。", "其誰受此施，觀此受施箴。"]'),
('3f824b71-3ca6-4956-8d7e-67af7118d69d','送宗無傳赴閩帥楊伯子西禪之招','釋居簡','宋','宋诗','song-poetry','','[]','尚有誠齋老寧馨，來尋方外阿師兄。',64,'全唐诗/poet.song.180000.json','["尚有誠齋老寧馨，來尋方外阿師兄。", "滔滔入海如涇濁，冏冏於公獨阮青。", "舊憶薰蕕分草木，新來一再扣柴荆。", "不龜手是家傳藥，莫遣人言藥不靈。"]'),
('f7ba44b6-9124-4b56-ba46-15204abad10a','盧太君','釋居簡','宋','宋诗','song-poetry','','[]','老顔瑩玉盧堂前，明年一百欠一年。',96,'全唐诗/poet.song.180000.json','["老顔瑩玉盧堂前，明年一百欠一年。", "歲時羅拜各有序，四三千指詵詵然。", "髮白衣斑傳冢嗣，子生孫了孫生子。", "寸田種德日蕃滋，一氣所鍾至於此。", "壽骨稜稜歲寒後，深拜伽梨問耆壽。", "盡將回向南極星，化凶短折爲脩齡。"]'),
('aacbde8b-adf9-4438-ada6-a4dbc143c760','不雨','釋居簡','宋','宋诗','song-poetry','','[]','田欲龜文曉尚龜，高高如燎恐雲焦。',64,'全唐诗/poet.song.180000.json','["田欲龜文曉尚龜，高高如燎恐雲焦。", "未應天上無炎熱，可是山中欠燮調。", "草偃風顛凉自至，雨隨車後暑應消。", "冷菰寒玉關心外，却立虛庭望泬寥。"]'),
('57e9a033-324e-4efe-808d-3d771ff6ab98','訪菊','釋居簡','宋','宋诗','song-poetry','','[]','東籬貶剝勿絲毫，著得先生一字褒。',64,'全唐诗/poet.song.180000.json','["東籬貶剝勿絲毫，著得先生一字褒。", "賸馥緬懷彭澤縣，落英掩恨楚江濤。", "綴團曉露心尤苦，揖遜春風節更高。", "不把幽妍酬憤悱，鸞膠弗解續離騷。"]'),
('ab0491b9-7e45-4468-a961-c84cce8b075b','泣胡晦叔  其一','釋居簡','宋','宋诗','song-poetry','','[]','一臂纔交小朵陰，傍池分石坐雲深。',64,'全唐诗/poet.song.180000.json','["一臂纔交小朵陰，傍池分石坐雲深。", "先生自袖春風手，喬木吾非故國心。", "操與蒼官同瘦立，思兼梁甫獨長吟。", "錦囊羞澀慙多助，卷盡牛腰尚忍尋。"]'),
('3b3176ea-038a-4b01-a5f5-938ecc8e4871','泣胡晦叔  其二','釋居簡','宋','宋诗','song-poetry','','[]','書恨來遲訃亦來，寸剛不覺爲君摧。',64,'全唐诗/poet.song.180000.json','["書恨來遲訃亦來，寸剛不覺爲君摧。", "雙眸忍俗終難瞑，流水無情去不回。", "定作雷霆輸宿憤，枉教風鑒在棼埃。", "斷魂巫峽歸丹旐，深注山茶酹一杯。"]'),
('9dca188b-8cb7-4c13-9179-d77d9727df0b','顔丞開爐','釋居簡','宋','宋诗','song-poetry','','[]','鱗差雲母著書窗，軟火深爐曉自粧。',64,'全唐诗/poet.song.180000.json','["鱗差雲母著書窗，軟火深爐曉自粧。", "篆恰纔消餘桂馥，手終不暖爲棖香。", "小中天地何妨大，閑裏工夫不欠忙。", "莫向市朝尋大隠，二松環水自湯湯。"]'),
('4c912fab-8880-4c8b-b075-a3e2b1aa74b5','梵天僧舍金竹中有綠竹一莖','釋居簡','宋','宋诗','song-poetry','','[]','手栽碧玉間黄金，炎赫流金弗敢侵。',64,'全唐诗/poet.song.180000.json','["手栽碧玉間黄金，炎赫流金弗敢侵。", "莫作兩般分實相，定知一等是虛心。", "根分麗水難沉色，節老藍田待賞音。", "終有九包來止息，萬竿何患不成林。"]'),
('2df38f99-3d10-4523-906e-6f7609fea0fd','書雪巢林景思詩卷','釋居簡','宋','宋诗','song-poetry','','[]','詩人巢雪如住山，巢中所得强得官。',143,'全唐诗/poet.song.180000.json','["詩人巢雪如住山，巢中所得强得官。", "官微不足了饘粥，盡日幽尋遣兒讀。", "舂容大篇輒千字，鍊字貴活不貴死。", "鄉來杜陵有布衣，晚到夔州也如此。", "乃今遺藁安在哉，古花囊錦宗文開。", "開緘宛見諫議面，隻字重哦復三嚥。", "三嚥然後耳有聞目有見，見人捧心顰兩眉。", "不學施家女，只學唐人詩。", "爲言諸子將安之，巢空雪明康鼎來。"]'),
('738fea3a-2b8b-4f31-8718-0fb8269dfb43','青梅子','釋居簡','宋','宋诗','song-poetry','','[]','雪未消時入旦評，纔黄又屬傅岩人。',32,'全唐诗/poet.song.180000.json','["雪未消時入旦評，纔黄又屬傅岩人。", "暫分葉底藏身地，部領鶑花過半春。"]'),
('79bea9f9-59b3-47b8-a36f-8ffb496b7b92','三友軒','釋居簡','宋','宋诗','song-poetry','','[]','矯矯蒼髯傍把茆，疎疎碧玉倚瓊梢。',64,'全唐诗/poet.song.180000.json','["矯矯蒼髯傍把茆，疎疎碧玉倚瓊梢。", "飽經霜後轉無恙，未及歲寒先定交。", "影瘦自隨窗月上，陰濃時有嶺雲巢。", "此君不獨論三益，高節還應待九包。"]'),
('aebfcf24-0d06-4b1e-9af3-b69b47becd83','小泊湖州','釋居簡','宋','宋诗','song-poetry','','[]','蜿蜒粉雉枕寒汀，闊著清苕碧界塵。',32,'全唐诗/poet.song.180000.json','["蜿蜒粉雉枕寒汀，闊著清苕碧界塵。", "帆落水晶宮未曉，素花開盡一溪蘋。"]'),
('32c1f1e3-4bae-4f49-a0eb-f2dbf38d36f0','酬晦齋謝司直和子壽宮使賦歸來望思之臺','釋居簡','宋','宋诗','song-poetry','','[]','推恩保四海，寡恩徒自戕。',121,'全唐诗/poet.song.180000.json','["推恩保四海，寡恩徒自戕。", "父兮不念子，悠悠我心傷。", "父子至情天性也，戾豈自經溝瀆者。", "回天無藥愈狂酲，朽索胡爲羈六馬。", "邪心不作天不疑，皇恤江充劉屈氂。", "靈脩一悟倘可冀，抑免殺身傷父慈。", "千秋一言機發弩，墮甑已非何所補。", "歸來望思兮胡不歸，千古萬古一抔土。"]'),
('114ae3e0-6480-430d-ab41-b31df62d3d14','昭臺行  其一','釋居簡','宋','宋诗','song-poetry','','[]','昭臺一鏁無開扉，君恩易隨朝露晞。',160,'全唐诗/poet.song.180000.json','["昭臺一鏁無開扉，君恩易隨朝露晞。", "桃笙葵扇果何物，不長相保終奚爲。", "人言昭臺失其所，殆不知其得其死。", "當時嫁作將相妻，赤族之頃寧獨遺。", "父兮久持震主威，兄也景升豚犬兒。", "負芒之背潛生疑，禍萌驂乘渠莫知。", "君王持心亦太薄，滋蔓不圖惟稔惡。", "立無嗣續勸功臣，只書官氏標麟閣。", "將軍惜子如惜金，不爲長計誠何心。", "丈夫事業當驚世，區區烏足私家計。"]'),
('42219800-ae66-46ab-880a-3429fad12700','昭臺行  其二','釋居簡','宋','宋诗','song-poetry','','[]','將軍發機陰中的，功如熟稼生螟蟘。',128,'全唐诗/poet.song.180000.json','["將軍發機陰中的，功如熟稼生螟蟘。", "母儀天下極尊榮，非道得之非所得。", "一朝樂去悲相隨，霜露既降風凄其。", "惸惸吊景將安之，不自爲計終奚爲。", "關中舊約三章法，法當夷宗讎逆節。", "况復曾孫誅大臣，項背相望眉不顰。", "昭臺不隔昭陽路，花落鳥啼春幾度。", "麟角鳳觜皆可煎，惆悵君恩非斷弦。"]'),
('d6b27da9-2345-465f-97d6-50575d1caf33','龍井吊古','釋居簡','宋','宋诗','song-poetry','','[]','井龍孤躅轉空濛，萬斛泉源憶長公。',64,'全唐诗/poet.song.180000.json','["井龍孤躅轉空濛，萬斛泉源憶長公。", "流水高山仍古意，落花啼鳥自春風。", "石題峴首千年後，人在蘇堤萬柳中。", "惆悵半生行樂地，闌干曲曲夕陽紅。"]'),
('76191fc1-7b72-451a-a610-2ad12bfdd436','病起書蕉葉  其一','釋居簡','宋','宋诗','song-poetry','','[]','寂寞經春苦未榮，驀舒新綠上疎楹。',64,'全唐诗/poet.song.180000.json','["寂寞經春苦未榮，驀舒新綠上疎楹。", "不追松柏凌霜操，漫學梧桐送雨聲。", "抽半卷心忺趁曉，剪全開葉恨遮明。", "炎炎三伏流金石，來相茶瓜枕簟清。"]'),
('a8aa802c-c903-4b5a-aaca-a42fa8449bd6','病起書蕉葉  其二','釋居簡','宋','宋诗','song-poetry','','[]','摇青已見及時榮，獵獵翩翩襯短楹。',64,'全唐诗/poet.song.180000.json','["摇青已見及時榮，獵獵翩翩襯短楹。", "似我不才非世用，對伊側枕聽秋聲。", "影鋪缺甃侵苔綠，叢倚疎櫺蔽月明。", "脆弱不勝連夜雨，亟憑幽討餞餘清。"]'),
('50a4e6d5-db34-4771-ba68-6054c192522e','病起書蕉葉  其三','釋居簡','宋','宋诗','song-poetry','','[]','青鸞翠尾曳前榮，仄雨番風綠闖楹。',64,'全唐诗/poet.song.180000.json','["青鸞翠尾曳前榮，仄雨番風綠闖楹。", "的自夢中包死鹿，悞從雪裏著嘉聲。", "煙寒曲砌秋容澹，句滿旁行墨色明。", "盡是吹來最奇警，與君分此一襟清。"]'),
('4a6a7a11-a581-4817-8ee4-e872c223fb88','代覺無象續楮衾吟謝樓大參','釋居簡','宋','宋诗','song-poetry','','[]','一合溪藤展樣裁，蒙頭疊足傍寒隈。',32,'全唐诗/poet.song.180000.json','["一合溪藤展樣裁，蒙頭疊足傍寒隈。", "玉樓凍合春初透，只有青燈伴定回。"]'),
('2ee24f3a-a4c4-4a13-ac12-aaab9a18d6bd','送譚浚明歸江西','釋居簡','宋','宋诗','song-poetry','','[]','恨無玉楮三千幅，盡使春風歸約束。',192,'全唐诗/poet.song.180000.json','["恨無玉楮三千幅，盡使春風歸約束。", "樂饑功謝明月璫，休景息慙芰荷屋。", "朋來皎皎歌白駒，不歌長鋏彈無魚。", "批風切月瘦弗腴，枕頭一束知何書。", "欲把列城憑軾下，餘子紛紛謾凌跨。", "歸來袖手如病瘖，舌在何曾問人借。", "占燈夜喜傍短檠，劇譚不知山月傾。", "元戎後乘沸笳鼓，之子但默黄鍾聲。", "平地邛郲九折坂，十年已恨相逢晚。", "四座悲歌漏正遲，一龕風雨花頻剪。", "鏡裏功名一橫槊，百鷙啾啾空一鶚。", "雙玉未傾罍未恥，自倒玉山還自起。"]'),
('b9e78806-dff5-4752-b300-511ddeba779e','酬銛朴翁梅花  其一','釋居簡','宋','宋诗','song-poetry','','[]','槎牙絕後復重甦，綽約衝寒瘦有餘。',32,'全唐诗/poet.song.180000.json','["槎牙絕後復重甦，綽約衝寒瘦有餘。", "自是靈根鍾間氣，不從春力借吹噓。"]'),
('0b4f0469-34c1-40e0-8e96-344fe26f887e','酬銛朴翁梅花  其二','釋居簡','宋','宋诗','song-poetry','','[]','未利山礬亦可人，聖之和與聖之清。',32,'全唐诗/poet.song.180000.json','["未利山礬亦可人，聖之和與聖之清。", "由來風物須彈壓，故遣孤芳集大成。"]'),
('af4b55b9-09d8-4b00-8e4a-8308ffd66d70','酬銛朴翁梅花  其三','釋居簡','宋','宋诗','song-poetry','','[]','暗香浮動月黄昏，直與離騷力抗衡。',32,'全唐诗/poet.song.180000.json','["暗香浮動月黄昏，直與離騷力抗衡。", "今日孤山山下路，對花如對老先生。"]'),
('b672984a-e39f-44a9-b206-ee2608e32d0d','酬銛朴翁梅花  其四','釋居簡','宋','宋诗','song-poetry','','[]','一枝分遣到朱門，未插銅壺已斷魂。',32,'全唐诗/poet.song.180000.json','["一枝分遣到朱門，未插銅壺已斷魂。", "龍液麝臍勻百和，清流難洗濁江渾。"]'),
('79290ed0-e0a3-4be2-a99b-c32c35e55035','早行','釋居簡','宋','宋诗','song-poetry','','[]','鵯鴂初聲戒趣裝，强携瘦影度重岡。',32,'全唐诗/poet.song.180000.json','["鵯鴂初聲戒趣裝，强携瘦影度重岡。", "畏途政爾吳牛喘，誤把殘蟾作夕陽。"]'),
('09e9bc18-fe4e-4c80-bb5a-7b58a5ad4ba6','楊宗伯知舉出院','釋居簡','宋','宋诗','song-poetry','','[]','三級桃花把要津，懿文儲德在權衡。',64,'全唐诗/poet.song.180000.json','["三級桃花把要津，懿文儲德在權衡。", "鸞雛將授三傳託，虎榜先同一瓣盟。", "榮以依光如晝錦，樂於兼善勝專城。", "履聲早晚星辰上，弗與群仙地上行。"]'),
('4bea264b-f4cd-4f39-b9a9-fdbcc4832397','紙帳','釋居簡','宋','宋诗','song-poetry','','[]','玉楮亭亭稱冷官，晴雲垂地著蒲團。',32,'全唐诗/poet.song.180000.json','["玉楮亭亭稱冷官，晴雲垂地著蒲團。", "夢回不復疑胡蝶，猶記蟾枝宿廣寒。"]'),
('39beeb05-ff04-489f-8200-4519d1578ced','柏香岩','釋居簡','宋','宋诗','song-poetry','','[]','卜築深雲榜柏香，小樓縹渺遠吞江。',64,'全唐诗/poet.song.180000.json','["卜築深雲榜柏香，小樓縹渺遠吞江。", "路隨山轉巧當戶，潮與月來高挂窗。", "得飽但慚秋稼足，愛眠嫌聽曉鐘撞。", "明明鬭劣無求勝，一任諸方建勝幢。"]'),
('92a812f2-6b70-4621-81aa-145ff6090ada','老母元宵初度是日立春','釋居簡','宋','宋诗','song-poetry','','[]','冰鑑呵雲薄，金蓮照夜遥。',48,'全唐诗/poet.song.180000.json','["冰鑑呵雲薄，金蓮照夜遥。", "灰飛催臘盡，雪擁待春消。", "簷已冰垂柱，山猶玉墜腰。", "不知初度酒，幾度酌元宵。"]'),
('1854c843-2848-40a6-8714-c33556394159','易水行贈修和謝德之高士','釋居簡','宋','宋诗','song-poetry','','[]','悠哉招隠琅琅然，畫然勇變易水寒。',208,'全唐诗/poet.song.180000.json','["悠哉招隠琅琅然，畫然勇變易水寒。", "槁梧語急聲欲乾，哀絲欲絕回風酸。", "激昂餘地涵清圜，弗落斷崖清夜湍。", "想當悲歌蓄真怒，髮立如棘衝其冠。", "慨慷一死不復惜，從容按轡無求還。", "投機之間不容髮，一失萬古成永嘆。", "塵侵匕首壯士死，誰冩遺恨歸清彈。", "謂言此曲無再彈，渾剛不敵智士肝。", "腦脂蓋眼日高卧，幽憤欲平良獨難。", "油然易感不易觸，徒使壯泪雙汍瀾。", "琴工推琴向我言，我指何自生憂端。", "物能移人不移物，安得心廣仍體胖。", "欲令心廣仍體胖，不妨試作如此觀。"]'),
('a2e629d1-f97f-4de9-b38d-637cbd7c15c3','再贈謝高士得之','釋居簡','宋','宋诗','song-poetry','','[]','我曲非俗音，亦非正始音。',144,'全唐诗/poet.song.180000.json','["我曲非俗音，亦非正始音。", "閴然洞遺響，萬籟俱爲瘖。", "有弦不足彈，無弦不足尋。", "與之俱浮沈，適以冩我心。", "謝郎介潔彌明操，結喉深目蒼髯槁。", "劉生侯喜不相逢，弗聯石鼎歌南風。", "援琴速我城南道，爲我從頭冩懷抱。", "不是山林同苦心，更有阿誰彈得到。", "曲終月墮仍反聞，欲彈不彈心自論。", "小俟茶甘回齒頰，喚起胎仙舞三疊。"]'),
('9a4b0404-31dc-4c65-8653-928ed92a39af','贈悟上人','釋居簡','宋','宋诗','song-poetry','','[]','峩峩復湯湯，夭閼不可尋。',150,'全唐诗/poet.song.180000.json','["峩峩復湯湯，夭閼不可尋。", "哀絲一彈絕，不捄焦尾瘖。", "遂使箏笛耳，喜厥鄭衛淫。", "劃然勇爲賞音廢，此道未必皆平沈。", "盍觀薰弦育萬彙，不育傲很頑嚚心。", "廩完未既使浚井，僅脫死地仍床琴。", "拳拳終慕不知老，放勛賞此不賞其聲音。", "聖賢不與我殊類，出乎其類吾所欽。", "彈兮須彈古人意，學平當學有虞氏。", "贈穎師者韓退之，悟師鑑賞今其誰。"]'),
('86df2e49-a1d1-4cd2-b70d-476edf087ba0','移蘭','釋居簡','宋','宋诗','song-poetry','','[]','蕕劣薰優只自强，寄林亦足稱孤芳。',64,'全唐诗/poet.song.180000.json','["蕕劣薰優只自强，寄林亦足稱孤芳。", "故應紉佩成春服，不爲無人閟國香。", "移傍瘦筠同雨露，怕隨行葦踐牛羊。", "客非九畹同心事，莫反離騷吊碧湘。"]'),
('00ca9c4c-581d-4281-8ac1-b4cde870337d','送客  其一','釋居簡','宋','宋诗','song-poetry','','[]','老矣無錢買沃洲，欲從苕霅問菟裘。',32,'全唐诗/poet.song.180000.json','["老矣無錢買沃洲，欲從苕霅問菟裘。", "却煩二子先歸去，好處林塘爲相攸。"]'),
('e8322d25-b994-4691-ba07-8d377a7e184e','送客  其二','釋居簡','宋','宋诗','song-poetry','','[]','欲快青眸忍白開，故將淵默自藏雷。',32,'全唐诗/poet.song.180000.json','["欲快青眸忍白開，故將淵默自藏雷。", "苕溪今日寧無晝，不見蘋吹好句來。"]'),
('64939d12-f069-49ef-9425-34c3e648bd0d','病起','釋居簡','宋','宋诗','song-poetry','','[]','藥性從前已慣諳，折鐺彷彿舊同參。',64,'全唐诗/poet.song.180000.json','["藥性從前已慣諳，折鐺彷彿舊同參。", "無禪無道了生死，問疾問安徒再三。", "人瘦可肥姑小待，憲貧非病固多慙。", "起來細數簷前竹，新綠猗猗籜半含。"]'),
('2ae5dab6-1a31-4996-99dd-6680cfa2b528','過錢塘','釋居簡','宋','宋诗','song-poetry','','[]','初日驅陰積翳銷，鸛鵞嘈雜櫓初摇。',32,'全唐诗/poet.song.180000.json','["初日驅陰積翳銷，鸛鵞嘈雜櫓初摇。", "白鷗踏浪平如地，不似吳兒學弄潮。"]'),
('880a0490-e8f9-4a42-a9b6-a58cc281deb1','月樓陳寺簿惠李陽冰千文新刻','釋居簡','宋','宋诗','song-poetry','','[]','厥初至文無一字，誰將鳥蹟分形似。',246,'全唐诗/poet.song.180000.json','["厥初至文無一字，誰將鳥蹟分形似。", "天淳屢警不知防，七鑿纔終混沌死。", "遂令天下後世空紛綸，蟲魚鍾鼎駢相新。", "茫然不理字外意，但見九州四海同軌仍同文。", "王郎羽化不可馽，小篆千人萬人習。", "祖龍無恙事如麻，稍緩簿書期會急。", "西京杜門草太玄，諸儒載酒尊所聞。", "莫言字是紙上語，尋古康逵須得門。", "朅來小楷無餘韻，更復顛狂闚草聖。", "不見當時石鼓歌，哂乃數紙博白鵝。", "悠悠古恨憑誰雪，想見月樓時對月。", "質衣訪古錦作囊，李侯屈鐵千琳琅。", "百金購工鑱翠琰，數間僦舍生寒光。", "欲壽此書休待賈，待向君家提此話。", "不圖復見古人心，要與月樓同博雅。"]'),
('07bdd8e0-60cc-419c-ac5d-4cbd392255a5','中秋','釋居簡','宋','宋诗','song-poetry','','[]','得月山房夜夜秋，仲秋既望豈常儔。',64,'全唐诗/poet.song.180000.json','["得月山房夜夜秋，仲秋既望豈常儔。", "狡移三穴雖明見，圓印千江恐暗投。", "於我覆盆虛鏡面，爲誰飛轍碾雲頭。", "吳兒不管團如璧，只唱彎彎照幾州。"]'),
('5ece3250-7f11-4d29-9b38-daa695ea4091','後中秋夕同淵清叟宗無傳登覺無象宿蟾小閣','釋居簡','宋','宋诗','song-poetry','','[]','練挂河源夜欲流，略無雲物礙雙眸。',64,'全唐诗/poet.song.180000.json','["練挂河源夜欲流，略無雲物礙雙眸。", "有時長恨菱花破，今夕何須玉斧修。", "五載重逢餘閏歲，百年幾見兩中秋。", "更舒望海亭東嘯，細把窮鄉令節酬。"]'),
('55018551-bab5-47f9-b724-ddaa6bba0b94','過剡  其一','釋居簡','宋','宋诗','song-poetry','','[]','曹娥泪血點江潮，百里都無綠半篙。',32,'全唐诗/poet.song.180000.json','["曹娥泪血點江潮，百里都無綠半篙。", "剡水迎潮須款曲，小分清瑩洗渾濤。"]'),
('0725cdf5-def4-41e9-9c5b-511d79e1bd8d','過剡  其二','釋居簡','宋','宋诗','song-poetry','','[]','春漲新痕綠漸開，只知東去不西回。',32,'全唐诗/poet.song.180000.json','["春漲新痕綠漸開，只知東去不西回。", "濯纓莫負滄浪詠，曾送扁舟泛雪來。"]'),
('6433545d-1dd7-42e0-8411-8f34e0ea1eaf','蜂房','釋居簡','宋','宋诗','song-poetry','','[]','各開戶牖復尊王，釀熟芳鮮又絕糧。',64,'全唐诗/poet.song.180000.json','["各開戶牖復尊王，釀熟芳鮮又絕糧。", "課有常程分殿最，日無餘暇息奔忙。", "酷嫌蠆尾長摇毒，終使花頭不損香。", "細細中邊分正味，莫教勤苦度韶光。"]'),
('e6962b1f-bd49-4969-89f0-15f163a62d0a','清明善住蜂歸用前韻','釋居簡','宋','宋诗','song-poetry','','[]','霧擁雲屯畏失王，相攸來此各賫糧。',64,'全唐诗/poet.song.180000.json','["霧擁雲屯畏失王，相攸來此各賫糧。", "絮輕漠漠移家晚，花冷冥冥領衆忙。", "卒歲緩營新旨蓄，掠叢怕有欲殘香。", "凜然暗室明如晝，不待通天一點光。"]'),
('4b5543e6-91f6-4c70-9423-2abe6ab7f22a','解嘲杜鵑','釋居簡','宋','宋诗','song-poetry','','[]','神武門頭穩挂冠，至今猶頌二疎賢。',32,'全唐诗/poet.song.180000.json','["神武門頭穩挂冠，至今猶頌二疎賢。", "試將史傳從頭讀，不說西京有杜鵑。"]'),
('ce49fb91-cefd-4ea3-85df-8fd695c07635','種瓜','釋居簡','宋','宋诗','song-poetry','','[]','一畝荒園石襯沙，若爲圖蔓不傷瓜。',32,'全唐诗/poet.song.180000.json','["一畝荒園石襯沙，若爲圖蔓不傷瓜。", "丁寧落蒂方拈出，輒莫攙先摘褪花。"]'),
('1c714b0f-92bb-4998-b2df-e044cb52372b','悼壽此山','釋居簡','宋','宋诗','song-poetry','','[]','七軸瀾翻卷怒潮，九天恩重記前朝。',64,'全唐诗/poet.song.180000.json','["七軸瀾翻卷怒潮，九天恩重記前朝。", "力鞭觳觫防侵稼，活冩厓𤠌惡吠堯。", "秋幌囊螢心未老，春風吹雪鬢先彫。", "青雷玉立青如削，千載高風不寂寥。"]'),
('06748c3f-0db3-46c4-8140-97b971bd1a70','花芥  其一','釋居簡','宋','宋诗','song-poetry','','[]','澹金生色染宮黄，只作坡羹亦擅場。',32,'全唐诗/poet.song.180000.json','["澹金生色染宮黄，只作坡羹亦擅場。", "稚子不能供小摘，相呼撲蝶趁斜陽。"]'),
('5ec0a3ed-5d85-483e-89d2-69e29d44d367','花芥  其二','釋居簡','宋','宋诗','song-poetry','','[]','謝遣氊根煮菜根，雨畦晴圃駐春痕。',32,'全唐诗/poet.song.180000.json','["謝遣氊根煮菜根，雨畦晴圃駐春痕。", "聽它歲歲蕃孫息，百億須彌不足吞。"]'),
('140e0971-769c-40e9-ad15-e5a1a8ed4711','書平田田家壁','釋居簡','宋','宋诗','song-poetry','','[]','笭箵埏埴自陶漁，上大人題小教書。',32,'全唐诗/poet.song.180000.json','["笭箵埏埴自陶漁，上大人題小教書。", "不過亂山深處路，人間無處問唐虞。"]'),
('b15f890c-53ea-40c6-a8b2-7884fae15624','積雨','釋居簡','宋','宋诗','song-poetry','','[]','積雨低田欲再車，經旬濕稼糵寒沙。',32,'全唐诗/poet.song.180000.json','["積雨低田欲再車，經旬濕稼糵寒沙。", "絕憐百念如焦穀，大浸稽天不復芽。"]'),
('2a87bd64-a228-4d85-af76-8428352fe2d6','竹居','釋居簡','宋','宋诗','song-poetry','','[]','水雲不羈隨所寓，破包不挂無竹處。',176,'全唐诗/poet.song.180000.json','["水雲不羈隨所寓，破包不挂無竹處。", "眼前一日無此君，朽索徒將六駿御。", "豈無花木事幽討，自然南北如歧路。", "苕溪阿珂秀而古，虛心冏冏雲同趣。", "數椽老屋傍深雲，一畝清陰著環堵。", "歲寒門戶不勝冷，春夢池塘時得助。", "堅剛老節貫凌霜，冷澹生涯不受暑。", "客來燒筍然竹枝，客去呼兒紉竹布。", "更製芰荷供歲晚，旋采蕨薇歌日暮。", "便從此地賦真游，更把故山爲別墅。", "不妨月夜據胡床，細掃苔痕印芒屨。"]'),
('252268e1-5772-432b-9bbf-549f15fd2fc9','紅葉  其一','釋居簡','宋','宋诗','song-poetry','','[]','獵獵翩翩赤羽旗，霜裁風剪亂零吹。',32,'全唐诗/poet.song.180000.json','["獵獵翩翩赤羽旗，霜裁風剪亂零吹。", "打窗便是敲篷響，夢斷吳江欲冷時。"]'),
('528ff8ba-199c-4e2a-bd9f-eefc5c500031','紅葉  其二','釋居簡','宋','宋诗','song-poetry','','[]','要與松筠共歲寒，聽它青女苦彫殘。',32,'全唐诗/poet.song.180000.json','["要與松筠共歲寒，聽它青女苦彫殘。", "不於葉上添生色，誰辨剛中一寸丹。"]'),
('c7dfd48b-7974-4ea6-924c-358fc2aa1d02','紅葉  其三','釋居簡','宋','宋诗','song-poetry','','[]','鄭老毫端醉墨濃，朝朝傴僂拾西風。',32,'全唐诗/poet.song.180000.json','["鄭老毫端醉墨濃，朝朝傴僂拾西風。", "那知猩血燕脂外，盡在銀鈎鐵畫中。"]'),
('b88c52c7-56dc-47e7-84c2-a620fd93588b','紅葉  其四','釋居簡','宋','宋诗','song-poetry','','[]','句滿山林冩不成，怕緣流水誤虛名。',32,'全唐诗/poet.song.180000.json','["句滿山林冩不成，怕緣流水誤虛名。", "夕陽滿樹牛羊下，只看玲瓏血色明。"]'),
('d96e39da-9ba8-432a-8737-ad229e3f06e0','紅葉  其五','釋居簡','宋','宋诗','song-poetry','','[]','趁得晴秋作許妍，動人春色政秋寒。',32,'全唐诗/poet.song.180000.json','["趁得晴秋作許妍，動人春色政秋寒。", "林塘水冷溪痕瘦，鏡裏何曾欠渥丹。"]'),
('a5ccf5a3-5650-4373-9acd-32c437ee69dd','紅葉  其六','釋居簡','宋','宋诗','song-poetry','','[]','樹下收帆繫斷航，樹頭新染夜來霜。',32,'全唐诗/poet.song.180000.json','["樹下收帆繫斷航，樹頭新染夜來霜。", "小春未凜猶相貸，款曲辭柯不要忙。"]'),
('3cdbb89d-1760-454c-a091-1090d3027edc','益老得廣惠呈制帥大資槔閑居士','釋居簡','宋','宋诗','song-poetry','','[]','客已梅山訪把茆，城隅閑鏁一枝巢。',64,'全唐诗/poet.song.180000.json','["客已梅山訪把茆，城隅閑鏁一枝巢。", "金園俗下謬公舉，玉帳眼明尋淡交。", "不但據鞍尤矍鑠，尚堪策蹇作推敲。", "采毫不借江山助，誰爲高人賦解嘲。"]'),
('31c127de-4f35-4589-90e0-d8da99bb1440','圓明後葬者居祖塔前屬寺僧樹表以識之','釋居簡','宋','宋诗','song-poetry','','[]','小橋南北盡僧居，彷彿天花傍鏡湖。',64,'全唐诗/poet.song.180000.json','["小橋南北盡僧居，彷彿天花傍鏡湖。", "支遁廄中多養駿，丈人屋上試占烏。", "軒窗面面雲痕濕，樓觀層層水影孤。", "惆悵門前一抔土，倩誰封殖戒樵蘇。"]'),
('5f35b4fb-ebd7-4afd-9ec9-2ee0408f5773','萬卷堂','釋居簡','宋','宋诗','song-poetry','','[]','吾聞先進之野人，耕養之外三年通一經。',132,'全唐诗/poet.song.180000.json','["吾聞先進之野人，耕養之外三年通一經。", "區區三六一十有八載，六經未必皆知津。", "獵獵牙籤三萬軸，當時想見從頭讀。", "若將有限趁無窮，偃鼠飲河徒滿腹。", "何如一笑俱忘言，文字洗空如露蟬。", "等閑一嗅盡其要，蕭郎餘習三生前。", "萬卷堂中浩如海，一點胸中無芥蒂。", "蘢葱初日上闌干，坦腹便便日中曬。"]'),
('f5e66d90-8f34-4ade-9987-20ec6e7a1060','西湖夜歸觀打魚懷趙京兆','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','德人天游樂者全，亦以此樂均魚鳶。',128,'全唐诗/poet.song.180000.json','["德人天游樂者全，亦以此樂均魚鳶。", "陶然亦復忘所樂，西湖澄澈如心淵。", "管領西湖人不少，前後無如趙京兆。", "至今畫手畫西湖，不著綠蓑人獨釣。", "胡爲今夜月滿湖，大船小船皆得魚。", "魚登罔罟叫不得，那知老子今歸歟。", "滔滔京兆萬人海，平地翻濤渺無蓋。", "活魚之外尤活人，人在甘棠頌遺愛。"]'),
('1727b384-d7f0-4b2f-b40b-c0a9203d5462','墨梅  其一','釋居簡','宋','宋诗','song-poetry','','[]','描邈檀欒黲素元，萬紅千紫失根源。',32,'全唐诗/poet.song.180000.json','["描邈檀欒黲素元，萬紅千紫失根源。", "大玄自古人嫌白，白盡何妨反太玄。"]'),
('1e54297f-0e31-4a94-b976-d0cf3fc2ca96','墨梅  其二','釋居簡','宋','宋诗','song-poetry','','[]','楚楚仙裳澹染緇，耐寒宜瘦不宜肥。',32,'全唐诗/poet.song.180000.json','["楚楚仙裳澹染緇，耐寒宜瘦不宜肥。", "莫言無子調商鼎，卿相當年有黑衣。"]'),
('63c8a671-21ef-4249-a237-4f9cefa11449','墨梅  其三','釋居簡','宋','宋诗','song-poetry','','[]','省力尋春愈出奇，闚篷圖上看新詩。',32,'全唐诗/poet.song.180000.json','["省力尋春愈出奇，闚篷圖上看新詩。", "殺風景問春知否，兩手風霜一樣龜。"]'),
('c022c7df-7899-484c-b569-4a4028acafd5','墨梅  其四','釋居簡','宋','宋诗','song-poetry','','[]','莫恨丹青廢畫工，不須求異只須同。',32,'全唐诗/poet.song.180000.json','["莫恨丹青廢畫工，不須求異只須同。", "玉容弗及寒鴉色，故託緇塵異漢宮。"]'),
('3d7691b1-0de8-4b7a-867b-855b5c4f9370','墨竹','釋居簡','宋','宋诗','song-poetry','','[]','搜攪微茫到物初，解衣盤礴便扶疎。',32,'全唐诗/poet.song.180000.json','["搜攪微茫到物初，解衣盤礴便扶疎。", "歲寒節節曾參透，不負剛明一寸虛。"]'),
('beb2bdaf-6874-4334-8386-90b3ed250989','送道州使君江西張正父','釋居簡','宋','宋诗','song-poetry','','[]','詞學清流屬上游，可曾輕外嘆遲留。',64,'全唐诗/poet.song.180000.json','["詞學清流屬上游，可曾輕外嘆遲留。", "半生蕭洒居仁宅，千騎精明赴道州。", "曾擬朝陽鳴老鳳，暫從楚水問盟鷗。", "不妨高索山人賈，款曲歸來儘黑頭。"]'),
('bc14c40e-bc39-42e0-bfec-80cb9647ef7b','客去','釋居簡','宋','宋诗','song-poetry','','[]','茗椀篝燈自校讎，長歌伐木歗吟儔。',64,'全唐诗/poet.song.180000.json','["茗椀篝燈自校讎，長歌伐木歗吟儔。", "九回斷續珠難度，八月凄凉燕不留。", "夜雨憶同湖上榻，舊題曾拂磵西樓。", "破囊猶有新篇在，輒莫逢人說暗投。"]'),
('b7c40a40-c3f3-438c-9c53-29863b9ec219','佛手岩雨過','釋居簡','宋','宋诗','song-poetry','','[]','白雲裹山裹不盡，高處露頭低露脛。',144,'全唐诗/poet.song.180000.json','["白雲裹山裹不盡，高處露頭低露脛。", "一條懸水透雲飛，雪色蜿蜒伸脊領。", "畫然怒卷風霆震，銀鱲玉鱗俱奮迅。", "滂然纔歇四山明，濕盡悠悠雲萬頃。", "是時豁達縱雙明，岩巘更無毫髮隠。", "太華巋然不較多，直上削成五千仞。", "想應有路近丹梯，未必無花開玉井。", "便欲搴花供歲晚，更擥藕根刳短艇。", "徑上明河欲盡頭，塊藐九州聊一瞬。"]'),
('6acffaa6-992b-44ef-9314-bddb99e5e1c7','飛湍','釋居簡','宋','宋诗','song-poetry','','[]','飛湍衮衮飛當戶，平地隆隆萬鼉鼓。',208,'全唐诗/poet.song.180000.json','["飛湍衮衮飛當戶，平地隆隆萬鼉鼓。", "澎轟亂石震風霆，崩奔千仞無朝莫。", "濤神何許駕潮來，餘憤未平方震怒。", "又若飛廉聲萬竅，餘勇尚多無處賈。", "年時旱涸尚如此，况當八月九月雨。", "淵潛雖伏不能安，林棲欲寐還驚顧。", "山翁慣聽如不聞，只應自樂山中趣。", "對床展轉悲游子，咫尺華胥迷去路。", "欲隨胡蝶翩翩舉，空過夜遥忘栩栩。", "起來晨炊惡草具，誤作迅雷仍失筯。", "呼童秣馬不少駐，不待黎明出山去。", "出山定入紅塵去，欲去謂言姑小住。", "此聲不似鄭聲淫，聒耳雖喧君勿惡。"]'),
('64e3e3bb-8eb1-4af0-9d45-20bfa21a07b5','雨後山水入潮江方岩索賦','釋居簡','宋','宋诗','song-poetry','','[]','湍雪投江只得渾，觀瀾未了復消魂。',32,'全唐诗/poet.song.180000.json','["湍雪投江只得渾，觀瀾未了復消魂。", "不知從此隨流去，清白何時得反元。"]'),
('9e773072-303e-41e5-a182-d4e0779fc8d8','海莊觀稼','釋居簡','宋','宋诗','song-poetry','','[]','東輸三十六谿湍，海若谽谺不足吞。',32,'全唐诗/poet.song.180000.json','["東輸三十六谿湍，海若谽谺不足吞。", "我有黄雲連斷岸，夜深隨月看潮痕。"]'),
('a54339af-9900-4917-a658-317f39dd2be3','方岩王侍郎江西破賊歸  其一','釋居簡','宋','宋诗','song-poetry','','[]','大厦難將一木支，駕言孺子託心期。',32,'全唐诗/poet.song.180000.json','["大厦難將一木支，駕言孺子託心期。", "絕憐十八灘頭樹，不管安危管別離。"]'),
('a9ce05eb-7cef-494b-8a9c-561fbde851d8','方岩王侍郎江西破賊歸  其二','釋居簡','宋','宋诗','song-poetry','','[]','左蠡揚瀾草葑湖，軸轤啣尾礙前驅。',32,'全唐诗/poet.song.180000.json','["左蠡揚瀾草葑湖，軸轤啣尾礙前驅。", "葦航摺疊多餘地，潜伏騫騰在卷舒。"]'),
('b032fcd6-3f71-4b49-a2a1-d675dd39468e','劉改之題王總幹虜中懷親帖拉朴翁與余同賦','釋居簡','宋','宋诗','song-poetry','','[]','白雲起處感親深，故倚西風動越吟。',64,'全唐诗/poet.song.180000.json','["白雲起處感親深，故倚西風動越吟。", "送老有田非住計，欲飛無翼是歸心。", "强隨隣里雖胡語，自教琵琶只漢音。", "玉瘞遐荒元不死，夜干牛斗尚千尋。"]'),
('0c0d32f5-e441-4c94-a800-bfe090791158','方岩惠蕉絲布','釋居簡','宋','宋诗','song-poetry','','[]','綠趁桄榔剪，黄如柘繭抽。',48,'全唐诗/poet.song.180000.json','["綠趁桄榔剪，黄如柘繭抽。", "海綃雲湛染，魯縞玉溫柔。", "待月投清夜，炊菰夢冷秋。", "直然無可報，雜佩不中酬。"]'),
('380d89c6-0a58-45ac-a400-3458c8ac27f9','舟中酬竹岩','釋居簡','宋','宋诗','song-poetry','','[]','官船只合辦清游，却載蛩聲雨夜愁。',32,'全唐诗/poet.song.180000.json','["官船只合辦清游，却載蛩聲雨夜愁。", "明日蓼花蘋葉上，不知輳得幾分秋。"]'),
('ccbd0a58-af38-4d8e-a51e-785e321bd0e3','松花','釋居簡','宋','宋诗','song-poetry','','[]','都將墜粉掃殘枝，聊伴伊蒲簪蕨薇。',32,'全唐诗/poet.song.180000.json','["都將墜粉掃殘枝，聊伴伊蒲簪蕨薇。", "合賦老饕矜厚享，秋池更有芰荷衣。"]'),
('b7877dc1-f7fb-4b7c-a1ed-d329b0a8aff5','候錢蛻堂','釋居簡','宋','宋诗','song-poetry','','[]','屬聞旌節西南歸，跨劍越棧闚峩眉。',96,'全唐诗/poet.song.180000.json','["屬聞旌節西南歸，跨劍越棧闚峩眉。", "便將峩眉軟廬阜，孔明十倍於曹丕。", "懷哉西南一萬里，日者庸人擾之耳。", "豁然天地復清明，斷自葛韋遺俗起。", "我尋竹岩踏雪來，好懷盡爲江山開。", "人物於人尤不惡，更於衆角尋麟角。"]'),
('a3fa73fd-af4d-4f96-9881-24820ee20901','松風閣','釋居簡','宋','宋诗','song-poetry','','[]','繞簷惡木方童童，蒼官著脚將焉從。',128,'全唐诗/poet.song.180000.json','["繞簷惡木方童童，蒼官著脚將焉從。", "海濤熨帖清涵空，不見蘋末來蓬蓬。", "是時散衣闌獨倚，不曉此中題榜意。", "但見茫茫漲軟紅，撲滿市人烏帽底。", "蜀仙茶鼎扛無人，寥寥不復聞此聲。", "玉川凉夜更渺邈，颼颼只今無地生。", "尚憐芳草春池句，夢破客兒煩舉似。", "奪胎換骨蛻氛埃，叢霄九萬泠然去。"]'),
('4f23d0b4-d14c-434d-8521-d7d8e2592127','躑躅','釋居簡','宋','宋诗','song-poetry','','[]','露凝丹臉粲芳肌，不御鉛華亦自奇。',32,'全唐诗/poet.song.180000.json','["露凝丹臉粲芳肌，不御鉛華亦自奇。", "强學海棠春睡足，如何學得未醒時。"]'),
('5c35c860-0026-418a-83ef-5e16b2c181cc','春江曲','釋居簡','宋','宋诗','song-poetry','','[]','十里西江日日佳，回汀曲渚艷春華。',32,'全唐诗/poet.song.180000.json','["十里西江日日佳，回汀曲渚艷春華。", "秋來等得明如練，未必蒲花似柳花。"]'),
('5ca08e6a-27c5-4fcb-ba19-09f1346c4aca','贈筆工','釋居簡','宋','宋诗','song-poetry','','[]','護惜神鋒逮缺殘，回觀敗塚只潸然。',32,'全唐诗/poet.song.180000.json','["護惜神鋒逮缺殘，回觀敗塚只潸然。", "只今汗血無人問，朽骨成山直幾錢。"]'),
('b59aa488-5a3a-44f0-9982-3b7080312747','劉簿分賜茶','釋居簡','宋','宋诗','song-poetry','','[]','吁嗟草木之擅場，政和御焙登俊良。',160,'全唐诗/poet.song.180000.json','["吁嗟草木之擅場，政和御焙登俊良。", "雙龍小鳳取巧制，斷璧零圭誇襲藏。", "晴窗團玉手自碾，旋熁鐵坏玄兔盞。", "瓦瓶只候蚯蚓泣，不復浪驚浮俗眼。", "卯金之子我所識，戶外青藜扶太一。", "十襲携來訪賞音，清白猶能勝黄白。", "君家阿伶兩眼花，以德頌酒不頌茶。", "遂令手閲三百片，風味盡在山人家。", "潮從委羽山前漲，少得清漣入瓶盎。", "瓢瀹天漿睡足時，香縯絲綸九天上。"]'),
('4af5d82f-df12-4b9b-8789-4c4571d8e561','笑軒沈仲歸挽章','釋居簡','宋','宋诗','song-poetry','','[]','尊周微意託炎劉，穢史端令後世羞。',64,'全唐诗/poet.song.180000.json','["尊周微意託炎劉，穢史端令後世羞。", "不把遺經究終始，安知吾志在春秋。", "虹霓未吐身先老，龜手空傳自不侯。", "奏賦長楊上天去，斷編殘簡亂山丘。"]'),
('faec47f4-9c4f-4020-9dac-0c448e930a07','黄侍郎帥閩解后皎如晦受業寺','釋居簡','宋','宋诗','song-poetry','','[]','送客稽山欲盡頭，丁寧一語駐驊騮。',64,'全唐诗/poet.song.180000.json','["送客稽山欲盡頭，丁寧一語駐驊騮。", "荔枝莫惜輕紅擘，醽醁何妨大白浮。", "語必驚人休散失，才多在野細尋搜。", "此懷只合從公賦，說與它人定暗投。"]'),
('5cc42d92-fa1b-495e-8312-0b8f37ffc591','蕙林','釋居簡','宋','宋诗','song-poetry','','[]','薰有騰芳蕙，蕕無砌埒金。',192,'全唐诗/poet.song.180000.json','["薰有騰芳蕙，蕕無砌埒金。", "綠窗涵一鏡，朱戶掩雙岑。", "度土觀肥瘠，移根較淺深。", "不愁新綠暗，長恐軟紅侵。", "剪翠滋繁露，留芬引碧潯。", "芝蘭元並德，姚魏不同心。", "暑戰知勍敵，霜零撫壯襟。", "曉梳風獵獵，晚沐雨森森。", "草色分春思，苔痕借夕陰。", "綴藂流夜照，擁砌遞秋吟。", "佳樹青油幕，幽泉綠綺琴。", "帳空從鶴怨，盟在聽鷗尋。", "觸勝齊蠻負，騷亡甚雅沉。", "吮香須細寫，搔短愜芳簪。", "野逸勤招隠，清狂苦不禁。", "悠然飽風味，送目挂岑崟。"]'),
('381215e6-ac5d-41a9-ae2d-5ddc9ad73a3c','夜泊故山  其一','釋居簡','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','群峯雪後尚崔嵬，行盡黄昏不見梅。',32,'全唐诗/poet.song.180000.json','["群峯雪後尚崔嵬，行盡黄昏不見梅。", "獨有故廬山數曲，殷勤推月過溪來。"]'),
('be42a482-1a83-4fb5-ac46-4c98a1e45d49','夜泊故山  其二','釋居簡','宋','宋诗','song-poetry','','[]','略彴橫溪度筍輿，穉松孫竹半蓁蕪。',32,'全唐诗/poet.song.180000.json','["略彴橫溪度筍輿，穉松孫竹半蓁蕪。", "呼童相伴鉏明月，缺處重添一兩株。"]'),
('d99204be-50bc-40d2-abaa-ec4ce46cb73d','己巳元宵種松慶母生初','釋居簡','宋','宋诗','song-poetry','','[]','白髮生初慶此朝，手移松桂上岧嶤。',64,'全唐诗/poet.song.180000.json','["白髮生初慶此朝，手移松桂上岧嶤。", "要知雪操寒尤勁，長伴庭萱老不彫。", "牲養獨慙虧夙志，綵衣猶記舞元宵。", "旋添萬本青青色，小作寒江漲怒潮。"]'),
('565e38f3-5f21-481c-81ec-3df9d9ab733b','曹侯舊作題紅扇子永嘉陳原父得之','釋居簡','宋','宋诗','song-poetry','','[]','未將心事付題紅，已有靈犀一點通。',32,'全唐诗/poet.song.180000.json','["未將心事付題紅，已有靈犀一點通。", "采筆春歸橫槊後，高情都屬小元龍。"]'),
('19d12736-f27e-40f4-8d04-7987321d2533','晚歸','釋居簡','宋','宋诗','song-poetry','','[]','晚凉初試出嚴城，雲表浮圖恰上燈。',32,'全唐诗/poet.song.180000.json','["晚凉初試出嚴城，雲表浮圖恰上燈。", "歸櫂只知將月去，不知摇碎玉稜稜。"]'),
('32bbfb06-38d4-4b68-ade8-62e2a245fe99','一犂春雨圖','釋居簡','宋','宋诗','song-poetry','','[]','謝家風流絕代無，底事要作耕田夫。',160,'全唐诗/poet.song.180000.json','["謝家風流絕代無，底事要作耕田夫。", "一犂春雨開新圖，此圖之作胡爲乎。", "莫是天民先覺者，小試經綸起莘野。", "復將斯道覺斯民，千載精神入模冩。", "不然淵明賦歸後，荷鉏去種南山豆。", "晚風新霽擢良苗，一段風光相授受。", "扣之輒笑橫點頭，老農老圃吾何求。", "六經蕪翳力穮蔉，百王理亂深鉏耰。", "剪剪茆茨出林罅，菽水清歡在其下。", "聖賢所樂屬吾廬，當觀吾廬莫觀圖。"]'),
('c6e573f7-62bd-4dbf-b06e-f25bd29640d1','朴翁加冠巾蘇召叟訝予不嘲之','釋居簡','宋','宋诗','song-poetry','','[]','見與聞同駭且猜，多應自斷不佗裁。',64,'全唐诗/poet.song.180000.json','["見與聞同駭且猜，多應自斷不佗裁。", "聰明斷種豈僧事，矍鑠據鞍須將才。", "好在夕陽愁夜近，懷哉鯢齒尚心孩。", "自非獨善林泉嬾，應是林泉少禍媒。"]'),
('3df8617a-a309-4302-a496-98b5c6344f93','酬水心葉待制見寄宿覺菴記并詩','釋居簡','宋','宋诗','song-poetry','','[]','天藏今偶得，人傑古猶存。',48,'全唐诗/poet.song.180000.json','["天藏今偶得，人傑古猶存。", "莫遣苔封徑，寧教竹礙門。", "市喧酣蟻戰，潮晚看鯨吞。", "金粟元非病，何妨一駕言。"]'),
('b96f1b48-3186-42c5-8eb6-5284549abafb','中津','釋居簡','宋','宋诗','song-poetry','','[]','帆挂中津趁落潮，且停雙槳不須摇。',32,'全唐诗/poet.song.180000.json','["帆挂中津趁落潮，且停雙槳不須摇。", "却將中散憑闌意，直送孤鴻到玉霄。"]'),
('3acdb3e5-77bf-4ea8-8ff0-c61565912b02','吳江道中','釋居簡','宋','宋诗','song-poetry','','[]','蔓滋螟螣燕孫謀，爭得嫠砧不怨秋。',32,'全唐诗/poet.song.180000.json','["蔓滋螟螣燕孫謀，爭得嫠砧不怨秋。", "築圃莫嫌登稼少，尚餘蕎麥趁霜收。"]'),
('1ff30515-a36a-4445-8d41-1aa25492e063','牧童','釋居簡','宋','宋诗','song-poetry','','[]','蓬鬆袒跣倒騎牛，折得山花便滿頭。',32,'全唐诗/poet.song.180000.json','["蓬鬆袒跣倒騎牛，折得山花便滿頭。", "强使倡歌渾不聽，聽它天籟自鳴休。"]'),
('1720b6d8-8c24-45bc-83c1-dca8540052cb','秀侍者致蕈','釋居簡','宋','宋诗','song-poetry','','[]','葵藿不甘羊酪羶，筍蕨雋永非薨鱻。',208,'全唐诗/poet.song.180000.json','["葵藿不甘羊酪羶，筍蕨雋永非薨鱻。", "樹雞風度掃藜莧，蓋其氏者尤稱賢。", "敷腴孕秀茁枯朽，軟濕不齊相後先。", "春風薰陶紫芝秀，陸地挺特荷錢圓。", "雖非靈椿八千歲，要與風月三千篇。", "古源阿棠文人行，薦新已辦羅百籩。", "開端慷慨約同餉，一語不移金石堅。", "過門走致縯綸手，不記舊約篝燈前。", "小空在左輒反睨，解衣作質呼芳鮮。", "曉罌嫩汲井花水，地爐瓦鼎相周旋。", "蒲萄餘瀝正其味，鹽醯不御全乎天。", "綴盂獨當第一義，曾水洗空十萬錢。", "不須沆瀣更疏瀹，欲跨明月凌風煙。"]'),
('382c9b4e-61dc-4691-bd78-3fffd4ffec6d','樵谷','釋居簡','宋','宋诗','song-poetry','','[]','谷口雲橫草不生，弗容斤斧弗容耕。',32,'全唐诗/poet.song.180000.json','["谷口雲橫草不生，弗容斤斧弗容耕。", "呼童盡拾風前葉，自去提撕折脚鐺。"]'),
('5c6b9f8b-e5d6-4bdf-bc4e-ee3fabf5f7ff','柏堂','釋居簡','宋','宋诗','song-poetry','','[]','千載霜苓孕屈盤，虐風饕雪不知難。',32,'全唐诗/poet.song.180000.json','["千載霜苓孕屈盤，虐風饕雪不知難。", "客來莫話西來意，添箇蒲團話歲寒。"]'),
('a7592a3e-4b4f-402e-ab17-3c7550215511','霅川','釋居簡','宋','宋诗','song-poetry','','[]','茅茨傍水似浮家，自把蘋洲缺處畬。',32,'全唐诗/poet.song.180000.json','["茅茨傍水似浮家，自把蘋洲缺處畬。", "魚菜常多蔬菜少，薺根挑盡到蘆芽。"]'),
('0cc7223b-67bc-4020-8b0d-3b1040d4fdb6','酬于君實','釋居簡','宋','宋诗','song-poetry','','[]','新有吳霜著鬢顛，却無俗駕到門前。',64,'全唐诗/poet.song.180000.json','["新有吳霜著鬢顛，却無俗駕到門前。", "試尋池草生春思，不爲樓鐘廢曉眠。", "葵苦易荒鉏短日，豆甘多種廩殘年。", "家生冷淡尤堪笑，却怕炎炎又可憐。"]'),
('32074fd6-cdc9-4560-87a4-009fddfddb30','驥無稱築牆護放生池','釋居簡','宋','宋诗','song-poetry','','[]','鑿山樊圃幻屏帷，自出胸中一段奇。',64,'全唐诗/poet.song.180000.json','["鑿山樊圃幻屏帷，自出胸中一段奇。", "拓壽域歸常住地，注恩波入放生池。", "剪蒿忍放蛙分部，空穴寧教兔不疑。", "坐看春風歸約勒，先開牆角向南枝。"]'),
('2e66a97d-4e80-443d-9f7a-bf228d1d9dbd','貧樂堂','釋居簡','宋','宋诗','song-poetry','','[]','瓦盂脫粟自成歌，直與簞瓢不較多。',32,'全唐诗/poet.song.180000.json','["瓦盂脫粟自成歌，直與簞瓢不較多。", "弗恨道人貧似我，却嫌所樂弗如它。"]'),
('32dc1275-e013-422d-9297-a3deb230609c','潘子善范先之林自知賦木犀囑和','釋居簡','宋','宋诗','song-poetry','','[]','孤芳如阿平，晚乃出六奇。',144,'全唐诗/poet.song.180000.json','["孤芳如阿平，晚乃出六奇。", "傍睨肅聽瑩，請試從元推。", "韻如聖之清，避世觀商衰。", "翠幄方童童，露葉流蟾輝。", "降真換骨法，譜牒當尋披。", "悠悠千斛香，鮮風如馹馳。", "霪秋百草死，不復干等威。", "江蘺交晚生，楚英託深知。", "羅柳追逸駕，峻坂方驅羸。", "尤物能移人，心正物自移。", "年年月中仙，一人簪一枝。", "後先不須問，亦各安其時。"]'),
('f6b1ef11-6aef-430d-aaf1-eb2a1b0df791','貣粟  其一','釋居簡','宋','宋诗','song-poetry','','[]','我有一斗粟，不暇春作糜。',48,'全唐诗/poet.song.180000.json','["我有一斗粟，不暇春作糜。", "寧受藜莧誑，不忍剛腸嘶。", "要果天下腹，吾饑吾敢辭。", "長願飽者飽，毋使饑人饑。"]'),
('16b45be7-773d-4723-ba08-e4fa2ee6c178','貣粟  其二','釋居簡','宋','宋诗','song-poetry','','[]','古之聖之清，吾獨稱夷齊。',48,'全唐诗/poet.song.180000.json','["古之聖之清，吾獨稱夷齊。", "采薇替周粟，所樂甘如飴。", "山亦不義山，薇亦不義薇。", "惟其不素食，食粟令人思。"]'),
('ccf5e348-d886-4740-b827-3d26a7a75b84','今歲蘭柳相先梅最後  其一','釋居簡','宋','宋诗','song-poetry','','[]','稍殿金絲與紫莖，駸駸躐等敗清盟。',32,'全唐诗/poet.song.180000.json','["稍殿金絲與紫莖，駸駸躐等敗清盟。", "白鷗認得橫斜影，應對清流訴不平。"]'),
('9a21f629-7e8b-403b-bd0d-487e89169cc1','今歲蘭柳相先梅最後  其二','釋居簡','宋','宋诗','song-poetry','','[]','長是年年趁雪妍，一鞭遲著笑今年。',32,'全唐诗/poet.song.180000.json','["長是年年趁雪妍，一鞭遲著笑今年。", "姓名雖在百花上，終不敢爲天下先。"]'),
('f3537a1d-c70a-4a7b-be3b-c24c726cf49f','雪中訪別魏使君  其一','釋居簡','宋','宋诗','song-poetry','','[]','踏雪尋春計亦優，不如去款魏君侯。',32,'全唐诗/poet.song.180000.json','["踏雪尋春計亦優，不如去款魏君侯。", "雪裘風帽台州去，豈是無才入蔡州。"]'),
('6b5398ef-b2dd-4b9e-a43e-9d9b5da6618a','雪中訪別魏使君  其二','釋居簡','宋','宋诗','song-poetry','','[]','大雅離騷不入時，反騷變雅又奚爲。',32,'全唐诗/poet.song.180000.json','["大雅離騷不入時，反騷變雅又奚爲。", "天台好處休提掇，只詠寒山拾得詩。"]'),
('0fa18317-b602-410c-b8b0-1437cd006e0c','晚歸遇雪','釋居簡','宋','宋诗','song-poetry','','[]','集霰繽繽趁雨飄，回風籍籍委江郊。',64,'全唐诗/poet.song.180000.json','["集霰繽繽趁雨飄，回風籍籍委江郊。", "重陰凍鎖天無畛，一眼平鋪池不坳。", "直恐徑迷隨意掃，又疑竹裂带寒敲。", "倚闌欲看連雲色，更待黄昏桂影交。"]'),
('7f269e41-9ea9-4f7d-9e36-aa07fb24340e','山陰道中殘雪','釋居簡','宋','宋诗','song-poetry','','[]','晃眼鮮明未寂寥，江村猶自礙漁樵。',64,'全唐诗/poet.song.180000.json','["晃眼鮮明未寂寥，江村猶自礙漁樵。", "積陰雖重消平地，背日猶多壓小橋。", "搶地竹頭扶眩起，種畬山脚望晴燒。", "天誅螟螣躬行罸，殺氣回春款款消。"]'),
('6bf93eb2-bfb4-4c5c-b025-6482ee984930','與應真遇','釋居簡','宋','宋诗','song-poetry','','[]','神游八極乘風車，小復按轡凌谽谺。',388,'全唐诗/poet.song.180000.json','["神游八極乘風車，小復按轡凌谽谺。", "龍湫下瞰不咫尺，下有深竇無底無津涯。", "應真長年一捫膝，俯觀塵滓井底蛙。", "朝來岩室忽閴寂，水流山空鵲槎槎。", "浮雲出岫杳杳不可馽，錫聲小振巔雲丫。", "問之何以出山去，一笑不知山日斜。", "共看八紘浄如洗，五雲明潔從東嘉。", "山川所鍾一人耳，半千千載何其遐。", "經綸才大輔以德，八斗一石初何加。", "天公不忍世寂寞，憖遺一老爲國華。", "一經指授豹則虎，未獲印可龍仍蛇。", "去尋宿覺言外意，助發康樂毫端花。", "粲然穎脫世間語，簡古佶屈仍聱牙。", "稱揚此老長不老，豈憚弱水蓬萊賒。", "綸巾羽扇凜如畫，恍然來泛叢霄楂。", "群仙奔走敬且肅，百神呵護嚴不譁。", "知公醉經不以酒，玉盌自澆新露芽。", "謂言正傳僅如縷，邪說詖行紛於麻。", "正音一震擊聾瞽，洗空亂耳秋池蛙。", "廉隅道喪日滋甚，習俗侈靡相矜誇。", "清風儉德起頹俗，革去極侈仍窮奢。", "黄金羈勒駕款段，青絲絡頭閑渥洼。", "小施尺箠試鞭策，駑驥庶毋遺等差。", "振衣小作一年別，傴指盈闕之蝦蟆。"]'),
('87e9a65e-06a8-4d35-9e15-f7b03677dc4b','白藕花','釋居簡','宋','宋诗','song-poetry','','[]','一楮三年工，欲賦無三都。',48,'全唐诗/poet.song.180000.json','["一楮三年工，欲賦無三都。", "剪作千葉芳，出水淵不枯。", "照影秋湛染，摇柄春敷腴。", "夜老勺華月，側此華玉壺。"]'),
('e123054d-4a57-45ee-a1d9-a3290f5180cd','送方岩出帥平峒寇  其一','釋居簡','宋','宋诗','song-poetry','','[]','草木猶知舊姓名，妖狐折膽在先聲。',64,'全唐诗/poet.song.180000.json','["草木猶知舊姓名，妖狐折膽在先聲。", "鄉來筆下三千字，今日胸中十萬兵。", "直把文章爲小技，橫遮江漢隠長城。", "油幢坐嘯祛鋒鏑，六合清風白羽生。"]'),
('b9b2b4b0-c476-45a0-bed9-766ddac81380','送方岩出帥平峒寇  其二','釋居簡','宋','宋诗','song-poetry','','[]','漠漠江城度柳花，江南春事又天涯。',64,'全唐诗/poet.song.180000.json','["漠漠江城度柳花，江南春事又天涯。", "綠抽秧穎秋占稼，碧凝檀雲晚未衙。", "風動十連咸自化，夜嚴千竈靜無譁。", "書生只事毛錐子，試把輕裘緩带誇。"]'),
('20b7b03b-741d-4af2-9645-b7bf563beb5a','許由觀','釋居簡','宋','宋诗','song-poetry','','[]','萬乘何曾換一瓢，羽成玉骨蛻塵囂。',32,'全唐诗/poet.song.180000.json','["萬乘何曾換一瓢，羽成玉骨蛻塵囂。", "是非到耳雖無迹，潁水何曾洗得消。"]'),
('408f9cce-949e-493f-a963-97d8ca8e172a','舟中','釋居簡','宋','宋诗','song-poetry','','[]','曝背初從曉日開，當時曾說獻君來。',32,'全唐诗/poet.song.180000.json','["曝背初從曉日開，當時曾說獻君來。", "船頭亦有茆簷暖，準擬排雲又一回。"]'),
('163d05e2-40b5-4a74-91b4-af2b6450cb8b','下池  其一','釋居簡','宋','宋诗','song-poetry','','[]','漾漾璇題湛鏡光，團團素璧剪方方。',32,'全唐诗/poet.song.180000.json','["漾漾璇題湛鏡光，團團素璧剪方方。", "一抔曾勺蟾蜍玉，猶带仇池翰墨香。"]'),
('f8a5a4ae-e4aa-4b7e-8e3d-1c31afab6f88','下池  其二','釋居簡','宋','宋诗','song-poetry','','[]','老子隨行苜蓿盤，不曾無客自開單。',32,'全唐诗/poet.song.180000.json','["老子隨行苜蓿盤，不曾無客自開單。", "更將餘粒投清淺，聊爲游魚小倚闌。"]'),
('12f7dcd1-90e2-4613-bdcc-2ee8a593ca64','酬竹岩江湖偉觀','釋居簡','宋','宋诗','song-poetry','','[]','偉觀如偉人，特立萬夫上。',168,'全唐诗/poet.song.180000.json','["偉觀如偉人，特立萬夫上。", "胸中九雲夢，浩然老益壯。", "挂窗著孤山，排闥數秦望。", "平湖宜陰晴，西子亦瀾浪。", "江潮齊晦朔，海若見情狀。", "由來非地獻，亦復豈天相。", "誰將萬象影，幻此千幅悵。", "悠然會真意，何以堪俗况。", "曲闌供小立，雙眸縱遐放。", "空濛辨畛畦，平漫分趣尚。", "外則盡諸物，內則了諸妄。", "何妨水涵空，勿使雲塞向。", "不須陋狹隘，更復事寬曠。", "湛此一寸虛，秘發千古藏。"]'),
('aaf80377-ec06-488a-a2cc-2e4a72d4a55f','圓方外明偉室','釋居簡','宋','宋诗','song-poetry','','[]','沙礫不自汰，清明日遄逝。',72,'全唐诗/poet.song.180000.json','["沙礫不自汰，清明日遄逝。", "充此一寸虛，八紘靜無翳。", "天風卷滄溟，濤山鬰岧嶤。", "悠然一漚滅，中有湛不摇。", "方其澄湛時，十日洞無際。", "用晦乃全功，何妨九烏斃。"]'),
('f38dd72a-7445-4f0c-9d2e-afa12e1b19eb','魏憲使石筍小築  其一','釋居簡','宋','宋诗','song-poetry','','[]','住山做得淡生涯，泉有金沙與白沙。',32,'全唐诗/poet.song.180000.json','["住山做得淡生涯，泉有金沙與白沙。", "自課小童城市去，歸來煮飯又煎茶。"]'),
('85b587fd-bf59-45ed-9549-959d76ab0f03','魏憲使石筍小築  其二','釋居簡','宋','宋诗','song-poetry','','[]','野芳佳木自衡斜，約勒春風占物華。',32,'全唐诗/poet.song.180000.json','["野芳佳木自衡斜，約勒春風占物華。", "聊復避喧非避世，種桃不似種梅花。"]'),
('77c60ed9-4b4e-439f-b1d9-187ff6a724e0','泉上苔梅方著一花  其一','釋居簡','宋','宋诗','song-poetry','','[]','華風先試老茶牙，煖破蒼苔著一花。',32,'全唐诗/poet.song.180000.json','["華風先試老茶牙，煖破蒼苔著一花。", "淺淺石泉都凍了，不容疎影浸橫斜。"]'),
('257e56d3-ab33-478f-8463-9dc4b82f4bf7','泉上苔梅方著一花  其二','釋居簡','宋','宋诗','song-poetry','','[]','冰鎖寒泓湛不摇，瘦枝無力闖春饒。',32,'全唐诗/poet.song.180000.json','["冰鎖寒泓湛不摇，瘦枝無力闖春饒。", "風中鮮馥來無跡，一點乾酥凍不消。"]'),
('d3b79639-6964-4347-b3be-6b3089049a32','盆蕉盆稼各一首  其一','釋居簡','宋','宋诗','song-poetry','','[]','不才脆弱自天全，亦既它憐復自憐。',64,'全唐诗/poet.song.180000.json','["不才脆弱自天全，亦既它憐復自憐。", "根託器盛宜瘦小，葉從心展看芳鮮。", "近聽似有秋聲遠，側卷都無露點圓。", "時把短屏遮鳳尾，不教細字上蠻牋。"]'),
('3378daca-6308-4caf-b93b-d597fa45e1a4','盆蕉盆稼各一首  其二','釋居簡','宋','宋诗','song-poetry','','[]','尺水涵空鏡不塵，晚秧疎密政亭勻。',64,'全唐诗/poet.song.180000.json','["尺水涵空鏡不塵，晚秧疎密政亭勻。", "葉膏微雨潜分潤，手櫛鮮風不厭頻。", "萬斛堂堂嗟既沒，數莖矗矗喜懷新。", "缽盂只靠家田飯，薄享無功弗媿人。"]'),
('476db1f3-988b-4e1d-848b-e519ad4fca47','野步','釋居簡','宋','宋诗','song-poetry','','[]','嶺上人歸欲寄梅，嶺根流水隔塵埃。',32,'全唐诗/poet.song.180000.json','["嶺上人歸欲寄梅，嶺根流水隔塵埃。", "水中忽見胡麻飯，不入桃源便出來。"]'),
('667735c7-7563-487d-9e67-aaf51fb0ef25','迓回菴譙卿持節東淛','釋居簡','宋','宋诗','song-poetry','','[]','廷尉天下平，軒輊論錙銖。',240,'全唐诗/poet.song.180000.json','["廷尉天下平，軒輊論錙銖。", "時稱無冤民，傳載西京于。", "舊史讀至此，遺恨輒有餘。", "元康神爵間，趙蓋靡其軀。", "陵遲至五鳳，繼以韓楊誅。", "孝宣不足道，定國其爭乎。", "不得言則去，何苦但囁嚅。", "大哉平恕心，至是果有諸。", "公乎開禧末，定見了萬殊。", "大本固易拔，滋蔓非難圖。", "在辟疑惟輕，寸田齋以虛。", "觸藩豈無羝，漏網固有魚。", "執中事寬大，吹春甦槁枯。", "近者獲自新，遠者免自洿。", "至仁不勝用，盛德多陰儲。", "一節雄東藩，六月馳軺車。", "歌謠沸先聲，弩矢觀前驅。", "清風方泠然，列城斯凜如。", "民物破鬰陶，雲翳亦展舒。", "歛此一道惠，歸爲商鼎需。"]'),
('8f0a6ab0-73cf-4aed-9c2f-f33c5524fd78','賀李臨海雨','釋居簡','宋','宋诗','song-poetry','','[]','喚得蜿蜒覺黑甜，油然雲氣起沉潛。',64,'全唐诗/poet.song.180000.json','["喚得蜿蜒覺黑甜，油然雲氣起沉潛。", "一聲霹靂飛寥泬，三日霶𩃱洗赫炎。", "水足舊畦仍浸閘，夜凉新月又闚簷。", "令君後樂先黎庶，大有今年不再占。"]'),
('e389243e-c473-4e91-9922-1f51e4cc9aa8','冷泉待月  其一','釋居簡','宋','宋诗','song-poetry','','[]','猶自單衣怯夜闌，不風亭戶子聲乾。',32,'全唐诗/poet.song.180000.json','["猶自單衣怯夜闌，不風亭戶子聲乾。", "平生知己蓮峯月，不爲衣單不倚欄。"]'),
('36020ee9-b150-47c4-a96b-74109d2642f7','冷泉待月  其二','釋居簡','宋','宋诗','song-poetry','','[]','閘住亭前綠半篙，泉中白兔眇秋毫。',32,'全唐诗/poet.song.180000.json','["閘住亭前綠半篙，泉中白兔眇秋毫。", "庾樓自是當年好，番襪工夫合反騷。"]'),
('83b9fdfe-6aff-4e55-b4b1-c024a25cbb69','冷泉待月  其三','釋居簡','宋','宋诗','song-poetry','','[]','眩轉金波凝不闌，特尋佳處閣團團。',32,'全唐诗/poet.song.180000.json','["眩轉金波凝不闌，特尋佳處閣團團。", "南飛烏鵲噇眠去，獨與飛來小朵看。"]'),
('a9ae6d52-5424-488a-ac5a-e6c40d543e20','金鰲山御榻','釋居簡','宋','宋诗','song-poetry','','[]','丁未龍飛動四溟，驚濤曾豈礙揚舲。',64,'全唐诗/poet.song.180000.json','["丁未龍飛動四溟，驚濤曾豈礙揚舲。", "抃鰲不露黄金背，跨岸誰開白玉京。", "環扈翠華驅海若，勒回釣艇問山靈。", "暮鍾萬歲千秋頌，澄徹堯聰得細聆。"]'),
('42154638-18ce-4f8f-ab0e-49117819a364','高潮莊中秋','釋居簡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','貫見冰盤出海山，可曾海上看團團。',64,'全唐诗/poet.song.180000.json','["貫見冰盤出海山，可曾海上看團團。", "全潮退舍開平地，萬里無雲展素紈。", "冷怯單衣沾沆瀣，皎如白晝數峰巒。", "敗荷深蕩僧歸去，髣髴西湖畫裏看。"]'),
('3ea6a902-6d42-4271-87f8-1ed4b33e077d','題永嘉楊孟均巫山圖','釋居簡','宋','宋诗','song-poetry','','[]','部領群峯壓小巫，陽臺猶自雪糢糊。',32,'全唐诗/poet.song.180000.json','["部領群峯壓小巫，陽臺猶自雪糢糊。", "若教指點猿啼處，判得剛腸百斷無。"]'),
('5e6402c0-a4d1-4f75-95a1-11dafb2a961b','蒙泉','釋居簡','宋','宋诗','song-poetry','','[]','坎井只丈尋，得名由參寥。',132,'全唐诗/poet.song.180000.json','["坎井只丈尋，得名由參寥。", "丈人玄豹姿，養德富不驕。", "想當發泉蒙，如此湛弗摇。", "珠明水增媚，鏡浄塵當消。", "陶泓勺餘瀝，采筆生春潮。", "止則雲沉沉，漲則桃夭夭。", "淘趁槐火新，戰與坡仙挑。", "壇拜十四字，高山鬰岧嶤。", "燈灺謾圖續，些苦何能招。", "須公起九原，爲我飲一瓢。", "於戲不可作，仰止蒼崖腰。"]'),
('fbb706e6-6359-4be9-b648-72bd743a40dc','酬子壽謝宮使七夕見寄','釋居簡','宋','宋诗','song-poetry','','[]','吾門開康莊，吾心洞秋旻。',132,'全唐诗/poet.song.180000.json','["吾門開康莊，吾心洞秋旻。", "泓澄湛無底，方寸無涯津。", "美人隔秋水，數月一合并。", "昨宵七月七，游子脚不停。", "仰看烏鵲橋，遥盼牛女星。", "籲天致私禱，席地羅廣庭。", "乞巧問天孫，逐物昧己靈。", "齊東田野間，語言殊不經。", "夫何古猶今，競作奔奔鶉。", "玉霄眇空闊，銀漢橫青冥。", "不須賦解嘲，且復歌閑情。"]'),
('f16c0140-50be-42bc-91b6-befcf7245c8b','霜柳','釋居簡','宋','宋诗','song-poetry','','[]','春傍垂楊困得醒，池塘部曲頓精明。',32,'全唐诗/poet.song.180000.json','["春傍垂楊困得醒，池塘部曲頓精明。", "褪寒欲試鵞兒淺，商略工夫苦未成。"]'),
('6064896c-bee1-4d2f-808c-df2a609b5b35','雙頭蘭','釋居簡','宋','宋诗','song-poetry','','[]','艾擁蕭陵雪未消，蒂連芳萼闖春饒。',32,'全唐诗/poet.song.180000.json','["艾擁蕭陵雪未消，蒂連芳萼闖春饒。", "國香不似傾城色，寂寞空山大小喬。"]'),
('925da1f1-3502-4696-8126-fe1d2786c727','落梅','釋居簡','宋','宋诗','song-poetry','','[]','一點消磨幾許春，苔生新綠襯殘馨。',32,'全唐诗/poet.song.180000.json','["一點消磨幾許春，苔生新綠襯殘馨。", "忍看卷地隨風去，不忍兒童掃亂零。"]'),
('65645f49-bd76-4ec3-a199-86ff8a992026','如隠','釋居簡','宋','宋诗','song-poetry','','[]','堂堂偉冠衣，琅琅歌紫芝。',96,'全唐诗/poet.song.180000.json','["堂堂偉冠衣，琅琅歌紫芝。", "洗空綺紈習，政恐富貴逼。", "富貴安在哉，一笑付倘來。", "不來亦不覓，不直水一杯。", "小圃時時開，不待春登臺。", "俗駕驅塵埃，合爲山靈回。", "隠非盛世事，說與隠君子。", "未盡碧山魚，此隠誠何如。"]'),
('f8aa2b52-d311-447f-97a5-277945070045','和素齋口占兼簡戇菴','釋居簡','宋','宋诗','song-poetry','','[]','岸巾斜日倚庭柯，調度疎明似小坡。',64,'全唐诗/poet.song.180000.json','["岸巾斜日倚庭柯，調度疎明似小坡。", "長鋏不彈秋寂寞，短檠更問夜如何。", "青雲舊約聯鑣上，白苧新聞對酒歌。", "秉鉞登壇誰獨步，今淮陰更辦多多。"]'),
('d1651090-f376-4688-a3ca-55ee68bb54ee','萬年寺前古杉','釋居簡','宋','宋诗','song-poetry','','[]','千載萬年門外樹，銅柯鐵幹古髯鬚。',64,'全唐诗/poet.song.180000.json','["千載萬年門外樹，銅柯鐵幹古髯鬚。", "鶴歸空誤單華表，鹿走徒羞五大夫。", "自厚本根雖磊砢，不煩枝葉衒敷腴。", "棟梁大厦知多少，落落群空只一株。"]'),
('cb73b3f4-353d-4d28-920c-82e190d603f0','羅漢嶺上古杉','釋居簡','宋','宋诗','song-poetry','','[]','一畝蔽蒼苔，曇猷手自栽。',48,'全唐诗/poet.song.180000.json','["一畝蔽蒼苔，曇猷手自栽。", "滴高零露馥，蟠厚烈風哀。", "黛色垂雲黑，丹心閲世灰。", "兒孫幾度老，獨立暝雲隈。"]'),
('19be67df-6ee6-4e91-8227-50852a108bc4','酬金陵吳別駕','釋居簡','宋','宋诗','song-poetry','','[]','鄉來王謝不傳衣，只有烏衣烏鵲知。',32,'全唐诗/poet.song.180000.json','["鄉來王謝不傳衣，只有烏衣烏鵲知。", "無限去思無處繫，斷魂長是燕歸時。"]'),
('a0f5a256-1330-4374-b25f-47b968e89f0a','盆荷','釋居簡','宋','宋诗','song-poetry','','[]','萍粘老瓦水涵天，數葉田田小帖錢。',32,'全唐诗/poet.song.180000.json','["萍粘老瓦水涵天，數葉田田小帖錢。", "才大古來無處用，不須十丈藕如船。"]'),
('072af8ae-74f4-41f0-a75c-4b1a43e6cc0e','池上','釋居簡','宋','宋诗','song-poetry','','[]','冰澌潄齒夜生寒，白苧生裁踏月殘。',32,'全唐诗/poet.song.180000.json','["冰澌潄齒夜生寒，白苧生裁踏月殘。", "水面有風人不見，只教荷氣上闌干。"]'),
('c3abd967-a55b-4ad4-878d-78fa4f2dca34','寄楊大監','釋居簡','宋','宋诗','song-poetry','','[]','商飈流西金，萬卉寒如灰。',156,'全唐诗/poet.song.180000.json','["商飈流西金，萬卉寒如灰。", "廣寒爛銀闕，初放蟾枝開。", "一花墮九地，四海無纖埃。", "鍾作河嶽靈，挺此梁棟才。", "倘可濟巨川，不然爲鹽梅。", "我欲問此翁，山林起摧頹。", "勺以長安酤，大白非鯨杯。", "擘麟配萬錢，鳥爪去不回。", "抑以頌與箴，聳德如徂徠。", "賦豈料敵手，吟非橫槊才。", "不如姑置之，高卧深雲隈。", "長嘯揖箕翼，更把靈椿栽。", "明年紫荷橐，此約當重來。"]'),
('0b51651a-a8d3-414a-8a3e-ce8ed9d79d02','次張文昌送川張道人韻','釋居簡','宋','宋诗','song-poetry','','[]','萬水遶千山，翩然去不難。',48,'全唐诗/poet.song.180000.json','["萬水遶千山，翩然去不難。", "雙明元自碧，方寸爲誰丹。", "鶴化曾留句，鳬輕欲振翰。", "不知藏世界，一粟幾何寬。"]'),
('07ca37d0-bf78-401d-b558-2d3cfd344421','樓大參囑珣起宗索孤山舊藁  其一','釋居簡','宋','宋诗','song-poetry','','[]','舊賦梅花欲反騷，效顰徒自不償勞。',64,'全唐诗/poet.song.180000.json','["舊賦梅花欲反騷，效顰徒自不償勞。", "未尋處士孤山夢，誤得先生一字褒。", "剪剪衰蘭甘草莽，朣朣華月在林皋。", "從來平地神仙脚，咫尺鈞衡步武高。"]');
